function orderShippingRatesSort($a, $b)
{
    // custom sort function to sort the shipping rates into the correct order
    // this has to sit outside the object

    if ($a['sell'] < $b['sell'])
    {
        return -1;
    }
    else if ($a['sell'] == $b['sell'])
    {
        return 0;
    }
    else
    {
        return 1;
    }
}

function orderItemComponentSortOrder($a, $b)
{
    // sorting the component array based on the components sort order.
    // this is so that they appear in the same order as they do on the product tree.
    // this has to sit outside the object

    if ($a['sortorder'] < $b['sortorder'])
    {
        return -1;
    }
    else if ($a['sortorder'] == $b['sortorder'])
    {
        return 0;
    }
    else
    {
        return 1;
    }
}

class taopixMySQLI extends mysqli
{

    protected static $connected = false;
    protected static $connectionCount = 0;

    function __construct($host = "", $username = "", $passwd = "", $dbname = "", $port = 0, $socket = 0)
    {
        if (!$host)
        {
            $host = ini_get("mysqli.default_host");
        }

        if (!$username)
        {
            $username = ini_get("mysqli.default_user");
        }

        if (!$passwd)
        {
            $passwd = ini_get("mysqli.default_pw");
        }

        if (!$port)
        {
            $port = ini_get("mysqli.default_port");
        }

        if (!$socket)
        {
            $socket = ini_get("mysqli.default_socket");
        }
        parent::__construct($host, $username, $passwd, $dbname, $port, $socket);

        if (!mysqli_connect_errno())
        {
            self::$connected = true;
            self::increaseCount();
        }
    }

    function increaseCount()
    {
        if (self::$connected)
        {
            self::$connectionCount++;
        }
    }

    function close()
    {
        /*
         * Writes database error messages to error log if there are any.
         */
        if ($this->error)
        {
            $backtrace = debug_backtrace();
            error_log($this->error . ', ' . $backtrace[1]['file'] . '::' . $backtrace[1]['function'] . '()' . '::' . $backtrace[1]['line']);
        }

        if (self::$connected)
        {
            self::$connectionCount--;
        }
    }

    function closeDB()
    {
        parent::close();
    }

}

class taopixDB
{
	/**
	 * @var taopixMySQLI|null
	 */
    protected static $connection = null;

	/**
	 * @return taopixMySQLI|null
	 */
    function connect()
    {
        // open and return a connection to the database
        global $ac_config;

        $dbhost = $ac_config['DBHOST'];
        $dbuser = $ac_config['DBUSER'];
        $dbpass = $ac_config['DBPASS'];

        if (!self::$connection)
        {
            $connected = false;
            $retryCount = 20;
            while ((!$connected) && ($retryCount > 0))
            {
                self::$connection = new taopixMySQLI($dbhost, $dbuser, $dbpass, $ac_config['DBNAME']);
                if ((self::$connection) && (!mysqli_connect_errno()))
                {
                    self::$connection->autocommit(true);
                    self::$connection->query("SET NAMES 'utf8'");
                    $connected = true;
                }
                else
                {
                    // we couldn't get a connection so sleep for a small length of time and try again
                    usleep(500000);
                    $retryCount--;
                }
            }
        }
        else
        {
            self::$connection->increaseCount();
            $connected = true;
        }

        if ($connected)
        {
            return self::$connection;
        }
        else
        {
            print mysqli_connect_error();
        }
    }

    function __destruct()
    {
        if (self::$connection)
        {
            self::$connection->closeDB();
        }
    }

}

class DatabaseObj
{

    protected static $connection = null;

    static function getConnection()
    {
        // open and return a connection to the database
        global $ac_config;

        $dbhost = $ac_config['DBHOST'];
        $dbuser = $ac_config['DBUSER'];
        $dbpass = $ac_config['DBPASS'];

        $connected = false;
        $retryCount = 20;
        while ((!$connected) && ($retryCount > 0))
        {
            $dbConnection = new mysqli($dbhost, $dbuser, $dbpass, $ac_config['DBNAME']);
            if (($dbConnection) && (!mysqli_connect_errno()))
            {
                $dbConnection->autocommit(true);
                $dbConnection->query("SET NAMES 'utf8'");
                $connected = true;
            }
            else
            {
                // we couldn't get a connection so sleep for a small length of time and try again
                usleep(500000);
                $retryCount--;
            }
        }

        if ($connected)
        {
            return $dbConnection;
        }
        else
        {
            print mysqli_connect_error();
        }
    }

    static function getGlobalDBConnection()
    {
        // open and return a connection to the database

        if (!self::$connection)
        {
            self::$connection = new taopixDB;
        }

        return self::$connection->connect();
    }

    static function stmt_bind_assoc(&$stmt, &$out)
    {
        // bind the results to an associative array
        $data = mysqli_stmt_result_metadata($stmt);

        $fields = Array();
        $out = Array();

        $fields[0] = $stmt;
        $count = 1;

        while ($field = mysqli_fetch_field($data))
        {
            $fields[$count] = &$out[$field->name];
            $count++;
        }

        call_user_func_array('mysqli_stmt_bind_result', $fields);
    }

    /**
     * Retrieves the product collection configuration data for this TAOPIX system
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 3.0.0
     */
    static function getAutoUpdateProductCollectionList($pGroupCode, $pCompanyCode, $pIncludeGlobal, $pSortBy = '', $pSortOrder = '')
    {
        // return an array containing the products that are available via auto-update for the group code
        global $gSession;

        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $productList = Array();
        $productID = 0;
        $productCode = '';
        $productName = '';
        $productVersion = '';
        $productAppVersion = '';
        $productDataVersion = '';
        $productFileName = '';
        $productUpdatePriority = 0;
        $productDependencies = '';
        $productFileSize = 0;
        $productFileChecksum = '';
        $productHasPreview = 0;
        $productSeparateComponents = 0;
        $isActive = 0;
        $deleted = 0;
        $company = '';
        $companyFilter = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // get product colelctions that are either assigned to a company or global, just global, or show all
            // if we need to include all companies then do not filter
            if ($pCompanyCode == '**ALL**')
            {
                $companyFilter = '';
            }
            else
            {
                // we are not including all companies so first filter by the company code
                $companyFilter = " AND ((`companycode` = '" . $pCompanyCode . "')";

                // if we need to include global products add this into the filter as long as the company code isn't empty as this will already include global products
                if (($pIncludeGlobal == true) && ($pCompanyCode != ''))
                {
                    $companyFilter .= "OR (`companycode` = '')";
                }

                $companyFilter .= ')';
            }

            if ($pSortBy !== '')
            {
                $customSort = ', `' . $pSortBy . '` ' . $pSortOrder;
            }
            else
            {
                $customSort = '';
            }
            if ($stmt = $dbObj->prepare('SELECT `id`, `companycode`, `ref`, `appversion`, `dataversion`, `name`, `filename`, `versiondate`,
            		`updatepriority`, `dependencies`, `size`, `checksum`, `haspreview`, `separatecomponents`, `hasdesktoplayouts`, `active`, `deleted`
                    FROM `APPLICATIONFILES` WHERE (`type` = 0)' . $companyFilter . ' ORDER BY `companycode` ' . $customSort . ', `ref`'))
            {
                if ($stmt->execute())
                {
                    // we store the result and then fetch the rows as this improves performance when there is a lot of data to retrieve
                    $stmt->store_result();

                    if ($stmt->bind_result($productID, $company, $productCode, $productAppVersion, $productDataVersion, $productName, $productFileName, $productVersion,
                                    $productUpdatePriority, $productDependencies, $productFileSize, $productFileChecksum, $productHasPreview,
                                    $productSeparateComponents, $hasDesktopLayouts, $isActive, $deleted))
                    {

                        // process each product
                        while ($stmt->fetch())
                        {
                            $addItem = true;

                            // determine if we should include this item
                            // taopix builder receives all non-deleted items
                            // taopix designer receives all items. however, items which have been deleted or items with no desktop layouts are marked as inactive
                            if ($pGroupCode == '**ALL**')
                            {
                                // taopix builder
                                if ($deleted == 1)
                                {
                                    $addItem = false;
                                }
                            }
                            else
                            {
                                //taopix designer
                                if ($hasDesktopLayouts == 0)
                                {
                                    $isActive = false;
                                }

                                if ($deleted == 1)
                                {
                                    $isActive = false;
                                }
                            }

                            if ($addItem == true)
                            {

                                // if the product is not active then clear data which is not required to optimise what is returned to the designer
                                if (($pGroupCode != '**ALL**') && ($isActive == false))
                                {
                                    $productName = '';
                                    $productDescription = '';
                                    $productDependencies = '';
                                    $productFileChecksum = '';
                                }

                                $productItem = Array();
                                $productItem['id'] = $productID;
                                $productItem['company'] = $company;
                                $productItem['code'] = $productCode;
                                $productItem['name'] = $productName;
                                $productItem['version'] = $productVersion;
                                $productItem['appversion'] = $productAppVersion;
                                $productItem['dataversion'] = $productDataVersion;
                                $productItem['filename'] = $productFileName;
                                $productItem['updatepriority'] = $productUpdatePriority;
                                $productItem['dependencies'] = $productDependencies;
                                $productItem['filesize'] = $productFileSize;
                                $productItem['checksum'] = $productFileChecksum;
                                $productItem['haspreview'] = $productHasPreview;
                                $productItem['separatecomponents'] = $productSeparateComponents;
                                $productItem['isactive'] = $isActive;
                                $productItem['deleted'] = $deleted;

                                $productList[] = $productItem;
                            }
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateProductCollectionList bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind result
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateProductCollectionList execute ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getAutoUpdateProductCollectionList prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getAutoUpdateProductCollectionList connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['productlist'] = &$productList;

        return $resultArray;
    }

	/**
	* Retrieves the product configuration data for this TAOPIX system
	*
	* @static
	*
	* @return array
	*   the result array will contain the response of the database operation
	*
	* @author Kevin Gale
	* @since Version 1.0.0
	*/
    static function getAutoUpdateProductList($pProductCollectionCode, $pGroupCode, $pCompanyCode, $pTaxZoneDataArray, $pIncludeGlobal,
            $pLicenseKeyProductTaxCode)
    {

        // return an array containing the products that are available via auto-update for the group code
        global $gSession;

        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $productList = Array();
        $productID = 0;
        $productCollectionCode = '';
        $productCode = '';
        $productName = '';
        $productType = 0;
        $createNewProjects = 1;
        $isActive = 0;
        $pricingModel = 0;
        $price = '';
        $priceDescription = '';
        $company = '';
        $companyFilter = '';
        $taxRateDataArray = Array();
        $productTaxCode = $pLicenseKeyProductTaxCode;
        $priceTaxRate = 0.00;
        $publishVersion = 0;
        $collectionThumbnailResourceRef = '';
        $collectionThumbnailResourceDataUID = '';
        $collectionPreviewResourceRef = '';
        $collectionPreviewResourceDataUID = '';
        $collectionSortLevel = '';
        $collectionTextEngineVersion = 0;
        $productTarget = 0;
        $productAIModeDesktop = 0;
        $productMinPageCount = 0;
        $productSelectorModeDesktop = 0;
        $collectionSummary = '';
        $collectionPreviewResourceDevicePixelRatio = 1;
        $collectionThumbnailResourceDevicePixelRatio = 1;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // get products that are either assigned to a company or global, just global, or show all
            // if this is an auto-update build a list of products that have cover or paper
            // this is used later on to reduce the number of component lookups we have to perform
            $dataCacheArray = Array();
            $componentArray = Array();

            if ($pCompanyCode != '**ALL**')
            {
				$sql = 'SELECT CONCAT(`parentpath`, `productcode`) AS componentproductpath, COUNT(*) FROM `PRICELINK`
                                            WHERE (`productcode` IN (SELECT `code` FROM `PRODUCTS`)) AND ((`parentpath` = "$COVER\\\\")
                                            OR (`parentpath` = "$PAPER\\\\") OR (`parentpath` = "$SINGLEPRINT\\\\") OR (`parentpath` = "$CALENDARCUSTOMISATION\\\\")
											OR (`parentpath` = "$TAOPIXAI\\\\"))
                                            AND ((`groupcode` = ?) OR (`groupcode` = ""))
                                            GROUP BY componentproductpath';

                if ($stmt = $dbObj->prepare($sql))
                {
                    if ($stmt->bind_param('s', $pGroupCode))
                    {
                        if ($stmt->bind_result($componentProductPath, $count))
                        {
                            if ($stmt->execute())
                            {
                                while ($stmt->fetch())
                                {
                                    $componentArray[$componentProductPath] = $count;
                                }
                            }
                        }
                    }

                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
            }


            // if we need to include all companies then do not filter
            if ($pCompanyCode == '**ALL**')
            {
                $companyFilter = '';
            }
            else
            {
                // we are not including all companies so first filter by the company code
                $companyFilter = " WHERE ((PRODUCTS.companycode = '" . $pCompanyCode . "')";

                // if we need to include global products add this into the filter as long as the company code isn't empty as this will already include global products
                if (($pIncludeGlobal == true) && ($pCompanyCode != ''))
                {
                    $companyFilter .= " OR (PRODUCTS.companycode = '')";
                }

				$companyFilter .= ")";
            }

            if ($pProductCollectionCode != '')
            {
                $collectionFilter = ' AND `collectioncode` = ? ';
                $typeArray = Array('s');
                $paramArray[] = $pProductCollectionCode;
            }
            else
            {
                $collectionFilter = '';
                $typeArray = Array();
                $paramArray = Array();
            }



			$sql = 'SELECT PRODUCTS.id, PRODUCTS.companycode, `collectioncode`, `code`, `name`, `collectiontype`, `availabledesktop`, `hasbeenavailabledesktop`,
            								PRODUCTS.taxlevel, `createnewprojects`, `productoptions`, `pricetransformationstage`, `active`, `deleted`,
                                            `pcl`.`publishversion`, `pcl`.`collectionthumbnailresourceref`, `pcl`.`collectionthumbnailresourcedatauid`,
                                            `pcl`.`collectionpreviewresourceref`, `pcl`.`collectionpreviewresourcedatauid`, `pcl`.`collectionsortlevel`, `pcl`.`collectiontextengineversion`,
                                            `pcl`.`producttarget`, `pcl`.`productminpagecount`, `pcl`.`productaimodedesktop`, `pcl`.`productselectormodedesktop`, `pcl`.`collectionsummary`,
                                            `pcl`.`collectionthumbnailresourcedevicepixelratio`, `pcl`.`collectionpreviewresourcedevicepixelratio`
                     					FROM `PRODUCTS` LEFT JOIN `PRODUCTCOLLECTIONLINK` AS `pcl` ON `code` = `productcode`' . $companyFilter . $collectionFilter .
                     					' ORDER BY `collectioncode`, `code`';

            if ($stmt = $dbObj->prepare($sql))
            {
                // this command allows the creation of multiple prepares before the original prepare statement data has been fetched.
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);

                $bindOK = DatabaseObj::bindParams($stmt, $typeArray, $paramArray);
                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                    	// we store the result and then fetch the rows as this improves performance when there is a lot of data to retrieve
                        $stmt->store_result();

                        if ($stmt->bind_result($productID, $company, $productCollectionCode, $productCode, $productName, $productType, $availableDesktop,
                                        $hasBeenAvailableDesktop, $productTaxLevel, $createNewProjects, $productOptions, $priceTransformationStage, $isActive, $productDeleted,
                                        $publishVersion, $collectionThumbnailResourceRef, $collectionThumbnailResourceDataUID,
                                        $collectionPreviewResourceRef, $collectionPreviewResourceDataUID, $collectionSortLevel, $collectionTextEngineVersion,
                                        $productTarget, $productMinPageCount, $productAIModeDesktop, $productSelectorModeDesktop, $collectionSummary,
                                        $collectionThumbnailResourceDevicePixelRatio, $collectionPreviewResourceDevicePixelRatio))
                        {
                            // process each product

                            $previousTaxCode = '';
                            while ($stmt->fetch())
                            {
                            	$includeProduct = true;
                                $priceDescription = '';
                                $pricingModel = 0;
                                $price = '';
                                $quantityIsDropDown = 0;
                                $coverArray = Array();
                                $paperArray = Array();
                                $singlePrintArray = Array();
								$singlePrintOptionArray = Array();
								$calendarCustomisationArray = Array();
								$AIComponentArray = Array();
                                $productTreeProductCode = $productCode;

								// if we are getting the data for the desktop designer auto-update process check to see if we can optimise what is returned
								if (($pGroupCode != '**ALL**') && ($pProductCollectionCode == ''))
                                {
                                	// if the product has never been available to the desktop designer we never include any data for the product
									if ($hasBeenAvailableDesktop == 0)
									{
										$isActive = 0;
										$includeProduct = false;
										$productDeleted = 1;
									}
									else
									{
										// the product has been available to the desktop designer at some point so we need to include some data
										// however, if it is currently not available to the desktop designer we can mark it as inactive and avoid retrieving the price data
										if ($availableDesktop == 0)
										{
											$isActive = 0;
										}
									}
                                }


								// if we are getting the products for the auto-update or live pricing process determine if we need to retrieve the pricing data
                                // we perform this if the user is allowed to create new projects for the product, it is active and hasn't been deleted
                                if (($pGroupCode != '**ALL**') && ($isActive == 1))
                                {
									if (($createNewProjects == 1) && ($productDeleted == 0))
									{
										// now check the price details
										// first check if we have already cached this product price as the same product could occur in several collections
										$dataCacheKey = 'PRODUCT.' . $productCode . '.' . $pGroupCode . '.' . $pCompanyCode;
										if (array_key_exists($dataCacheKey, $dataCacheArray))
										{
											$priceArray = $dataCacheArray[$dataCacheKey];
										}
										else
										{
											$priceArray = self::getProductPriceRow(0, $productCode, $pGroupCode, $pCompanyCode);
											$dataCacheArray[$dataCacheKey] = $priceArray;
										}

                                        if ($priceArray['result'] == '')
                                        {
                                            // get the product linking code for use in all component checks
                                            $productLinkingArray = self::getApplicableProductLinkCode($productCode);

                                            if ($productLinkingArray['error'] == '')
                                            {
                                                if ($productLinkingArray['linkedcode'] !== '')
                                                {
                                                    $productTreeProductCode = $productLinkingArray['linkedcode'];
                                                }
                                            }
                                            else
                                            {
                                                // cannot safely price the product, set to inactive
                                                $isActive = 0;
                                            }
                                        }

										if (($isActive == 1) && ($priceArray['result'] == ''))
										{
											$pricingModel = $priceArray['pricingmodel'];
											$price = $priceArray['price'];
											$priceDescription = $priceArray['pricedescription'];
											$quantityIsDropDown = $priceArray['quantityisdropdown'];
											$isActive = $priceArray['isactive'];
											$priceTaxRate = $priceArray['taxrate'];


											// check if we have cover entries for this product
											// first check if we have already cached the cover data as the same product / cover combination could occur in several collections
											$dataCacheKey = 'COVER.' . $productTreeProductCode . '.' . $pGroupCode . '.' . $pCompanyCode;
											if (array_key_exists($dataCacheKey, $dataCacheArray))
											{
												$coverArray = $dataCacheArray[$dataCacheKey];
											}
											else
											{
												// check to see if there are cover components available for this product
												if (array_key_exists('$COVER\\' . $productTreeProductCode, $componentArray))
												{
													// we have some cover components so now look deeper and retrieve the list of available cover components for the product
													$coverArray = self::getComponentsInOrderSectionByCategory('$COVER\\', 'COVER',
																	$pCompanyCode, $productTreeProductCode, $pGroupCode, 1.0, 2, -1, -1, -1, '', false, false);
													$coverArray = $coverArray['component'];
												}
												else
												{
													$coverArray = Array();
												}

												$dataCacheArray[$dataCacheKey] = $coverArray;
											}


											// check if we have paper entries for this product
											// first check if we have already cached the paper data as the same product / paper combination could occur in several collections
											$dataCacheKey = 'PAPER.' . $productTreeProductCode . '.' . $pGroupCode . '.' . $pCompanyCode;
											if (array_key_exists($dataCacheKey, $dataCacheArray))
											{
												$paperArray = $dataCacheArray[$dataCacheKey];
											}
											else
											{
												// check to see if there are paper components available for this product
												if (array_key_exists('$PAPER\\' . $productTreeProductCode, $componentArray))
												{
													// we have some paper components so now look deeper and retrieve the list of available paper components for the product
													$paperArray = self::getComponentsInOrderSectionByCategory('$PAPER\\', 'PAPER',
																	$pCompanyCode, $productTreeProductCode, $pGroupCode, 1.0, 2, -1, -1, -1, '', false, false);

													$paperArray = $paperArray['component'];
												}
												else
												{
													$paperArray = Array();
												}

												$dataCacheArray[$dataCacheKey] = $paperArray;
											}


											// check if we have single print entries for this product
											// first check if we have already cached the single print data as the same product / single print combination could occur in several collections
											$dataCacheKey = 'SINGLEPRINT.' . $productTreeProductCode . '.' . $pGroupCode . '.' . $pCompanyCode;
											$dataCacheKey2 = 'SINGLEPRINTOPTION.' . $productTreeProductCode . '.' . $pGroupCode . '.' . $pCompanyCode;
											if (array_key_exists($dataCacheKey, $dataCacheArray))
											{
												$singlePrintArray = $dataCacheArray[$dataCacheKey];
												$singlePrintOptionArray = $dataCacheArray[$dataCacheKey2];
											}
											else
											{
												// check to see if there are single print components available for this product
												if (array_key_exists('$SINGLEPRINT\\' . $productTreeProductCode, $componentArray))
												{
													// we have some single print components so now look deeper and retrieve the list of available single print components for the product
													$singlePrintArray = self::getComponentsInOrderSectionByCategory('$SINGLEPRINT\\',
																	'SINGLEPRINT', $pCompanyCode, $productTreeProductCode, $pGroupCode, 1.0, 2, -1, -1, -1, '', false, false);
													$singlePrintArray = $singlePrintArray['component'];

													// for each single print component look for single print option sub-components
													$itemCount = count($singlePrintArray);
													for ($i = 0; $i < $itemCount; $i++)
													{
														$singlePrintItemLocalCode = $singlePrintArray[$i]['localcode'];

														$tempOptionArray = self::getComponentsInOrderSectionByCategory('$SINGLEPRINT\\' . $singlePrintItemLocalCode . '\\$SINGLEPRINTOPTION\\',
																	'SINGLEPRINTOPTION', $pCompanyCode, $productTreeProductCode, $pGroupCode, 1.0, 2, -1, -1, -1, '', false, false);
														$tempOptionArray = $tempOptionArray['component'];

														$itemCount2 = count($tempOptionArray);
														if ($itemCount2 > 0)
														{
															for ($i2 = 0; $i2 < $itemCount2; $i2++)
															{
																$tempOptionItem = &$tempOptionArray[$i2];

																$tempOptionItem['localcode'] = $singlePrintItemLocalCode . '\\' . $tempOptionItem['localcode'];
															}

															$singlePrintOptionArray[$singlePrintItemLocalCode] = $tempOptionArray;
														}
													}
												}
												else
												{
													$singlePrintArray = Array();
													$singlePrintOptionArray = Array();
												}

												$dataCacheArray[$dataCacheKey] = $singlePrintArray;
												$dataCacheArray[$dataCacheKey2] = $singlePrintOptionArray;
											}


											// check if we have calendar customisation entries for this product
											// first check if we have already cached the calendar customisation data as the same product / calendar customisation combination could occur in several collections
											$dataCacheKey = 'CALENDARCUSTOMISATION.' . $productTreeProductCode . '.' . $pGroupCode . '.' . $pCompanyCode;
											if (array_key_exists($dataCacheKey, $dataCacheArray))
											{
												$calendarCustomisationArray = $dataCacheArray[$dataCacheKey];
											}
											else
											{
												// check to see if there are calendar customisation components available for this product
												if (array_key_exists('$CALENDARCUSTOMISATION\\' . $productTreeProductCode, $componentArray))
												{
													// we have some calendar customisation components so now look deeper and retrieve the list of available calendar customisation components for the product
													$calendarCustomisationArray = self::getComponentsInOrderSectionByCategory('$CALENDARCUSTOMISATION\\', 'CALENDARCUSTOMISATION',
																	$pCompanyCode, $productTreeProductCode, $pGroupCode, 1.0, 2, -1, -1, -1, '', false, false);
													$calendarCustomisationArray = $calendarCustomisationArray['component'];
												}
												else
												{
													$calendarCustomisationArray = Array();
												}

												$dataCacheArray[$dataCacheKey] = $calendarCustomisationArray;
											}


											// check if we have an AI component configured for this product
											// first check if we have already cached the AI Component data as the same product customisation combination could occur in several collection
											$dataCacheKey = 'TAOPIXAI' . $productTreeProductCode . '.' . $pGroupCode . '.' . $pCompanyCode;
											if (array_key_exists($dataCacheKey, $dataCacheArray))
											{
												$AIComponentArray = $dataCacheArray[$dataCacheKey];
											}
											else
											{
												if (array_key_exists('$TAOPIXAI\\' . $productTreeProductCode, $componentArray))
												{
													// we have some AI components so now look deeper and retreive the list of available AI components for the product
													// we are only expecting one component but are retrieving an array to maintain structural consistency
													$AIComponentArray = self::getComponentsInOrderSectionByCategory('$TAOPIXAI\\', 'TAOPIXAI', $pCompanyCode, $productTreeProductCode, $pGroupCode,
														1.0, 2 ,-1, -1, -1, "", false, false);
													$AIComponentArray = $AIComponentArray['component'];
												}
												else
												{
													$AIComponentArray = Array();
												}

												$dataCacheArray[$dataCacheKey] = $AIComponentArray;
											}
										}
										else
										{
											// no price list so disable the product
											$isActive = 0;
										}
									}
									else
									{
										// the user is not allowed to create new projects or the product has been deleted so disable the product
										$isActive = 0;
									}
								}


                                // include the product as long as:
                                // a) we haven't decided to skip the product (desktop designer with an online product that has never been available for the desktop)
                                // and
                                // b) either the caller is the designer (groupcode != **ALL) or we haven't flagged the product as deleted (to hide from creator)
                                if (($includeProduct) && (($pGroupCode != '**ALL**') || ($productDeleted == 0)))
                                {
                                    if ($pLicenseKeyProductTaxCode == '')
                                    {
                                        switch ($productTaxLevel)
                                        {
                                            case 1:
                                                $productTaxCode = $pTaxZoneDataArray['producttaxlevel1'];

                                                break;
                                            case 2:
                                                if ($pTaxZoneDataArray['producttaxlevel2'] != '')
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel2'];
                                                }
                                                else
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel1'];
                                                }

                                                break;
                                            case 3:
                                                if ($pTaxZoneDataArray['producttaxlevel3'] != '')
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel3'];
                                                }
                                                else
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel1'];
                                                }

                                                break;
                                            case 4:
                                                if ($pTaxZoneDataArray['producttaxlevel4'] != '')
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel4'];
                                                }
                                                else
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel1'];
                                                }

                                                break;
                                            case 5:
                                                if ($pTaxZoneDataArray['producttaxlevel5'] != '')
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel5'];
                                                }
                                                else
                                                {
                                                    $productTaxCode = $pTaxZoneDataArray['producttaxlevel1'];
                                                }

                                                break;
                                        }
                                    }

                                    if ($previousTaxCode != $productTaxCode)
                                    {
                                        $taxRateDataArray = self::getTaxRate($productTaxCode);
                                        $previousTaxCode = $productTaxCode;
                                    }

                                    $productItem['id'] = $productID;
                                    $productItem['collectioncode'] = $productCollectionCode;
                                    $productItem['code'] = $productCode;
                                    $productItem['name'] = $productName;
                                    $productItem['type'] = $productType;
                                    $productItem['pricingmodel'] = $pricingModel;
                                    $productItem['price'] = $price;
                                    $productItem['pricedescription'] = $priceDescription;
                                    $productItem['pricetaxrate'] = $priceTaxRate;
                                    $productItem['qtyisdropdown'] = $quantityIsDropDown;
                                    $productItem['productoption'] = $productOptions;
									$productItem['pricetransformationstage'] = $priceTransformationStage;
                                    $productItem['isactive'] = $isActive;
                                    $productItem['company'] = $company;
                                    $productItem['coverlist'] = $coverArray;
                                    $productItem['paperlist'] = $paperArray;
                                    $productItem['singleprintlist'] = $singlePrintArray;
                                    $productItem['singleprintoptionlist'] = $singlePrintOptionArray;
									$productItem['calendarcustomisationlist'] = $calendarCustomisationArray;
									$productItem['taopixailist'] = $AIComponentArray;
                                    $productItem['taxrate'] = $taxRateDataArray['rate'];
                                    $productItem['publishversion'] = $publishVersion;
                                    $productItem['collectionthumbnailresourceref'] = $collectionThumbnailResourceRef;
                                    $productItem['collectionthumbnailresourcedatauid'] = $collectionThumbnailResourceDataUID;
                                    $productItem['collectionpreviewresourceref'] = $collectionPreviewResourceRef;
                                    $productItem['collectionpreviewresourcedatauid'] = $collectionPreviewResourceDataUID;
                                    $productItem['collectionsortlevel'] = $collectionSortLevel;
                                    $productItem['collectiontextengineversion'] = $collectionTextEngineVersion;
                                    $productItem['producttarget'] = $productTarget;
                                    $productItem['productminpagecount'] = $productMinPageCount;
                                    $productItem['productaimodedesktop'] = $productAIModeDesktop;
                                    $productItem['productselectormodedesktop'] = $productSelectorModeDesktop;
                                    $productItem['collectionsummary'] = $collectionSummary;
                                    $productItem['collectionthumbnailresourcedevicepixelratio'] = $collectionThumbnailResourceDevicePixelRatio;
                                    $productItem['collectionpreviewresourcedevicepixelratio'] = $collectionPreviewResourceDevicePixelRatio;

                                    $productList[] = $productItem;
                                }
                            }
                        }
                        else
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateProductList bind result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateProductList execute ' . $dbObj->error;
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getAutoUpdateProductList prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getAutoUpdateProductList connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['productlist'] = &$productList;

        return $resultArray;
    }

    /**
     * Retrieves the current status for the specified upload refs
     *
     * @static
     *
     * @return array
     *   the result array will contain the status of the supplied upload refs
     *
     * @author Kevin Gale
     * @since Version 3.0.2
     */
    static function getAutoUpdateUploadRefList($pUploadRefData)
    {
        global $gSession;

        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $uploadRefsStatusArray = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $uploadRefArray = explode(',', $pUploadRefData);
            $uploadRefDataTypes = str_repeat('s', count($uploadRefArray));

            $uploadBind = str_repeat('?,', count($uploadRefArray));
            $uploadBind = substr($uploadBind, 0, strlen($uploadBind) - 1);

            if ($stmt = $dbObj->prepare('SELECT `oi`.`uploadbatchref`, `oi`.`uploadref`, `oi`.`status`, `oi`.`canmodify`, `oi`.`canupload`, `oi`.`canuploadproductcodeoverride`,
        	                            `oi`.`canuploadpagecountoverride`, `oi`.`active`, `oh`.`temporder`, `oh`.`temporderexpirydate`
        								FROM `ORDERITEMS` oi JOIN `ORDERHEADER` oh ON `oh`.`id` = `oi`.`orderid` WHERE `oi`.`uploadref` IN (' . $uploadBind . ') AND `oi`.`parentorderitemid` = 0'))
            {
                if (DatabaseObj::bindParams($stmt, $uploadRefDataTypes, $uploadRefArray))
                {
                    if ($stmt->bind_result($uploadBatchRef, $uploadRef, $status, $canModify, $canUpload, $canUploadProductCodeOverride,
                                    $canUploadPageCountOverride, $orderItemActive, $tempOrder, $tempOrderExpiryDate))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                // filter the current production status
                                if ($status == TPX_ITEM_STATUS_AWAITING_FILES)
                                {
                                    $status = 0; // waiting for files
                                }
                                elseif (($status >= TPX_ITEM_STATUS_FILES_ON_REMOTE_FTP_SERVER) && ($status < TPX_ITEM_STATUS_SHIPPED_TO_CUSTOMER))
                                {
                                    $status = 1; // item in production
                                }
                                elseif ($status == TPX_ITEM_STATUS_SHIPPED_TO_CUSTOMER)
                                {
                                    $status = 2; // item shipped to customer
                                }
                                elseif (($status >= TPX_ITEM_STATUS_SHIPPED_TO_DISTRIBUTION_CENTRE) && ($status < TPX_ITEM_STATUS_SHIPPED_RECEIVED_AT_STORE))
                                {
                                    $status = 3; // item shipped to distribution centre / store
                                }
                                elseif ($status == TPX_ITEM_STATUS_SHIPPED_RECEIVED_AT_STORE)
                                {
                                    $status = 4; // item received at store
                                }
                                elseif ($status == TPX_ITEM_STATUS_SHIPPED_COLLECTED_BY_CUSTOMER)
                                {
                                    $status = 5; // item collected by customer
                                }

                                $statusArray['uploadbatchref'] = $uploadBatchRef;
                                $statusArray['uploadref'] = $uploadRef;
                                $statusArray['canmodify'] = $canModify;
                                $statusArray['canupload'] = $canUpload;
                                $statusArray['canuploadproductcodeoverride'] = $canUploadProductCodeOverride;
                                $statusArray['canuploadpagecountoverride'] = $canUploadPageCountOverride;
                                $statusArray['status'] = $status;
                                $statusArray['status2'] = $orderItemActive;
                                $statusArray['temporder'] = $tempOrder;
                                $statusArray['temporderexpirydate'] = $tempOrderExpiryDate;
                                $uploadRefsStatusArray[] = $statusArray;
                            }
                        }
                        else
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateUploadRefList execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateUploadRefList bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateUploadRefList bind params ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                $result = 'str_DatabaseError';
                $resultParam = 'getAutoUpdateUploadRefList prepar ' . $dbObj->error;
            }

            $dbObj->close();
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['uploadrefslist'] = &$uploadRefsStatusArray;

        return $resultArray;
    }

    /**
     * Retrieve a list of application files for use either by TAOPIX™ Web, TAOPIX™ Builder or TAOPIX™ Designer
     *
     * @static
     *
     * @return array
     *   the result array will contain the list of files that meet the specified criteria
     *
     * @author Kevin Gale
     * @since Version 1.0.0
     */
    static function getAutoUpdateApplicationFilesList($pGroupCode, $pWebBrandCode, $pFileType, $pAPIVersion, $pCompanyCode = '',
            $pSort = '', $pSortDirection = '', $pHideInactive = 0)
    {
        // return an array containing the application files that are available via auto-update for the group and brand codes
        global $gSession;

        $result = '';
        $resultParam = '';
        $filelist = Array();

        $id = 0;
        $fileCompanyCode = '';
        $fileRef = '';
        $fileAppVersion = '';
        $fileDataVersion = 0;
        $fileCategoryCode = '';
        $fileCategoryName = '';
        $fileName = '';
        $fileDescription = '';
        $fileProducts = '';
        $fileThemes = '';
        $fileFileName = '';
        $fileVersionDate = '';
        $fileEncrypted = 0;
        $fileUpdatePriority = 0;
        $fileDependencies = '';
        $fileFileSize = 0;
        $fileFileChecksum = '';
        $fileHasFPO = 0;
        $fileHasPreview = 0;
        $fileSeparateComponents = 0;
        $fileHiddenFromUser = 0;
        $isActive = 0;
        $deleted = 0;
        $webBrandCode = '';
        $webBrandApplicationName = '';
        $filter = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $searchFields = UtilsObj::getPOSTParam('fields');
            $typesArray = array();
            $paramArray = array();
			$stmtArray = array();
			$hideInactiveClause = '';

            if ($searchFields != '')
            {
                $searchQuery = $_POST['query'];
                $selectedfields = explode(',', str_replace('"', '', str_replace(']', '', str_replace('[', '', $_POST['fields']))));

                if ($searchQuery != '')
                {
                    foreach ($selectedfields as $value)
                    {
                        switch ($value)
                        {
                            case 'categoryName':
                                $value = '`a`.`categoryname`';
                                break;
                            case 'nameName':
                                $value = '`a`.`name`';
                                break;
                            case 'fileName':
                                $value = '`a`.`filename`';
                                break;
                            case 'versionName':
                                $value = '`a`.`versiondate`';
                                break;
                        }

                        $stmtArray[] = '(' . $value . ' LIKE ?)';
                        $paramArray[] = '%' . $searchQuery . '%';
                        $typesArray[] = 's';
                    }
				}
				else
				{
					if ($pHideInactive)
					{
						$hideInactiveClause = ' AND (`a`.`active` = 1)';
					}
				}
			}
			else
			{
				if ($pHideInactive)
				{
					$hideInactiveClause = ' AND (`a`.`active` = 1)';
				}
			}

            if (count($stmtArray) > 0)
            {
                $stmtArray = '(' . join(' OR ', $stmtArray) . ') AND (`a`.`type` = ?)';
            }
            else
            {
                $stmtArray = '(`a`.`type` = ?)';
            }

            $paramArray[] = $pFileType;
            $typesArray[] = 'i';

            if ($pWebBrandCode == '**ALL**')
            {
                if (($pSort != '') && ($pSortDirection != ''))
                {
                    switch ($pSort)
                    {
                        case 'brandName':
                            $pSort = '`a`.`webbrandcode`';
                            break;
                        case 'categoryName':
                            $pSort = '`a`.`categoryname`';
                            break;
                        case 'nameName':
                            $pSort = '`a`.`name`';
                            break;
                        case 'fileName':
                            $pSort = '`a`.`filename`';
                            break;
                        case 'versionName':
                            $pSort = '`a`.`versiondate`';
                            break;
                        case 'privateName':
                            $pSort = '`a`.`hiddenfromuser`';
                            break;
                        case 'activeName':
                            $pSort = '`a`.`active`';
                            break;
                        default:
                            $pSort = '`a`.`webbrandcode`';
                    }

                    $filter = ' ' . $pSort . ' ' . $pSortDirection . ', ';
                }

                if (($pCompanyCode != '' || $pCompanyCode == '') && ($gSession['userdata']['usertype'] != TPX_LOGIN_SYSTEM_ADMIN))
                {
                    if (($pCompanyCode == '') && ($gSession['userdata']['usertype'] != TPX_LOGIN_SYSTEM_ADMIN))
                    {
                        $pCompanyCode = $gSession['userdata']['companycode'];
                    }

                    $stmt = $dbObj->prepare('SELECT `a`.`id`, `a`.`companycode`, `a`.`ref`, `a`.`appversion`, `a`.`dataversion`,
												`a`.`categorycode`, `a`.`categoryname`, `a`.`name`, `a`.`description`, `a`.`products`, `a`.`themes`,
												`a`.`filename`, `a`.`versiondate`, `a`.`encrypted`, `a`.`updatepriority`, "", `a`.`size`,
												`a`.`checksum`, `a`.`hasfpo`, `a`.`haspreview`, `a`.`separatecomponents`, `a`.`hiddenfromuser`, `a`.`webbrandcode`,
												`a`.`active`, `a`.`onlineactive`, `a`.`deleted`, `b`.`applicationname`
											FROM `APPLICATIONFILES` `a` LEFT JOIN `BRANDING` `b` ON `b`.`code` = `a`.`webbrandcode`
											WHERE ' . $stmtArray . $hideInactiveClause . ' AND (`a`.`webbrandcode` in (SELECT `code` from `BRANDING` WHERE companycode = ?))
											ORDER BY `a`.webbrandcode,' . $filter . '
											`a`.categoryname, `a`.name');
                    $paramArray[] = $pCompanyCode;
                    $typesArray[] = 's';
                }
                else
                {
                    $stmt = $dbObj->prepare('SELECT `a`.`id`, `a`.`companycode`, `a`.`ref`, `a`.`appversion`, `a`.`dataversion`,
												`a`.`categorycode`, `a`.`categoryname`, `a`.`name`, `a`.`description`, `a`.`products`, `a`.`themes`,
												`a`.`filename`, `a`.`versiondate`, `a`.`encrypted`, `a`.`updatepriority`, "", `a`.`size`,
												`a`.`checksum`, `a`.`hasfpo`, `a`.`haspreview`, `a`.`separatecomponents`, `a`.`hiddenfromuser`, `a`.`webbrandcode`,
												`a`.`active`, `a`.`onlineactive`, `a`.`deleted`, `b`.`applicationname`
											FROM `APPLICATIONFILES` `a` LEFT JOIN `BRANDING` `b` ON `b`.`code` = `a`.`webbrandcode`
                    						WHERE ' . $stmtArray . $hideInactiveClause . ' ORDER BY `a`.`webbrandcode`,' . $filter . ' `a`.`categoryname`, `a`.`name`');
                }

                if ($stmt)
                {
                    DatabaseObj::bindParams($stmt, $typesArray, $paramArray);
                    if ($stmt->bind_result($id, $fileCompanyCode, $fileRef, $fileAppVersion, $fileDataVersion, $fileCategoryCode,
                                    $fileCategoryName, $fileName, $fileDescription, $fileProducts, $fileThemes, $fileFileName,
                                    $fileVersionDate, $fileEncrypted, $fileUpdatePriority, $fileDependencies, $fileFileSize,
                                    $fileFileChecksum, $fileHasFPO, $fileHasPreview, $fileSeparateComponents, $fileHiddenFromUser,
                                    $webBrandCode, $isActive, $onlineIsActive, $deleted, $webBrandApplicationName))
                    {
                        if (!$stmt->execute())
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateApplicationFilesList execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateApplicationFilesList bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateApplicationFilesList prepare ' . $dbObj->error;
                }
            }
            else
            {
                // auto-update
                // we use an inner join here as it prevents mysql from retrieving blob data until we have a final list of rows we need to retrieve
                // we also don't sort the result set as it introduces a large overhead
                $stmtArray .= ' AND (`webbrandcode` = ?)';
                $paramArray[] = $pWebBrandCode;
                $typesArray[] = 's';
                if ($stmt = $dbObj->prepare('SELECT `a3`.`id`, `a3`.`companycode`, `a3`.`ref`, `a3`.`appversion`, `a3`.`dataversion`, `a3`.`categorycode`,
								`a3`.`categoryname`, `a3`.`name`, `a3`.`description`, `a3`.`products`, `a3`.`themes`, `a3`.`filename`, `a3`.`versiondate`,
								`a3`.`encrypted`, `a3`.`updatepriority`, `a3`.`dependencies`, `a3`.`size`, `a3`.`checksum`, `a3`.`hasfpo`, `a3`.`haspreview`,
								`a3`.`separatecomponents`, `a3`.`hiddenfromuser`, `a3`.`webbrandcode`, `a3`.`active`, `a3`.`onlineactive`, `a3`.`deleted`
							FROM `APPLICATIONFILES` `a3` INNER JOIN
								(SELECT `a`.`id` FROM `APPLICATIONFILES` `a` WHERE ' . $stmtArray . '
								) AS `a2`
							WHERE `a3`.`id` = `a2`.`id`'))
                {
                    DatabaseObj::bindParams($stmt, $typesArray, $paramArray);

                    if ($stmt->execute())
                    {
                        $stmt->store_result();

                        if (!$stmt->bind_result($id, $fileCompanyCode, $fileRef, $fileAppVersion, $fileDataVersion, $fileCategoryCode,
                                        $fileCategoryName, $fileName, $fileDescription, $fileProducts, $fileThemes, $fileFileName,
                                        $fileVersionDate, $fileEncrypted, $fileUpdatePriority, $fileDependencies, $fileFileSize,
                                        $fileFileChecksum, $fileHasFPO, $fileHasPreview, $fileSeparateComponents, $fileHiddenFromUser,
                                        $webBrandCode, $isActive, $onlineIsActive, $deleted))
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateApplicationFilesList bind result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateApplicationFilesList execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateApplicationFilesList prepare ' . $dbObj->error;
                }
            }

            if ($result == '')
            {
                // process each file
                while ($stmt->fetch())
                {
                    $addItem = true;

                    // determine if we should include this item
                    // taopix builder receives all non-deleted items
                    // taopix designer older than v3 only receives active non-deleted items
                    // taopix designer older than v3 cannot receive items that require v3
                    // taopix designer v3 and above receives all items but deleted items are marked as inactive
                    if ($pGroupCode == '**ALL**')
                    {
                        // taopix builder
                        if ($deleted == 1)
                        {
                            $addItem = false;
                        }
                    }
                    else
                    {
                        // taopix designer

                        if ($deleted == 1)
                        {
                            $isActive = false;
                        }

                        if ($fileAppVersion != '')
                        {
                            $fileMajorVersion = (int) substr($fileAppVersion, 0, 1);
                            if (($fileMajorVersion >= 3) && ($pAPIVersion < 3))
                            {
                                $addItem = false;
                            }
                        }

                        if (($isActive == 0) && ($pAPIVersion < 3))
                        {
                            $addItem = false;
                        }
                    }

                    if ($addItem == true)
                    {
                        $fileItem['id'] = $id;
                        $fileItem['company'] = $fileCompanyCode;
                        $fileItem['ref'] = $fileRef;
                        $fileItem['appversion'] = $fileAppVersion;
                        $fileItem['dataversion'] = $fileDataVersion;
                        $fileItem['categorycode'] = $fileCategoryCode;
                        $fileItem['categoryname'] = $fileCategoryName;
                        $fileItem['name'] = $fileName;
                        $fileItem['description'] = $fileDescription;
                        $fileItem['products'] = $fileProducts;
                        $fileItem['themes'] = $fileThemes;
                        $fileItem['filename'] = $fileFileName;
                        $fileItem['datemodified'] = $fileVersionDate;
                        $fileItem['isencrypted'] = $fileEncrypted;
                        $fileItem['updatepriority'] = $fileUpdatePriority;
                        $fileItem['dependencies'] = $fileDependencies;
                        $fileItem['filesize'] = $fileFileSize;
                        $fileItem['checksum'] = $fileFileChecksum;
                        $fileItem['hasfpo'] = $fileHasFPO;
                        $fileItem['haspreview'] = $fileHasPreview;
                        $fileItem['separatecomponents'] = $fileSeparateComponents;
                        $fileItem['hiddenfromuser'] = $fileHiddenFromUser;
                        $fileItem['webbrandcode'] = $webBrandCode;
                        $fileItem['webbrandapplicationname'] = $webBrandApplicationName;
                        $fileItem['isactive'] = $isActive;
                        $fileItem['onlineisactive'] = $onlineIsActive;
                        $fileItem['deleted'] = $deleted;

                        $filelist[] = $fileItem;
                    }
                }
            }

            if ($stmt)
            {
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getAutoUpdateApplicationFilesList connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['filelist'] = &$filelist;

        return $resultArray;
    }

    /**
     * Retrieves the license key configuration data for this TAOPIX system
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 1.0.0
     */
    static function getAutoUpdateLicenseKeyList($pGroupCode, $pCompanyCode = '', $pSortBy = '', $pSortDir = '', $pSearchFields = '',
            $pSearchQuery = '', $pHideInactive = 0)
    {
        global $gConstants;
        global $gSession;

        $result = '';
        $resultParam = '';
        $licenseKeyList = Array();
        $licenseKeyID = 0;
        $licenseKeyGroupCode = '';
        $licenseKeyGroupName = '';
        $licenseKeyFileName = '';
        $licenseKeyFileSize = 0;
        $licenseKeyFileChecksum = '';
        $licenseKeyUpdatePriority = 0;
        $licenseKeyVersion = '';
        $licenseKeyLogin = '';
        $licenseKeyWebBrandCode = '';
        $licenceKeyUseDefaultCurrency = 1;
        $licenceKeyCurrencyCode = '';
        $isActive = 0;
        $keyFileDataVersion = 1;
        $company = '';
        $companyFilter = '';

        $stmtFilterStr = '';

        $stmtArray = array();
        $paramArray = array();
        $typesArray = array();

        $stmtStr = '';
        $paramStr = '';
		$typeStr = '';
		$hideInactiveStr = '';

        $customSort = '';
        if ($pSortBy != '')
        {
            switch ($pSortBy)
            {
                case 'groupcode':
                    $pSortBy = '`groupcode`';
                    break;
                case 'groupname':
                    $pSortBy = '`name`';
                    break;
                case 'filename':
                    $pSortBy = '`keyfilename`';
                    break;
                case 'version':
                    $pSortBy = '`keyfilenameversion`';
                    break;
                case 'webbrandcode':
                    $pSortBy = '`webbrandcode`';
                    break;
                case 'currencycode':
                    $pSortBy = '`currencycode`';
                    break;
                case 'active':
                    $pSortBy = '`active`';
                    break;
                case 'priority':
                    $pSortBy = '`keyupdatepriority`';
                    break;
            }
            $customSort = ', ' . $pSortBy;
        }

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($pGroupCode == '**ALL**')
            {
				$whereClauseNeeded = false;

                if ($pSearchFields != '')
                {
                    $SearchFieldsArray = explode(',', str_replace('"', "", str_replace("]", "", str_replace("[", "", $pSearchFields))));

                    if ($pSearchQuery != '')
                    {
                        foreach ($SearchFieldsArray as $value)
                        {
                            switch ($value)
                            {
                                case 'groupcode': $value = 'groupcode';
                                    break;
                                case 'groupname': $value = 'name';
                                    break;
                                case 'filename': $value = 'keyfilename';
                                    break;
                                case 'version': $value = 'keyfilenameversion';
                                    break;
                                case 'webbrandcode': $value = 'webbrandcode';
                                    break;
                            }

                            $stmtArray[] = '(`' . $value . '` LIKE ?)';
                            $paramArray[] = '%' . $pSearchQuery . '%';
							$typesArray[] = 's';
							$whereClauseNeeded = true;
                        }
					}
					else
					{
						if ($pHideInactive == 1)
						{
							$hideInactiveStr = '(`active` = true) ';
							$whereClauseNeeded = true;
						}
					}
				}
				else
				{
					if ($pHideInactive == 1)
					{
						$hideInactiveStr = '(`active` = true) ';
						$whereClauseNeeded = true;
					}
				}

                $stmtStr = (count($stmtArray) > 0) ? ' (' . join(' OR ', $stmtArray) . ')' : '';
                $paramStr = (count($paramArray) > 0) ? join('', $paramArray) : '';
				$typeStr = (count($typesArray) > 0) ? join('', $typesArray) : '';
				$whereClause = '';
				// search and hide inactive are mutually exclusive so the AND clause will never be needed after search queries
				$andNeeded = false;

                // We need to get either Global license keys, for particular company or all
                if (($pCompanyCode != '') || (($pCompanyCode == '') && (isset($gSession['userdata'])) && ($gSession['userdata']['usertype'] != TPX_LOGIN_SYSTEM_ADMIN)))
                {
                    if (($pCompanyCode == '') && ($gSession['userdata']['usertype'] != TPX_LOGIN_SYSTEM_ADMIN))
                    {
                        $pCompanyCode = $gSession['userdata']['companycode'];

						$companyFilter = "(`companycode` = '" . $pCompanyCode . "') ";
						$whereClauseNeeded = true;
						$andNeeded = true;
                    }
                    else
                    {
                        if ($pCompanyCode == '' || $pCompanyCode == 'GLOBAL')
                        {
							$companyFilter = "(`companycode` = '') ";
							$whereClauseNeeded = true;
							$andNeeded = true;
                        }
                        else
                        {
							$companyFilter = "(`companycode` = '" . $pCompanyCode . "') ";
							$whereClauseNeeded = true;
							$andNeeded = true;
                        }
                    }
                }

				// if an and clause does not need inserting the stmtstr can be used directly in the query
                if (($stmtStr != '') && ($andNeeded))
                {
            	    $stmtStr = ' AND ' . $stmtStr;
				}
				// stmtstr and hideinactive are mutually exclusive, no need to run both tests if a stmtstr has already been found
				else if (($hideInactiveStr != '') && ($andNeeded))
				{
					$hideInactiveStr = ' AND '  . $hideInactiveStr;
				}

				// only insert the where clause when it is actually needed
				if ($whereClauseNeeded)
				{
					$whereClause = ' WHERE ';
				}

                $sqlStr = 'SELECT  `id`, `groupcode`, `name`, `keyfilename`, `keyfilenameversion`, `keyfilesize`, `keyfilechecksum`, `keyupdatepriority`, `login`,
                    `webbrandcode`, `usedefaultcurrency`, `taxcode`, `currencycode`, `active`, `availableonline`, `companycode`, `showpriceswithtax`, `keyfiledataversion`
                    FROM `LICENSEKEYS` ' . $whereClause . $companyFilter . $stmtStr . $hideInactiveStr . ' ORDER BY `companycode` ' . $customSort . ' ' . $pSortDir;

                if ($stmt = $dbObj->prepare($sqlStr))
                {
                    if (DatabaseObj::bindParams($stmt, $typesArray, $paramArray))
                    {
                        if ($stmt->bind_result($licenseKeyID, $licenseKeyGroupCode, $licenseKeyGroupName, $licenseKeyFileName,
                                        $licenseKeyVersion, $licenseKeyFileSize, $licenseKeyFileChecksum, $licenseKeyUpdatePriority,
                                        $licenseKeyLogin, $licenseKeyWebBrandCode, $licenceKeyUseDefaultCurrency, $licenseKeyProductTaxCode,
                                        $licenceKeyCurrencyCode, $isActive, $availableOnline, $company, $showPricesWithTax, $keyFileDataVersion))
                        {

                            if (!$stmt->execute())
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'getAutoUpdateLicenseKeyList execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateLicenseKeyList bind result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind params
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateLicenseKeyList bind params ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateLicenseKeyList prepare ' . $dbObj->error;
                }
            }
            else
            {
                if ($stmt = $dbObj->prepare('SELECT `id`, `groupcode`, `name`, `keyfilename`, `keyfilenameversion`, `keyfilesize`, `keyfilechecksum`, `keyupdatepriority`, `login`, `webbrandcode`, `usedefaultcurrency`, `taxcode`,
                				`currencycode`, `active`, `availableonline`, `companycode`, `showpriceswithtax`, `keyfiledataversion`
                    			FROM `LICENSEKEYS`
                    			WHERE `groupcode` = ?
                    			ORDER BY `webbrandcode`, `groupcode`'))
                {
                    if ($stmt->bind_param('s', $pGroupCode))
                    {
                        if ($stmt->bind_result($licenseKeyID, $licenseKeyGroupCode, $licenseKeyGroupName, $licenseKeyFileName,
                                        $licenseKeyVersion, $licenseKeyFileSize, $licenseKeyFileChecksum, $licenseKeyUpdatePriority,
                                        $licenseKeyLogin, $licenseKeyWebBrandCode, $licenceKeyUseDefaultCurrency, $licenseKeyProductTaxCode,
                                        $licenceKeyCurrencyCode, $isActive, $availableOnline, $company, $showPricesWithTax, $keyFileDataVersion))
                        {
                            if (!$stmt->execute())
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'getAutoUpdateLicenseKeyList execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateLicenseKeyList bind result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateLicenseKeyList bind params ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateLicenseKeyList prepare ' . $dbObj->error;
                }
            }

            if ($result == '')
            {
                // process each license key
                while ($stmt->fetch())
                {
                    $licenseKeyItem['id'] = $licenseKeyID;
                    $licenseKeyItem['groupcode'] = $licenseKeyGroupCode;
                    $licenseKeyItem['groupname'] = $licenseKeyGroupName;
                    $licenseKeyItem['filename'] = $licenseKeyFileName;
                    $licenseKeyItem['version'] = $licenseKeyVersion;
                    $licenseKeyItem['filesize'] = $licenseKeyFileSize;
                    $licenseKeyItem['filechecksum'] = $licenseKeyFileChecksum;
                    $licenseKeyItem['updatepriority'] = $licenseKeyUpdatePriority;
                    $licenseKeyItem['login'] = $licenseKeyLogin;
                    $licenseKeyItem['webbrandcode'] = $licenseKeyWebBrandCode;
                    $licenseKeyItem['usedefaultcurrency'] = $licenceKeyUseDefaultCurrency;
                    $licenseKeyItem['producttaxcode'] = $licenseKeyProductTaxCode;
                    if ($licenceKeyUseDefaultCurrency == 1)
                    {
                        $licenseKeyItem['currencycode'] = $gConstants['defaultcurrencycode'];
                    }
                    else
                    {
                        $licenseKeyItem['currencycode'] = $licenceKeyCurrencyCode;
                    }
                    $licenseKeyItem['availableonline'] = $availableOnline;
                    $licenseKeyItem['isactive'] = $isActive;
                    $licenseKeyItem['company'] = $company;
                    $licenseKeyItem['showpriceswithtax'] = $showPricesWithTax;
                    $licenseKeyItem['keyfiledataversion'] = $keyFileDataVersion;

                    $licenseKeyList[] = $licenseKeyItem;
                }
            }

            if ($stmt)
            {
                $stmt->free_result();
                $stmt->close();
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getAutoUpdateLicenseKeyList connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['licensekeylist'] = $licenseKeyList;

        return $resultArray;
    }

    /**
     * Retrieves the application update data for the specified parameters
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 1.0.0
     */
    static function getAutoUpdateApplicationBuildDetails($pWebBrandCode, $pGroupCode, $pOSVersion = '', $pCPUType = '', $pCompanyCode = '',
            $pSortBy = '', $pSortDir = '')
    {
        global $gSession;

        $result = '';
        $resultParam = '';
        $ref = 0;
        $macVersion = '';
        $macArchiveFileName = '';
        $macExecutableFileName = '';
        $macArchiveFileSize = 0;
        $macArchiveChecksum = '';
        $macUpdatePriority = 0;
        $macHasPreview = 0;
        $win32Version = '';
        $win32ArchiveFileName = '';
        $win32ExecutableFileName = '';
        $win32ArchiveFileSize = 0;
        $win32ArchiveChecksum = '';
        $win32UpdatePriority = 0;
        $win32HasPreview = 0;
        $webBrandCode = '';
        $webBrandApplicationName = '';
        $companyFilter = '';

        $appItemsList = Array();

        $customSort = '';
        if ($pSortBy != '')
        {
            switch ($pSortBy)
            {
                case 'brandName':
                    $pSortBy = 'BRANDING.applicationname ' . $pSortDir;
                    break;
                case 'versionCode':
                    $pSortBy = 'APPLICATIONBUILD.macversion ' . $pSortDir . ', APPLICATIONBUILD.win32version ' . $pSortDir;
                    break;
                case 'archiveName':
                    $pSortBy = 'APPLICATIONBUILD.macarchivefilename ' . $pSortDir . ', APPLICATIONBUILD.win32archivefilename ' . $pSortDir;
                    break;
                case 'exeName':
                    $pSortBy = 'APPLICATIONBUILD.macexecutablefilename ' . $pSortDir . ', APPLICATIONBUILD.win32executablefilename ' . $pSortDir;
                    break;
            }

            $customSort = ', ' . $pSortBy;
        }


        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($pWebBrandCode == '**ALL**')
            {
                if (($pCompanyCode != '') || (($pCompanyCode == '') && ($gSession['userdata']['usertype'] != TPX_LOGIN_SYSTEM_ADMIN)))
                {
                    if (($pCompanyCode == '') && ($gSession['userdata']['usertype'] != TPX_LOGIN_SYSTEM_ADMIN))
                    {
                        $pCompanyCode = $gSession['userdata']['companycode'];
                    }
                    $companyFilter = " WHERE APPLICATIONBUILD.webbrandcode in (SELECT `code` from `BRANDING` WHERE `companycode` = '" . $pCompanyCode . "')";
                }

                if ($stmt = $dbObj->prepare('SELECT APPLICATIONBUILD.id, APPLICATIONBUILD.macarchivefilename, APPLICATIONBUILD.macexecutablefilename, APPLICATIONBUILD.win32archivefilename,
                                APPLICATIONBUILD.win32executablefilename, APPLICATIONBUILD.macversion, APPLICATIONBUILD.win32version, APPLICATIONBUILD.macarchivefilesize,
                                APPLICATIONBUILD.win32archivefilesize, APPLICATIONBUILD.macarchivechecksum, APPLICATIONBUILD.win32archivechecksum, APPLICATIONBUILD.macupdatepriority,
                                APPLICATIONBUILD.win32updatepriority, APPLICATIONBUILD.machaspreview, APPLICATIONBUILD.win32haspreview, APPLICATIONBUILD.webbrandcode, BRANDING.applicationname
                                FROM `APPLICATIONBUILD`
                                LEFT JOIN `BRANDING` ON BRANDING.code = APPLICATIONBUILD.webbrandcode' . $companyFilter . ' ORDER BY APPLICATIONBUILD.webbrandcode' . $customSort))
                {
                    if ($stmt->bind_result($ref, $macArchiveFileName, $macExecutableFileName, $win32ArchiveFileName,
                                    $win32ExecutableFileName, $macVersion, $win32Version, $macArchiveFileSize, $win32ArchiveFileSize,
                                    $macArchiveChecksum, $win32ArchiveChecksum, $macUpdatePriority, $win32UpdatePriority, $macHasPreview,
                                    $win32HasPreview, $webBrandCode, $webBrandApplicationName))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $appItem['ref'] = $ref;
                                $appItem['macarchivefilename'] = $macArchiveFileName;
                                $appItem['macexecutablefilename'] = $macExecutableFileName;
                                $appItem['win32archivefilename'] = $win32ArchiveFileName;
                                $appItem['win32executablefilename'] = $win32ExecutableFileName;
                                $appItem['macversion'] = $macVersion;
                                $appItem['win32version'] = $win32Version;
                                $appItem['macarchivefilesize'] = $macArchiveFileSize;
                                $appItem['win32carchivefilesize'] = $win32ArchiveFileSize;
                                $appItem['macarchivechecksum'] = $macArchiveChecksum;
                                $appItem['win32archivechecksum'] = $win32ArchiveChecksum;
                                $appItem['macupdatepriority'] = $macUpdatePriority;
                                $appItem['win32updatepriority'] = $win32UpdatePriority;
                                $appItem['machaspreview'] = $macHasPreview;
                                $appItem['win32haspreview'] = $win32HasPreview;
                                $appItem['webbrandcode'] = $webBrandCode;
                                $appItem['webbrandapplicationname'] = $webBrandApplicationName;

                                $appItemsList[] = $appItem;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateApplicationBuildDetails execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = 'getAutoUpdateApplicationBuildDetails bind result ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateApplicationBuildDetails prepare ' . $dbObj->error;
                }
            }
            else
            {
                $stmt = $dbObj->prepare('SELECT `id`, `macarchivefilename`, `macexecutablefilename`, `win32archivefilename`,
                                            `win32executablefilename`, `macversion`, `win32version`, `macarchivefilesize`,
                                            `win32archivefilesize`, `macarchivechecksum`, `win32archivechecksum`, `macupdatepriority`,
                                            `win32updatepriority`, `machaspreview`, `win32haspreview`, `webbrandcode`
                                        FROM `APPLICATIONBUILD`
                                        WHERE `webbrandcode` = ?');
                if ($stmt)
                {
                    if ($stmt->bind_param('s', $pWebBrandCode))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($ref, $macArchiveFileName, $macExecutableFileName, $win32ArchiveFileName,
                                                    $win32ExecutableFileName, $macVersion, $win32Version, $macArchiveFileSize,
                                                    $win32ArchiveFileSize, $macArchiveChecksum, $win32ArchiveChecksum, $macUpdatePriority,
                                                    $win32UpdatePriority, $macHasPreview, $win32HasPreview, $webBrandCode))
                                    {
                                        if ($stmt->fetch())
                                        {

                                        	// only perform the checks if the request was from the desktop designer
                                        	if ($pGroupCode != '**ALL**')
                                        	{
												// mac running 10.8 or earlier cannot run v2018r1 or later so we need to filter out invalid operating systems
												// macs running 10.3.9 cannot run v3 or later so we need to filter out invalid operating systems
												// ppc macs cannot run v4 or later so we need to filter out invalid operating systems
												if ($macVersion != '')
												{
													$allowUpgrade = true;

													$appVersionArray = explode('.', $macVersion);

													$appMajorVersion = (int) $appVersionArray[0];

													if ($appMajorVersion >= 2018)
													{
														if ($pOSVersion != '')
														{
															$pos = strpos($pOSVersion, '10.');
															if ($pos !== false)
															{
																$osVersionArray = explode('.', substr($pOSVersion, $pos));

																if (count($osVersionArray) > 1)
																{
																	$osVersion = (int) $osVersionArray[1];

																	if ($osVersion < 9)
																	{
																		// the operating system is too old
																		$allowUpgrade = false;
																	}
																}
																else
																{
																	// the operating system version string isn't the format we expect so we had better not allow the upgrade
																	$allowUpgrade = false;
																}
															}
															else
															{
																// we don't know the operating system version so we had better not allow the upgrade
																$allowUpgrade = false;
															}
														}
														else
														{
															// we don't know the operating system version so we had better not allow the upgrade
															$allowUpgrade = false;
														}
													}
													else
													{
														if ((($appMajorVersion >= 3) && ($pOSVersion != '') && (strpos($pOSVersion, 'Mac OS X 10.3') !== false))
															|| (($appMajorVersion >= 4) && ($pCPUType == 'PPC')))
														{
															// the operating system / cpu architecture is incompatible
															$allowUpgrade = false;
														}
													}

													if (! $allowUpgrade)
													{
														$macVersion = '';
														$macArchiveFileName = '';
														$macExecutableFileName = '';
														$macArchiveFileSize = 0;
														$macArchiveChecksum = '';
														$macUpdatePriority = 0;
														$macHasPreview = 0;
													}
												}


												// from taopix 2018 the computer must be running windows 7 or newer so we need to filter out invalid operating systems
												if ($win32Version != '')
												{
													$allowUpgrade = true;

													$appVersionArray = explode('.', $win32Version);

													$appMajorVersion = (int) $appVersionArray[0];

													if ($appMajorVersion >= 2018)
													{
														if ($pOSVersion != '')
														{
															if ((strpos($pOSVersion, 'Windows 95') !== false) || (strpos($pOSVersion, 'Windows 98') !== false) ||
																(strpos($pOSVersion, 'Windows 2000') !== false) || (strpos($pOSVersion, 'Windows XP') !== false) ||
																(strpos($pOSVersion, 'Windows Vista') !== false) || (strpos($pOSVersion, 'Windows Server 2003') !== false))
															{
																// the operating system is too old
																$allowUpgrade = false;
															}
														}
														else
														{
															// we don't know the operating system version so we had better not allow the upgrade
															$allowUpgrade = false;
														}
													}

													if (! $allowUpgrade)
													{
														$win32Version = '';
														$win32ArchiveFileName = '';
														$win32ExecutableFileName = '';
														$win32ArchiveFileSize = 0;
														$win32cArchiveChecksum = '';
														$win32UpdatePriority = 0;
														$win32HasPreview = 0;
													}
												}
											}
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getAutoUpdateApplicationBuildDetails bind result ' . $dbObj->error;
                                    }
                                }
                            }
                            else
                            {
                                $result = 'str_DatabaseError';
                                $resultParam = 'getAutoUpdateApplicationBuildDetails store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getAutoUpdateApplicationBuildDetails execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'uploadProductsUpdate bind ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getAutoUpdateApplicationBuildDetails prepare ' . $dbObj->error;
                }
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getAutoUpdateApplicationBuildDetails connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['ref'] = $ref;
        $resultArray['macarchivefilename'] = $macArchiveFileName;
        $resultArray['macexecutablefilename'] = $macExecutableFileName;
        $resultArray['macversion'] = $macVersion;
        $resultArray['macarchivefilesize'] = $macArchiveFileSize;
        $resultArray['macarchivechecksum'] = $macArchiveChecksum;
        $resultArray['macupdatepriority'] = $macUpdatePriority;
        $resultArray['machaspreview'] = $macHasPreview;
        $resultArray['win32archivefilename'] = $win32ArchiveFileName;
        $resultArray['win32executablefilename'] = $win32ExecutableFileName;
        $resultArray['win32version'] = $win32Version;
        $resultArray['win32archivefilesize'] = $win32ArchiveFileSize;
        $resultArray['win32archivechecksum'] = $win32ArchiveChecksum;
        $resultArray['win32updatepriority'] = $win32UpdatePriority;
        $resultArray['win32haspreview'] = $win32HasPreview;
        $resultArray['webbrandcode'] = $webBrandCode;
        $resultArray['webbrandapplicationname'] = $webBrandApplicationName;
        $resultArray['applist'] = $appItemsList;

        return $resultArray;
    }

    /**
     * Retrieves the configuration data for this TAOPIX system
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 3.0.0
     */
    static function getSystemConfig()
    {
        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $recordID = '';
        $dateCreated = '';
        $ownerCode = '';
        $ownerCode2 = '';
        $systemKey = '';
        $systemCertificate = '';
        $tenantID = 0;
        $tenantKey = '';
        $tenantSecret = '';
        $key = '';
        $secret = '';
        $webVersionDate = '';
        $webVersionNumber = '';
        $webVersionString = '';
        $lastInstallScriptNumber = '';
        $cronLastRunTime = '';
        $cronActive = '';
        $config = 0;
        $supportedLocales = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $stmt = $dbObj->prepare('SELECT * FROM `SYSTEMCONFIG`');
            if ($stmt)
            {
                if ($stmt->execute())
                {
                    if ($stmt->store_result())
                    {
                        if ($stmt->num_rows > 0)
                        {
                            if ($stmt->bind_result($recordID, $dateCreated, $ownerCode, $ownerCode2, $systemKey, $systemCertificate,
                                            $tenantID, $tenantKey, $tenantSecret, $key, $secret, $config, $webVersionDate, $webVersionNumber,
                                            $webVersionString, $lastInstallScriptNumber, $cronLastRunTime, $cronActive, $supportedLocales))
                            {
                                if (!$stmt->fetch())
                                {
                                    // no row
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'getSystemConfig no row';
                                }
                            }
                            else
                            {
                                // could not bind result
                                $result = 'str_DatabaseError';
                                $resultParam = 'getSystemConfig bind result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'getSystemConfig no row';
                        }
                    }
                    else
                    {
                        $result = 'str_DatabaseError';
                        $resultParam = 'getSystemConfig store result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not execute statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getSystemConfig execute ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getSystemConfig prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getSystemConfig connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['ownercode'] = $ownerCode;
        $resultArray['ownercode2'] = $ownerCode2;
        $resultArray['systemkey'] = $systemKey;
        $resultArray['systemcertificate'] = $systemCertificate;
        $resultArray['tenantid'] = $tenantID;
        $resultArray['tenantkey'] = $tenantKey;
        $resultArray['tenantsecret'] = $tenantSecret;
        $resultArray['key'] = $key;
        $resultArray['secret'] = $secret;
        $resultArray['systemconfig'] = $config;
        $resultArray['webversiondate'] = $webVersionDate;
        $resultArray['webversionnumber'] = $webVersionNumber;
        $resultArray['webversionstring'] = $webVersionString;
        $resultArray['lastinstallscriptnumber'] = $lastInstallScriptNumber;
        $resultArray['cronlastruntime'] = $cronLastRunTime;
        $resultArray['cronactive'] = $cronActive;
        $resultArray['supportedlocales'] = $supportedLocales;

        return $resultArray;
    }

	/**
	 * Get a list of brands
	 *
	 * Get a list of brands, optionally restricted by company code and optionally
	 * excluding the global company.
	 *
	 * @param string $companyCode
	 * @param string $excludeGlobalCompany
	 * @return array
	 */
    static function getBrandingList($companyCode = '', $excludeGlobalCompany = '')
    {
        // return an array containing the TAOPIX web brandings
        // replace payment methods with settings from constants if usedefaultpaymentmethods is true
        $brandingList = Array();

        $companyFilter = '';

        global $gSession;

        $imageScalingBefore = 0.00;
        $imageScalingAfter = 0.00;
        $imageScalingBeforeEnabled = 0;
        $imageScalingAfterEnabled = 0;
        $shuffleLayout = 0;
        $showShuffleLayoutOptions = 0;
		$onlineEditorMode = TPX_ONLINE_EDITOR_MODE_EASY;
		$enableSwitchingEditor = 0;
		$onlineDesignerLogoLinkURL = '';
		$onlineDesignerLogoLinkTooltip = '';
		$smartGuidesEnable = 0;
		$smartGuidesObjectGuideColour = TPX_SMARTGUIDES_OBJECT_GUIDECOLOUR;
		$smartGuidesPageGuideColour = TPX_SMARTGUIDES_PAGE_GUIDECOLOUR;
		$allowGiftcards = 1;
		$allowVouchers = 1;
		$sizeAndPositionMeasurementUnits = TPX_COORDINATE_SCALE_INCHES;
		$automaticallyApplyPerfectlyClear = 0;
		$allowUsersToTogglePerfectlyClear = 0;
		$insertDeleteButtonsVisibility = 1;
        $totalPagesDropdownMode = 1;
        $averagePicturesPerPage = 0;
        $componentUpsellSettings = 6;
        $useDefaultAccountPagesURL = 1;

        if ((isset($gSession['userdata'])) && ($gSession['userdata']['companycode'] != ''))
        {
            $companyCode = $gSession['userdata']['companycode'];
        }

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            // let SQL do the work and replace payment methods with settings from constants if usedefaultpaymentmethods is true
            if ($companyCode == '')
            {
                if ($stmt = $dbObj->prepare('SELECT `id`, `owner`, `code`, `name`, `applicationname`, `displayurl`, `weburl`, `usedefaultpaymentmethods`,
					IF (`usedefaultpaymentmethods` = 1, (SELECT `paymentmethods` FROM `BRANDING` WHERE `code` = ""), `paymentmethods`) as `paymentmethods`,
                    `imagescalingbefore`, `imagescalingbeforeenabled`,
                    `imagescalingafter`, `imagescalingafterenabled`,
                    `shufflelayout`, `showshufflelayoutoptions`,
					`onlineeditormode`, `enableswitchingeditor`,
					`onlinedesignerlogolinkurl`, `onlinedesignerlogolinktooltip`,
					`allowgiftcards`, `allowvouchers`, `sizeandpositionmeasurementunits`,
					`smartguidesenable`, `smartguidesobjectguidecolour`, `smartguidespageguidecolour`, `automaticallyapplyperfectlyclear`,
					`allowuserstotoggleperfectlyclear`, `insertdeletebuttonsvisibility`, `totalpagesdropdownmode`, `averagepicturesperpage`,
                    `componentupsellsettings`, `active`, `usedefaultaccountpagesurl` FROM `BRANDING` ORDER BY `code`'))
                {
                    $stmt->bind_result($recordID, $brandingOwner, $brandingCode, $brandingName, $applicationName, $displayURL, $webURL,
                            $useDefaultPaymentMethods, $paymentMethods,
                            $imageScalingBefore, $imageScalingBeforeEnabled,
                            $imageScalingAfter, $imageScalingAfterEnabled,
                            $shuffleLayout, $showShuffleLayoutOptions,
							$onlineEditorMode, $enableSwitchingEditor,
							$onlineDesignerLogoLinkURL, $onlineDesignerLogoLinkTooltip,
							$allowGiftcards, $allowVouchers, $sizeAndPositionMeasurementUnits,
							$smartGuidesEnable, $smartGuidesObjectGuideColour, $smartGuidesPageGuideColour, $automaticallyApplyPerfectlyClear,
							$allowUsersToTogglePerfectlyClear, $insertDeleteButtonsVisibility, $totalPagesDropdownMode, $averagePicturesPerPage,
                            $componentUpsellSettings, $isActive, $useDefaultAccountPagesURL);
                }
            }
            else
            {
            	// Check if the list include the global company
				// and apply the correct SQL
                if ($excludeGlobalCompany == 1)
                {
                    $companyFilter = '';
                }
                else
                {
                    $companyFilter = 'OR `companycode` = "" ';
                }

                if (($stmt = $dbObj->prepare('SELECT `id`, `owner`, `code`, `name`, `applicationname`, `displayurl`, `weburl`, `usedefaultpaymentmethods`,
					IF (`usedefaultpaymentmethods` = 1, (SELECT `paymentmethods` FROM `BRANDING` WHERE `code` = ""), `paymentmethods`) as `paymentmethods`,
                    `imagescalingbefore`, `imagescalingbeforeenabled`,
                    `imagescalingafter`, `imagescalingafterenabled`,
                    `shufflelayout`, `showshufflelayoutoptions`,
					`onlineeditormode`, `enableswitchingeditor`,
					`onlinedesignerlogolinkurl`,
					`allowgiftcards`, `allowvouchers`, `sizeandpositionmeasurementunits`,
					`smartguidesenable`, `smartguidesobjectguidecolour`, `smartguidespageguidecolour`, `automaticallyapplyperfectlyclear`,
					`allowuserstotoggleperfectlyclear`, `insertdeletebuttonsvisibility`, `totalpagesdropdownmode`, `averagepicturesperpage`,
                    `componentupsellsettings`, `active`, `accountpagesurl` FROM `BRANDING` WHERE `companycode`= ? ' . $companyFilter . '  ORDER BY `code`')) && ($stmt->bind_param('s',
                                $companyCode)))
                {
                    $stmt->bind_result($recordID, $brandingOwner, $brandingCode, $brandingName, $applicationName, $displayURL, $webURL,
                            $useDefaultPaymentMethods, $paymentMethods,
                            $imageScalingBefore, $imageScalingBeforeEnabled,
                            $imageScalingAfter, $imageScalingAfterEnabled,
                            $shuffleLayout, $showShuffleLayoutOptions,
							$onlineEditorMode, $enableSwitchingEditor,
							$onlineDesignerLogoLinkURL,
							$allowGiftcards, $allowVouchers, $sizeAndPositionMeasurementUnits,
							$smartGuidesEnable, $smartGuidesObjectGuideColour, $smartGuidesPageGuideColour, $automaticallyApplyPerfectlyClear,
							$allowUsersToTogglePerfectlyClear, $insertDeleteButtonsVisibility, $totalPagesDropdownMode, $averagePicturesPerPage,
                            $componentUpsellSettings, $isActive, $useDefaultAccountPagesURL);
                }
            }

            if ($stmt->execute())
            {
                while ($stmt->fetch())
                {
                    $brandingItem['id'] = $recordID;
                    $brandingItem['owner'] = $brandingOwner;
                    $brandingItem['code'] = $brandingCode;
                    $brandingItem['name'] = $brandingName;
                    $brandingItem['applicationname'] = $applicationName;
                    $brandingItem['displayurl'] = $displayURL;
                    $brandingItem['weburl'] = $webURL;
                    $brandingItem['usedefaultpaymentmethods'] = $useDefaultPaymentMethods;
                    $brandingItem['paymentmethods'] = $paymentMethods;
                    $brandingItem['imagescalingbefore'] = $imageScalingBefore;
                    $brandingItem['imagescalingbeforeenabled'] = $imageScalingBeforeEnabled;
                    $brandingItem['imagescalingafter'] = $imageScalingAfter;
                    $brandingItem['imagescalingafterenabled'] = $imageScalingAfterEnabled;
                    $brandingItem['shufflelayout'] = $shuffleLayout;
                    $brandingItem['showshufflelayoutoptions'] = $showShuffleLayoutOptions;
					$brandingItem['onlineeditormode'] = $onlineEditorMode;
					$brandingItem['enableswitchingeditor'] = $enableSwitchingEditor;
					$brandingItem['onlinedesignerlogolinkurl'] = $onlineDesignerLogoLinkURL;
					$brandingItem['onlinedesignerlogolinktooltip'] = $onlineDesignerLogoLinkTooltip;
					$brandingItem['smartguidesenable'] = $smartGuidesEnable;
					$brandingItem['smartguidesobjectguidecolour'] = $smartGuidesObjectGuideColour;
					$brandingItem['smartguidespageguidecolour'] = $smartGuidesPageGuideColour;
					$brandingItem['allowgiftcards'] = $allowGiftcards;
					$brandingItem['allowvouchers'] = $allowVouchers;
					$brandingItem['sizeandpositionmeasurementunits'] = $sizeAndPositionMeasurementUnits;
					$brandingItem['automaticallyapplyperfectlyclear'] = $automaticallyApplyPerfectlyClear;
                    $brandingItem['allowuserstotoggleperfectlyclear'] = $allowUsersToTogglePerfectlyClear;
					$brandingItem['insertdeletebuttonsvisibility'] = $insertDeleteButtonsVisibility;
                    $brandingItem['totalpagesdropdownmode'] = $totalPagesDropdownMode;
                    $brandingItem['averagepicturesperpage'] = $averagePicturesPerPage;
                    $brandingItem['componentupsellenabled'] = ($componentUpsellSettings & TPX_COMPONENT_UPSELL_ENABLED) ? 1 : 0;
                    $brandingItem['componentupsellproductquantity'] = ($componentUpsellSettings & TPX_COMPONENT_UPSELL_ALLOW_PRODUCT_QTY) ? 1 : 0;
                    $brandingItem['isactive'] = $isActive;
                    $brandingItem['usedefaultaccountpagesurl'] = $useDefaultAccountPagesURL;

                    $brandingList[] = $brandingItem;
                }
            }
            $stmt->free_result();
            $stmt->close();
            $stmt = null;
        }

        $dbObj->close();

        return $brandingList;
    }

