    /* Returns Brand which WebUrl domail is equal to the one provided.
     *
     * Tries to match WebUrl domain part in the Branding database table with the string passed as a parameter.
     *
     * @param string $host
     *  Requested domain name
     * @return string $webBrandResult
     *  Returns Brand code or empty string if domain name doesn't match any WebUrl in the Branding table
     *
     * @since Version 3.0.0
     * @author Dasha Salo
     */

    static function getBrandFromWebUrl($host)
    {
        $dbObj = self::getGlobalDBConnection();
        $webBrandResult = '';
        if ($dbObj)
        {
            $hostLike = '%' . $host . '%';
            $stmt = $dbObj->prepare('SELECT `code`, `weburl` FROM `BRANDING` WHERE `weburl` LIKE ?');
            if ($stmt)
            {
                if ($stmt->bind_param('s', $hostLike))
                {
                    if ($stmt->bind_result($webBrandCode, $webUrl))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $domain = str_ireplace('www.', '', parse_url($webUrl, PHP_URL_HOST));
                                if (strcasecmp($domain, $host) == 0)
                                {
                                    $webBrandResult = $webBrandCode;
                                    break;
                                }
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }
        return $webBrandResult;
    }

    static function getCompanyCodeFromSiteCode($pSiteCode)
    {
        // return the companycode of the production site
        $companyCode = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $stmt = $dbObj->prepare('SELECT `companycode` FROM `SITES` WHERE `code` = ?');
            if ($stmt)
            {
                if ($stmt->bind_param('s', $pSiteCode))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($companyCode))
                                {
                                    $stmt->fetch();
                                }
                            }
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        return $companyCode;
    }

    /**
     * Gets company data based on company code.
     *
     * @since Version 3.0.0
     * @version 3.0.0
     * @author Steffen Haugk
     * @return array
     */
    static function getCompanyFromCode($pCompanyCode)
    {
        $result = '';
        $resultParam = '';
        $recordID = 0;
        $dateCreated = '';
        $companyCode = '';
        $companyName = '';
        $address1 = '';
        $address2 = '';
        $address3 = '';
        $address4 = '';
        $city = '';
        $county = '';
        $state = '';
        $regionCode = '';
        $region = '';
        $postCode = '';
        $countryCode = '';
        $countryName = '';
        $telephoneNumber = '';
        $emailAddress = '';
        $contactFirstName = '';
        $contactLastName = '';
        $taxAddress = 0;
        $usedefaultipaccesslist = 0;
        $ipaccesslist = '';
        $licenseDataDate = '';
        $licenseData1 = '';
        $licenseData2 = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $stmt = $dbObj->prepare('SELECT * FROM `COMPANIES` WHERE (`code` = ?)');
            if ($stmt)
            {
                if ($stmt->bind_param('s', $pCompanyCode))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($recordID, $dateCreated, $companyCode, $companyName, $address1, $address2, $address3,
                                                $address4, $city, $county, $state, $regionCode, $region, $postCode, $countryCode,
                                                $countryName, $telephoneNumber, $emailAddress, $contactFirstName, $contactLastName,
                                                $taxAddress, $usedefaultipaccesslist, $ipaccesslist, $licenseDataDate, $licenseData1,
                                                $licenseData2))
                                {
                                    if (!$stmt->fetch())
                                    {
                                        // no matching payment method code
                                        $result = 'str_InvalidCompanyCode';
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'getCompanyFromCode bind result ' . $dbObj->error;
                                }
                            }
                            else
                            {
                                // no matching payment method code
                                $result = 'str_InvalidCompanyCode';
                            }
                        }
                        else
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'getCompanyFromCode store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'getCompanyFromCode execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'getCompanyFromCode bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getCompanyFromCode prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getCompanyFromCode connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['id'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['code'] = $companyCode;
        $resultArray['companyname'] = $companyName;
        $resultArray['address1'] = $address1;
        $resultArray['address2'] = $address2;
        $resultArray['address3'] = $address3;
        $resultArray['address4'] = $address4;
        $resultArray['city'] = $city;
        $resultArray['county'] = $county;
        $resultArray['state'] = $state;
        $resultArray['regioncode'] = $regionCode;
        $resultArray['region'] = $region;
        $resultArray['postcode'] = $postCode;
        $resultArray['countrycode'] = $countryCode;
        $resultArray['countryname'] = $countryName;
        $resultArray['telephonenumber'] = $telephoneNumber;
        $resultArray['emailaddress'] = $emailAddress;
        $resultArray['contactfirstname'] = $contactFirstName;
        $resultArray['contactlastname'] = $contactLastName;
        $resultArray['taxaddress'] = $taxAddress;
        $resultArray['usedefaultipaccesslist'] = $usedefaultipaccesslist;
        $resultArray['ipaccesslist'] = $ipaccesslist;
        $resultArray['licensedatadate'] = $licenseDataDate;
        $resultArray['licensedata1'] = $licenseData1;
        $resultArray['licensedata2'] = $licenseData2;

        return $resultArray;
    }

