                            $resultArrayItem['region'] = $region;
                            $resultArrayItem['postcode'] = $postCode;
                            $resultArrayItem['countrycode'] = $countryCode;
                            $resultArrayItem['countryname'] = $countryName;
                            $resultArrayItem['telephonenumber'] = $telephoneNumber;
                            $resultArrayItem['emailaddress'] = $emailAddress;
                            $resultArrayItem['contactfirstname'] = $contactFirstName;
                            $resultArrayItem['contactlastname'] = $contactLastName;
                            $resultArrayItem['taxaddress'] = $taxAddress;
                            $resultArrayItem['usedefaultipaccesslist'] = $useDefaultIpAccessList;
                            $resultArrayItem['ipaccesslist'] = $ipAccessList;
                            $resultArrayItem['licensedatadate'] = $licenseDataDate;
                            $resultArrayItem['licensedata1'] = $licenseData1;
                            $resultArrayItem['licensedata2'] = $licenseData2;

                            $resultArray[] = $resultArrayItem;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'getCompanyFromCode execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind result
                    $result = 'str_DatabaseError';
                    $resultParam = 'getCompanyFromCode bind result ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getCompanyFromCode prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getCompanyFromCode connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

        return $resultArray;
    }

    static function componentCategoriesList($pCompanyCode, $pFromProductConfigTree, $pHideInactive = 0)
    {
        global $gSession;

        $resultArray = Array();
		$whereParamString = '';

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
			$baseSql = 'SELECT `id`, `companycode`, `code`, `name`, `prompt`, `pricingmodel`, `islist`, `requirespagecount`,
						`componentpricingdecimalplaces`, `active`
						FROM `COMPONENTCATEGORIES` WHERE (`deleted` = 0)';

			if ($pHideInactive)
			{
				$baseSql .= ' AND (`active` = 1) ';
			}

			// if we have a company code then we must return both global and company specific categories.
			// This applies from both the product config screen or the component category grid.
			if ($pCompanyCode != '')
			{
				$baseSql .= ' AND ((`companycode` = "") OR (`companycode` = ?))';
				$whereParamString = 's';
			}
			else
			{
				// if the company code is GLOBAL and we are coming from the product tree then
				// we should only return GLOBAL categories. However if we are from the categories grid we should
				// retrun all categories i.e all global and company categories.
				$bindOK = true;

				if ($pFromProductConfigTree)
				{
					$baseSql .= ' AND (`companycode` = "")';
				}
			}

			if ($pFromProductConfigTree)
			{
				$baseSql .= ' ORDER BY `code`';
			}
			else
			{
				$baseSql .= ' ORDER BY `companycode`, `code`';
			}


			$stmt = $dbObj->prepare($baseSql);

            if ($stmt)
            {
				if ($whereParamString != '')
				{
					$bindOK = $stmt->bind_param($whereParamString, $pCompanyCode);
				}

                if ($bindOK)
                {
                    if ($stmt->bind_result($compCatID, $compCompanycode, $compCatCode, $compCatName, $compCatPrompt, $compCatPricingModel,
                                    $compIsList, $compRequiresPage, $decimalPlaces, $compCatActive))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $categoryItem['id'] = $compCatID;
                                $categoryItem['companycode'] = $compCompanycode;
                                $categoryItem['code'] = $compCatCode;
                                $categoryItem['name'] = $compCatName;
                                $categoryItem['prompt'] = $compCatPrompt;
                                $categoryItem['pricingmodel'] = $compCatPricingModel;
                                $categoryItem['islist'] = $compIsList;
                                $categoryItem['active'] = $compCatActive;
                                $categoryItem['requirespagecount'] = $compRequiresPage;
                                $categoryItem['decimalplaces'] = $decimalPlaces;

                                $resultArray[] = $categoryItem;
                            }
                        }
                    }

                    $stmt->free_result();
                    $stmt->close();
                }
            }

            $dbObj->close();
        }

        return $resultArray;
    }

