    /**
     * Returns a list of components of a given type that can be used in this order section.
     *
     * At the same time determine the default component (list components)
     * or if a checkbox should be ticked by default (checkbox components).
     *
     * @static
     *
     * @param string $pSectionPath
     * @param string $pCategoryCode
     * @param string $pCompanyCode
     * @param string $pProductCode
     * @param string $pGroupCode
     * @param float  $pCurrencyExchangeRate
     * @param integer $pCurrencyDecimalPlaces
     * @param integer $pQty
     * @param integer $pPageCount
     *
     * @return array $resultArray => (
     * 				    [component]   => array of components
     * 					[defaultcode] => comde of default component
     * 					[result] 	  => string
     * 					[resultparam] => string
     * 				)
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function getComponentsInOrderSectionByCategory($pSectionPath, $pCategoryCode, $pCompanyCode, $pProductCode, $pGroupCode,
            $pExchangeRate, $pCurrencyDecimalPlaces, $pQty, $pPageCount, $pComponentQuantity, $pComponentCode, $pRebuild, $pSortComponentsForCart)
    {
        $resultArray = Array();
        $resultArray['component'] = Array();
        $result = '';
        $resultParam = '';

        $existingCodesList = Array();
        $existingCodesList2 = Array();
        $itemArray = Array();
        $componentID = 0;
        $componentPreviewType = '';
        $componentDateCreated = 0;
        $componentCode = '';
        $componentLocalCode = '';
        $componentSkuCode = '';
        $componentName = '';
        $componentInfo = '';
		$componentMoreInfoLinkURL = '';
		$componentMoreInfoLinkText = '';
        $defaultCode = '';
        $defaultLocalCode = '';
        $defaultSkuCode = '';
        $defaultPriceInfo = '';
        $defaultOrderFooterUsesProductQty = 0;
        $defaultOrderFooterTaxLevel = 1;
        $defaultPrice = 0.00;
        $defaultPriceTaxCode = '';
        $defaultPriceTaxRate = 0.00;
        $defaultQtyIsDropDown = 0;
        $defaultComponentQty = $pQty;
        $isdefaultPrice = -1;
        $parentPath = '';
        $sortOrder = 0;
        $priceInfo = '';
        $componentUnitCost = 0;
        $componentWeight = 0;
        $componentPriceID = 0;
        $componentPriceProductCode = '';
        $componentPriceGroupCode = '';
        $componentPriceCompanyCode = '';
        $componentMinPageCount = 0;
        $componentMaxPageCount = 0;
        $componentRequiresPageCount = 0;
        $componentHasPrice = 0;
        $shoppingCartType = TPX_SHOPPINGCARTTYPE_INTERNAL;
		$inheritParentQty = 0;

        $dbObj = self::getGlobalDBConnection();

        if ($dbObj)
        {
			$sql = '(SELECT 0 AS `isdefaultprice`, `cmp`.`id`, `cmp`.`datecreated`, `cmp`.`code`, `cmp`.`localcode`, `cmp`.`skucode`, `cmp`.`name`, `cmp`.`info`, `cmp`.`moreinfolinkurl`, `cmp`.`moreinfolinktext`, `cmp`.`unitcost`, `cmp`.`minimumpagecount`, `cmp`.`maximumpagecount`, `cmp`.`weight`,
											`cmp`.`orderfooterusesproductquantity`, `cmp`.`orderfootertaxlevel`, `cmp`.`storewhennotselected`, `cc`.`requirespagecount`, `pr`.`id`, `pl`.`productcode`, `pl`.`groupcode`, `pl`.`companycode`, `pl`.`isdefault`, `pl`.`parentpath`, `pl`.`sortorder`, `pl`.`priceinfo`, `pr`.`quantityisdropdown`, `pr`.`price`, `pl`.`shoppingcarttype`, `pl`.`inheritparentqty`, `pr`.`taxcode`,
											IF (tr.rate IS NULL, "0.00", tr.rate)
											FROM `PRICELINK` pl JOIN `COMPONENTS` cmp ON `cmp`.`code` = `pl`.`componentcode`
												JOIN `COMPONENTCATEGORIES` cc ON `cc`.`code` = `cmp`.`categorycode`
												JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
												LEFT JOIN `TAXRATES` tr ON `pr`.`taxcode` = `tr`.`code`
											WHERE (`pl`.`productcode` = ?)
												AND (`pl`.`parentpath` = ?)
												AND (`pl`.`companycode` = ? OR `pl`.`companycode` = "")
												AND (`pl`.`groupcode` = ? OR `pl`.`groupcode` = "")
												AND (`pl`.`priceid` > 0)
												AND (`pl`.`active` = 1)
												AND (`cmp`.`companycode` = ? OR `cmp`.`companycode` = "")
												AND (`cmp`.`categorycode` = ?)
												AND (`cmp`.`active` = 1)
												AND (`cc`.`active` = 1)
												AND (`pr`.`active` = 1)
										)
										UNION
										(SELECT 1 AS `isdefaultprice`, `cmp`.`id`, `cmp`.`datecreated`, `cmp`.`code`, `cmp`.`localcode`, `cmp`.`skucode`, `cmp`.`name`, `cmp`.`info`, `cmp`.`moreinfolinkurl`, `cmp`.`moreinfolinktext`, `cmp`.`unitcost`, `cmp`.`minimumpagecount`,
										        `cmp`.`maximumpagecount`, `cmp`.`weight`, `cmp`.`orderfooterusesproductquantity`, `cmp`.`orderfootertaxlevel`, `cmp`.`storewhennotselected`, `cc`.`requirespagecount`, `pr`.`id`, `pl3`.`productcode`, `pl`.`groupcode`,
										        `pl`.`companycode`, `pl3`.`isdefault`, `pl3`.`parentpath`, `pl3`.`sortorder`, `pl`.`priceinfo`, `pr`.`quantityisdropdown`, `pr`.`price`, `pl`.`shoppingcarttype`, `pl`.`inheritparentqty`, `pr`.`taxcode`, IF (tr.rate IS NULL, "0.00", tr.rate)
											FROM `PRICELINK` pl JOIN COMPONENTS cmp ON `cmp`.`code` = `pl`.`componentcode`
												JOIN `COMPONENTCATEGORIES` cc ON `cc`.`code` = `cmp`.`categorycode`
												JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
												LEFT JOIN `TAXRATES` tr ON `pr`.`taxcode` = `tr`.`code`
											    INNER JOIN
												(SELECT `pl2`.`productcode`, `pl2`.`componentcode`, `pl2`.`sortorder`, `pl2`.`parentpath`, `pl2`.`isdefault` FROM `PRICELINK` pl2
												    JOIN `COMPONENTS` cmp2 ON `cmp2`.`code` = `pl2`.`componentcode`
													JOIN `COMPONENTCATEGORIES` cc2 ON `cc2`.`code` = `cmp2`.`categorycode`
												    WHERE (`pl2`.`productcode` = ?)
												 	AND (`pl2`.`parentpath` = ?)
												 	AND (`pl2`.`priceid` = -1)
												 	AND (`pl2`.`companycode` = ? OR `pl2`.`companycode` = "")
												 	AND (`pl2`.`active` = 1)
												 	AND (`cmp2`.`categorycode` = ?)
												 	AND (`cmp2`.`companycode` = ? OR `cmp2`.`companycode` = "")
												 	AND (`cmp2`.`active` = 1)
													AND (`cc2`.`active` = 1)
												) AS pl3
												WHERE `pl`.`componentcode` = `pl3`.`componentcode`
												AND (`pl`.`productcode` = "")
												AND (`pl`.`companycode` = ? OR `pl`.`companycode` = "")
												AND (`pl`.`groupcode` = ? OR `pl`.`groupcode` = "")
												AND (`pl`.`priceid` > 0)
												AND (`pl`.`active` = 1)
												AND (`pr`.`active` = 1)
												AND (`cmp`.`companycode` = ? OR `cmp`.`companycode` = "")
												AND (`cmp`.`categorycode` = ?)
												AND (`cc`.`active` = 1)
												AND (`cmp`.`active` = 1)
										)
										ORDER BY companycode DESC, isdefaultprice ASC, productcode DESC, groupcode DESC;';

			$bindParams = array('ssssss' . 'sssss' . 'ssss',
								$pProductCode, $pSectionPath, $pCompanyCode, $pGroupCode, $pCompanyCode, $pCategoryCode,
								$pProductCode, $pSectionPath, $pCompanyCode, $pCategoryCode, $pCompanyCode,
								$pCompanyCode, $pGroupCode, $pCompanyCode, $pCategoryCode);

            if ($stmt = $dbObj->prepare($sql))
            {
                // this command allows the creation of multiple prepares before the original prepare statement data has been fetched.
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);

				$bindOK = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindParams));

                if ($bindOK)
                {
                    if ($stmt->bind_result($isdefaultPrice, $componentID, $componentDateCreated, $componentCode, $componentLocalCode,
                                    $componentSkuCode, $componentName, $componentInfo, $componentMoreInfoLinkURL, $componentMoreInfoLinkText,
									$componentUnitCost, $componentMinPageCount,
                                    $componentMaxPageCount, $componentWeight, $componentOrderFooterUsesProdQty,
                                    $componentOrderFooterTaxLevel, $componentStoreWhenNotSelected, $componentRequiresPageCount, $componentPriceID,
                                    $componentPriceProductCode, $componentPriceGroupCode, $componentPriceCompanyCode, $default, $parentPath,
                                    $sortOrder, $priceInfo, $quantityIsDropDown, $price, $shoppingCartType, $inheritParentQty, $priceTaxCode, $priceTaxRate))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $includeComponent = true;

                                // if the component requires a page count and we have been passed a page count check that the page count is in range
                                if (($componentRequiresPageCount == 1) && ($pPageCount >= 0))
                                {
                                    if (($componentMinPageCount > $pPageCount) || ($componentMaxPageCount < $pPageCount))
                                    {
                                        $includeComponent = false;
                                    }
                                }

                                if ($includeComponent)
                                {
                                    // verify there is a price
                                    $priceArray = self::getPrice($pSectionPath, $componentCode, false, $componentPriceProductCode,
                                                    $componentPriceGroupCode, $componentPriceCompanyCode, $pExchangeRate,
                                                    $pCurrencyDecimalPlaces, $pQty, $pPageCount, $pComponentQuantity, $pComponentQuantity,
													true, true, $componentPriceID, $shoppingCartType,
                                                    $priceInfo, true);

                                    // make sure we have a default
                                    if ($defaultCode == '')
                                    {
                                        $defaultCode = $componentCode;
                                        $defaultLocalCode = $componentLocalCode;
                                        $defaultSkuCode = $componentSkuCode;
                                        $defaultPriceInfo = $priceInfo;
                                        $defaultOrderFooterUsesProductQty = $componentOrderFooterUsesProdQty;
                                        $defaultOrderFooterTaxLevel = $componentOrderFooterTaxLevel;
                                        $defaultQtyIsDropDown = $quantityIsDropDown;
                                        $defaultPrice = $price;
                                        $defaultPriceTaxCode = $priceTaxCode;
                                        $defaultPriceTaxRate = $priceTaxRate;

                                        if ($quantityIsDropDown)
                                        {
                                            if (!empty($priceArray['itemqtydropdown']))
                                            {
                                                $defaultComponentQty = $priceArray['itemqtydropdown'][0];
                                            }
                                        }
                                        else
                                        {
                                            $defaultComponentQty = $priceArray['newqty'];
                                        }
                                    }

                                    // the results are sorted so that a product will be before 'any product' and license keys will be before any license key
                                    // first check to make sure we haven't already added this component
                                    // if the quantity and pagecount are both -1 then this is auto-update so we include duplicates for the same default price status

									if ($isdefaultPrice == 0)
									{
										$defaultPriceComponentCodeKey = '0' . $componentCode;
										$defaultPriceComponentCodeKey2 = '1' . $componentCode;
									}
									else
									{
										$defaultPriceComponentCodeKey = '1' . $componentCode;
										$defaultPriceComponentCodeKey2 = '0' . $componentCode;
									}

									if (($pQty == -1) && ($pPageCount == -1))
									{
										// only include the component if it has not been included already for the opposite default price status
										$includeComponent = ! in_array($defaultPriceComponentCodeKey2, $existingCodesList2);
									}
									else
									{
										// only include the component if it has not been included already
										$includeComponent = ! in_array($componentCode, $existingCodesList);
									}


                                    if ($includeComponent)
                                    {
                                        if ($priceArray['result'] == '')
                                        {
                                            // reset the result since we have a valid price
                                            $result = '';

                                            $itemArray['id'] = $componentID;
                                            $itemArray['datecreated'] = $componentDateCreated;
                                            $itemArray['code'] = $componentCode;
                                            $itemArray['localcode'] = $componentLocalCode;
                                            $itemArray['skucode'] = $componentSkuCode;
                                            $itemArray['name'] = $componentName;
                                            $itemArray['info'] = $componentInfo;
											$itemArray['moreinfolinkurl'] = $componentMoreInfoLinkURL;
											$itemArray['moreinfolinktext'] = $componentMoreInfoLinkText;
                                            $itemArray['default'] = $default;
                                            $itemArray['ticked'] = $default;
                                            $itemArray['unitcost'] = $componentUnitCost;
                                            $itemArray['unitweight'] = $componentWeight;
                                            $itemArray['requirespagecount'] = $componentRequiresPageCount;
                                            $itemArray['minpagecount'] = $componentMinPageCount;
                                            $itemArray['maxpagecount'] = $componentMaxPageCount;
                                            $itemArray['pricingmodel'] = $priceArray['pricingmodel'];
                                            $itemArray['pricedata'] = $priceArray['pricedata'];
                                            $itemArray['sell'] = $priceArray['totalsell'];
                                            $itemArray['sortorder'] = $sortOrder;
                                            $itemArray['priceinfo'] = $priceInfo;
                                            $itemArray['itemqtydropdown'] = $priceArray['itemqtydropdown'];
                                            $itemArray['quantityisdropdown'] = $priceArray['quantityisdropdown'];
                                            $itemArray['orderfooterusesproductquantity'] = $componentOrderFooterUsesProdQty;
                                            $itemArray['orderfootertaxlevel'] = $componentOrderFooterTaxLevel;
                                            $itemArray['storewhennotselected'] = $componentStoreWhenNotSelected;
                                            $itemArray['pricetaxcode'] = $priceArray['taxcode'];
                                            $itemArray['pricetaxrate'] = $priceArray['taxrate'];
                                            $itemArray['quantity'] = $pQty;

                                            if ($quantityIsDropDown)
											{
												if (!empty($priceArray['itemqtydropdown']))
												{
													$itemArray['quantity'] = $priceArray['itemqtydropdown'][0];
												}
											}
											else
											{
												$itemArray['quantity'] = $priceArray['newqty'];
											}

                                            array_push($resultArray['component'], $itemArray);

                                            // remember the component code so that we don't get duplicates
                                            $existingCodesList[] = $componentCode;
                                            $existingCodesList2[] = $defaultPriceComponentCodeKey;

                                            // save code should this be the default list component
                                            // (there will never be both a global default component and a company default component)
                                            if ($default)
                                            {
                                                $defaultCode = $componentCode;
                                                $defaultLocalCode = $componentLocalCode;
                                                $defaultSkuCode = $componentSkuCode;
                                                $defaultPriceInfo = $priceInfo;
                                                $defaultOrderFooterUsesProductQty = $componentOrderFooterUsesProdQty;
                                                $defaultOrderFooterTaxLevel = $componentOrderFooterTaxLevel;
                                                $defaultQtyIsDropDown = $quantityIsDropDown;
                                                $defaultPrice = $price;
                                                $defaultPriceTaxCode = $priceTaxCode;
                                                $defaultPriceTaxRate = $priceTaxRate;
                                                if ($quantityIsDropDown)
                                                {
                                                    if (!empty($priceArray['itemqtydropdown']))
                                                    {
                                                        $defaultComponentQty = $priceArray['itemqtydropdown'][0];
                                                    }
                                                }
                                                else
                                                {
                                                    $defaultComponentQty = $priceArray['newqty'];
                                                }
                                            }

                                            $componentHasPrice = 1;

                                            // we need to check to see if this is a rebuild i.e the component has been changed in the shopping cart
                                            // if it is a rebuild then we need to find the record that corresponds to the component we are changing to
                                            // we then need to exit the loop so that the quanty is not overwritten.
                                            if (($pRebuild) && ($pComponentCode == $componentCode))
                                            {
                                                break;
                                            }
                                        }
                                        else
                                        {
                                            // a valid price was not found
                                            // if the component does not already have a price then set the result
                                            if ($componentHasPrice == 0)
                                            {
                                                $result = 'str_ErrorNoPriceForRange';
                                            }
                                        }
                                    }
                                }
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = __FUNCTION__ . ' execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . ' bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = __FUNCTION__ . ' prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        if ($pSortComponentsForCart)
        {
        	// sorting the component array based on the components sort order.
        	// this is so that they appear in the same order in the cart as they do on the product tree.
        	usort($resultArray['component'], 'orderItemComponentSortOrder');
		}

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['defaultcode'] = $defaultCode;
        $resultArray['defaultlocalcode'] = $defaultLocalCode;
        $resultArray['defaultskucode'] = $defaultSkuCode;
        $resultArray['defaultpriceinfo'] = $defaultPriceInfo;
        $resultArray['defaultcomponenthasprice'] = $componentHasPrice;
        $resultArray['productcode'] = $pProductCode;
        $resultArray['itemqty'] = $pQty;
        $resultArray['quantity'] = $defaultComponentQty;
        $resultArray['itempagecount'] = $pPageCount;
        $resultArray['pricedata'] = $defaultPrice;
        $resultArray['pricetaxcode'] = $defaultPriceTaxCode;
        $resultArray['pricetaxrate'] = $defaultPriceTaxRate;
        $resultArray['quantityisdropdown'] = $defaultQtyIsDropDown;
        $resultArray['orderfooterusesproductquantity'] = $defaultOrderFooterUsesProductQty;
        $resultArray['orderfootertaxlevel'] = $defaultOrderFooterTaxLevel;

        return $resultArray;
    }

    /**
     * Gets the price that suits all the parameters.
     *
     * And then calculates the price accordingly to the pricing model, exchange rate.
     * Rounds price.
     * This function replaces existing functions to retrieve cover and paper prices.
     *
     * @static
     *
     * @param string  $pComponentCategoryCode
     * @param string  $pComponentCode This is not the local code, i.e. it contains company and component category prefix
     * @param string  $pProductCode
     * @param string  $pGroupCode
     * @param string  $pCompanyCode
     * @param integer $pQty
     * @param float   $pCurrencyExchangeRate
     * @param integer $pCurrencyDecimalPlaces
     * @param integer $pPageCount optional since it is not needed for every pricing model
     *
     * @return array Price row
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function getProductPrice($pProductCode, $pGroupCode, $pCompanyCode, $pCurrencyExchangeRate, $pCurrencyDecimalPlaces, $pQty)
    {
        return self::getPrice('', '', true, $pProductCode, $pGroupCode, $pCompanyCode, $pCurrencyExchangeRate, $pCurrencyDecimalPlaces,
                        $pQty, 0, 0, 0, true, true, -1, 0, '', true);
    }

    /**
     * Gets the price that suits all the parameters.
     *
     * And then calculates the price accordingly to the pricing model, exchange rate.
     * Rounds price.
     * This function replaces existing functions to retrieve cover and paper prices.
     *
     * @static
     *
     * @param string  $pComponentCategoryCode
     * @param string  $pComponentCode This is not the local code, i.e. it contains company and component category prefix
     * @param string  $pProductCode
     * @param string  $pGroupCode
     * @param string  $pCompanyCode
     * @param integer $pQty
     * @param float   $pCurrencyExchangeRate
     * @param integer $pCurrencyDecimalPlaces
     * @param integer $pPageCount optional since it is not needed for every pricing model
     *
     * @return array Price row
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function getPrice($pSectionPath, $pComponentCode, $pIsProductPrice, $pProductCode, $pGroupCode, $pCompanyCode,
            $pCurrencyExchangeRate, $pCurrencyDecimalPlaces, $pQty, $pPageCount, $pLineBreakQty, $pComponentQty, $pCanAdjustComponentQty, $pLineBreakQTYIsComponentQty, $pPriceId, $pShoppingCartType, $pPriceInfo, $pApplyBasePriceLineSubtract)
    {
		$resultArray = Array();
        $priceArray = self::getPriceRow($pSectionPath, $pComponentCode, $pProductCode, $pGroupCode, $pCompanyCode, $pIsProductPrice, $pQty,
                        $pPriceId, $pShoppingCartType, $pPriceInfo, $pPageCount);

		if ($priceArray['result'] == '')
        {
            if ($priceArray['isactive'] == 0)
            {
                $resultArray['result'] = 'str_ErrorPriceNotActive';
                $resultArray['resultparam'] = '';
            }
            else
            {
                $resultArray = self::calculatePrice($priceArray, $pIsProductPrice, $pCurrencyExchangeRate, $pCurrencyDecimalPlaces, $pQty,
                                $pPageCount, $pLineBreakQty, $pComponentQty, $pCanAdjustComponentQty, $pLineBreakQTYIsComponentQty, $pApplyBasePriceLineSubtract);
            }
        }
        else
        {
            $resultArray['result'] = $priceArray['result'];
            $resultArray['resultparam'] = $priceArray['resultparam'];
        }

        $resultArray['componentCode'] = $pComponentCode;
        $resultArray['productcode'] = $pProductCode;
        $resultArray['groupcode'] = $pGroupCode;
        $resultArray['productinfo'] = $priceArray['priceinfo'];
        $resultArray['itemqtydropdown'] = $priceArray['itemqtydropdown'];
        $resultArray['quantityisdropdown'] = $priceArray['quantityisdropdown'];
        $resultArray['inheritparentqty'] = $priceArray['inheritparentqty'];
        $resultArray['pricingmodel'] = $priceArray['pricingmodel'];
        $resultArray['pricedata'] = $priceArray['price'];
        $resultArray['taxcode'] = $priceArray['taxcode'];
        $resultArray['taxrate'] = $priceArray['taxrate'];

		return $resultArray;
    }

    /**
     * Get an empty price row.
     *
     * @static
     *
     * @return array Empty price row
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function getEmptyPriceRow()
    {
        $resultArray = array();

        $resultArray['result'] = '';
        $resultArray['resultparam'] = '';
        $resultArray['recordid'] = 0;
        $resultArray['datecreated'] = '';
        $resultArray['companycode'] = '';
        $resultArray['categorycode'] = '';
        $resultArray['pricingmodel'] = 0;
        $resultArray['price'] = '';
        $resultArray['quantityisdropdown'] = 0;
        $resultArray['inheritparentqty'] = 0;
        $resultArray['allowinherit'] = 0;
        $resultArray['priceinfo'] = '';
        $resultArray['pricedescription'] = '';
        $resultArray['pricelistcode'] = '';
        $resultArray['pricelistname'] = '';
        $resultArray['itemqtydropdown'] = array();
        $resultArray['ispricelist'] = 0;
        $resultArray['taxcode'] = '';
        $resultArray['isactive'] = 0;

        return $resultArray;
    }

    /**
     * Gets a list of in an order section.
     *
     * Returns a list of checkbox components in an order section that have a price
     * defined for the specified parameters.
     *
     * $pParentSection is the container section we are searching in. It can be
     * 	blank: sections inside an order item
     * 	$LINEFOOTER\: sections inside an order item line footer
     * 	$ORDERFOOTER\: sections inside an order footer
     * 	[$LINEFOOTER\|$ORDERFOOTER\]$some_section\some_component\: sub-sections to hold sub-components of a component
     *
     * @static
     *
     * @param string $pProductCode
     * @param string $pGroupCode
     * @param string $pCompanyCode
     * @param string $pParentSection
     *
     * @return array
     * price row
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function getOrderCheckboxes($pProductCode, $pGroupCode, $pCompanyCode, $pParentSection, $pExchangeRate, $pCurrencyDecimalPlaces,
            $pQty, $pPageCount, $pParentOrderLineId, $pRebuild = false)
    {
        global $gSession;

        $result = '';
        $resultParam = '';
        $existingCodesList = array();
        $checkBoxArray = array();
        $resultArray = array();

        $component = Array('code' => '',
            'skucode' => '',
            'name' => '',
            'info' => '',
			'moreinfolinkurl' => '',
			'moreinfolinktext' => '',
            'priceinfo' => '',
            'categorycode' => '',
            'categoryname' => '',
            'pricingmodel' => 0,
            'productcode' => '',
            'prompt' => '',
            'islist' => 0,
            'default' => 0,
            'checked' => 0,
            'storewhennotselected' => 1,
            'id' => 0,
            'path' => '', // will be set in the calling function
            'orderfootertaxrate' => 0.00,
            'orderfootertaxcode' => '',
            'orderfootertaxname' => '',
            'unitcost' => 0.00,
            'unitsell' => 0.00,
            'totalcost' => 0.00,
            'totalsell' => 0.00,
            'totaltax' => 0.00,
            'totalsellnotax' => 0.00,
            'totalsellwithtax' => 0.00,
            'pricetaxcode' => '',
            'pricetaxrate' => 0.00,
            'discountvalue' => 0.0,
            'discountvalueraw' => 0.0,
            'discountvaluenotax' => 0.0,
            'discountvaluewithtax' => 0.0,
            'discountedtax' => 0.0,
            'unitweight' => 0.0000,
            'totalweight' => 0.0000,
            'quantity' => 1,
            'itemqty' => 0,
            'itemqtyaccumulative' => 0,
            'itempagecount' => 0,
            'orderlineid' => '',
            'metadata' => array(),
            'componenthasprice' => 0,
            'subtotal' => 0.00,
            'metadatahtml' => '');

        $isList = TPX_COMPONENTCATEGORY_DISPLAYTYPE_CHECKBOX;

        $dbObj = self::getGlobalDBConnection();

        if ($dbObj)
        {
			$sql = '(SELECT 0 AS isdefaultprice, `cmp`.`id`, `cmp`.`code`, `cmp`.`skucode`, `cmp`.`name`, `cmp`.`info`, `moreinfolinkurl`, `moreinfolinktext`, `cmp`.`categorycode`, `cat`.`name`, `cat`.`pricingmodel`, `cat`.`prompt`, `pl`.`isdefault`, `cmp`.`unitcost`,
                                                `cmp`.`weight`, `cmp`.`orderfooterusesproductquantity`, `cmp`.`orderfootertaxlevel`, `cmp`.`storewhennotselected`, `pl`.`companycode`, `pl`.`productcode`, `pl`.`groupcode`, `cmp`.`keywordgroupheaderid`, `pl`.`priceinfo`,
                                                `pl`.`sortorder`, `cmp`.`localcode`
        								FROM `PRICELINK` pl
        								JOIN `COMPONENTS` cmp ON `pl`.`componentcode` = `cmp`.`code`
        								JOIN `COMPONENTCATEGORIES` cat ON `cat`.`code` = `cmp`.`categorycode`
        								JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
					            		WHERE (`pl`.`companycode` = "" OR `pl`.`companycode` = ?)
					            		    AND (`pl`.`groupcode` = "" OR `pl`.`groupcode` = ?)
					            		    AND ((`pl`.`productcode` = ?) AND (`pl`.`parentpath` = ?))
					            		    AND (`pl`.`active` = 1)
					            		    AND (`pl`.`priceid` > 0)
					            		    AND (`pr`.`active` = 1)
					            		    AND (`cmp`.`companycode` = "" OR `cmp`.`companycode` = ?)
					            		    AND (`cmp`.`active` = 1)
											AND (`cat`.`islist` = ?)
											AND (`cat`.`active` = 1)
											AND ((`cat`.`requirespagecount` = 0) OR ((`cmp`.`minimumpagecount` <= ?) AND (`cmp`.`maximumpagecount` >= ?)))
										)
										UNION
										(SELECT 1 AS isdefaultprice, `cmp`.`id`, `cmp`.`code`, `cmp`.`skucode`, `cmp`.`name`, `cmp`.`info`, `cmp`.`moreinfolinkurl`, `cmp`.`moreinfolinktext`, `cmp`.`categorycode`, `cat`.`name`, `cat`.`pricingmodel`, `cat`.`prompt`, `pl3`.`isdefault`, `cmp`.`unitcost`,
										        `cmp`.`weight`, `cmp`.`orderfooterusesproductquantity`, `cmp`.`orderfootertaxlevel`, `cmp`.`storewhennotselected`, `pl`.`companycode`, `pl3`.`productcode`, `pl`.`groupcode`, `cmp`.`keywordgroupheaderid`, `pl`.`priceinfo`,
                                                `pl3`.`sortorder`, `cmp`.`localcode`
        								FROM `PRICELINK` pl
        								JOIN `COMPONENTS` cmp ON `pl`.`componentcode` = `cmp`.`code`
        								JOIN `COMPONENTCATEGORIES` cat ON `cat`.`code` = `cmp`.`categorycode`
        								JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
					            		INNER JOIN
					            			(SELECT `cmp2`.`code`, `pl2`.`productcode`, `pl2`.`isdefault`, `pl2`.`sortorder` FROM `PRICELINK` pl2
											JOIN `COMPONENTS` cmp2 ON `cmp2`.`code` = `pl2`.`componentcode`
											JOIN `COMPONENTCATEGORIES` cat2 ON `cat2`.`code` = `cmp2`.`categorycode`
											WHERE (`pl2`.`companycode` = "" OR `pl2`.`companycode` = ?)
												AND (`pl2`.`groupcode` = "" OR `pl2`.`groupcode` = ?)
												AND ((`pl2`.`productcode` = ?) AND (`pl2`.`parentpath` = ?))
												AND (`pl2`.`active` = 1)
												AND (`pl2`.`priceid` = -1)
												AND (`cmp2`.`companycode` = "" OR `cmp2`.`companycode` = ?)
												AND (`cmp2`.`active` = 1)
												AND (`cat2`.`islist` = ?)
												AND (`cat2`.`active` = 1)
												AND ((`cat2`.`requirespagecount` = 0) OR ((`cmp2`.`minimumpagecount` <= ?) AND (`cmp2`.`maximumpagecount` >= ?)))
											) AS pl3
											WHERE (`pl`.`componentcode` = `pl3`.`code`)
											AND (`pl`.`productcode` = "")
											AND (`pl`.`active` = 1)
											AND (`pl`.`companycode` = "" OR `pl`.`companycode` = ?)
											AND (`pl`.`groupcode` = "" OR `pl`.`groupcode` = ?)
											AND (`pl`.`priceid` > 0)
											AND (`pr`.`active` = 1)
										)
					            		ORDER BY sortorder';

			$bindParams = array('sssssiii' . 'sssssiii' . 'ss',
								$pCompanyCode, $pGroupCode, $pProductCode, $pParentSection, $pCompanyCode, $isList, $pPageCount, $pPageCount,
								$pCompanyCode, $pGroupCode, $pProductCode, $pParentSection, $pCompanyCode, $isList, $pPageCount, $pPageCount,
								$pCompanyCode, $pGroupCode);

            // get defaults from component category
            if ($stmt = $dbObj->prepare($sql))
            {
                // this command allows the creation of multiple prepares before the original prepare statement data has been fetched.
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);

				$bindOK = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindParams));

                if ($bindOK)
                {
                    if ($stmt->bind_result($isdefaultpricing, $componentId, $componentCode, $componentSkuCode, $componentName,
                                    $componentInfo, $componentMoreInfoLinkURL, $componentMoreInfoText, $categoryCode, $categoryName, $pricingModel, $categoryPrompt, $default, $unitCost,
                                    $weight, $orderFooterUsesProdQty, $orderFooterTaxLevel, $storeWhenNotSelected, $priceLinkCompanyCode,
                                    $priceLinkProductCode, $priceLinkGroupCode, $componentMetadataGroupId, $priceInfo, $sortOrder, $localCode))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                // the results are sorted so that a product will be before 'any product' and license keys will be before any license key
                                // first check to make sure we haven't already added this component
                                if (!in_array($componentCode, $existingCodesList))
                                {
                                    // verify there is a price
                                    $priceArray = self::getPrice($pParentSection, $componentCode, false, $priceLinkProductCode,
                                                    $priceLinkGroupCode, $priceLinkCompanyCode, $pExchangeRate, $pCurrencyDecimalPlaces,
                                                    $pQty, $pPageCount, 0, 0, true, true, -1, 0, '', true);

                                    $parentSectionArray = self::parseComponentOrSectionPath($pParentSection);
                                    $parentPath = '';

                                    foreach($parentSectionArray as $section)
                                    {
                                        $parentPath = ($parentPath != '') ? $parentPath . '.' : $parentPath;
                                        $parentPath .= $section['code'];
                                    }

                                    $component['code'] = $componentCode;
                                    $component['skucode'] = $componentSkuCode;
                                    $component['name'] = $componentName;
                                    $component['info'] = $componentInfo;
                                    $component['moreinfolinkurl'] = $componentMoreInfoLinkURL;
                                    $component['moreinfolinktext'] = $componentMoreInfoText;
                                    $component['categorycode'] = $categoryCode;
                                    $component['categoryname'] = $categoryName;
                                    $component['pricingmodel'] = $pricingModel;
                                    $component['productcode'] = $pProductCode;
                                    $component['prompt'] = $categoryPrompt;
                                    $component['default'] = $default;
                                    $component['checked'] = $default;
                                    $component['id'] = $componentId;
                                    $component['path'] = $pParentSection;
                                    $component['unitcost'] = $unitCost;
                                    $component['unitweight'] = $weight;
                                    $component['orderlineid'] = $pParentOrderLineId . '_' . Order_model::getNextOrderLineId();
                                    $component['sell'] = $priceArray['totalsell'];
                                    $component['priceinfo'] = $priceInfo;
                                    $component['itemqty'] = $priceArray['newqty'];
                                    $component['itemqtyaccumulative'] = $pQty;
                                    $component['itemqtydropdown'] = $priceArray['itemqtydropdown'];
                                    $component['orderfooterusesproductquantity'] = $orderFooterUsesProdQty;
                                    $component['orderfootertaxlevel'] = $orderFooterTaxLevel;
                                    $component['storewhennotselected'] = $storeWhenNotSelected;
                                    $component['itempagecount'] = $pPageCount;
                                    $component['pricetaxcode'] = $priceArray['taxcode'];
                                    $component['pricetaxrate'] = $priceArray['taxrate'];

                                    // check to see if we are dealing with components in the $ORDERFOOTER section
                                    if (substr($component['path'], 0, 13) == '$ORDERFOOTER\\')
                                    {
                                        // check to see if the component should use the product quantites to calcualte the price.
                                        if ($component['orderfooterusesproductquantity'] == 1)
                                        {
                                            $component['itemqty'] = $pQty;
                                            $component['itemqtyaccumulative'] = $pQty;
                                        }
                                        else
                                        {
                                            $startPriceArray = self::priceStringToArray($component['pricingmodel'], $priceArray['pricedata']);
                                            $component['itemqty'] = $startPriceArray[0]['startqty'];
                                            $component['itemqtyaccumulative'] = $startPriceArray[0]['startqty'];
                                        }
                                    }
                                    else
                                    {
                                        $component['itemqty'] = $pQty;
                                        $component['itemqtyaccumulative'] = $pQty;
                                    }


                                    if ($priceArray['result'] == '')
                                    {
                                        $component['componenthasprice'] = 1;
                                    }
                                    else
                                    {
                                        $component['componenthasprice'] = 0;
                                    }

                                    if ($componentMetadataGroupId > 0)
                                    {
                                        $component['metadata'] = MetaDataObj::getKeywordList('COMPONENT', '', '', $componentMetadataGroupId);
                                        $component['metadatahtml'] = '';
                                    }
                                    else
                                    {
                                        $component['metadata'] = Array();
                                        $component['metadatahtml'] = '';
                                    }

                                    // check to see if we are rebuilding the order footer section.
                                    // If we are then we need to rebuild the ordermetata data and remember the checkbox selection
                                    if ($pRebuild)
                                    {
                                        $hit = false;
                                        $index = 0;
                                        $origCheckboxArray = &$gSession['order']['orderFooterCheckboxes'];
                                        $orderFootSections = &$gSession['order']['orderFooterSections'];

                                        $itemCount = count($origCheckboxArray);

                                        for ($i = 0; $i < $itemCount; $i++)
                                        {
                                            if ($origCheckboxArray[$i]['path'] == $pParentSection)
                                            {
                                                $hit = true;
                                                $index = $i;
                                                break;
                                            }
                                        }

                                        if ($hit)
                                        {
                                            foreach ($origCheckboxArray as &$existingCheckboxItem)
                                            {
                                                if ($componentCode == $existingCheckboxItem['code'])
                                                {
                                                    $component['checked'] = $existingCheckboxItem['checked'];
                                                    $component['quantity'] = $existingCheckboxItem['quantity'];

                                                    // check to see if we are dealing with components in the $ORDERFOOTER section
                                                    if (substr($component['path'], 0, 13) == '$ORDERFOOTER\\')
                                                    {
                                                        // check to see if the component should use the product quantites to calcualte the price.
                                                        if ($component['orderfooterusesproductquantity'] == 1)
                                                        {
                                                            $component['itemqty'] = $pQty;
                                                        }
                                                        else
                                                        {
                                                            $priceArray = self::priceStringToArray($component['pricingmodel'],
                                                                            $priceArray['pricedata']);
                                                            $component['itemqty'] = $priceArray[0]['startqty'];
                                                        }
                                                    }
                                                    else
                                                    {
                                                        $component['itemqty'] = $pQty;
                                                    }

                                                    foreach ($component['metadata'] as &$metadataItem)
                                                    {
                                                        foreach ($existingCheckboxItem['metadata'] as &$oldMetadataItem)
                                                        {
                                                            if ($metadataItem['ref'] == $oldMetadataItem['ref'])
                                                            {
                                                                $metadataItem['defaultvalue'] = $oldMetadataItem['defaultvalue'];
                                                                break;
                                                            }
                                                        }
                                                    }
                                                    break;
                                                }
                                            }
                                        }
                                    }

                                    array_push($checkBoxArray, $component);

                                    // remember the component code so that we don't get duplicates
                                    array_push($existingCodesList, $componentCode);
                                }
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getOrderCheckboxes execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = 'getOrderCheckboxes bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'getOrderCheckboxes bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getOrderCheckboxes prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getOrderCheckboxes connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['checkboxes'] = $checkBoxArray;

        return $resultArray;
    }

	/**
	 * Gets a list of checkbox codes for an order
	 *
	 * Returns a list of checkboxes that have a price defined for the specified parameters.
	 * The sections are sorted by their sort order.
	 *
	 * $pParentSection is the container section we are searching in. It can be
	 * 	blank: sections inside an order item
	 * 	$LINEFOOTER\: sections inside an order item line footer
	 * 	$ORDERFOOTER\: sections inside an order footer
	 * 	[$LINEFOOTER\|$ORDERFOOTER\]$some_section\some_component\: sub-sections to hold sub-components of a component
	 *
	 * @param string $pProductCode
	 * @param string $pGroupCode
	 * @param string $pCompanyCode
	 * @param string $pParentSection
	 * @return mixed[]
	 */
	static function getOrderCheckboxList($pProductCode, $pGroupCode, $pCompanyCode, $pParentSection)
	{
		$result = '';
		$resultParam = '';
		$checkboxCodes = [];

		$dbObj = self::getGlobalDBConnection();
		if ($dbObj)
		{
			$sql = '(
					SELECT `cmp`.`code`
					FROM `PRICELINK` pl
					JOIN `COMPONENTS` cmp ON `pl`.`componentcode` = `cmp`.`code`
					JOIN `COMPONENTCATEGORIES` cat ON `cat`.`code` = `cmp`.`categorycode`
					JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
					WHERE (`pl`.`companycode` = "" OR `pl`.`companycode` = ?)
					AND (`pl`.`groupcode` = "" OR `pl`.`groupcode` = ?)
					AND ((`pl`.`productcode` = ?) AND (`pl`.`parentpath` = ?))
					AND (`pl`.`active` = 1)
					AND (`pl`.`priceid` > 0)
					AND (`pr`.`active` = 1)
					AND (`cmp`.`companycode` = "" OR `cmp`.`companycode` = ?)
					AND (`cmp`.`active` = 1)
					AND (`cat`.`islist` = 0)
					AND (`cat`.`active` = 1)
				)
				UNION
				(
					SELECT `cmp`.`code`
					FROM `PRICELINK` pl
					JOIN `COMPONENTS` cmp ON `pl`.`componentcode` = `cmp`.`code`
					JOIN `COMPONENTCATEGORIES` cat ON `cat`.`code` = `cmp`.`categorycode`
					JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
					INNER JOIN (
						SELECT `cmp2`.`code`, `pl2`.`productcode`, `pl2`.`isdefault`, `pl2`.`sortorder`
						FROM `PRICELINK` pl2
						JOIN `COMPONENTS` cmp2 ON `cmp2`.`code` = `pl2`.`componentcode`
						JOIN `COMPONENTCATEGORIES` cat2 ON `cat2`.`code` = `cmp2`.`categorycode`
						WHERE (`pl2`.`companycode` = "" OR `pl2`.`companycode` = ?)
						AND (`pl2`.`groupcode` = "" OR `pl2`.`groupcode` = ?)
						AND ((`pl2`.`productcode` = ?) AND (`pl2`.`parentpath` = ?))
						AND (`pl2`.`active` = 1)
						AND (`pl2`.`priceid` = -1)
						AND (`cmp2`.`companycode` = "" OR `cmp2`.`companycode` = ?)
						AND (`cmp2`.`active` = 1)
						AND (`cat2`.`islist` = 0)
						AND (`cat2`.`active` = 1)
					) AS pl3
					WHERE (`pl`.`componentcode` = `pl3`.`code`)
					AND (`pl`.`productcode` = "")
					AND (`pl`.`active` = 1)
					AND (`pl`.`companycode` = "" OR `pl`.`companycode` = ?)
					AND (`pl`.`groupcode` = "" OR `pl`.`groupcode` = ?)
					AND (`pl`.`priceid` > 0)
					AND (`pr`.`active` = 1)
				)';

			// get defaults from component category
			if ($stmt = $dbObj->prepare($sql))
			{
				if ($stmt->bind_param('sssss' . 'sssss' . 'ss',
					$pCompanyCode, $pGroupCode, $pProductCode, $pParentSection, $pCompanyCode,
					$pCompanyCode, $pGroupCode, $pProductCode, $pParentSection, $pCompanyCode,
					$pCompanyCode, $pGroupCode))
				{
					if ($stmt->bind_result($componentCode))
					{
						if ($stmt->execute())
						{
							while ($stmt->fetch())
							{
								$checkboxCodes[] = $componentCode;
							}
						}
						else
						{
							// could not execute statement
							$result = 'str_DatabaseError';
							$resultParam = __FUNCTION__ . ' execute ' . $dbObj->error;
						}
					}
					else
					{
						// could not bind result
						$result = 'str_DatabaseError';
						$resultParam = __FUNCTION__ . ' bind result ' . $dbObj->error;
					}
				}
				else
				{
					// could not bind parameters
					$result = 'str_DatabaseError';
					$resultParam = __FUNCTION__ . ' bind params ' . $dbObj->error;
				}

				$stmt->free_result();
				$stmt->close();
				$stmt = null;
			}
			else
			{
				// could not prepare statement
				$result = 'str_DatabaseError';
				$resultParam = __FUNCTION__ . ' prepare ' . $dbObj->error;
			}

			$dbObj->close();
		}
		else
		{
			// could not open database connection
			$result = 'str_DatabaseError';
			$resultParam = __FUNCTION__ . ' connect ' . $dbObj->error;
		}

		$resultArray['result'] = $result;
		$resultArray['resultparam'] = $resultParam;
		$resultArray['checkboxes'] = $checkboxCodes;

		return $resultArray;
	}

    /**
     * Gets a list of section codes for an order.
     *
     * Returns a list of sections to hold components that have a price defined for the
     * specified parameters. Hidden sections will be removed. The sections are sorted
     * by their sort order.
     *
     * $pParentSection is the container section we are searching in. It can be
     * 	blank: sections inside an order item
     * 	$LINEFOOTER\: sections inside an order item line footer
     * 	$ORDERFOOTER\: sections inside an order footer
     * 	[$LINEFOOTER\|$ORDERFOOTER\]$some_section\some_component\: sub-sections to hold sub-components of a component
     *
     * @static
     *
     * @param string $pProductCode
     * @param string $pGroupCode
     * @param string $pCompanyCode
     * @param string $pParentSection
     *
     * @return array
     * price row
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function getOrderSectionList($pProductCode, $pGroupCode, $pCompanyCode, $pParentSection)
    {
        $result = '';
        $resultParam = '';

        $existingSectionsArray = Array();
        $sectionArray = Array();
        $hiddenArray = Array();
        $resultArray = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // get list of hidden sections
            if ($stmt = $dbObj->prepare('SELECT DISTINCT(`sectionpath`) FROM `PRICELINK`
					 					WHERE (`productcode` = ?)
											AND (`groupcode` = ? OR `groupcode` = "")
											AND (`companycode` = ? OR `companycode` = "")
											AND (`componentcode` = "")
											AND (`priceid` = 0)
											AND (`isvisible` = 0)'))
            {
                if ($stmt->bind_param('sss', $pProductCode, $pGroupCode, $pCompanyCode))
                {
                    if ($stmt->bind_result($hiddenSectionPath))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $hiddenArray[] = $hiddenSectionPath;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = __FUNCTION__ . '1 execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . '1 bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . '1 bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = __FUNCTION__ . '1 prepare ' . $dbObj->error;
            }

            // get a list of sections for which prices are defined
            // parent path starting with $pParentSection, followed by no more than one section code
            // section path ending in section code, which is immediately preceded by a dollar sign
            $isList = TPX_COMPONENTCATEGORY_DISPLAYTYPE_LIST;
            $parentSectionDepth = substr_count($pParentSection, '\\') + 1;

            // appears to be a bug in MYSQLi that prevents us including the backslash in the REPLACE statement.
            // so we have to pass the \ as a bind parameter.
            $slashBindParameter = '\\';

            if ($stmt = $dbObj->prepare('(SELECT `sc`.`code`, `pl`.`parentpath`, `pl`.`sortorder`, `ct`.`code`
			                                FROM `PRICELINK` pl JOIN `COMPONENTS` cp ON `cp`.`code` = `pl`.`componentcode`
												JOIN `COMPONENTCATEGORIES` ct ON `ct`.`code` = `cp`.`categorycode`
												JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
			                                    JOIN `SECTIONS` sc ON `sc`.`categorycode` = `ct`.`code`
											WHERE (`pl`.`componentcode` <> "")
												AND (`pl`.`groupcode` = ? OR `pl`.`groupcode` = "")
												AND (`pl`.`companycode` = ? OR `pl`.`companycode` = "")
												AND (`pl`.`productcode` = ?)
												AND (`pl`.`parentpath` LIKE CONCAT(?, "%"))
												AND ((LENGTH(`pl`.`parentpath`) - LENGTH(REPLACE(`pl`.`parentpath`, ? , ""))) = ?)
												AND (`ct`.`islist` = ?)
												AND (`pl`.`active` = 1)
												AND (`pr`.`active` = 1)
												AND (`sc`.`active` = 1)
										)
										UNION
										(SELECT `sc`.`code`, `pl3`.`parentpath`, `pl3`.`sortorder`, `ct`.`code`
										    FROM `PRICELINK` pl JOIN `COMPONENTS` cp ON `cp`.`code` = `pl`.`componentcode`
												JOIN `COMPONENTCATEGORIES` ct ON `ct`.`code` = `cp`.`categorycode`
												JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
										        JOIN `SECTIONS` sc ON `sc`.`categorycode` = `ct`.`code`
										        INNER JOIN
										    	(SELECT `pl2`.`componentcode`, `pl2`.`sortorder`,`pl2`.`parentpath` FROM `PRICELINK` pl2
										    		WHERE (`pl2`.`componentcode` <> "")
													AND (`pl2`.`productcode` = ?)
													AND (`pl2`.`parentpath` LIKE CONCAT(?, "%"))
													AND ((LENGTH(`pl2`.`parentpath`) - LENGTH(REPLACE(`pl2`.`parentpath`, ? , ""))) = ?)
													AND (`pl2`.`priceid` = -1)
													AND (`pl2`.`companycode` = ? OR `pl2`.`companycode` = "")
												) AS pl3
											WHERE (`pl`.`componentcode`  = `pl3`.`componentcode`)
											AND (`pl`.`productcode` = "")
											AND (`pl`.`groupcode` = ? OR `pl`.`groupcode` = "")
											AND (`pl`.`priceid` > 0)
											AND (`ct`.`islist` = ?)
											AND (`pl`.`active` = 1)
											AND (`pr`.`active` = 1)
											AND (`sc`.`active` = 1)
										)
										ORDER BY sortorder'))
            {

                $slashesParentSection = addslashes($pParentSection);

                if ($stmt->bind_param('sssssiisssissi', $pGroupCode, $pCompanyCode, $pProductCode, $slashesParentSection,
                                $slashBindParameter, $parentSectionDepth, $isList, $pProductCode, $slashesParentSection,
                                $slashBindParameter, $parentSectionDepth, $pCompanyCode, $pGroupCode, $isList))
                {
                    if ($stmt->bind_result($code, $path, $sortorder, $categoryCode))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                // we need to stop SINGLEPRINT sections displaying as sections in the jobticket so we filter them out here.
								if (($categoryCode != TPX_PRIVATECATEGORY_SINGLEPRINT) && ($categoryCode != TPX_PRIVATECATEGORY_CALENDARCUSTOMISATION)
									&& ($categoryCode != TPX_PRIVATECATEGORY_TAOPIXAI))
                                {
                                    // make sure we get the immediate sections, not anything further down the hierarchy
                                    // only add if not in the list of hidden sections
                                    if (!in_array($path, $hiddenArray))
                                    {
                                        if (!in_array($path, $existingSectionsArray))
                                        {
                                            $sectionArray[] = $code;
                                            $existingSectionsArray[] = $path;
                                        }
                                    }
                                }
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = __FUNCTION__ . '2 execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . '2 bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . '2 bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = __FUNCTION__ . '2 prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['sections'] = $sectionArray;

        return $resultArray;
    }

	/**
	 * Get a row from PRICES table.
	 *
	 * Return an array containing the price row which best matches the supplied parameters.
	 * Price entries that point to a pricelist will be resolved, i.e. the latter is returned.
	 * This function is used to fetch product and component prices and thus replaces
	 * existing functions to retrieve prices for products, covers and papers.
	 *
	 * @static
	 *
	 * @param string $pSectionPath path to component
	 * @param string $pComponentCode This is not the local code, i.e. it contains company and component category prefix
	 * @param string $pProductCode
	 * @param string $pGroupCode
	 * @param string $pCompanyCode
	 * @param bool $pIsProductPrice
	 * @param int $pProductQty
	 * @param int $pPriceId
	 * @param int $pShoppingCartType
	 * @param mixed $pPriceInfo
	 * @param int $pPageQty
	 * @return array
	 *
	 * @author Steffen Haugk
	 * @since Version 3.0.0
	 */
    static function getPriceRow($pSectionPath, $pComponentCode, $pProductCode, $pGroupCode, $pCompanyCode,
		$pIsProductPrice, $pProductQty, $pPriceId, $pShoppingCartType, $pPriceInfo, $pPageQty)
    {
        $result = '';
        $resultParam = '';

        $id = $pPriceId;
        $isDefault = 0;
        $companycode = '';
        $productcode = '';
        $groupcode = '';
        $recordID = 0;
        $dateCreated = '';
        $companyCode = '';
        $categoryCode = '';
        $shoppingCartType = $pShoppingCartType;
        $pricingModel = 0;
        $price = '';
        $priceInfo = $pPriceInfo;
        $priceDescription = '';
        $priceListCode = '';
        $priceListLocalCode = '';
        $priceListName = '';
        $itemQtyDropdown = array();
        $quantityIsDropdown = 0;
        $isPriceList = 0;
        $isActive = 0;
        $taxCode = '';
        $taxRate = 0.00;
        $priceLinkActive = 0;
        $linkedPriceListId = 0;
        $bindOK = false;
        $inheritParentQty = 0;

        // decide whether to fetch inactive prices
        // (an inactive product price can switch off a global product)
        $activeOnly = ($pIsProductPrice) ? 0 : 1;

        if ($pIsProductPrice)
        {
            $pComponentCode = '';
        }

        $dbObj = self::getGlobalDBConnection();

        if ($dbObj)
        {
            if ($id == -1)
            {
                //determine the best price match
                //- product and component prices both have a priceid
                //- component prices look at active prices only, product prices fetch inactive prices as well (see above)
                //- component code can be set (component price) or blank (product price)
                //- product code can be set or blank (default prices)
                //- if component code and product code are set, parentpath has to match $pSectionPath
                if ($pComponentCode != '' && $pProductCode != '')
                {
 					$sql = '(SELECT 0 AS isdefaultprice, `pl`.`companycode`, `productcode`, `groupcode`, `priceid`, `pricedescription`, `shoppingcarttype`, `priceinfo`, `inheritparentQty`
											FROM `PRICELINK` pl JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
											WHERE (`pl`.`componentcode` = ?)
												AND (`pl`.`productcode` = ?)
												AND (`pl`.`parentpath` = ?)
												AND (`pl`.`groupcode` = ? OR `pl`.`groupcode` = "")
												AND (`pl`.`companycode` = ? OR `pl`.`companycode` = "")
												AND (`pl`.`active` = ? OR `pl`.`active` = 1)
												AND (`pl`.`priceid` > 0)
												AND (`pr`.`active` = ? OR `pr`.`active` = 1)
											)
											UNION
											(SELECT 1 AS isdefaultprice, `pl`.`companycode`, `pl3`.`productcode`, `groupcode`, `priceid`, `pricedescription`, `shoppingcarttype`, `priceinfo`, `inheritparentQty`
											FROM `PRICELINK` pl JOIN `PRICES` pr ON `pr`.`id` = `pl`.`priceid`
											INNER JOIN
												(SELECT `pl2`.`productcode`, `pl2`.`componentcode` FROM `PRICELINK` pl2
													WHERE (`pl2`.`componentcode` = ?)
													AND (`pl2`.`productcode` = ?)
													AND (`pl2`.`parentpath` = ?)
													AND (`pl2`.`priceid` = -1)
													AND (`pl2`.`companycode` = ? OR `pl2`.`companycode` = "")
												) AS pl3
												WHERE (`pl`.`componentcode` = `pl3`.`componentcode`)
												AND (`pl`.`productcode` = "") AND (`pl`.`groupcode` = ? OR `pl`.`groupcode` = "")
												AND (`pl`.`companycode` = ? OR `pl`.`companycode` = "")
												AND (`pl`.`active` = ? OR `pl`.`active` = 1)
												AND (`pr`.`active` = ? OR `pr`.`active` = 1)
											)
											ORDER BY companycode DESC, isdefaultprice ASC, productcode DESC, groupcode DESC;';

					$bindParams = array('sssssii' . 'ssssssi' . 'i',
										$pComponentCode, $pProductCode, $pSectionPath, $pGroupCode, $pCompanyCode, $activeOnly, $activeOnly,
										$pComponentCode, $pProductCode, $pSectionPath, $pCompanyCode, $pGroupCode, $pCompanyCode, $activeOnly,
										$activeOnly);
				}
                else
                {
					$sql = 'SELECT `priceid`, `pricedescription`, `shoppingcarttype`, `priceinfo`, `pl`.`active` FROM `PRICELINK` pl, `PRICES` pr
												WHERE ((`pl`.`componentcode` = ?) OR (`pl`.`productcode` = "") OR (`pl`.`parentpath` = ?))
												  AND (`pl`.`componentcode` = ? OR `pl`.`componentcode` = "")
												  AND (`pl`.`productcode`   = ? OR `pl`.`productcode` = "")
												  AND (`pl`.`groupcode`     = ? OR `pl`.`groupcode`   = "")
												  AND (`pl`.`companycode`   = ? OR `pl`.`companycode` = "")
												  AND (`pl`.`active` 		= ? OR `pl`.`active` 	  =  1)
												  AND (`pr`.`active`  		= ? OR `pr`.`active`  	  =  1)
												  AND (`pl`.`priceid` = `pr`.`id`)
												ORDER BY `pl`.`companycode` DESC, `productcode` DESC, `groupcode` DESC;';

 					$bindParams = array('sssss' . 'sii',
										$pComponentCode, $pSectionPath, $pComponentCode, $pProductCode, $pGroupCode,
										$pCompanyCode, $activeOnly, $activeOnly);
                }

				$stmt = $dbObj->prepare($sql);

				if ($stmt)
				{
					$bindOK = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindParams));

					if ($bindOK)
					{
						if ($stmt->execute())
						{
							if ($stmt->store_result())
							{
								if ($stmt->num_rows > 0)
								{
									if ($pComponentCode != '' && $pProductCode != '')
									{
										$bindResultOK = $stmt->bind_result($isDefault, $companycode, $productcode, $groupcode, $id, $priceDescription, $shoppingCartType, $priceInfo, $inheritParentQty);
									}
									else
									{
										$bindResultOK = $stmt->bind_result($id, $priceDescription, $shoppingCartType, $priceInfo, $priceLinkActive);
									}

									if ($bindResultOK)
									{
										if (!$stmt->fetch())
										{
											// no matching price
											$id = 0;
										}
									}
									else
									{
										// could not bind result
										$result = 'str_DatabaseError';
										$resultParam = __FUNCTION__ . ' 1 bind result ' . $dbObj->error;
									}
								}
								else
								{
									// no matching price
									$id = 0;
								}
							}
							else
							{
								$result = 'str_DatabaseError';
								$resultParam = __FUNCTION__ . ' 1 store result ' . $dbObj->error;
							}
						}
						else
						{
							// could not execute statement
							$result = 'str_DatabaseError';
							$resultParam = __FUNCTION__ . ' 1 execute ' . $dbObj->error;
						}
					}
					else
					{
						// could not bind parameters
						$result = 'str_DatabaseError';
						$resultParam = __FUNCTION__ . ' 1 bind params ' . $dbObj->error;
					}
					$stmt->free_result();
					$stmt->close();

					$stmt = null;
				}
				else
				{
					// could not prepare statement
					$result = 'str_DatabaseError';
					$resultParam = __FUNCTION__ . ' 1 prepare ' . $dbObj->error;
				}
			}

            // only try and retrieve price row if there is an id
            if ($id > 0)
            {
                $stmt = $dbObj->prepare('SELECT `pr`. *, IF (tr.rate IS NULL, "0.00", tr.rate)
                                            FROM `PRICES` pr
                                            LEFT JOIN `TAXRATES` tr ON `tr`.`code` = `pr`.`taxcode`
                                            WHERE `pr`.`id` = ?');
                if ($stmt)
                {
                    if ($stmt->bind_param('i', $id))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($recordID, $dateCreated, $companyCode, $categoryCode, $linkedPriceListId,
                                                    $pricingModel, $price, $priceListCode, $priceListLocalCode, $priceListName,
                                                    $quantityIsDropdown, $isPriceList, $taxCode, $isActive, $taxRate))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching price
                                            $result = 'str_ErrorInvalidPrice';
                                        }
                                        else
                                        {
                                            // Is this a product price
                                            if ($pIsProductPrice)
                                            {
                                                // we have a product price so we need to check to see if
                                                // both pricelink records and prices are active
                                                if ($priceLinkActive & $isActive)
                                                {
                                                    $isActive = 1;
                                                }
                                                else
                                                {
                                                    $isActive = 0;
                                                }
                                            }

                                            if ($quantityIsDropdown)
                                            {
                                                $priceItemArray = self::priceStringToArray($pricingModel, $price);

                                                if ($pIsProductPrice)
                                                {
                                                    foreach ($priceItemArray as $priceRow)
                                                    {
                                                        $itemQtyDropdown[] = $priceRow['endqty'];
                                                    }
                                                }
                                                else
                                                {
                                                    // if the product quantity is passed in as -1 then we must set it to the first startqty of the price record.
                                                    if ($pProductQty == -1)
                                                    {
                                                        $pProductQty = $priceItemArray[0]['startqty'];
                                                    }

                                                    foreach ($priceItemArray as $priceRow)
                                                    {

                                                        if ($pricingModel == TPX_PRICINGMODEL_PERSIDEPERPRODPERCMPQTY)
                                                        {

                                                            if (($pProductQty <= $priceRow['endqty'] && $pProductQty >= $priceRow['startqty']) &&
                                                                    ($pPageQty <= $priceRow['endpagecount'] && $pPageQty >= $priceRow['startpagecount']))
                                                            {
                                                                $itemQtyDropdown[] = $priceRow['endcmpqty'];
                                                            }
                                                        }
                                                        else
                                                        {

                                                            if ($pProductQty <= $priceRow['endqty'] && $pProductQty >= $priceRow['startqty'])
                                                            {
                                                                $itemQtyDropdown[] = $priceRow['endcmpqty'];
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = __FUNCTION__ . '2 bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no matching price
                                    $result = 'str_ErrorInvalidPrice';
                                }
                            }
                            else
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = __FUNCTION__ . '2 store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = __FUNCTION__ . '2 execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . '2 bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . '2 prepare ' . $dbObj->error;
                }
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['companycode'] = $companyCode;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['categorycode'] = $categoryCode;
        $resultArray['shoppingcarttype'] = $shoppingCartType;
        $resultArray['pricingmodel'] = $pricingModel;
        $resultArray['price'] = $price;
        $resultArray['priceinfo'] = $priceInfo;
        $resultArray['pricedescription'] = $priceDescription;
        $resultArray['pricelistcode'] = $priceListCode;
        $resultArray['pricelistname'] = $priceListName;
        $resultArray['itemqtydropdown'] = $itemQtyDropdown;
        $resultArray['ispricelist'] = $isPriceList;
        $resultArray['quantityisdropdown'] = $quantityIsDropdown;
        $resultArray['inheritparentqty'] = $inheritParentQty;
        $resultArray['taxcode'] = $taxCode;
        $resultArray['taxrate'] = $taxRate;
        $resultArray['isactive'] = $isActive;

        return $resultArray;
    }

    /**
     * Gets system constants.
     *
     * Retrieves an array of TAOPIX constants.
     *
     * @since Version 1.5.3
     * @version 3.0.0
     * @author Kevin Gale, Steffen Haugk
     * @return array
     */
    static function getConstants()
    {
        $resultArray = Array();
        $recordID = 0;
        $config = 0;
        $result = '';
        $resultParam = '';
        $dateCreated = '';
        $homeCountryCode = '';
        $defaultCurrencyCode = '';
        $defaultLanguageCode = 'en';
        $defaultCreditLimit = 0.00;
        $taxAddress = 0;
        $companyCount = 1;
        $ipAccessList = '';
        $webVersionDate = '';
        $webVersionNumber = '';
        $webVersionString = '';
		$maxLoginAttempts = 10;
		$accountLockoutTime = 60;
		$maxIPLoginAttempts = 10;
		$maxIPLoginAttemptsMinutes = 60;
		$minPasswordScore = 0;
		$customerUpdateAuthRequired = 0;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $sql = 'SELECT c.id, c.datecreated, c.defaultcurrencycode, c.defaultlanguagecode, c.defaultcreditlimit, c.maxloginattempts, ' .
					'c.accountlockouttime, c.maxiploginattempts, c.maxiploginattemptsminutes, c.minpasswordscore, c.customerupdateauthrequired, ' .
                    '(SELECT `countrycode` FROM `companies` WHERE `code`=""), (SELECT `taxaddress` FROM `companies` WHERE `code`=""), ' .
                    '(SELECT COUNT(`id`) FROM `COMPANIES`), (SELECT `ipaccesslist` FROM `COMPANIES` WHERE `code`=""), ' .
                    '(SELECT `webversiondate` FROM `SYSTEMCONFIG`), (SELECT `webversionnumber` FROM `SYSTEMCONFIG`), ' .
                    '(SELECT `webversionstring` FROM `SYSTEMCONFIG`), (SELECT `config` FROM `SYSTEMCONFIG`)' .
                    'FROM `CONSTANTS` c';

			$stmt = $dbObj->prepare($sql);
            if ($stmt)
            {
                if ($stmt->execute())
                {
                    if ($stmt->store_result())
                    {
                        if ($stmt->num_rows > 0)
                        {
                            if ($stmt->bind_result($recordID, $dateCreated, $defaultCurrencyCode, $defaultLanguageCode, $defaultCreditLimit,
                                            $maxLoginAttempts, $accountLockoutTime, $maxIPLoginAttempts, $maxIPLoginAttemptsMinutes,
                                            $minPasswordScore, $customerUpdateAuthRequired, $homeCountryCode, $taxAddress, $companyCount, $ipAccessList,
                                            $webVersionDate, $webVersionNumber, $webVersionString, $config))
                            {
                                if (!$stmt->fetch())
                                {
                                    // no row
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'getconstants no constants row';
                                }
                            }
                            else
                            {
                                // could not bind result
                                $result = 'str_DatabaseError';
                                $resultParam = 'getconstants bind result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'getconstants no constants row';
                        }
                    }
                    else
                    {
                        $result = 'str_DatabaseError';
                        $resultParam = 'getconstants store result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not execute statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getconstants execute ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getconstants prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getconstants connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['homecountrycode'] = $homeCountryCode;
        $resultArray['defaultcurrencycode'] = $defaultCurrencyCode;
        $resultArray['defaultlanguagecode'] = $defaultLanguageCode;
        $resultArray['defaultcreditlimit'] = $defaultCreditLimit;
        $resultArray['taxaddress'] = $taxAddress;
        $resultArray['defaultipaccesslist'] = $ipAccessList;
		$resultArray['maxloginattempts'] = $maxLoginAttempts;
		$resultArray['accountlockouttime'] = $accountLockoutTime;
		$resultArray['maxiploginattempts'] = $maxIPLoginAttempts;
		$resultArray['maxiploginattemptsminutes'] = $maxIPLoginAttemptsMinutes;
		$resultArray['minpasswordscore'] = $minPasswordScore;
		$resultArray['customerupdateauthrequired'] = $customerUpdateAuthRequired;
        $resultArray['webversiondate'] = $webVersionDate;
        $resultArray['webversionnumber'] = $webVersionNumber;
        $resultArray['webversionstring'] = $webVersionString;
        $resultArray['config'] = $config;
        $resultArray['optioncfs'] = ($config & 1) ? 1 : 0;
        $resultArray['optionms'] = ($config & 2) ? 1 : 0;
        $resultArray['optionams'] = ($config & 4) ? 1 : 0;
        $resultArray['optionmc'] = (($companyCount > 0) && ($config & 2)) ? 1 : 0;
        $resultArray['optionscbo'] = ($config & 8) ? 1 : 0;
        $resultArray['optionwscrp'] = ($config & 16) ? 1 : 0;
        $resultArray['optionptsnpr'] = ($config & 32) ? 1 : 0;
        $resultArray['optionai'] = ($config & 64) ? 1 : 0;
        $resultArray['optiondesdt'] = ($config & 128) ? 1 : 0;
        $resultArray['optiondesol'] = ($config & 256) ? 1 : 0;
        $resultArray['optiontdpv'] = ($config & 512) ? 1 : 0;
        $resultArray['optionscmlol'] = ($config & 1024) ? 1 : 0;
        $resultArray['optionhcc'] = ($config & 2048) ? 1 : 0;
        $resultArray['optionholdes'] = ($config & 4096) ? 1 : 0;
        $resultArray['optionptphbk'] = ($config & 8192) ? 1 : 0;
		$resultArray['optionptpfbk'] = ($config & 16384) ? 1 : 0;
		$resultArray['optionptcndr'] = ($config & 32768) ? 1 : 0;
		$resultArray['optionscntr'] = ($config & 65536) ? 1 : 0;

        $optionbc = $config & 71776119061217280; // maximum 255 brands
        $resultArray['optionbc'] = $optionbc >> 48;

        // variable to cache localised formats from the config file
        // this is used in the getLocaleFormatValue function within UtilsLocalization.php
        // this is much faster than getting the value from the config file each time
        $resultArray['localeFormatCache'] = Array();

        // variable to cache pricing information for different products/components
		// this is used to prevent unecessary database calls to the database to calculate pricing
        $resultArray['pricecachedata'] = Array();

        //add this parameter empty, we will populate it on reorder action in order_control.php
        $resultArray['initlang'] = '';

        return $resultArray;
    }

    static function getCover($pID, $pCoverCode)
    {
        // return an array containing the cover based on the supplied parameters
        // this does not return the preview image as there are memory issues when binding blob types

        $result = '';
        $resultParam = '';
        $recordID = 0;
        $dateCreated = '';
        $coverCompanyCode = '';
        $coverCode = '';
        $coverName = '';
        $coverInfo = '';
		$moreInfoLinkURL = '';
		$moreInfoLinkText = '';
        $coverUnitCost = 0.00;
        $coverMinPageCount = 0;
        $coverMaxPageCount = 0;
        $coverWeight = 0.00;
        $isActive = 0;

        if ($pCoverCode != '')
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                $stmt = $dbObj->prepare('SELECT `id`, `datecreated`, `companycode`, `code`, `name`, `info`, `moreinfolinkurl`, `moreinfolinktext`, `unitcost`, `minimumpagecount`,
                                            `maximumpagecount`, `weight`, `active`
                                        FROM `COMPONENTS`
                                        WHERE (`code` = ?)');
                if ($stmt)
                {
                    if ($stmt->bind_param('s', $pCoverCode))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($recordID, $dateCreated, $coverCompanyCode, $coverCode, $coverName, $coverInfo,
														$moreInfoLinkURL, $moreInfoLinkText, $coverUnitCost, $coverMinPageCount, $coverMaxPageCount, $coverWeight, $isActive))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching cover
                                            $result = 'str_InvalidCoverCode';
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getCover bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no matching cover
                                    $result = 'str_InvalidCoverCode';
                                }
                            }
                            else
                            {
                                $result = 'str_DatabaseError';
                                $resultParam = 'getCover store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'getCover execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getCover bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getCover prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
                // could not open database connection
                $result = 'str_DatabaseError';
                $resultParam = 'getCover connect ' . $dbObj->error;
            }
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['companyCode'] = $coverCompanyCode;
        $resultArray['code'] = $coverCode;
        $resultArray['name'] = $coverName;
        $resultArray['info'] = $coverInfo;
		$resultArray['moreinfolinkurl'] = $moreInfoLinkURL;
        $resultArray['moreinfolinktext'] = $moreInfoLinkText;
        $resultArray['unitcost'] = $coverUnitCost;
        $resultArray['minpagecount'] = $coverMinPageCount;
        $resultArray['maxpagecount'] = $coverMaxPageCount;
        $resultArray['weight'] = $coverWeight;
        $resultArray['isactive'] = $isActive;

        return $resultArray;
    }

    static function getCoverFromCode($pCode)
    {
        // return an array containing the cover for the specified cover code

        return self::getCover(0, $pCode);
    }

