                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getCurrencyFromNumber prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getCurrencyFromNumber connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['code'] = $currencyCode;
        $resultArray['name'] = $currencyName;
        $resultArray['isonumber'] = $isoNumber;
        $resultArray['symbol'] = $currencySymbol;
        $resultArray['symbolatfront'] = $currencySymbolAtFront;
        $resultArray['decimalplaces'] = $decimalPlaces;
        $resultArray['exchangeratedateset'] = $exchangeRateDateSet;
        $resultArray['exchangerate'] = $exchangeRate;

        return $resultArray;
    }

    static function getCurrencyList()
    {
        // return an array containing the TAOPIX currencies

        $currencyList = Array();

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `id`, `code`, `name`, `isonumber`, `symbol`, `symbolatfront`, `decimalplaces`, `exchangeratedateset`, `exchangerate` FROM `CURRENCIES` ORDER BY `code` '))
            {
                if ($stmt->bind_result($recordID, $currencyCode, $currencyName, $isoNumber, $currencySymbol, $currencySymbolAtFront,
                                $decimalPlaces, $exchangeRateDateSet, $exchangeRate))
                {
                    if ($stmt->execute())
                    {
                        while ($stmt->fetch())
                        {
                            $currencyItem['id'] = $recordID;
                            $currencyItem['code'] = $currencyCode;
                            $currencyItem['name'] = $currencyName;
                            $currencyItem['isonumber'] = $isoNumber;
                            $currencyItem['symbol'] = $currencySymbol;
                            $currencyItem['symbolatfront'] = $currencySymbolAtFront;
                            $currencyItem['decimalplaces'] = $decimalPlaces;
                            $currencyItem['exchangeratedateset'] = $exchangeRateDateSet;
                            $currencyItem['exchangerate'] = $exchangeRate;

                            $currencyList[] = $currencyItem;
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $currencyList;
    }

