	/**
	 * Get a list containing the data retension policies for the purge automation
	 *
	 * @param integer $pID ID of the desired policy, use -1 to return all policies
	 *
	 * @return array
	 */
	static function getOnlineDataPolicy($pID)
    {
		$resultArray = array('error' => '', 'errorMessage' => '', 'data' => array());

        $policyList = Array();

		$policyID = -1;
		$policyDateCreated = '';
		$policyCode = '';
		$policyName = '';
		$policyGuestProjects = 0;
		$policyGuestAge = 4;
		$policyUnsavedProjects = 0;
		$policyUnsavedAge = 7;
		$policyUnsavedDays = 14;
		$policyUnsavedEmail = 0;
		$policyUnsavedEmailFrequency = 0;
		$policyNotOrderedProjects = 0;
		$policyNotOrderedAge = 90;
		$policyNotOrderedDays = 60;
		$policyNotOrderedEmail = 0;
		$policyNotOrderedEmailFrequency = 0;
		$policyNotOrderedArchiveActive = 0;
		$policyNotOrderedArchiveDays = 45;
		$policyOrderedProjects = 0;
		$policyOrderedAge = 90;
		$policyOrderedDays = 60;
		$policyOrderedEmail = 0;
		$policyOrderedEmailFrequency = 0;
		$policyOrderedArchiveActive = 0;
		$policyOrderedArchiveDays = 45;
        $policyOrderedUnusedAssets = 0;
        $policyOrderedUnusedAssetsAge = 90;
        $policyNotOrderedUnusedAssets = 0;
        $policyNotOrderedUnusedAssetsAge = 90;
		$policyActive = 0;

		$bindOK = true;

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
			$sql = 'SELECT `id`, `datecreated`, `code`, `name`,
						`guestprojects`, `guestage`,
						`unsavedprojects`, `unsavedage`,`unsaveddays`, `unsavedemail`, `unsavedemailfrequency`,
						`notorderedprojects`, `notorderedage`, `notordereddays`, `notorderedemail`, `notorderedemailfrequency`, `notorderedarchiveactive`, `notorderedarchivedays`,
						`orderedprojects`, `orderedage`, `ordereddays`, `orderedemail`, `orderedemailfrequency`, `orderedarchiveactive`, `orderedarchivedays`,
						`orderedunusedassets`, `orderedunusedassetsage`, `notorderedunusedassets`, `notorderedunusedassetsage`, `active`
					FROM `DATAPOLICIES`';

			if ($pID != -1)
			{
				$sql .= ' WHERE `id` = ? ';
			}
			else
			{
				// only need to order by code if more than 1 policy returned
				$sql .= ' ORDER BY `code`';
			}

			if ($stmt = $dbObj->prepare($sql))
            {
				if ($pID != -1)
				{
					$bindOK = $stmt->bind_param('i', $pID);
				}

				if ($bindOK)
				{
					if ($stmt->execute())
					{
						if ($stmt->store_result())
						{
							if ($stmt->num_rows > 0)
							{
								if ($stmt->bind_result($policyID, $policyDateCreated, $policyCode, $policyName,
											$policyGuestProjects, $policyGuestAge,
											$policyUnsavedProjects, $policyUnsavedAge, $policyUnsavedDays, $policyUnsavedEmail, $policyUnsavedEmailFrequency,
											$policyNotOrderedProjects, $policyNotOrderedAge, $policyNotOrderedDays, $policyNotOrderedEmail, $policyNotOrderedEmailFrequency, $policyNotOrderedArchiveActive, $policyNotOrderedArchiveDays,
											$policyOrderedProjects, $policyOrderedAge, $policyOrderedDays, $policyOrderedEmail, $policyOrderedEmailFrequency, $policyOrderedArchiveActive, $policyOrderedArchiveDays,
											$policyOrderedUnusedAssets, $policyOrderedUnusedAssetsAge, $policyNotOrderedUnusedAssets, $policyNotOrderedUnusedAssetsAge, $policyActive))
								{
									while ($stmt->fetch())
									{
										$policyItem = array();

										$policyItem['id'] = $policyID;
										$policyItem['datecreated'] = $policyDateCreated;
										$policyItem['code'] = $policyCode;
										$policyItem['name'] = $policyName;
										$policyItem['ordered']['projects'] = $policyOrderedProjects;
										$policyItem['ordered']['age'] = $policyOrderedAge;
										$policyItem['ordered']['days'] = $policyOrderedDays;
										$policyItem['ordered']['email'] = $policyOrderedEmail;
										$policyItem['ordered']['emailfrequency'] = $policyOrderedEmailFrequency;
										$policyItem['ordered']['archiveactive'] = $policyOrderedArchiveActive;
										$policyItem['ordered']['archivedays'] = $policyOrderedArchiveDays;
										$policyItem['ordered']['total'] = ($policyOrderedAge + ($policyOrderedEmail == 1 ? $policyOrderedDays : 0));
										$policyItem['notordered']['projects'] = $policyNotOrderedProjects;
										$policyItem['notordered']['age'] = $policyNotOrderedAge;
										$policyItem['notordered']['days'] = $policyNotOrderedDays;
										$policyItem['notordered']['email'] = $policyNotOrderedEmail;
										$policyItem['notordered']['emailfrequency'] = $policyNotOrderedEmailFrequency;
										$policyItem['notordered']['archiveactive'] = $policyNotOrderedArchiveActive;
										$policyItem['notordered']['archivedays'] = $policyNotOrderedArchiveDays;
										$policyItem['notordered']['total'] = ($policyNotOrderedAge + ($policyNotOrderedEmail == 1 ? $policyNotOrderedDays : 0));
										$policyItem['unsaved']['projects'] = $policyUnsavedProjects;
										$policyItem['unsaved']['age'] = $policyUnsavedAge;
										$policyItem['unsaved']['days'] = $policyUnsavedDays;
										$policyItem['unsaved']['email'] = $policyUnsavedEmail;
										$policyItem['unsaved']['emailfrequency'] = $policyUnsavedEmailFrequency;
										$policyItem['unsaved']['total'] = ($policyUnsavedAge + ($policyUnsavedEmail == 1 ? $policyUnsavedDays : 0));
										$policyItem['guest']['projects'] = $policyGuestProjects;
										$policyItem['guest']['age'] = $policyGuestAge;
                                        $policyItem['orderedunused']['assets'] = $policyOrderedUnusedAssets;
                                        $policyItem['orderedunused']['assetsage'] = $policyOrderedUnusedAssetsAge;
                                        $policyItem['orderedunused']['total'] = $policyOrderedUnusedAssetsAge;
                                        $policyItem['notorderedunused']['assets'] = $policyNotOrderedUnusedAssets;
                                        $policyItem['notorderedunused']['assetsage'] = $policyNotOrderedUnusedAssetsAge;
                                        $policyItem['notorderedunused']['total'] = $policyNotOrderedUnusedAssetsAge;
										$policyItem['active'] = $policyActive;

										$policyList[] = $policyItem;
									}
								}
								else
								{
									$resultArray['error'] = 'str_DatabaseError';
									$resultArray['errorMessage'] = __FUNCTION__ . ': bind_result ' . $dbObj->error;
								}
							}
						}
						else
						{
							$resultArray['error'] = 'str_DatabaseError';
							$resultArray['errorMessage'] = __FUNCTION__ . ': store_result ' . $dbObj->error;
						}
					}
					else
					{
						$resultArray['error'] = 'str_DatabaseError';
						$resultArray['errorMessage'] = __FUNCTION__ . ': execute ' . $dbObj->error;
					}

				}
				else
				{
					$resultArray['error'] = 'str_DatabaseError';
					$resultArray['errorMessage'] = __FUNCTION__ . ': bind_param ' . $dbObj->error;
				}
				$stmt->free_result();
				$stmt->close();
				$stmt = null;
			}
			else
			{
				$resultArray['error'] = 'str_DatabaseError';
				$resultArray['errorMessage'] = __FUNCTION__ . ': prepare ' . $dbObj->error;
			}
		}
		else
		{
			$resultArray['error'] = 'str_DatabaseError';
			$resultArray['errorMessage'] = __FUNCTION__ . ': Connection Error ' . $dbObj->error;
		}

		if ($resultArray['error'] == '')
		{
			$resultArray['data'] = $policyList;
		}

        return $resultArray;
    }

    /**
     * Make sure the login is not already in use.
     *
     * @param $pWebBrandCode string brand to check for login.
     * @param $pLoginToCheck string login (email address) to check if already in use.
     * @return string empty if login is not in use.
     */
    static function checkLoginUnique($pWebBrandCode, $pLoginToCheck)
    {
		$resultArray = array('result' => '', 'resultparam' => '');

        // Check if an account exist for the specified login and brand.
        $userAccountArray = self::getUserAccountFromBrandAndLogin($pWebBrandCode, $pLoginToCheck);

        // A 'str_ErrorNoAccount' error means that no account exists. This is the desired result.
        // Any other result from the getUserAccount function should be returned.
        if ('str_ErrorNoAccount' != $userAccountArray['result'])
		{
            if ('' == $userAccountArray['result'])
            {
                // An account has been found, the login cannot be used.
                $resultArray['result'] = 'str_ErrorAccountExists';
            }
            else
            {
                // Some other error occurred, no action can be taken at this time.
                $resultArray['result'] = $userAccountArray['result'];
                $resultArray['resultparam'] = $userAccountArray['resultparam'];
            }
        }

		return $resultArray;
	}

