            {
                if ($pID > 0)
                {
                    $stmt = $dbObj->prepare('SELECT * FROM `USERS` WHERE (`id` = ?)');
                }
                else if ($pAccountCode != '-')
                {
                    /*
                    perform a search for the account code
                    */
                    $stmt = $dbObj->prepare('SELECT * FROM `USERS` WHERE (`accountcode` = ?)');
                }
                else if ($pBrandCode != '-')
                {
                    if ($pPassword != '-')
                    {
                        /*
                          perform a search for the login, password and brand code
                          the login index is case insensitive meaning that the case of the login text will not be taken into account
                          to solve this we look-up the user record again based on the id returned along with a binary comparison of the login
                          if we just performed a binary comparison of the login no index would be used which would cause a performance hit
                         */
                        $stmt = $dbObj->prepare('SELECT `u2`.* FROM `USERS` `u2` INNER JOIN
													(SELECT `id`, `login` FROM `USERS` WHERE (`login` = ?) AND (`webbrandcode` = ?)) AS `u1`
