													$lastLoginDateTemp, $nextValidLoginDateTemp, $loginAttemptCountTemp, $blockReasonTemp,
													$lastLoginIPTemp, $redactionProgressTemp, $redactionStateTemp, $redactionReasonTemp, $redactionDateTemp,
													$protectedFromRedactionTemp, $useDefaultVoucherSettingsTemp, $allowVouchersTemp, $allowGiftCardsTemp, $isActiveTemp))
