												$canModifyShippingAddress = $canModifyShippingAddressTemp;
												$canModifyShippingContactDetails = $canModifyShippingContactDetailsTemp;
												$useLicenseKeyForBillingAddress = $useLicenseKeyForBillingAddressTemp;
												$canModifyBillingAddress = $canModifyBillingAddressTemp;
												$userEmailDestination = $userEmailDestinationTemp;
												$defaultAddressControl = $defaultAddressControlTemp;
												$canModifyPassword = $canModifyPasswordTemp;
												$creditLimit = $creditLimitTemp;
												$accountBalance = $accountBalanceTemp;
												$giftCardBalance = $giftCardBalanceTemp;
												$sendMarketingInfo = $sendMarketingInfoTemp;
												$sendMarketingInfoOptInDate = $sendMarketingInfoOptInDateTemp;
												$ipAccessType = $ipAccessTypeTemp;
												$ipAccessList = $ipAccessListTemp;
												$lastLoginDate = $lastLoginDateTemp;
												$nextValidLoginDate = $nextValidLoginDateTemp;
												$blockReason = $blockReasonTemp;
												$lastLoginIP = $lastLoginIPTemp;
												$redactionProgress = $redactionProgressTemp;
												$redactionState = $redactionStateTemp;
												$redactionReason = $redactionReasonTemp;
												$redactionDate = $redactionDateTemp;
												$protectedFromRedaction = $protectedFromRedactionTemp;
												$useDefaultVoucherSettings = $useDefaultVoucherSettingsTemp;
												$allowVouchers = $allowVouchersTemp;
												$allowGiftCards = $allowGiftCardsTemp;
												$isActive = $isActiveTemp;

												// do not convert or upgrade the password for the licence server user
												if (($loginTemp != '_taopixlicenseserver') || ($userType != TPX_LOGIN_LICENCE_SERVER_API))
												{
													// convert the customers password if a stronger algorithm is available
													if ($convertPasswordHash)
													{
														$newPasswordHashResult = AuthenticateObj::generatePasswordHash($pPassword, $pPasswordFormat);

														// doesn't matter if generate password failed so there is no need to return an error as the old password will still be valid
														if ($newPasswordHashResult['result'] == '')
														{
															$newPasswordHash = $newPasswordHashResult['data'];

															AuthenticateObj::updateUserPassword($newPasswordHash, $recordID);
														}
													}

													// verify the php api password is up to date
													if ($verifyPasswordHash)
													{
														if ($hashFirstCharacter == '+')
														{
															$passwordHash = substr($password, 1);
														}
														else
														{
															$passwordHash = $password;
														}

														$passwordNeedsRehashResult = AuthenticateObj::checkPasswordNeedsRehash($passwordHash);
														if ($passwordNeedsRehashResult)
														{
															AuthenticateObj::rehashUserPassword($pPassword, $recordID, TPX_PASSWORDFORMAT_CLEARTEXT);
														}
													}
												}

												// if the address needs updating, try and match region to get a region code
												if (($countryCode != '') && ($addressUpdated == 0))
												{
													// first see if state or county is actually region code,
													// i.e. the customer has entered 'CA' and not 'California'
													$match = UtilsAddressObj::getRegionCodeFromCode($countryCode, $state, $county);

													// if no match found, try to match the region name
													if ($match['regioncode'] == '')
													{
														$match = UtilsAddressObj::getRegionCodeFromName($countryCode, $state, $county);
													}
													// if region is STATE,  $match[regioncode] holds state code
													// if region is COUNTY, $match[regioncode] holds county code
													$regionCode = $match['regioncode'];
													$region = $match['region'];

													if ($regionCode != '')
													{
														if ($region == 'STATE')
														{
															$state = $match['regionname'];
														}
														else
														{
															$county = $match['regionname'];
														}
													}
												}

												// Make sure the account is not locked at the moment.
												if (strtotime($nextValidLoginDateTemp) > strtotime(DatabaseObj::getServerTimeUTC()))
												{
													// Keep the number of attempts to detect if we are locking the account or just increasing the time for the next attempt.
													$loginAttemptCount = $loginAttemptCountTemp;

													if ($loginAttemptCountTemp >= $gConstants['maxloginattempts'])
													{
														// Maximum of attempts exceeded retrun the error message.
														$getLimetResult = AuthenticateObj::getLimitErrorMessage($nextValidLoginDateTemp, $loginAttemptCountTemp);
														$result = $getLimetResult['message'];
														$resultParam = $getLimetResult['value'];
													}
													else
													{
														// Log happening to quick.
														$result = 'str_ErrorAccountCouldNotBeSignedIn';
													}
												}
											}
											else
											{
												// Password does not match.
												$result = 'str_ErrorNoAccount';

												// Do not lock the account for the licence server user.
												if (($loginTemp != '_taopixlicenseserver') && ($userType != TPX_LOGIN_LICENCE_SERVER_API) && ($userType != TPX_LOGIN_API))
												{
													// Handle limits.
													$failedLoginID = $recordIDTemp;

													// Keep the number of attempts to detect if we are locking the account or just increasing the time for the next attempt.
													$loginAttemptCount = $loginAttemptCountTemp;
												}
											}
                                        }
                                        else
                                        {
                                            // no matching account
                                            $result = 'str_ErrorNoAccount';
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getuseraccount bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no matching account
                                    $result = 'str_ErrorNoAccount';
                                }
                            }
                            else
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'getuseraccount store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getuseraccount execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getuseraccount bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getuseraccount prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
                // could not open database connection
                $result = 'str_DatabaseError';
                $resultParam = 'getuseraccount connect ' . $dbObj->error;
            }
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
		$resultArray['failedloginid'] = $failedLoginID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['companycode'] = $companyCode;
        $resultArray['webbrandcode'] = $brandCode;
        $resultArray['owner'] = $owner;
        $resultArray['login'] = $login;
        $resultArray['password'] = $password;
        $resultArray['iscustomer'] = $isCustomer;
        $resultArray['usertype'] = $userType;
        $resultArray['groupcode'] = $groupCode;
        $resultArray['accountcode'] = $accountCode;
        $resultArray['companyname'] = $companyName;
        $resultArray['address1'] = $address1;
        $resultArray['address2'] = $address2;
        $resultArray['address3'] = $address3;
        $resultArray['address4'] = $address4;
        $resultArray['city'] = $city;
        $resultArray['county'] = $county;
        $resultArray['state'] = $state;
        $resultArray['regioncode'] = $regionCode;
        $resultArray['region'] = $region;
        $resultArray['addressupdated'] = $addressUpdated;
        $resultArray['postcode'] = $postCode;
        $resultArray['countrycode'] = $countryCode;
        $resultArray['countryname'] = $countryName;
        $resultArray['telephonenumber'] = $telephoneNumber;
        $resultArray['emailaddress'] = $emailAddress;
        $resultArray['contactfirstname'] = $contactFirstName;
        $resultArray['contactlastname'] = $contactLastName;
        $resultArray['usedefaultcurrency'] = $useDefaultCurrency;
        $resultArray['currencycode'] = $currencyCode;
        $resultArray['usedefaultpaymentmethods'] = $useDefaultPaymentMethods;
        $resultArray['paymentmethods'] = $paymentMethods;
        $resultArray['taxcode'] = $taxCode;
        $resultArray['shippingtaxcode'] = $shippingTaxCode;
        $resultArray['registeredtaxnumbertype'] = $registeredTaxNumberType;
        $resultArray['registeredtaxnumber'] = $registeredTaxNumber;
        $resultArray['uselicensekeyforshippingaddress'] = $useLicenseKeyForShippingAddress;
        $resultArray['canmodifyshippingaddress'] = $canModifyShippingAddress;
        $resultArray['canmodifyshippingcontactdetails'] = $canModifyShippingContactDetails;
        $resultArray['uselicensekeyforbillingaddress'] = $useLicenseKeyForBillingAddress;
        $resultArray['canmodifybillingaddress'] = $canModifyBillingAddress;
        $resultArray['useremaildestination'] = $userEmailDestination;
        $resultArray['defaultaddresscontrol'] = $defaultAddressControl;
        $resultArray['canmodifypassword'] = $canModifyPassword;
        $resultArray['creditlimit'] = $creditLimit;
        $resultArray['accountbalance'] = $accountBalance;
        $resultArray['giftcardbalance'] = $giftCardBalance;
        $resultArray['sendmarketinginfo'] = $sendMarketingInfo;
        $resultArray['sendmarketinginfooptindate'] = $sendMarketingInfoOptInDate;
        $resultArray['ipaccesstype'] = $ipAccessType;
        $resultArray['ipaccesslist'] = $ipAccessList;
        $resultArray['lastlogindate'] = $lastLoginDate;
		$resultArray['nextvalidlogindate'] = $nextValidLoginDate;
		$resultArray['loginattemptcount'] = $loginAttemptCount;
		$resultArray['blockreason'] = $blockReason;
        $resultArray['lastloginip'] = $lastLoginIP;
        $resultArray['redactionprogress'] = $redactionProgress;
        $resultArray['redactionsate'] = $redactionState;
        $resultArray['redactionreason'] = $redactionReason;
        $resultArray['redactiondate'] = $redactionDate;
        $resultArray['protectedfromredaction'] = $protectedFromRedaction;
		$resultArray['usedefaultvouchersettings'] = $useDefaultVoucherSettings;
		$resultArray['allowvouchers'] = $allowVouchers;
		$resultArray['allowgiftcards'] = $allowGiftCards;
        $resultArray['isactive'] = $isActive;
        $resultArray['pendingEmailChange'] = false;

        return $resultArray;
    }

    static function getUserAccountFromID($pID)
    {
        // return an array containing the user account for the specified user account id

        return self::getUserAccount($pID, '-', '-', '-', '-');
    }

    static function getUserAccountFromAccountCode($pAccountCode)
    {
        // return an array containing the user account for the specified user account code

        return self::getUserAccount(0, $pAccountCode, '-', '-', '-');
    }

    static function getUserAccountFromLoginAndPassword($pLogin, $pPassword, $pPasswordFormat)
    {
        // return an array containing the user account for the specified login and password

        if ($pPassword == '-')
        {
            // if the password is our no password tag change it to one that will never be found
            $pPassword = "!@£$%\t^&*()_";
        }

        return self::getUserAccount(0, '-', '-', $pLogin, $pPassword, $pPasswordFormat);
    }

    static function getUserAccountFromLogin($pLogin)
    {
        // return an array containing the user account for the specified login

        return self::getUserAccount(0, '-', '-', $pLogin, '-');
    }

    static function getUserAccountFromBrandAndLoginAndPassword($pBrandCode, $pLogin, $pPassword, $pPasswordFormat)
    {
        // return an array containing the user account for the specified login, password and brand

        if ($pBrandCode == '-')
        {
            // if the brand is our no brand tag change it to one that will never be found
            $pBrandCode = "!@£$%\t^&*()_";
        }

        return self::getUserAccount(0, '-', $pBrandCode, $pLogin, $pPassword, $pPasswordFormat);
    }

    static function getUserAccountFromBrandAndLogin($pBrandCode, $pLogin)
    {
        // return an array containing the user account for the specified login and brand

        if ($pBrandCode == '-')
        {
            // if the brand is our no brand tag change it to one that will never be found
            $pBrandCode = "!@£$%\t^&*()_";
        }

        return self::getUserAccount(0, '-', $pBrandCode, $pLogin, '-');
    }

    static function getEmptyUserAccount()
    {
        // return an array containing an empty user account record

        return self::getUserAccount(-1, '-', '-', '-', '-');
    }

    /**
     * Find all customer accounts which use the specified email address. Restrict the search to the specified brand.
     *
     * @param $pBrandCode string
     * @param $pEmail string
     * @param $pPassword string
     * @param $pPasswordFormat string
     */
    static function getValidUserAccountsForEmailAndBrand($pBrandCode, $pEmail, $pPassword, $pPasswordFormat)
    {
		global $gConstants;

        $resultArray = array('result' => '', 'resultparam' => '', 'count' => 0, 'validcount' => 0, 'accounts' => array());
        $userType = TPX_LOGIN_CUSTOMER;

        $accID = -1;
        $accLogin = '';
        $accPassword = '';
		$accLastLoginDate = '';
        $passwordValid = false;

        $sql = "SELECT `id`, `login`, `password`, IF(`lastlogindate` = '0000-00-00 00:00:00', `datecreated`, `lastlogindate`) as `lastuseddate`
                FROM `USERS`
                WHERE (`emailaddress` = ?) AND (`webbrandcode` = ?) AND (`active` = 1) AND (`usertype` = ?)
                ORDER BY `lastuseddate` DESC";

        $bindParamsArrays = array('ssi', $pEmail, $pBrandCode, $userType);

        $dateTimeFormat = LocalizationObj::getLocaleDateTimeFormat();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // Prepare the SQL.
            $stmt = $dbObj->prepare($sql);

            if ($stmt)
            {
                $bindOK = $stmt->bind_param(...$bindParamsArrays);

                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($accID, $accLogin, $accPassword, $accLastLoginDate))
                                {
                                    while ($stmt->fetch())
                                    {
                                        // Check the account password, Only if the password has been passed to the function.
                                        // $passwordValid will always be false if no password is passed.
                                        if ('' != $pPassword)
                                        {
                                            $verifyPasswordResult = AuthenticateObj::verifyPassword($pPassword, $accPassword, $pPasswordFormat);

                                            $passwordValid = $verifyPasswordResult['data']['passwordvalid'];
                                        }

                                        $accountFound = array();
                                        $accountFound['id'] = $accID;
                                        $accountFound['login'] = $accLogin;
                                        $accountFound['passwordvalid'] = $passwordValid;
                                        $accountFound['lastlogindate'] = LocalizationObj::formatDateTime($accLastLoginDate, $dateTimeFormat);

                                        // Add the account into the return array.
                                        $resultArray['accounts'][] = $accountFound;
                                        $resultArray['count']++;

                                        // Keep count of the number of accounts found which pass validation.
                                        if ($passwordValid)
                                        {
                                            $resultArray['validcount']++;
                                        }
                                    }
                                }
                                else
                                {
                                    // Bind result error.
                                    $resultArray['result'] = 'str_DatabaseError';
                                    $resultArray['resultparam'] = __FUNCTION__ . ' bind result ' . $dbObj->error;
                                }
                            }
                            else
                            {
                                // No records found.
                                $resultArray['result'] = 'str_ErrorNoAccount';
                            }
                        }
                        else
                        {
                            // Store result error.
                            $resultArray['result'] = 'str_DatabaseError';
                            $resultArray['resultparam'] = __FUNCTION__ . ' store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // Execute error.
                        $resultArray['result'] = 'str_DatabaseError';
                        $resultArray['resultparam'] = __FUNCTION__ . ' execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // Bind params error.
                    $resultArray['result'] = 'str_DatabaseError';
                    $resultArray['resultparam'] = __FUNCTION__ . ' bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // Prepare statement error.
                $resultArray['result'] = 'str_DatabaseError';
                $resultArray['resultparam'] = __FUNCTION__ . ' prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // Database connection error.
            $resultArray['result'] = 'str_DatabaseError';
            $resultArray['resultparam'] = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        return $resultArray;
    }


    /**
