     *
     * @author Kevin Gale
     * @since Version 1.0.0
     */
    static function getLicenseKey($pLogin, $pPassword, $pID, $pGroupCode)
    {
        // return an array containing the license key based on the supplied parameters
        global $gConstants;

        $result = '';
        $resultParam = '';
        $recordID = 0;
        $dateCreated = '';
        $companyCode = '';
        $groupCode = '';
        $companyName = '';
        $address1 = '';
        $address2 = '';
        $address3 = '';
        $address4 = '';
        $city = '';
        $county = '';
