        $paymentMethods = '';
        $designerSplashScreenAssetID = 0;
        $designerSplashScreenStartDate = '';
        $designerSplashScreenEndDate = '';
        $designerBannerAssetID = 0;
        $designerBannerStartDate = '';
        $designerBannerEndDate = '';
        $isActive = 0;
        $onlineDesignerGuestWorkFlowMode = 0;
        $maxOrderBatchSize = 1;
        $cacheVersion = '';
        $registeredTaxNumberType = 0;
        $registeredTaxNumber = '';
        $availableOnline = '';
        $orderFromPreview = 0;
        $imageScalingBefore = 0.0;
        $imageScalingBeforeEnabled = 0;
        $useDefaultImageScalingBefore = 1;
        $imageScalingAfter = 0.0;
        $imageScalingAfterEnabled = 0;
        $useDefaultImageScalingAfter = 1;
        $shuffleLayout = 0;
        $showShuffleLayoutOptions = 0;
        $useDefaultShuffleLayout = 1;
		$onlineEditorMode = TPX_ONLINE_EDITOR_MODE_EASY;
        $enableSwitchingEditor = 0;
        $useDefaultOnlineEditorMode = 1;
		$onlineDesignerLogoLinkURL = '';
		$useDefaultOnlineDesignerLogoLinkURL = 0;
		$onlineDesignerLogoLinkTooltip = '';
		$smartGuidesEnable = 0;
		$smartGuidesObjectGuideColour = TPX_SMARTGUIDES_OBJECT_GUIDECOLOUR;
		$smartGuidesPageGuideColour = TPX_SMARTGUIDES_PAGE_GUIDECOLOUR;
		$useDefaultSmartGuidesSettings = 1;
		$useDefaultVoucherSettings = 1;
		$allowVouchers = 1;
		$allowGiftCards = 1;
		$useDefaultSizeAndPositionSettings = 1;
		$sizeAndPositionMeasurementUnits = TPX_COORDINATE_SCALE_INCHES;
		$useDefaultAutomaticallyApplyPerfectlyClear = 1;
		$automaticallyApplyPerfectlyClear = 0;
		$allowUsersToTogglePerfectlyClear = 0;
		$useDefaultInsertDeleteButtonsVisibility = 0;
		$insertDeleteButtonsVisibility = 1;
		$useDefaultTotalPagesDropdownMode = 0;
        $totalPagesDropdownMode = 1;
        $useDefaultAveragePicturesPerPage = 0;
        $averagePicturesPerPage = 0;
        $componentUpsellSettings = 6;
        $useDefaultComponentUpsellSettings = 1;
        $useDefaultAccountPagesURL = 0;
        $accountPagesURL = '';
        $keyFileDataVersion = 1;
        $promoPanelOverrideMode = 0;
        $promoPanelOverrideStartDate = '';
        $promoPanelOverrideEndDate = '';
        $promoPanelOverideURL = '';
        $promoPanelOverrideHeight = 0;
        $promoPanelOveridePixelRatio = 1;
        $promoPanelOverrideHiDPICanToggle = 0;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($pGroupCode != '-')
            {
                $stmt = $dbObj->prepare('SELECT * FROM `LICENSEKEYS` WHERE (`groupcode` = ?)');
            }
            else if ($pID != '-')
            {
                $stmt = $dbObj->prepare('SELECT * FROM `LICENSEKEYS` WHERE (`id` = ?)');
            }
            else
            {
                if ($pPassword != '-')
                {
                    // perform a case sensitive search as this is a login
                    $stmt = $dbObj->prepare('SELECT * FROM `LICENSEKEYS` WHERE (`login` COLLATE utf8_bin = ?) AND (`password` = ?)');
                }
                else
                {
                    // perform a case insensitive search as this is used to check for duplicate logins
                    $stmt = $dbObj->prepare('SELECT * FROM `LICENSEKEYS` WHERE (`login` = ?)');
                }
            }

            if ($stmt)
            {
                if ($pGroupCode != '-')
                {
                    $bindOK = $stmt->bind_param('s', $pGroupCode);
                }
                else if ($pID != '-')
                {
                    $bindOK = $stmt->bind_param('i', $pID);
                }
                else
                {
                    if ($pPassword != '-')
                    {
                        $bindOK = $stmt->bind_param('ss', $pLogin, $pPassword);
                    }
                    else
                    {
                        $bindOK = $stmt->bind_param('s', $pLogin);
                    }
                }

                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($recordID, $dateCreated, $companyCode, $groupCode, $companyName, $address1, $address2, $address3,
                                    $address4, $city, $county, $state, $regionCode, $region, $postCode, $countryCode, $countryName,
                                    $telephoneNumber, $emailAddress, $contactFirstName, $contactLastName, $canCreateAccounts,
                                    $useAddressForBilling, $useAddressForShipping, $canModifyShippingAddress, $canModifyBillingAddress,
                                    $canModifyShippingContactDetails, $userEmailDestination, $orderFromPreview, $showPricesWithTax,
                                    $showTaxBreakdown, $showZeroTax, $showAlwaysTaxTotal, $login, $password, $keyFileName, $keyFileNameVersion,
                                    $keyFileSize, $keyFileChecksum, $keyUpdatePriority, $webBrandCode, $licenceKeyUseDefaultCurrency,
                                    $licenceKeyCurrencyCode, $taxCode, $shippingTaxCode, $registeredTaxNumberType, $registeredTaxNumber,
                                    $useDefaultPaymentMethods, $paymentMethods, $designerSplashScreenAssetID,
                                    $designerSplashScreenStartDate, $designerSplashScreenEndDate, $designerBannerAssetID,
                                    $designerBannerStartDate, $designerBannerEndDate, $onlineDesignerGuestWorkFlowMode, $maxOrderBatchSize, $isActive,
                                    $availableOnline, $cacheVersion, $imageScalingBefore, $imageScalingBeforeEnabled, $useDefaultImageScalingBefore,
                                    $imageScalingAfter, $imageScalingAfterEnabled, $useDefaultImageScalingAfter,
                                    $shuffleLayout, $showShuffleLayoutOptions, $useDefaultShuffleLayout, $onlineEditorMode, $enableSwitchingEditor,
									$useDefaultOnlineEditorMode, $onlineDesignerLogoLinkURL, $useDefaultOnlineDesignerLogoLinkURL,
									$onlineDesignerLogoLinkTooltip, $useDefaultVoucherSettings,	$allowVouchers, $allowGiftCards,
									$useDefaultSizeAndPositionSettings, $sizeAndPositionMeasurementUnits,
									$smartGuidesEnable, $smartGuidesObjectGuideColour, $smartGuidesPageGuideColour, $useDefaultSmartGuidesSettings,
									$useDefaultAutomaticallyApplyPerfectlyClear, $automaticallyApplyPerfectlyClear, $allowUsersToTogglePerfectlyClear,
                                    $useDefaultInsertDeleteButtonsVisibility, $insertDeleteButtonsVisibility, $useDefaultTotalPagesDropdownMode, $totalPagesDropdownMode,
                                    $useDefaultAveragePicturesPerPage, $averagePicturesPerPage, $useDefaultComponentUpsellSettings, $componentUpsellSettings,
                                    $useDefaultAccountPagesURL, $accountPagesURL, $keyFileDataVersion, $promoPanelOverrideMode, $promoPanelOverrideStartDate,
                                    $promoPanelOverrideEndDate, $promoPanelOverideURL, $promoPanelOverrideHeight, $promoPanelOveridePixelRatio,
                                    $promoPanelOverrideHiDPICanToggle))
                                {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching account
                                            $result = 'str_ErrorNoAccount';
                                        }
                                        else
                                        {
                                            // if the address needs updating, try and match region to get a region code
                                            // unlike USERS, LICENSEKEYS has no 'addressupdated' field
                                            // use 'regionCode' field to see if address has been updated
                                            if (($countryCode != '') && ($regionCode == ''))
                                            {
                                                // first see if state or county is actually region code,
                                                // i.e. the customer has entered 'CA' and not 'California'
                                                $match = UtilsAddressObj::getRegionCodeFromCode($countryCode, $state, $county);

                                                // if no match found, try to match the region name
                                                if ($match['regioncode'] == '')
                                                {
                                                    $match = UtilsAddressObj::getRegionCodeFromName($countryCode, $state, $county);
                                                }
                                                // if region is STATE,  $match[regioncode] holds state code
                                                // if region is COUNTY, $match[regioncode] holds county code
                                                $regionCode = $match['regioncode'];
                                                $region = $match['region'];

                                                if ($regionCode != '')
                                                {
                                                    if ($region == 'STATE')
                                                    {
                                                        $state = $match['regionname'];
                                                    }
                                                    else
                                                    {
                                                        $county = $match['regionname'];
                                                    }
                                                }
                                            }
                                        }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'getlicensekey bind result ' . $dbObj->error;
                                }
                            }
                            else
                            {
                                // no matching account
                                $result = 'str_ErrorNoAccount';
                            }
                        }
                        else
                        {
                            // could not store result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getlicensekey store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'getlicensekey execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'getlicensekey bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getlicensekey prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getlicensekey connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['companyCode'] = $companyCode;
