    static function getLicenseKeyFromID($pID)
    {
        // return an array containing the license key for the specified license key record id

        return self::getLicenseKey('-', '-', $pID, '-');
    }

    static function getLicenseKeyFromCode($pGroupCode)
    {
        // return an array containing the license key for the specified license key code

        return self::getLicenseKey('-', '-', '-', $pGroupCode);
    }

    static function getLicenseKeyFromLoginAndPassword($pLogin, $pPassword)
    {
        // return an array containing the license key for the specified license key login and password

        return self::getLicenseKey($pLogin, $pPassword, '-', '-');
    }

    static function getLicenseKeyFromLogin($pLogin)
    {
        // return an array containing the license key for the specified license key login

        return self::getLicenseKey($pLogin, '-', '-', '-');
    }

    static function getLicenseKeysList($companyCode = '', $brandCode = '', $userPage = 0)
    {
        // return an array containing the TAOPIX web brandings
        // replace payment methods with settings from constants if usedefaultpaymentmethods is true

        $licenseList = Array();

        global $gSession;

        if ($gSession['userdata']['companycode'] != '')
		{
			$companyCode = $gSession['userdata']['companycode'];
		}

		$whereOptions = array();
		$bindString = '';
		$whereValues = array();

		$baseSql = 'SELECT `groupcode`, `name`, `availableonline` FROM `LICENSEKEYS`';

		if ($companyCode !== '')
		{
			if ($userPage == 1)
			{
				$whereOptions[] = '(`companycode` = ?)';
			}
			else
			{
				$whereOptions[] = '(`companycode` = ? OR `companycode` = "")';
			}

			$bindString .= 's';
			$whereValues[] = $companyCode;
		}

		if ($brandCode !== '' || $gSession['userdata']['usertype'] === TPX_LOGIN_BRAND_OWNER)
		{
			$whereOptions[] = '`webbrandcode` = ?';
			$bindString .= 's';
			$whereValues[] = $brandCode;
		}

		if ($whereOptions !== array())
		{
			$baseSql .= ' WHERE ' . join(' AND ', $whereOptions);
		}
		$baseSql .= ' ORDER BY `groupcode`';

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
			if ($stmt = $dbObj->prepare($baseSql))
			{
				$stmt->bind_result($groupCode, $groupName, $active);
			}

			if ($whereOptions !== array())
			{
				// bind search criteria
				$bindOk = self::bindParams($stmt, $bindString, $whereValues);
			}

            if ($stmt->execute())
            {
                while ($stmt->fetch())
                {
                    $licenseItem['id'] = $groupCode;
                    $licenseItem['name'] = $groupName;
                    $licenseItem['active'] = $active;

                    $licenseList[] = $licenseItem;
                }
            }
            $stmt->free_result();
            $stmt->close();
        }
        $dbObj->close();

        return $licenseList;
    }

    static function getBrandLicenseKeyCodes($brandCode = '')
    {
        // return an array containing the TAOPIX groupcodes for the specified brand

        $licenseList = Array();
		$groupCode = '';
		$groupName = '';
		$active = 0;

		$dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            // let SQL do the work and replace payment methods with settings from constants if usedefaultpaymentmethods is true
           if (($stmt = $dbObj->prepare('SELECT `groupcode`, `name`, `availableonline` FROM `LICENSEKEYS` WHERE `webbrandcode` = ? ORDER BY `groupcode`'))
				   && ($stmt->bind_param('s', $brandCode)))
			{
				if ($stmt->bind_result($groupCode, $groupName, $active))
				{
					if ($stmt->execute())
					{
						while ($stmt->fetch())
						{
							$licenseItem['id'] = $groupCode;
							$licenseItem['name'] = $groupName;
							$licenseItem['active'] = $active;

							$licenseList[] = $licenseItem;
						}
					}
					$stmt->free_result();
					$stmt->close();
				}
            }
        }
        $dbObj->close();


        return $licenseList;
    }

