                    $parameter = $pID;
                }
                else
                {
                    $column = 'code';
                    $type = 's';
                    $parameter = $pProductCode;
                }

                $stmt = $dbObj->prepare('SELECT * FROM `PRODUCTS` WHERE `' . $column . '` = ?');

                if ($stmt)
                {
                    if ($stmt->bind_param($type, $parameter))
