                                                    $minimumPrintsPerProject, $usedefaultimagescalingbefore, $imagescalingbeforeenabled, $imagescalingbefore,
                                                    $useDefaultAveragePicturesPerPage, $averagePicturesPerPage, $retroPrints,
                                                    $isActive, $isDeleted))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching product
                                            $result = 'str_InvalidProductCode';
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getProduct bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no matching product
                                    $result = 'str_InvalidProductCode';
                                }
                            }
                            else
                            {
                                $result = 'str_DatabaseError';
                                $resultParam = 'getProduct store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getProduct execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getProduct bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getProduct prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
