        $resultArray['pricetransformationstage'] = $priceTransformationStage;
        $resultArray['minimumprintsperproject'] = $minimumPrintsPerProject;
        $resultArray['usedefaultimagescalingbefore'] = $usedefaultimagescalingbefore;
        $resultArray['imagescalingbeforeenabled'] = $imagescalingbeforeenabled;
        $resultArray['imagescalingbefore'] = $imagescalingbefore;
        $resultArray['productpagewidth'] = $productPageWidth;
        $resultArray['productpageheight'] = $productPageHeight;
        $resultArray['usedefaultaveragepicturesperpage'] = $useDefaultAveragePicturesPerPage;
        $resultArray['averagepicturesperpage'] = $averagePicturesPerPage;
        $resultArray['retroprints'] = $retroPrints;

        return $resultArray;
    }

