    static function getProductCollectionFromCode($pProductCollectionCode)
    {
        $resultArray = Array();

        $result = '';
        $resultParam = '';
        $recordID = 0;
        $dateCreated = '';
        $productCollectionCode = '';
        $productCollectionName = '';
        $productCollectionDescription = '';
        $isActive = 0;
        $isDeleted = 0;

        if ($pProductCollectionCode != '')
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                $stmt = $dbObj->prepare('SELECT `id`, `datecreated`, `ref`, `name`, `description`, `active`, `deleted`
                                            FROM `APPLICATIONFILES`
                                            WHERE (`ref` = ?)
                                                AND (`type` = 0)');
                if ($stmt)
                {
                    if ($stmt->bind_param('s', $pProductCollectionCode))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($recordID, $dateCreated, $productCollectionCode, $productCollectionName,
                                                    $productCollectionDescription, $isActive, $isDeleted))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching product collection
                                            $result = 'str_InvalidProductCode';
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getProductCollectionFromCode bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no matching product collection
                                    $result = 'str_InvalidProductCode';
                                }
                            }
                            else
                            {
                                $result = 'str_DatabaseError';
                                $resultParam = 'getProductCollectionFromCode store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getProductCollectionFromCode execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getProductCollectionFromCode bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getProductCollectionFromCode prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
                // could not open database connection
                $result = 'str_DatabaseError';
                $resultParam = 'getProductCollectionFromCode connect ' . $dbObj->error;
            }
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['code'] = $productCollectionCode;
        $resultArray['name'] = $productCollectionName;
        $resultArray['description'] = $productCollectionDescription;
        $resultArray['isactive'] = $isActive;
        $resultArray['deleted'] = $isDeleted;

        return $resultArray;
    }

