    static function getShippingMethodFromCode($pShippingMethodCode)
    {
        // return an array containing the shipping method data

        $shippingMethodID = 0;
        $shippingMethodCode = '';
        $shippingMethodName = '';
        $requiresDelivery = 0;
        $orderValueType = 0;
        $orderMinimumValue = 0;
        $orderMaximumValue = 0;
        $orderValueIncludesDiscount = 0;
        $isDefault = 0;
        $collectFromStore = 0;
        $siteGroupLabel = '';
        $allowGroupingByStoreGroupName = 0;
        $allowGroupingByCountry = 1;
        $allowGroupingByRegion = 1;
		$showStoreListOnOpen = 1;
        $assetid = 0;
        $useDefaultShippingAddress = 0;
        $useDefaultBillingAddress = 0;

        $shippingMethodItem = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $stmt = $dbObj->prepare('SELECT `id`, `code`, `name`, `usedefaultbillingaddress`, `usedefaultshippingaddress`,
                                        `requiresdelivery`, `ordervaluetype`, `orderminimumvalue`, `ordermaximumvalue`,
					        			`ordervalueincludesdiscount`, `default`, `collectfromstore`, `sitegrouplabel`,
					        			`allowgroupingbystoregroupname`, `allowgroupingbycountry`, `allowgroupingbyregion`,
                                        `showstorelistonopen`, `assetid`
                                    FROM `SHIPPINGMETHODS`
                                    WHERE `code` = ?');
            if ($stmt)
            {
                if ($stmt->bind_param('s', $pShippingMethodCode))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($shippingMethodID, $shippingMethodCode, $shippingMethodName,
                                                $useDefaultBillingAddress, $useDefaultShippingAddress, $requiresDelivery, $orderValueType,
                                                $orderMinimumValue, $orderMaximumValue, $orderValueIncludesDiscount, $isDefault,
                                                $collectFromStore, $siteGroupLabel, $allowGroupingByStoreGroupName, $allowGroupingByCountry,
                                                $allowGroupingByRegion, $showStoreListOnOpen , $assetid))
                                {
                                    $stmt->fetch();
                                }
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        $shippingMethodItem['id'] = $shippingMethodID;
        $shippingMethodItem['code'] = $shippingMethodCode;
        $shippingMethodItem['name'] = $shippingMethodName;
        $shippingMethodItem['usedefaultbillingaddress'] = $useDefaultBillingAddress;
        $shippingMethodItem['usedefaultshippingaddress'] = $useDefaultShippingAddress;
        $shippingMethodItem['requiresdelivery'] = $requiresDelivery;
        $shippingMethodItem['ordervaluetype'] = $orderValueType;
        $shippingMethodItem['orderminimumvalue'] = $orderMinimumValue;
        $shippingMethodItem['ordermaximumvalue'] = $orderMaximumValue;
        $shippingMethodItem['ordervalueincludesdiscount'] = $orderValueIncludesDiscount;
        $shippingMethodItem['isdefault'] = $isDefault;
        $shippingMethodItem['collectfromstore'] = $collectFromStore;
        $shippingMethodItem['sitegrouplabel'] = $siteGroupLabel;
        $shippingMethodItem['allowgroupingbystoregroupname'] = $allowGroupingByStoreGroupName;
        $shippingMethodItem['allowgroupingbycountry'] = $allowGroupingByCountry;
        $shippingMethodItem['allowgroupingbyregion'] = $allowGroupingByRegion;
		$shippingMethodItem['showstorelistonopen'] = $showStoreListOnOpen;
        $shippingMethodItem['assetid'] = $assetid;

        return $shippingMethodItem;
    }

    static function getShippingMethodsList()
    {
        // return an array containing the TAOPIX shipping methods

