    static function getShippingZonesList($pOrderBy)
    {
        // return an array containing the TAOPIX shipping zones
        global $gSession;

        $shippingZonesList = Array();

        $dbObj = self::getGlobalDBConnection();

		// If order by is not set, use companycode and code by default
		if ($pOrderBy == '')
		{
			$pOrderBy = 'ORDER BY `companycode`, `code`';
		}

        if ($dbObj)
        {
            switch ($gSession['userdata']['usertype'])
            {
                case TPX_LOGIN_SYSTEM_ADMIN:
					$stmt = $dbObj->prepare('SELECT `id`, `companycode`, `code`,`localcode`, `name`, `countrycodes` FROM `SHIPPINGZONES` ' . $pOrderBy);
					$bindOK = true;
                    break;
                case TPX_LOGIN_COMPANY_ADMIN:
