                if ($bindOK)
                {
                    if ($stmt->bind_result($shippingZoneID, $shippingZoneCompanyCode, $shippingZoneCode, $shippingZoneLocalCode,
                                    $shippingZoneName, $countryCodes))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $shippingZoneItem['id'] = $shippingZoneID;
                                $shippingZoneItem['companycode'] = $shippingZoneCompanyCode;
                                $shippingZoneItem['code'] = $shippingZoneLocalCode;
                                $shippingZoneItem['localcode'] = $shippingZoneLocalCode;
                                $shippingZoneItem['name'] = $shippingZoneName;
                                $shippingZoneItem['countrycodes'] = $countryCodes;
                                $shippingZonesList[] = $shippingZoneItem;
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $shippingZonesList;
    }

