    static function shippingRateStringToArray($pShippingRateString)
    {
        // return an array containing the exploded shipping rate data
        // the shipping rate string data is in the format 'startweight-endweight-shippingcost-shippingsell'
        $result = Array();
        $shippingRateList = explode(' ', $pShippingRateString);

        $rateCount = count($shippingRateList);

        for ($i = 0; $i < $rateCount; $i++)
        {
            $shippingRateItemList = explode('-', $shippingRateList[$i]);
            $shippingRateItem['start'] = $shippingRateItemList[0];
            $shippingRateItem['end'] = $shippingRateItemList[1];
            $shippingRateItem['cost'] = $shippingRateItemList[2];
            $shippingRateItem['sell'] = $shippingRateItemList[3];
            $shippingRateItem['ordervaluepercentage'] = $shippingRateItemList[4];

            $result[] = $shippingRateItem;
        }

        return $result;
    }

    static function getOrderShippingMethods($pProductCodes, $pProductDataArray, $pGroupCode, $pExchangeRate, $pCurrencyDecimalPlaces,
            $pOrderTotalWeight, $pOrderValueWithoutTaxNoDiscount, $pOrderValueWithTaxNoDiscount, $pOrderValueWithoutTax,
            $pOrderValueWithTax, $pShippingCountryCode, $pShippingRegionCode, $pBillingCountryCode, $pBillingRegionCode)
    {
        // return an array containing the shipping methods available for the order based on the supplied parameters
        global $gSession;
        global $gConstants;

        $orderShippingRatesList = Array();
        $orderDefaultShippingList = Array();
        $shippingMethodsToSkipList = Array();
        $shippingMethodsList = Array();
        $shippingRatesList = Array();
        $shippingRatesItem = Array();
        $shippingMethodProductCodeKeyList = Array();
        $shippingMethodMasterList = Array();
        $processedProductsAndMethodsList = Array();
        $processedMethodsList = Array();

        $productCount = count($pProductDataArray);

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT sr.companycode, sr.code, sr.shippingmethodcode, sr.shippingzonecode, sr.productcode, sr.info, sr.rate,
        	    sr.ordervaluetype, sr.orderminimumvalue, sr.ordermaximumvalue, sr.ordervalueincludesdiscount, sr.payinstoreallowed,
        	    sm.name, sm.usedefaultbillingaddress, sm.usedefaultshippingaddress, sm.canmodifycontactdetails, sm.requiresdelivery, sm.ordervaluetype, sm.orderminimumvalue, sm.ordermaximumvalue,
        	    sm.ordervalueincludesdiscount, sm.default, sm.collectfromstore, sz.countrycodes, sr. taxcode, IF (tr.rate IS NULL, "0.00", tr.rate),
				(SELECT `active` from `PAYMENTMETHODS` WHERE `code` = "PAYINSTORE")
        		FROM `SHIPPINGRATES` sr
        		LEFT JOIN `SHIPPINGMETHODS` sm ON sm.code = sr.shippingmethodcode
        		LEFT JOIN `SHIPPINGZONES` sz ON sz.code = sr.shippingzonecode
        		LEFT JOIN `TAXRATES` tr ON `sr`.`taxcode` = `tr`.`code`
        		WHERE (`sr`.`active` = 1)
        		AND ((sr.productcode = "") OR (sr.productcode IN (' . $pProductCodes . ')))
        		AND ((sr.groupcode = "") OR (sr.groupcode = ?))
        		AND ((sr.companycode = "") OR (sr.companycode = ?))
        		ORDER BY sr.companycode DESC, sr.productcode DESC, sr.groupcode DESC, sz.countrycodes DESC'))
            {
                if ($stmt->bind_param('ss', $pGroupCode, $gSession['userdata']['companycode']))
                {
                    $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);

                    if ($stmt->bind_result($shippingRateCompanyCode, $shippingRateCode, $shippingMethodCode, $shippingZoneCode,
                                    $shippingProductCode, $shippingInfo, $shippingRates, $shippingRateOrderValueType,
                                    $shippingRateOrderMinValue, $shippingRateOrderMaxValue, $shippingRateOrderValueIncludesDiscount,
                                    $payInStoreAllowed, $shippingMethodName, $useDefaultBillingAddress, $useDefaultShippingAddress,
                                    $canModifyContactDetails, $requiresDelivery, $shippingMethodOrderValueType,
                                    $shippingMethodOrderMinValue, $shippingMethodOrderMaxValue, $shippingMethodOrderValueIncludesDiscount,
                                    $isDefault, $collectFromStore, $countryCodes,
                                    $shippingRatePriceRecordTaxCode, $shippingRatePriceRecordTaxRate, $payInStoreIsActive))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                // before we can include this shipping rate make sure it's zone is valid for the order address
                                // this is to prevent problems on multi-line orders when some zones are valid and others are not
                                $includeRate = false;

                                if ($countryCodes != '')
                                {
                                    $theCodeList = explode(',', $countryCodes);
                                    $codeCount = count($theCodeList);
                                    for ($i = 0; $i < $codeCount; $i++)
                                    {
                                        // go off shipping address
                                        if ($collectFromStore == 0)
                                        {
                                            if (($theCodeList[$i] == $pShippingCountryCode) ||
                                                    ($theCodeList[$i] == $pShippingCountryCode . '_' . $pShippingRegionCode))
                                            {
                                                $includeRate = true;
                                                break;
                                            }
                                        }
                                        else
                                        {
                                            // if Collect From Store go off billing address
                                            if (($theCodeList[$i] == $pBillingCountryCode) ||
                                                    ($theCodeList[$i] == $pBillingCountryCode . '_' . $pBillingRegionCode))
                                            {
                                                $includeRate = true;
                                                break;
                                            }
                                        }
                                    }
                                }
                                else
                                {
                                    // we have a 'rest of world'
                                    $includeRate = true;
                                }

                                // if the zone data is valid include the rate in the list we wish to process
                                if ($includeRate)
                                {
                                    $shippingRatesItem = Array();
                                    $shippingRatesItem['shippingratecompanycode'] = $shippingRateCompanyCode;
                                    $shippingRatesItem['shippingratecode'] = $shippingRateCode;
                                    $shippingRatesItem['shippingmethodcode'] = $shippingMethodCode;
                                    $shippingRatesItem['shippingzonecode'] = $shippingZoneCode;
                                    $shippingRatesItem['shippingrateproductcode'] = $shippingProductCode;
                                    $shippingRatesItem['shippingrateinfo'] = $shippingInfo;
                                    $shippingRatesItem['shippingrates'] = $shippingRates;
                                    $shippingRatesItem['shippingrateordervaluetype'] = $shippingRateOrderValueType;
                                    $shippingRatesItem['shippingrateorderminvalue'] = $shippingRateOrderMinValue;
                                    $shippingRatesItem['shippingrateordermaxvalue'] = $shippingRateOrderMaxValue;
                                    $shippingRatesItem['shippingrateordervalueincludesdiscount'] = $shippingRateOrderValueIncludesDiscount;
                                    $shippingRatesItem['shippingratepayinstoreallowed'] = $payInStoreAllowed;
                                    $shippingRatesItem['shippingmethodname'] = $shippingMethodName;
                                    $shippingRatesItem['shippingmethodusedefaultbillingaddress'] = $useDefaultBillingAddress;
                                    $shippingRatesItem['shippingmethodusedefaultshippingaddress'] = $useDefaultShippingAddress;
                                    $shippingRatesItem['shippingmethodcanmodifycontactdetails'] = $canModifyContactDetails;
                                    $shippingRatesItem['shippingmethodrequiresdelivery'] = $requiresDelivery;
                                    $shippingRatesItem['shippingmethodordervaluetype'] = $shippingMethodOrderValueType;
                                    $shippingRatesItem['shippingmethodorderminvalue'] = $shippingMethodOrderMinValue;
                                    $shippingRatesItem['shippingmethodordermaxvalue'] = $shippingMethodOrderMaxValue;
                                    $shippingRatesItem['shippingmethodordervalueincludesdiscount'] = $shippingMethodOrderValueIncludesDiscount;
                                    $shippingRatesItem['shippingmethodisdefault'] = $isDefault;
                                    $shippingRatesItem['shippingmethodcollectfromstore'] = $collectFromStore;
                                    $shippingRatesItem['shippingzonescountrycodes'] = $countryCodes;
                                    $shippingRatesItem['payinstoreactive'] = $payInStoreIsActive;
                                    $shippingRatesItem['cost'] = 0.00;
                                    $shippingRatesItem['sell'] = 0.00;
                                    $shippingRatesItem['ordervaluepercentage'] = 0.00;
                                    $shippingRatesItem['productcount'] = 0;
                                    $shippingRatesItem['taxcode'] = $shippingRatePriceRecordTaxCode;
                                    $shippingRatesItem['taxrate'] = $shippingRatePriceRecordTaxRate;

                                    $shippingRatesList[] = $shippingRatesItem;

                                    $shippingMethodsList[$shippingMethodCode] = true;

                                    $shippingMethodProductCodeKeyList[$shippingProductCode . '_' . $shippingMethodCode] = true;
                                }
                            }


                            // process the shipping rates we have found
                            // the results are sorted so that rates for a company will be before global,
                            // products will be before 'any product',
                            // license keys will be before any license key
                            // and country lists will be before 'rest of world'
                            $shippingRateCount = count($shippingRatesList);
                            for ($i = 0; $i < $shippingRateCount; $i++)
                            {
                                $shippingRatesItem = $shippingRatesList[$i];

                                $processRate = true;

                                $shippingMethodCode = $shippingRatesItem['shippingmethodcode'];
                                $shippingRateProductCode = $shippingRatesItem['shippingrateproductcode'];


                                // first make sure that we have not added this product code and shipping method code combination for the shipping rate company
                                $productCodeAndShippingMethodCode = $shippingRatesItem['shippingratecompanycode'] . '.' . $shippingRateProductCode . '_' . $shippingMethodCode;
                                if (!array_key_exists($productCodeAndShippingMethodCode, $processedProductsAndMethodsList))
                                {
                                    if ($shippingRateProductCode != '')
                                    {
                                        // we are going to be testing using a product code so make sure we have not already processed this rate for any product
                                        if (array_key_exists('_' . $shippingMethodCode, $processedProductsAndMethodsList))
                                        {
                                            // the combination already exists so do not process it
                                            $processRate = false;
                                        }
                                    }
                                    else
                                    {
                                        // we are going to be testing for any product code so make sure we have not already processed this rate for a product
                                        if (array_key_exists($shippingMethodCode, $processedMethodsList))
                                        {
                                            // the combination already exists so do not process it
                                            $processRate = false;
                                        }
                                    }
                                }
                                else
                                {
                                    // the combination already exists so do not process it
                                    $processRate = false;
                                }


                                // now make sure the shipping rate supports the products we have
                                if ($processRate)
                                {
                                    // if the shipping rate is for a specific product then we need to check that the shipping method for the rate is available for all products
                                    // this allows shipping rates that do not cover all products to be ignored
                                    if ($shippingRateProductCode != '')
                                    {
                                        foreach ($pProductDataArray as $cartProductCode => $value)
                                        {
                                            if (!array_key_exists($cartProductCode . '_' . $shippingMethodCode,
                                                            $shippingMethodProductCodeKeyList))
                                            {
                                                $processRate = false;
                                                break;
                                            }
                                        }
                                    }


                                    // if we can still process the shipping rate we now need to make sure that
                                    // a) the payment method is valid for collect from store
                                    // b) the shipping rate order value is in range
                                    // if none of these are valid then we skip the rate rather than the entire shipping method
                                    if ($processRate)
                                    {
                                        // calculate the order values taking the exchange rate into account
                                        $shippingMethodOrderMinValue = UtilsObj::bround($shippingRatesItem['shippingmethodorderminvalue'] * $pExchangeRate,
                                                        $pCurrencyDecimalPlaces);
                                        $shippingMethodOrderMaxValue = UtilsObj::bround($shippingRatesItem['shippingmethodordermaxvalue'] * $pExchangeRate,
                                                        $pCurrencyDecimalPlaces);
                                        $shippingRateOrderMinValue = UtilsObj::bround($shippingRatesItem['shippingrateorderminvalue'] * $pExchangeRate,
                                                        $pCurrencyDecimalPlaces);
                                        $shippingRateOrderMaxValue = UtilsObj::bround($shippingRatesItem['shippingrateordermaxvalue'] * $pExchangeRate,
                                                        $pCurrencyDecimalPlaces);

                                        foreach ($pProductDataArray as $cartProductCode => $value)
                                        {
                                            if (($shippingRateProductCode == $cartProductCode) || ($shippingRateProductCode == ''))
                                            {
                                                // if the shipping method order value is in range and the shipping method is Collect From Store
                                                // make sure the PAYINSTORE payment method is available if payinstoreallowed is TPX_PAY_IN_STORE_ONLY
                                                if (($shippingRatesItem['shippingmethodcollectfromstore'] == 1) && ($shippingRatesItem['shippingratepayinstoreallowed'] == TPX_PAY_IN_STORE_ONLY))
                                                {
                                                    // is PAYINSTORE in the user's payment methods?
                                                    if (strpos($gSession['userpaymentmethods'], 'PAYINSTORE') === false)
                                                    {
                                                        // the payment method is not available so skip the rate
                                                        $processRate = false;
                                                        break;
                                                    }
                                                    else
                                                    {
                                                        // the payment method is available but skip the rate if the store is not active
                                                        if ($payInStoreIsActive == 0)
                                                        {
                                                            $processRate = false;
                                                            break;
                                                        }
                                                    }
                                                }


                                                // if we have reached this point then the payment method is valid
                                                // now make sure that the shipping rate order value is within range
                                                if ($shippingRatesItem['shippingrateordervaluetype'] != '')
                                                {
                                                    if ($shippingRateProductCode == '')
                                                    {
                                                        if ($shippingRatesItem['shippingrateordervalueincludesdiscount'] == 1)
                                                        {
                                                            $valueWithoutTax = $pOrderValueWithoutTax;
                                                            $valueWithTax = $pOrderValueWithTax;
                                                        }
                                                        else
                                                        {
                                                            $valueWithoutTax = $pOrderValueWithoutTaxNoDiscount;
                                                            $valueWithTax = $pOrderValueWithTaxNoDiscount;
                                                        }
                                                    }
                                                    else
                                                    {
                                                        if ($shippingRatesItem['shippingrateordervalueincludesdiscount'] == 1)
                                                        {
                                                            $valueWithoutTax = $pProductDataArray[$cartProductCode]['itemtotalsellnotaxalldiscounted'];
                                                            $valueWithTax = $pProductDataArray[$cartProductCode]['itemtotalsellwithtaxalldiscounted'];
                                                        }
                                                        else
                                                        {
                                                            $valueWithoutTax = $pProductDataArray[$cartProductCode]['itemtotalsellnotaxnodiscount'];
                                                            $valueWithTax = $pProductDataArray[$cartProductCode]['itemtotalsellwithtaxnodiscount'];
                                                        }
                                                    }

                                                    if ($shippingRatesItem['shippingrateordervaluetype'] == 'WITHOUTTAX')
                                                    {
                                                        if (($shippingRatesItem['shippingrateorderminvalue'] > $valueWithoutTax) || ($shippingRatesItem['shippingrateordermaxvalue'] < $valueWithoutTax))
                                                        {
                                                            // the total is not in range so we must exclude this shipping rate
                                                            $processRate = false;
                                                            break;
                                                        }
                                                    }
                                                    elseif ($shippingRatesItem['shippingrateordervaluetype'] == 'WITHTAX')
                                                    {
                                                        if (($shippingRatesItem['shippingrateorderminvalue'] > $valueWithTax) || ($shippingRatesItem['shippingrateordermaxvalue'] < $valueWithTax))
                                                        {
                                                            // the total is not in range so we must exclude this shipping rate
                                                            $processRate = false;
                                                            break;
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                                else
                                {
                                    $processRate = false;
                                }


                                // if we can still process the rate finally check to see if this is a shipping method we need to ignore
                                // this is done last as the list may be manipulated earlier on
                                if (in_array($shippingMethodCode, $shippingMethodsToSkipList))
                                {
                                    $processRate = false;
                                }


                                // at this point we will either be processing the rate or not
                                // if validation fails after this point then the shipping method should be ignored altogether
                                if ($processRate == true)
                                {
                                    $addItem = true;
                                    $processedValidProducts = false;

                                    // we must check that the products this rate applies to is valid for all products it applies to
                                    foreach ($pProductDataArray as $cartProductCode => $value)
                                    {
                                        if (($shippingRateProductCode == $cartProductCode) || ($shippingRateProductCode == ''))
                                        {
                                            // check to make sure that the shipping method isn't excluded due to the order total
                                            if ($shippingRatesItem['shippingmethodordervaluetype'] != '')
                                            {
                                                if ($shippingRateProductCode == '')
                                                {
                                                    if ($shippingRatesItem['shippingmethodordervalueincludesdiscount'] == 1)
                                                    {
                                                        $valueWithoutTax = $pOrderValueWithoutTax;
                                                        $valueWithTax = $pOrderValueWithTax;
                                                    }
                                                    else
                                                    {
                                                        $valueWithoutTax = $pOrderValueWithoutTaxNoDiscount;
                                                        $valueWithTax = $pOrderValueWithTaxNoDiscount;
                                                    }
                                                }
                                                else
                                                {
                                                    if ($shippingRatesItem['shippingmethodordervalueincludesdiscount'] == 1)
                                                    {
                                                        $valueWithoutTax = $pProductDataArray[$cartProductCode]['itemtotalsellnotaxalldiscounted'];
                                                        $valueWithTax = $pProductDataArray[$cartProductCode]['itemtotalsellwithtaxalldiscounted'];
                                                    }
                                                    else
                                                    {
                                                        $valueWithoutTax = $pProductDataArray[$cartProductCode]['itemtotalsellnotaxnodiscount'];
                                                        $valueWithTax = $pProductDataArray[$cartProductCode]['itemtotalsellwithtaxnodiscount'];
                                                    }
                                                }

                                                if ($shippingRatesItem['shippingmethodordervaluetype'] == 'WITHOUTTAX')
                                                {
                                                    if (($shippingRatesItem['shippingmethodorderminvalue'] > $valueWithoutTax) || ($shippingRatesItem['shippingmethodordermaxvalue'] < $valueWithoutTax))
                                                    {
                                                        // the total is not in range so we must exclude this shipping method
                                                        $addItem = false;
                                                    }
                                                }
                                                elseif ($shippingRatesItem['shippingmethodordervaluetype'] == 'WITHTAX')
                                                {
                                                    if (($shippingRatesItem['shippingmethodorderminvalue'] > $valueWithTax) || ($shippingRatesItem['shippingmethodordermaxvalue'] < $valueWithTax))
                                                    {
                                                        // the total is not in range so we must exclude this shipping method
                                                        $addItem = false;
                                                    }
                                                }
                                            }


                                            // if the order value is in range continue the validation
                                            if ($addItem == true)
                                            {
                                                $addItem = false;
                                                $processedValidProducts = true;

                                                // attempt to find a match for the weight
                                                // if the rate is for a specific product then we use the total weight for that product which will exclude order footer components
                                                // if the rate is for any product then we use the total order weight including order footer components

                                                $shippingRateItemList = self::shippingRateStringToArray($shippingRatesItem['shippingrates']);
                                                $rateItemCount = count($shippingRateItemList);
                                                for ($i2 = 0; $i2 < $rateItemCount; $i2++)
                                                {
                                                    $shippingRateItem = $shippingRateItemList[$i2];

                                                    $rangeStart = $shippingRateItem['start'];
                                                    $rangeEnd = $shippingRateItem['end'];

                                                    if ($shippingRateProductCode == '')
                                                    {
                                                        $weight = $pOrderTotalWeight;
                                                    }
                                                    else
                                                    {
                                                        $weight = $pProductDataArray[$cartProductCode]['itemtotalweight'];
                                                    }

                                                    if (($weight >= $rangeStart) && ($weight <= $rangeEnd))
                                                    {
                                                        // the weight is in range so we can exit the loop
                                                        $addItem = true;
                                                        break;
                                                    }
                                                }

                                                // if we have not matched the weight then we do not check any other products
                                                if (!$addItem)
                                                {
                                                    break;
                                                }
                                            }
                                            else
                                            {
                                                // if the order value is not in range then we do not check any other products
                                                break;
                                            }
                                        }
                                    }


                                    // if we have matched the weight range add this item to our master list of shipping methods
                                    if (($addItem == true) && ($processedValidProducts == true))
                                    {
                                        if (array_key_exists($shippingMethodCode, $shippingMethodMasterList))
                                        {
                                            // we have already added this shipping method so just update it

                                            $tempItem = &$shippingMethodMasterList[$shippingMethodCode];
                                            $tempItem['cost'] += $shippingRateItem['cost'];
                                            $tempItem['sell'] += UtilsObj::bround($shippingRateItem['sell'] * $pExchangeRate,
                                                            $pCurrencyDecimalPlaces);
                                            $tempItem['ordervaluepercentage'] += $shippingRateItem['ordervaluepercentage'];

                                            // update the product count for the item
                                            if ($tempItem['shippingrateproductcode'] == '')
                                            {
                                                // this is for any product so just set the count to the number of products we have
                                                $tempItem['productcount'] = $productCount;

                                                // this rate covers all products so exclude the shipping method from any further tests
                                                $shippingMethodsToSkipList[] = $shippingMethodCode;
                                            }
                                            else
                                            {
                                                // this is for a specific product so increment the count
                                                $tempItem['productcount']++;

                                                // if the count has reached the number of products exclude the shipping method from any further tests
                                                if ($tempItem['productcount'] == $productCount)
                                                {
                                                    $shippingMethodsToSkipList[] = $shippingMethodCode;
                                                }
                                            }
                                        }
                                        else
                                        {
                                            // this is the first time for the shipping method so add it

                                            $shippingRatesItem['cost'] = $shippingRateItem['cost'];
                                            $shippingRatesItem['sell'] = UtilsObj::bround($shippingRateItem['sell'] * $pExchangeRate,
                                                            $pCurrencyDecimalPlaces);
                                            $shippingRatesItem['ordervaluepercentage'] = $shippingRateItem['ordervaluepercentage'];

                                            // update the product count for the item
                                            if ($shippingRateProductCode == '')
                                            {
                                                // this is for any product so just set the count to the number of products we have
                                                $shippingRatesItem['productcount'] = $productCount;

                                                // this rate covers all products so exclude the shipping method from any further tests
                                                $shippingMethodsToSkipList[] = $shippingMethodCode;
                                            }
                                            else
                                            {
                                                // this is for a specific product so initialise the count
                                                $shippingRatesItem['productcount'] = 1;

                                                // if the count has reached the number of products exclude the shipping method from any further tests
                                                if ($productCount == 1)
                                                {
                                                    $shippingMethodsToSkipList[] = $shippingMethodCode;
                                                }
                                            }

                                            $shippingMethodMasterList[$shippingMethodCode] = $shippingRatesItem;
                                        }

                                        // make sure we do not process this product code and shipping method code combination again
                                        $processedProductsAndMethodsList[$productCodeAndShippingMethodCode] = true;
                                        $processedMethodsList[$shippingMethodCode] = true;
                                    }
                                    else
                                    {
                                        // the validation failed so we need to remember this shipping method so that we can skip any other rates with the same shipping method
                                        $shippingMethodsToSkipList[] = $shippingMethodCode;
                                    }
                                }
                            }


                            // process the shipping methods list that we have created
                            $processedArrayCount = count($shippingMethodMasterList);
                            foreach ($shippingMethodMasterList as $shippingMethodMasterItem)
                            {
                                // before we accept this shipping method make sure that all products have been accounted for
                                if ($shippingMethodMasterItem['productcount'] == $productCount)
                                {
                                    $resetShippingMethod = false;

                                    // if the shipping method currently selected exists in the new list then we use that one as the default
                                    if (array_key_exists($shippingMethodMasterItem['shippingmethodcode'],
                                                    $gSession['shipping'][0]['shippingMethods']))
                                    {
                                        // make sure this shipping method code is the same as the one we have already selected
                                        if ($gSession['shipping'][0]['shippingmethodcode'] == $shippingMethodMasterItem['shippingmethodcode'])
                                        {
                                            $shippingMethodEntry = $gSession['shipping'][0]['shippingMethods'][$shippingMethodMasterItem['shippingmethodcode']];

                                            // if the shipping rate codes are different we need to make sure the collect from store selection is still okay
                                            if ($shippingMethodMasterItem['shippingratecode'] != $gSession['shipping'][0]['shippingratecode'])
                                            {
                                                if ($shippingMethodMasterItem['shippingmethodcollectfromstore'] == 1)
                                                {
                                                    if ($stmt2 = $dbObj->prepare('SELECT `s`.`id` FROM `SITES` s WHERE `s`.`sitegroup` IN
															(SELECT `sitegroupcode` FROM `SHIPPINGRATESITES` ss WHERE `ss`.`shippingratecode` = ?) AND (`s`.`code` = ?)'))
                                                    {
                                                        if ($stmt2->bind_param('ss', $shippingMethodMasterItem['shippingratecode'],
                                                                        $shippingMethodEntry['storeCode']))
                                                        {
                                                            if ($stmt2->bind_result($id))
                                                            {
                                                                if ($stmt2->execute())
                                                                {
                                                                    // if there are no records returned then the store selected is not available for that rate
                                                                    if (!$stmt2->fetch())
                                                                    {
                                                                        // we need to reset the storeid so that the user is prompted to select a store
                                                                        $gSession['shipping'][0]['storeid'] = '';
                                                                        $resetShippingMethod = true;
                                                                    }
                                                                }
                                                            }
                                                        }

                                                        $stmt2->free_result();
                                                        $stmt2->close();
                                                        $stmt2 = null;
                                                    }
                                                }
                                            }
                                        }
										else
										{
											// the shipping method currently selected is not this one so create an item containing its data
											$shippingMethodEntry = Array();
											$resetShippingMethod = true;
										}
                                    }
                                    else
                                    {
                                        // the shipping method currently selected is not this one so create an item containing its data
                                        $shippingMethodEntry = Array();
                                        $resetShippingMethod = true;
                                    }


                                    // reset the collect from store properties if required
                                    if ($resetShippingMethod)
                                    {
										Order_model::setShippingMethodDefaults($shippingMethodEntry);
                                        $gSession['shipping'][0]['shippingMethods'][$shippingMethodMasterItem['shippingmethodcode']] = $shippingMethodEntry;
                                    }

                                    // always copy the payinstoreallowed flag from the master item
                                    // this is needed as the currently selected shipping method may match the item being processed but the payinstoreallowed flags could be different
                                    $shippingMethodEntry['payInStoreAllowed'] = $shippingMethodMasterItem['shippingratepayinstoreallowed'];

                                    // if shipping method is CFS and uses an external script then run the script's initialize() function
                                    if ($shippingMethodMasterItem['shippingmethodcollectfromstore'] == 1)
                                    {
                                        Order_model::setCollectFromStoreValues($shippingMethodMasterItem['shippingmethodcode'], $shippingMethodMasterItem['shippingmethodname'], $shippingMethodEntry, $pGroupCode);
                                    }

                                    // if resetShippingMethod is true then we need to update the shippingMethods list
                                    if ($resetShippingMethod)
                                    {
                                        $gSession['shipping'][0]['shippingMethods'][$shippingMethodMasterItem['shippingmethodcode']] = $shippingMethodEntry;
                                    }

                                    $shippingRateItem = Array();
                                    $shippingRateItem['ratecode'] = $shippingMethodMasterItem['shippingratecode'];
                                    $shippingRateItem['zonecode'] = $shippingMethodMasterItem['shippingzonecode'];
                                    $shippingRateItem['methodcode'] = $shippingMethodMasterItem['shippingmethodcode'];
                                    $shippingRateItem['methodname'] = $shippingMethodMasterItem['shippingmethodname'];
                                    $shippingRateItem['info'] = $shippingMethodMasterItem['shippingrateinfo'];
                                    $shippingRateItem['usedefaultbillingaddress'] = $shippingMethodMasterItem['shippingmethodusedefaultbillingaddress'];
                                    $shippingRateItem['usedefaultshippingaddress'] = $shippingMethodMasterItem['shippingmethodusedefaultshippingaddress'];
                                    $shippingRateItem['canmodifycontactdetails'] = $shippingMethodMasterItem['shippingmethodcanmodifycontactdetails'];
                                    $shippingRateItem['requiresdelivery'] = $shippingMethodMasterItem['shippingmethodrequiresdelivery'];
                                    $shippingRateItem['isdefault'] = $shippingMethodMasterItem['shippingmethodisdefault'];
                                    $shippingRateItem['cost'] = $shippingMethodMasterItem['cost'];
                                    $shippingRateItem['payinstoreallowed'] = $shippingMethodMasterItem['shippingratepayinstoreallowed'];
                                    $shippingRateItem['orderminvalue'] = $shippingMethodMasterItem['shippingmethodorderminvalue'];
                                    $shippingRateItem['ordermaxvalue'] = $shippingMethodMasterItem['shippingmethodordermaxvalue'];

                                    if ($shippingMethodMasterItem['ordervaluepercentage'] > 0)
                                    {
                                        $shippingRateItem['sell'] = UtilsObj::bround($shippingMethodMasterItem['sell'] + ($gSession['order']['ordertotalitemsell'] * $shippingMethodMasterItem['ordervaluepercentage'] / 100),
                                                        $pCurrencyDecimalPlaces);
                                    }
                                    else
                                    {
                                        $shippingRateItem['sell'] = $shippingMethodMasterItem['sell'];
                                    }

                                    $shippingRateItem['taxcode'] = $shippingMethodMasterItem['taxcode'];
                                    $shippingRateItem['taxrate'] = $shippingMethodMasterItem['taxrate'];

                                    if ($shippingMethodMasterItem['shippingmethodisdefault'] == 1)
                                    {
                                        $orderDefaultShippingList[] = $shippingRateItem;
                                    }
                                    else
                                    {
                                        if (($shippingMethodMasterItem['shippingmethodcollectfromstore'] == 0) || ($gConstants['optioncfs'] == 1))
                                        {
                                            $orderShippingRatesList[] = $shippingRateItem;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
            }

            $dbObj->close();
        }

        usort($orderShippingRatesList, 'orderShippingRatesSort');

        $orderShippingRatesList = array_merge($orderDefaultShippingList, $orderShippingRatesList);

        return $orderShippingRatesList;
    }

    static function getSite($pID, $pSiteCode)
    {
        // return an array containing the site based on the supplied parameters
        $result = '';
        $resultParam = '';

        $recordID = 0;
        $dateCreated = '';
        $companyCode = '';
        $owner = '';
        $code = '';
        $productionSiteKey = '';
        $productionSiteType = 0;
        $acceptAllProducts = 0;
        $companyName = '';
        $address1 = '';
        $address2 = '';
        $address3 = '';
        $address4 = '';
        $city = '';
        $county = '';
        $state = '';
        $regionCode = '';
        $region = '';
        $postCode = '';
        $countryCode = '';
        $countryName = '';
        $locationLong = 0;
        $locationLat = 0;
        $telephoneNumber = '';
        $emailAddress = '';
        $contactFirstName = '';
        $contactLastName = '';
        $siteType = TPX_SITE_TYPE_PRODUCTION;
        $siteOnline = 0;
        $isExternalStore = 0;
        $siteGroup = '';
        $distributionCentreCode = '';
        $openingTimes = '';
        $storeURL = '';
        $smtpProductionAddress = '';
        $smtpProductionName = '';
        $isActive = 0;

        if ($pSiteCode != '')
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                if ($pID > 0)
                {
                    $stmt = $dbObj->prepare('SELECT * FROM `SITES` WHERE (`id` = ?)');
                }
                else
                {
                    $stmt = $dbObj->prepare('SELECT * FROM `SITES` WHERE (`code` = ?)');
                }

                if ($stmt)
                {
                    if ($pID > 0)
                    {
                        $bindOK = $stmt->bind_param('i', $pID);
                    }
                    else
                    {
                        $bindOK = $stmt->bind_param('s', $pSiteCode);
                    }

                    if ($bindOK)
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($recordID, $dateCreated, $companyCode, $owner, $code, $productionSiteKey,
                                                    $productionSiteType, $acceptAllProducts, $companyName, $address1, $address2, $address3,
                                                    $address4, $city, $county, $state, $regionCode, $region, $postCode, $countryCode,
                                                    $countryName, $locationLong, $locationLat, $telephoneNumber, $emailAddress,
                                                    $contactFirstName, $contactLastName, $siteType, $siteOnline, $isExternalStore,
                                                    $siteGroup, $distributionCentreCode, $openingTimes, $storeURL, $smtpProductionName,
                                                    $smtpProductionAddress, $isActive))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching site
                                            $result = 'str_InvalidSiteCode';
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getSite bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no matching site
                                    $result = 'str_InvalidSiteCode';
                                }
                            }
                            else
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'getSite store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getSite execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getSite bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getSite prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
                // could not open database connection
                $result = 'str_DatabaseError';
                $resultParam = 'getSite connect ' . $dbObj->error;
            }
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

        $resultArray['recordid'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['companycode'] = $companyCode;
        $resultArray['owner'] = $owner;
        $resultArray['code'] = $code;
        $resultArray['productionsitekey'] = $productionSiteKey;
        $resultArray['productionsitetype'] = $productionSiteType;
        $resultArray['acceptallproducts'] = $acceptAllProducts;
        $resultArray['companyname'] = $companyName;
        $resultArray['address1'] = $address1;
        $resultArray['address2'] = $address2;
        $resultArray['address3'] = $address3;
        $resultArray['address4'] = $address4;
        $resultArray['city'] = $city;
        $resultArray['county'] = $county;
        $resultArray['state'] = $state;
        $resultArray['regioncode'] = $regionCode;
        $resultArray['region'] = $region;
        $resultArray['postcode'] = $postCode;
        $resultArray['countrycode'] = $countryCode;
        $resultArray['countryname'] = $countryName;
        $resultArray['locationlong'] = $locationLong;
        $resultArray['locationlat'] = $locationLat;
        $resultArray['telephonenumber'] = $telephoneNumber;
        $resultArray['emailaddress'] = $emailAddress;
        $resultArray['contactfirstname'] = $contactFirstName;
        $resultArray['contactlastname'] = $contactLastName;
        $resultArray['sitetype'] = $siteType;
        $resultArray['siteonline'] = $siteOnline;
        $resultArray['isexternalstore'] = $isExternalStore;
        $resultArray['sitegroup'] = $siteGroup;
        $resultArray['distributioncentrecode'] = $distributionCentreCode;
        $resultArray['openingtimes'] = $openingTimes;
        $resultArray['storeurl'] = $storeURL;
        $resultArray['smtpproductionname'] = $smtpProductionName;
        $resultArray['smtpproductionaddress'] = $smtpProductionAddress;
        $resultArray['isactive'] = $isActive;

        return $resultArray;
    }

    static function getSiteFromCode($pCode)
    {
        // return an array containing the site for the specified site code

        return self::getSite(0, $pCode);
    }

    static function getSiteFromID($pID)
    {
        // return an array containing the site for the specified site record id

        return self::getSite($pID, '-');
    }

    /**
     * Gets list of site groups.
     *
     * @since Version 3.0.0
     * @version 3.0.0
     * @author Steffen Haugk
     * @return array
     */
    static function getSiteGroupList()
    {
        $siteGroupList = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `id`, `code`, `name` FROM `SITEGROUPS` ORDER BY `code`'))
            {
                if ($stmt->bind_result($siteGroupID, $siteGroupCode, $siteGroupName))
                {
                    if ($stmt->execute())
                    {
                        while ($stmt->fetch())
                        {
                            $item['id'] = $siteGroupID;
                            $item['code'] = $siteGroupCode;
                            $item['name'] = $siteGroupName;

                            $siteGroupList[] = $item;
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $siteGroupList;
    }

    /**
     * Return section information.
     *
     * @since Version 3.0.0
     * @version 3.0.0
     * @author Steffen Haugk
     * @return array
     */
    static function getSection($pSectionId, $pSectionCode)
    {
        $result = '';
        $resultParam = '';

        $recordID = 0;
        $dateCreated = '0000-00-00 00:00:00';
        $companyCode = '';
        $code = '';
        $label = '';
        $name = '';
        $categoryCode = '';
        $displayType = 0;
        $sortOrder = 0;
        $itemOrder = 0;
        $displaySection = 0;
        $isPrivate = 0;
        $isActive = 0;
        $deleted = 0;

        if ($pSectionCode != '')
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                if ($pSectionId > 0)
                {
                    $stmt = $dbObj->prepare('SELECT * FROM `SECTIONS` WHERE (`id` = ?)');
                }
                else
                {
                    $stmt = $dbObj->prepare('SELECT * FROM `SECTIONS` WHERE (`code` = ?)');
                }

                if ($stmt)
                {
                    if ($pSectionId > 0)
                    {
                        $bindOK = $stmt->bind_param('i', $pSectionId);
                    }
                    else
                    {
                        $bindOK = $stmt->bind_param('s', $pSectionCode);
                    }

                    if ($bindOK)
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($recordID, $dateCreated, $companyCode, $code, $label, $name, $categoryCode,
                                                    $displayType, $sortOrder, $itemOrder, $displaySection, $isPrivate, $isActive, $deleted))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching site
                                            $result = 'str_InvalidSectionCode';
                                        }
                                    }
