    /**
     * Return an array containing the store locator logo for the specified shipping method
     *
     * @since Version 3.0.0
     * @version 3.0.0
     * @author Steffen Haugk
     * @return array
     */
    static function getStoreLocatorLogo($pAssetID, $pShowTempFile)
    {
        global $gSession;

        $resultArray = Array();
        $logoType = '';
        $logoWidth = '';
        $logoHeight = '';
        $logo = '';

        if (($pShowTempFile == '1') && ($gSession['shippingmethodlogopath'] != ''))
        {
            // a temporary image file has been uploaded
            $logoPath = $gSession['shippingmethodlogopath'];
            $logoType = $gSession['shippingmethodlogotype'];
            $logoSize = filesize($logoPath);

            list($logoWidth, $logoHeight) = getimagesize($logoPath);

            // read the image data
            $fp = fopen($logoPath, 'rb');
            if ($fp)
            {
                $logo = fread($fp, $logoSize);
                fclose($fp);
            }
        }
        else
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                $stmt = $dbObj->prepare('SELECT `previewtype`, `data`, `previewwidth`, `previewheight` FROM `ASSETDATA` WHERE (`id` = ?)');
                if ($stmt)
                {
                    if ($stmt->bind_param('s', $pAssetID))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($logoType, $logo, $logoWidth, $logoHeight))
                                    {
                                        $stmt->fetch();
                                    }
                                }
                            }
                        }
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                $dbObj->close();
            }
        }

        $resultArray['logotype'] = $logoType;
        $resultArray['logo'] = $logo;
        $resultArray['logowidth'] = $logoWidth;
        $resultArray['logoheight'] = $logoHeight;

        return $resultArray;
    }

