    static function getTaxRateFromCountry($pCountryCode)
    {
        // return the tax rate data for the specified country code

        $resultArray = Array();

        $taxCode = '';
        $taxName = '';
        $taxRate = 0.00;
        $shippingTaxCode = '';
        $shippingTaxName = '';
        $shippingTaxRate = 0.00;

        $defaultTaxCode = '';
        $defaultTaxName = '';
        $defaultTaxRate = 0.00;
        $defaultShippingTaxCode = '';
        $defaultShippingTaxName = '';
        $defaultShippingTaxRate = 0.00;

        $foundTaxRate = false;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `code`, `taxlevel1`, `taxlevel2`, `taxlevel3`, `taxlevel4`, `taxlevel5`, `shippingtaxcode`, `countrycodes` FROM `TAXZONES`'))
            {
                if ($stmt->bind_result($taxZoneCode, $taxLevel1, $taxLevel2, $taxLevel3, $taxLevel4, $taxLevel5, $shippingTaxCode,
                                $countryCodes))
                {
                    if ($stmt->execute())
                    {
                        while ($stmt->fetch())
                        {
                            if ($taxZoneCode == '')
                            {
                                $taxRateArray = self::getTaxRate($taxLevel1);
                                if ($taxRateArray['result'] == '')
                                {
                                    $defaultTaxCode = $taxLevel1;
                                    $defaultTaxName = $taxRateArray['name'];
                                    $defaultTaxRate = $taxRateArray['rate'];
                                }

                                $shippingTaxRateArray = self::getTaxRate($shippingTaxCode);
                                if ($shippingTaxRateArray['result'] == '')
                                {
                                    $defaultShippingTaxCode = $shippingTaxCode;
                                    $defaultShippingTaxName = $shippingTaxRateArray['name'];
                                    $defaultShippingTaxRate = $shippingTaxRateArray['rate'];
                                }
                            }
                            else
                            {
                                $theCodeList = explode(',', $countryCodes);
                                $codeCount = count($theCodeList);
                                for ($i = 0; $i < $codeCount; $i++)
                                {
                                    if ($theCodeList[$i] == $pCountryCode)
                                    {
                                        $taxRateArray = self::getTaxRate($taxLevel1);
                                        if ($taxRateArray['result'] == '')
                                        {
                                            $taxLevel1 = $taxLevel1;
                                            $taxName = $taxRateArray['name'];
                                            $taxRate = $taxRateArray['rate'];
                                        }

                                        $shippingTaxRateArray = self::getTaxRate($shippingTaxCode);
                                        if ($shippingTaxRateArray['result'] == '')
                                        {
                                            $shippingTaxCode = $shippingTaxCode;
                                            $shippingTaxName = $shippingTaxRateArray['name'];
                                            $shippingTaxRate = $shippingTaxRateArray['rate'];
                                        }

                                        $foundTaxRate = true;
                                        break;
                                    }
                                }

                                if ($foundTaxRate == true)
                                {
                                    break;
                                }
                            }
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
            }

            $dbObj->close();
        }

        if ($foundTaxRate == true)
        {
            $resultArray['taxratecode'] = $taxLevel1;
            $resultArray['taxratename'] = $taxName;
            $resultArray['taxrate'] = $taxRate;
            $resultArray['shippingtaxratecode'] = $shippingTaxCode;
            $resultArray['shippingtaxratename'] = $shippingTaxName;
            $resultArray['shippingtaxrate'] = $shippingTaxRate;
        }
        else
        {
            $resultArray['taxratecode'] = $defaultTaxCode;
            $resultArray['taxratename'] = $defaultTaxName;
            $resultArray['taxrate'] = $defaultTaxRate;
            $resultArray['shippingtaxratecode'] = $defaultShippingTaxCode;
            $resultArray['shippingtaxratename'] = $defaultShippingTaxName;
            $resultArray['shippingtaxrate'] = $defaultShippingTaxRate;
        }

        return $resultArray;
    }

    static function getTaxZoneDataFromSession()
    {
        global $gSession;
        global $gConstants;

        // which address to use for tax
        $taxAddress = $gConstants['taxaddress'];

        if ($taxAddress == TPX_TAX_CALCULATION_BY_BILLING_ADDRESS)
        {
            $countryCode = $gSession['order']['billingcustomercountrycode'];
            $regionCode = $gSession['order']['billingcustomerregioncode'];
        }
        else
        {
            $countryCode = $gSession['shipping'][0]['shippingcustomercountrycode'];
            $regionCode = $gSession['shipping'][0]['shippingcustomerregioncode'];
        }

        $companyCode = $gSession['userdata']['companycode'];

        return self::getTaxZoneDataFromRegion($companyCode, $countryCode, $regionCode);
    }

    static function getTaxZoneDataFromRegion($pCompanyCode, $pCountryCode, $pRegionCode)
    {
        $countryCode = $pCountryCode;
        $regionCode = $countryCode . '_' . $pRegionCode;

        $globalTaxCodes = array(
            'default' => array('producttaxlevel1' => '', 'producttaxlevel2' => '', 'producttaxlevel3' => '', 'producttaxlevel4' => '', 'producttaxlevel5' => '',
                'shippingtaxcode' => ''),
            'country' => array('producttaxlevel1' => '', 'producttaxlevel2' => '', 'producttaxlevel3' => '', 'producttaxlevel4' => '', 'producttaxlevel5' => '',
                'shippingtaxcode' => ''),
            'region' => array('producttaxlevel1' => '', 'producttaxlevel2' => '', 'producttaxlevel3' => '', 'producttaxlevel4' => '', 'producttaxlevel5' => '',
                'shippingtaxcode' => ''));

        $taxCodes = array(
            'default' => array('producttaxlevel1' => '', 'producttaxlevel2' => '', 'producttaxlevel3' => '', 'producttaxlevel4' => '', 'producttaxlevel5' => '',
                'shippingtaxcode' => ''),
            'country' => array('producttaxlevel1' => '', 'producttaxlevel2' => '', 'producttaxlevel3' => '', 'producttaxlevel4' => '', 'producttaxlevel5' => '',
                'shippingtaxcode' => ''),
            'region' => array('producttaxlevel1' => '', 'producttaxlevel2' => '', 'producttaxlevel3' => '', 'producttaxlevel4' => '', 'producttaxlevel5' => '',
                'shippingtaxcode' => ''));

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            // sort by company code so global entries will be found first
            if ($stmt = $dbObj->prepare('SELECT `id`, `localcode`, `name`, `companycode`, `taxlevel1`,`taxlevel2`, `taxlevel3`, `taxlevel4`, `taxlevel5`, `shippingtaxcode`, `countrycodes`
			                            FROM `TAXZONES` WHERE (`companycode` = ?) OR (`companycode` = "") ORDER BY `companycode`'))
            {
                if ($stmt->bind_param('s', $pCompanyCode))
                {
                    if ($stmt->bind_result($taxZoneID, $taxZoneCode, $taxZoneName, $companyCode,
                                    $taxLevel1, $taxLevel2, $taxLevel3, $taxLevel4, $taxLevel5, $shippingTaxCode, $countryCodes))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                if ($companyCode == '')
                                {
                                    // global tax zones
                                    if ($taxZoneCode == '')
                                    {
                                        $globalTaxCodes['default']['producttaxlevel1'] = $taxLevel1;
                                        $globalTaxCodes['default']['producttaxlevel2'] = $taxLevel2;
                                        $globalTaxCodes['default']['producttaxlevel3'] = $taxLevel3;
                                        $globalTaxCodes['default']['producttaxlevel4'] = $taxLevel4;
                                        $globalTaxCodes['default']['producttaxlevel5'] = $taxLevel5;
                                        $globalTaxCodes['default']['shippingtaxcode'] = $shippingTaxCode;
                                    }
                                    else
                                    {
                                        $theCodeList = explode(',', $countryCodes);
                                        foreach ($theCodeList as $code)
                                        {
                                            if ($code == $countryCode)
                                            {
                                                $globalTaxCodes['country']['producttaxlevel1'] = $taxLevel1;
                                                $globalTaxCodes['country']['producttaxlevel2'] = $taxLevel2;
                                                $globalTaxCodes['country']['producttaxlevel3'] = $taxLevel3;
                                                $globalTaxCodes['country']['producttaxlevel4'] = $taxLevel4;
                                                $globalTaxCodes['country']['producttaxlevel5'] = $taxLevel5;
                                                $globalTaxCodes['country']['shippingtaxcode'] = $shippingTaxCode;
                                            }
                                            elseif ($code == $regionCode)
                                            {
                                                $globalTaxCodes['region']['producttaxlevel1'] = $taxLevel1;
                                                $globalTaxCodes['region']['producttaxlevel2'] = $taxLevel2;
                                                $globalTaxCodes['region']['producttaxlevel3'] = $taxLevel3;
                                                $globalTaxCodes['region']['producttaxlevel4'] = $taxLevel4;
                                                $globalTaxCodes['region']['producttaxlevel5'] = $taxLevel5;
                                                $globalTaxCodes['region']['shippingtaxcode'] = $shippingTaxCode;
                                            }
                                        }
                                    }
                                }
                                else
                                {
                                    // company tax zones
                                    if ($taxZoneCode == '')
                                    {
                                        $taxCodes['default']['producttaxlevel1'] = $taxLevel1;
                                        $taxCodes['default']['producttaxlevel2'] = $taxLevel2;
                                        $taxCodes['default']['producttaxlevel3'] = $taxLevel3;
                                        $taxCodes['default']['producttaxlevel4'] = $taxLevel4;
                                        $taxCodes['default']['producttaxlevel5'] = $taxLevel5;
                                        $taxCodes['default']['shippingtaxcode'] = $shippingTaxCode;
                                    }
                                    else
                                    {
                                        $theCodeList = explode(',', $countryCodes);
                                        foreach ($theCodeList as $code)
                                        {
                                            if ($code == $countryCode)
                                            {
                                                $taxCodes['country']['producttaxlevel1'] = $taxLevel1;
                                                $taxCodes['country']['producttaxlevel2'] = $taxLevel2;
                                                $taxCodes['country']['producttaxlevel3'] = $taxLevel3;
                                                $taxCodes['country']['producttaxlevel4'] = $taxLevel4;
                                                $taxCodes['country']['producttaxlevel5'] = $taxLevel5;
                                                $taxCodes['country']['shippingtaxcode'] = $shippingTaxCode;
                                            }
                                            elseif ($code == $regionCode)
                                            {
                                                $taxCodes['region']['producttaxlevel1'] = $taxLevel1;
                                                $taxCodes['region']['producttaxlevel2'] = $taxLevel2;
                                                $taxCodes['region']['producttaxlevel3'] = $taxLevel3;
                                                $taxCodes['region']['producttaxlevel4'] = $taxLevel4;
                                                $taxCodes['region']['producttaxlevel5'] = $taxLevel5;
                                                $taxCodes['region']['shippingtaxcode'] = $shippingTaxCode;
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        // only return one set of values
        // select in this order: settings found for region, for country, default (rest of the world)
        // first try and find match for company, only then global
		if ($taxCodes['region']['producttaxlevel1'] != '')
        {
            return $taxCodes['region'];
        }
        elseif ($taxCodes['country']['producttaxlevel1'] != '')
        {
            return $taxCodes['country'];
        }
        elseif ($taxCodes['default']['producttaxlevel1'] != '')
        {
            return $taxCodes['default'];
        }
        if ($globalTaxCodes['region']['producttaxlevel1'] != '')
        {
            return $globalTaxCodes['region'];
        }
        elseif ($globalTaxCodes['country']['producttaxlevel1'] != '')
        {
            return $globalTaxCodes['country'];
        }
        else
        {
            return $globalTaxCodes['default'];
        }
    }

    static function getTaxRatesList()
    {
        // return an array containing the TAOPIX tax rates

        $taxRatesList = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `id`, `code`, `name`, `rate` FROM `TAXRATES` ORDER BY `code`'))
            {
                if ($stmt->bind_result($taxRateID, $taxRateCode, $taxRateName, $taxRate))
                {
                    if ($stmt->execute())
                    {
                        while ($stmt->fetch())
                        {
                            $taxItem['id'] = $taxRateID;
                            $taxItem['code'] = $taxRateCode;
                            $taxItem['name'] = $taxRateName;
                            $taxItem['rate'] = $taxRate;

                            $taxRatesList[] = $taxItem;
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $taxRatesList;
    }

    /**
     * Returns an array containing the exploded price data.
     *
     * @static
     *
     * @param integer $pPricingModel
     * @param string $pPriceString
     *
     * @return array
     * price list array
     *
     * @author Dasha Salo
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function priceStringToArray($pPricingModel, $pPriceString)
    {
        $resultArray = array();

        $priceItem = array();
        $priceItem['startqty'] = 0;
        $priceItem['endqty'] = 0;
        $priceItem['startcmpqty'] = 0;
        $priceItem['endcmpqty'] = 0;
        $priceItem['startpagecount'] = 0;
        $priceItem['endpagecount'] = 0;
        $priceItem['baseprice'] = 0.00;
        $priceItem['unitsell'] = 0.00;
        $priceItem['linesubtract'] = 0.00;

        $priceList = explode(' ', $pPriceString);
        $itemCount = count($priceList);

        for ($i = 0; $i < $itemCount; $i++)
        {
            if ($priceList[$i] != '')
            {
                $priceItemList = explode('*', $priceList[$i]);
                switch ($pPricingModel)
                {
                    case TPX_PRICINGMODEL_PERQTY:
                        // the price string data is in the format 'startqty-endqty-baseprice-unitsell-linesubtract'
                        $priceItem['startqty'] = $priceItemList[0];
                        $priceItem['endqty'] = $priceItemList[1];
                        $priceItem['baseprice'] = $priceItemList[2];
                        $priceItem['unitsell'] = $priceItemList[3];
                        $priceItem['linesubtract'] = $priceItemList[4];
                        break;
                    case TPX_PRICINGMODEL_PERSIDEQTY:
                        // the price string data is in the format 'startqty-endqty--startpagecount-endpagecount-baseprice-unitsell-linesubtract'
                        $priceItem['startqty'] = $priceItemList[0];
                        $priceItem['endqty'] = $priceItemList[1];
                        $priceItem['startpagecount'] = $priceItemList[2];
                        $priceItem['endpagecount'] = $priceItemList[3];
                        $priceItem['baseprice'] = $priceItemList[4];
                        $priceItem['unitsell'] = $priceItemList[5];
                        $priceItem['linesubtract'] = $priceItemList[6];
                        break;
                    case TPX_PRICINGMODEL_PERPRODCMPQTY:
                        $priceItem['startqty'] = $priceItemList[0];
                        $priceItem['endqty'] = $priceItemList[1];
                        $priceItem['startcmpqty'] = $priceItemList[2];
                        $priceItem['endcmpqty'] = $priceItemList[3];
                        $priceItem['baseprice'] = $priceItemList[4];
                        $priceItem['unitsell'] = $priceItemList[5];
                        $priceItem['linesubtract'] = $priceItemList[6];
                        break;
                    case TPX_PRICINGMODEL_PERSIDEPERPRODPERCMPQTY:
                        $priceItem['startqty'] = $priceItemList[0];
                        $priceItem['endqty'] = $priceItemList[1];
                        $priceItem['startcmpqty'] = $priceItemList[2];
                        $priceItem['endcmpqty'] = $priceItemList[3];
                        $priceItem['startpagecount'] = $priceItemList[4];
                        $priceItem['endpagecount'] = $priceItemList[5];
                        $priceItem['baseprice'] = $priceItemList[6];
                        $priceItem['unitsell'] = $priceItemList[7];
                        $priceItem['linesubtract'] = $priceItemList[8];
                        break;
                }

                $resultArray[] = $priceItem;
            }
        }

        return $resultArray;
    }

    static function getDefaultDiscounts($pGroupCode, $pUserID, $pStartTime, $pCompanyCode, $pProductsArray, $pCollectionsArray)
    {
        global $gSession;

        $resultArray = Array();

        $currentTime = date('Y-m-d H:i:s', $pStartTime);

        $sql = '';
        $typeList = 'ssisss';
        $bindOK = false;
        $voucherArray = Array();
        $voucherCode = '';
        $userOrder = 0;
        $voucherPromotionID = 0;
        $voucherPromotionCode = '';
        $voucherPromotionName = '';
        $voucherPromotionActive = 0;
        $voucherType = 0;
        $voucherName = '';
        $collectionIn = '';
        $productCode = '';
        $minimumQty = 0;
        $maximumyQty = 0;
        $lockQty = 0;
        $discountSection = '';
        $discountType = '';
        $discountValue = 0.00;
        $applicationMethod = 0;
        $applyToQty = 9999;
        $sellPrice = 0.00;
        $agentFee = 0.00;
        $productGroupFound = 0;
        $hasProductGroup = 0;
        // products present is a placeholder variable for binding to so the having clause works
        $productsPresent = 0;
        $productGroupID = 0;
		$repeatType = '';

		$productIn = "'" . implode("','", $pProductsArray) . "',''";
        $collectionIn = "'" . implode("','", $pCollectionsArray) . "'";

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
			$usedVouchersUserRaw = self::getDataFromTable(['vouchercode'], 'ORDERHEADER', $dbObj, '', false, ['userid' => $pUserID]);
			$usedVouchersLicenseRaw = self::getDataFromTable(['vouchercode'], 'ORDERHEADER', $dbObj, '', false, ['groupcode' => $pGroupCode]);
			$usedVouchersUser = array_map(function($item) { return $item[0]; }, $usedVouchersUserRaw['data']);
			$usedVouchersLicense = array_map(function($item) { return $item[0]; }, $usedVouchersLicenseRaw['data']);
            /*
             * USERORDER is used to make sure the users default discounts are displayed first.
             * The sort order is important here because it makes sure that the default discount most
             * relivant to the user are displayed.
             * Discount which has been targetted at a user and a product needs to take preference over others.
             * We run a having at the end to filter out vouchers with inapplicable product groups based on the aggregate columns
             */
            $sql = "SELECT `v`.`code`, IF (`v`.`userid` = ?, 1, 0) AS USERORDER, COALESCE(`vp`.`id`, 0),
                        COALESCE(`vp`.`code`, ''), COALESCE(`vp`.`name`, ''), COALESCE(`vp`.`active`, 1), `v`.`type`,
                        `v`.`name`, `v`.`productcode`, `v`.`minimumqty`, `v`.`maximumqty`,
                        `v`.`lockqty`, `v`.`discountsection`, `v`.`discounttype`, `v`.`discountvalue`, `v`.`applicationmethod`,
                        `v`.`maxqtytoapplydiscountto`, `v`.`sellprice`, `v`.`agentfee`,
                        `v`.`hasproductgroup`, !ISNULL(`pgp`.`productgroupid`) AS `productspresent`, COALESCE(`pgh`.`id`, 0), `v`.`repeattype`
                        FROM `VOUCHERS` AS `v` LEFT JOIN `VOUCHERPROMOTIONS` AS `vp` ON `vp`.`code` = `v`.`promotioncode`
                        LEFT JOIN `productgrouplink` AS `pgl` ON  ((`v`.`hasproductgroup` = 1) AND (`pgl`.`assigneetype` = 0) AND (`pgl`.`assigneecode` =`v`.`code`))
                        LEFT JOIN `productgroupheader` AS `pgh` ON (`pgl`.`productgroupid` = `pgh`.`id`
                            AND (`pgh`.`active` = 1))
                        LEFT JOIN `productgroupproducts` AS `pgp` ON (`pgh`.`id` = `pgp`.`productgroupid`
                            AND ((`pgp`.`collectioncode` IN (" . $collectionIn . "))
                            OR (`pgp`.`productcode` IN ('" . implode("','", $pProductsArray) . "'))))
						WHERE (`v`.`defaultdiscount` = 1)
						  AND ((`v`.`groupcode` = '') OR (`v`.`groupcode` = ?))
						  AND ((`v`.`userid` = 0) OR (`v`.`userid` = ?))
						  AND ((`v`.`startdate` <= ?) AND (`v`.`enddate` > ?))
						  AND (`v`.`companycode` = ? OR `v`.`companycode` = '')
						  AND (`v`.`active` = 1)";

			$sql .= " AND (`v`.`productcode` IN (" . $productIn . "))";
            $sql .= " GROUP BY `pgp`.`productgroupid`, `v`.`code`";
            $sql .= " HAVING ((`hasproductgroup` = 0) OR (`hasproductgroup` = 1 AND `productspresent` = 1))";
            $sql .= " ORDER BY `USERORDER` DESC, `v`.`COMPANYCODE` DESC, `v`.`PRODUCTCODE` DESC, `v`.`GROUPCODE` DESC, `v`.`USERID` DESC";


            if ($stmt = $dbObj->prepare($sql))
            {
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);

                if ($stmt->bind_param('isisss', $pUserID, $pGroupCode, $pUserID, $currentTime, $currentTime, $pCompanyCode))
                {
                    if ($stmt->bind_result($voucherCode, $userOrder, $voucherPromotionID, $voucherPromotionCode, $voucherPromotionName,
                            $voucherPromotionActive, $voucherType, $voucherName, $productCode, $minimumQty,
                            $maximumyQty, $lockQty, $discountSection, $discountType, $discountValue, $applicationMethod, $applyToQty,
                            $sellPrice, $agentFee, $hasProductGroup, $productsPresent, $productGroupID, $repeatType))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $voucherArray['result'] = '';
                                $voucherArray['promotioncode'] = $voucherPromotionCode;
                                $voucherArray['promotionname'] = $voucherPromotionName;
                                $voucherArray['code'] = $voucherCode;
                                $voucherArray['type'] = $voucherType;
                                $voucherArray['name'] = $voucherName;
                                $voucherArray['productcode'] = $productCode;
                                $voucherArray['minqty'] = $minimumQty;
                                $voucherArray['maxqty'] = $maximumyQty;
                                $voucherArray['lockqty'] = $lockQty;
                                $voucherArray['discountsection'] = $discountSection;
                                $voucherArray['discounttype'] = $discountType;
                                $voucherArray['discountvalue'] = $discountValue;
                                $voucherArray['sellprice'] = $sellPrice;
                                $voucherArray['agentfee'] = $agentFee;
                                $voucherArray['applicationmethod'] = $applicationMethod;
                                $voucherArray['applytoqty'] = $applyToQty;
                                $voucherArray['custommessage'] = '';
                                $voucherArray['hasproductgroup'] = $hasProductGroup;
                                $voucherArray['productgroupid'] = $productGroupID;

								// Validate that the voucher has not been used if it's just a once per user/license.
								if ('MULTIONCECUSTOMER' === $repeatType && in_array($voucherCode, $usedVouchersUser)) {
									continue;
								}
								if ('MULTIONCEKEY' === $repeatType && in_array($voucherCode, $usedVouchersLicense)) {
									continue;
								}

                                $resultArray[] = $voucherArray;
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $resultArray;
    }

    static function getVoucher($pVoucherCode, $pQty, $pProductCode, $pGroupCode, $pUserID, $pStartTime, $pCompanyCode = '',
            $pCodeType = TPX_VOUCHER_TYPE_DISCOUNT)
    {
        // return an array containing the voucher details for the supplied parameters
        global $gSession;

        $resultArray = Array();

        $result = 'str_LabelInvalidVoucher';
        $promotionID = 0;
        $promotionCode = '';
        $promotionName = '';
        $promotionActive = 0;
        $voucherCode = '';
        $voucherType = 0;
        $voucherDefaultDiscount = 0;
        $voucherName = '';
        $voucherDescription = '';
        $voucherMinQty = 0;
        $voucherMaxQty = 0;
        $voucherLockQty = 0;
        $voucherRepeatType = '';
        $voucherDiscountSection = '';
        $voucherDiscountType = '';
        $voucherDiscountValue = 0.00;
        $voucherSellPrice = 0.00;
        $voucherAgentFee = 0.00;
        $voucherRedeemedUserID = 0;
        $voucherSessionRef = 0;
        $voucherOrderID = 0;
        $voucherProductCode = '';
        $voucherGroupCode = '';
        $voucherApplicationMethod = TPX_VOUCHER_APPLY_EACH_MATCHING_PRODUCT;
        $voucherApplyToQty = 9999;
        $voucherHasProductGroup = false;
        $minOrderValue = 0.00;
        $minOrderValueIncTax = 0;
        $minOrderValueIncShipping = 0;

        $currentTime = date('Y-m-d H:i:s', $pStartTime);

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $sql = 'SELECT IF(ISNULL(VOUCHERPROMOTIONS.id), 0, VOUCHERPROMOTIONS.id), IF(ISNULL(VOUCHERPROMOTIONS.code), \'\', VOUCHERPROMOTIONS.code),
                IF(ISNULL(VOUCHERPROMOTIONS.name), \'\', VOUCHERPROMOTIONS.name), IF(ISNULL(VOUCHERPROMOTIONS.active), 1, VOUCHERPROMOTIONS.active),
                VOUCHERS.code, VOUCHERS.type, VOUCHERS.defaultdiscount, VOUCHERS.name, VOUCHERS.description, `productcode`, `groupcode`,
                `minimumqty`, `maximumqty`, `lockqty`, `repeattype`, `discountsection`, `discounttype`,
                `discountvalue`, `applicationmethod`, `maxqtytoapplydiscountto`, `sellprice`, `agentfee`, `redeemeduserid`, `sessionref`, `orderid`,
                `minordervalue`, `minordervalueinctax`, `minordervalueincshipping`, `hasproductgroup`
                FROM `VOUCHERS`
                    LEFT JOIN `VOUCHERPROMOTIONS` ON VOUCHERPROMOTIONS.code = VOUCHERS.promotioncode
                WHERE (VOUCHERS.code = ?)
                    AND ((`groupcode` = \'\') OR (`groupcode` = ?))
                    AND ((`userid` = 0) OR (`userid` = ?))
                    AND ((VOUCHERS.startdate <= ?) AND (VOUCHERS.enddate > ?))
                    AND (VOUCHERS.companycode = ? OR VOUCHERS.companycode = \'\')
                    AND (VOUCHERS.active = 1)';

            if ($pCodeType == TPX_VOUCHER_TYPE_GIFTCARD)
            {
                $sql .= ' AND (VOUCHERS.type = ' . TPX_VOUCHER_TYPE_GIFTCARD . ')';
            }
            else
            {
                $sql .= ' AND (VOUCHERS.type < ' . TPX_VOUCHER_TYPE_GIFTCARD . ')';
            }

            $stmt = $dbObj->prepare($sql);
            if ($stmt)
            {
                if ($stmt->bind_param('ssisss', $pVoucherCode, $pGroupCode, $pUserID, $currentTime, $currentTime, $pCompanyCode))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($promotionID, $promotionCode, $promotionName, $promotionActive, $voucherCode,
                                                $voucherType, $voucherDefaultDiscount, $voucherName, $voucherDescription,
                                                $voucherProductCode, $voucherGroupCode, $voucherMinQty, $voucherMaxQty, $voucherLockQty,
                                                $voucherRepeatType, $voucherDiscountSection, $voucherDiscountType, $voucherDiscountValue,
                                                $voucherApplicationMethod, $voucherApplyToQty, $voucherSellPrice, $voucherAgentFee, $voucherRedeemedUserID,
                                                $voucherSessionRef, $voucherOrderID, $minOrderValue, $minOrderValueIncTax, $minOrderValueIncShipping, $voucherHasProductGroup))
                                {
                                    if ($stmt->fetch())
                                    {
                                        // make sure that the promotion is active (this will also be true for non promotion vouchers)
                                        if ($promotionActive == 1)
                                        {
                                            // we have a matching voucher so we now need to determine if it can be used
                                            if ($voucherRepeatType == 'MULTI')
                                            {
                                                // the voucher is 'multi' so we can re-use it
                                                $result = '';
                                            }
                                            else if ($voucherRepeatType == 'MULTIONCECUSTOMER')
                                            {
                                                // the voucher is 'multi' but only once per customer so first make sure it hasn't already been used by the customer
                                                $stmt->free_result();
                                                $stmt->close();
                                                $stmt = null;

                                                $stmt = $dbObj->prepare('SELECT `id` FROM `ORDERHEADER` WHERE (`vouchercode` = ?) AND (`userid` = ?)');
                                                if ($stmt)
                                                {
                                                    if ($stmt->bind_param('si', $pVoucherCode, $pUserID))
                                                    {
                                                        if ($stmt->execute())
                                                        {
                                                            if ($stmt->store_result())
                                                            {
                                                                if ($stmt->num_rows == 0)
                                                                {
                                                                    // if we have no result then the voucher hasn't been used by this customer
                                                                    $result = '';
                                                                }
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                            else if ($voucherRepeatType == 'MULTIONCEKEY')
                                            {
                                                // the voucher is 'multi' but only once per license key so first make sure it hasn't already been used by the license key
                                                $stmt->free_result();
                                                $stmt->close();
                                                $stmt = null;

                                                $stmt = $dbObj->prepare('SELECT `id` FROM `ORDERHEADER` WHERE (`vouchercode` = ?) AND (`groupcode` = ?)');
                                                if ($stmt)
                                                {
                                                    if ($stmt->bind_param('ss', $pVoucherCode, $pGroupCode))
                                                    {
                                                        if ($stmt->execute())
                                                        {
                                                            if ($stmt->store_result())
                                                            {
                                                                if ($stmt->num_rows == 0)
                                                                {
                                                                    // if we have no result then the voucher hasn't been used by this license key
                                                                    $result = '';
                                                                }
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                            else
                                            {
                                                // the voucher is single use
                                                // is the voucher a gift card?
                                                if ($voucherType == TPX_VOUCHER_TYPE_GIFTCARD)
                                                {
                                                    if ($voucherRedeemedUserID == 0)
                                                    {
                                                        // Voucher has not been used, Add Value of gift card to users account, mark card as used
                                                        $stmt->free_result();
                                                        $stmt->close();
                                                        $stmt = null;

                                                        $updateVoucherOK = false;
                                                        $result = 'str_LabelGiftCardFailed';

                                                        if ($stmt = $dbObj->prepare('UPDATE `VOUCHERS` SET `redeemeduserid` = ?, `redeemeddate` = now(), `sessionref` = ?, `orderid` = ? WHERE (`code` = ?)'))
                                                        {
                                                            if ($stmt->bind_param('iiis', $gSession['userid'], $gSession['ref'],
                                                                            $voucherOrderID, $voucherCode))
                                                            {
                                                                if ($stmt->execute())
                                                                {
                                                                    $result = 'str_LabelGiftCardAccepted';
                                                                    $updateVoucherOK = true;

                                                                    self::updateCustomerGiftCardBalance($gSession['userid'],
                                                                            $voucherDiscountValue);
                                                                }
                                                            }
                                                        }
                                                    }
                                                    else
                                                    {
                                                        $result = 'str_LabelGiftCardUsed';
                                                    }
                                                }
                                                else
                                                { // voucher or pre-paid
                                                    if ($voucherOrderID == 0)
                                                    {
                                                        // the voucher hasn't been used in an order so check to see if it has been allocated to a session
                                                        if (($voucherSessionRef == 0) || ($voucherSessionRef == $gSession['ref']))
                                                        {
                                                            // the voucher has not been allocated to a session (or has been allocated to our session) so we can use the voucher
                                                            $result = '';
                                                        }
                                                        else
                                                        {
                                                            // the voucher has been allocated to a session
                                                            $sessionDataArray = self::getSessionData($voucherSessionRef);

                                                            if ($sessionDataArray['result'] == 'str_ErrorNoSessionRef')
                                                            {
                                                                // the session doesn't exist anymore so we can use the voucher
                                                                $result = '';
                                                            }
                                                            else
                                                            {
																// the session still exists

																// make sure the voucher session is at a stage we can abort
																if (($sessionDataArray['order']['currentstage'] != 'promptforcard') &&
																	($sessionDataArray['order']['currentstage'] != 'complete'))
																{
																	// check to see if the uploadref is the same
																	if (($gSession['items'][0]['itemuploadref'] == $sessionDataArray['items'][0]['itemuploadref']) && ($gSession['userid'] == $sessionDataArray['userid']))
																	{
																		// the upload ref and the user are the same so we can use the voucher (this solves a problem where the user closed the browser window by accident)
																		$result = '';

																		// kill the voucher session so that it cannot be used
																		self::deleteSession($voucherSessionRef);
																	}
																}
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        $resultArray['result'] = $result;
        $resultArray['promotioncode'] = $promotionCode;
        $resultArray['promotionname'] = $promotionName;
        $resultArray['code'] = $voucherCode;
        $resultArray['type'] = $voucherType;
        $resultArray['defaultdiscount'] = $voucherDefaultDiscount;
        $resultArray['name'] = $voucherName;
        $resultArray['description'] = $voucherDescription;
        $resultArray['productcode'] = $voucherProductCode;
        $resultArray['groupcode'] = $voucherGroupCode;
        $resultArray['minqty'] = $voucherMinQty;
        $resultArray['maxqty'] = $voucherMaxQty;
        $resultArray['lockqty'] = $voucherLockQty;
        $resultArray['repeattype'] = $voucherRepeatType;
        $resultArray['discountsection'] = $voucherDiscountSection;
        $resultArray['discounttype'] = $voucherDiscountType;
        $resultArray['discountvalue'] = $voucherDiscountValue;
        $resultArray['sellprice'] = $voucherSellPrice;
        $resultArray['agentfee'] = $voucherAgentFee;
        $resultArray['applicationmethod'] = $voucherApplicationMethod;
        $resultArray['applytoqty'] = $voucherApplyToQty;
        $resultArray['custommessage'] = '';
        $resultArray['hasproductgroups'] = $voucherHasProductGroup;
        $resultArray['minordervalue'] = $minOrderValue;
        $resultArray['minordervalueinctax'] = $minOrderValueIncTax;
        $resultArray['minordervalueincshipping'] = $minOrderValueIncShipping;

        return $resultArray;
    }

    static function getVoucherPromotion($pID, $pPromotionCode)
    {
        // return an array containing the promotion based on the supplied parameters

        $result = '';
        $resultParam = '';
        $recordID = 0;
        $dateCreated = '';
        $promotionCode = '';
        $promotionName = '';
        $promotionStartDate = '';
        $promotionEndDate = '';
        $companyCode = '';
        $isActive = 0;

        $sqlStatement = '';
        $bindParams = array();

        if ($pPromotionCode != '')
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                if ($pID > 0)
                {
                    $sqlStatement = 'SELECT `id`, `datecreated`, `companycode`, `code`, `name`, `startdate`, `enddate`, `active` FROM `VOUCHERPROMOTIONS` WHERE (`id` = ?)';
                    $bindParams[0] = 'i';
                    $bindParams[1] = $pID;
                }
                else
                {
                    $sqlStatement = 'SELECT `id`, `datecreated`, `companycode`, `code`, `name`, `startdate`, `enddate`, `active` FROM `VOUCHERPROMOTIONS` WHERE (`code` = ?)';
                    $bindParams[0] = 's';
                    $bindParams[1] = $pPromotionCode;
                }


                if ($stmt = $dbObj->prepare($sqlStatement))
                {
                    if ($stmt->bind_param($bindParams[0], $bindParams[1]))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($recordID, $dateCreated, $companyCode, $promotionCode, $promotionName,
                                                    $promotionStartDate, $promotionEndDate, $isActive))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // no matching promotion
                                            $result = 'str_InvalidVoucherPromotionCode';
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getVoucherPromotion bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no matching promotion
                                    $result = 'str_InvalidVoucherPromotionCode';
                                }
                            }
                            else
                            {
                                // could not store result
                                $result = 'str_DatabaseError';
                                $resultParam = 'getVoucherPromotion store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getVoucherPromotion execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getVoucherPromotion bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getVoucherPromotion prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
                // could not open database connection
                $result = 'str_DatabaseError';
                $resultParam = 'getVoucherPromotion connect ' . $dbObj->error;
            }
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['companycode'] = $companyCode;
        $resultArray['code'] = $promotionCode;
        $resultArray['name'] = $promotionName;
        $resultArray['startdate'] = $promotionStartDate;
        $resultArray['enddate'] = $promotionEndDate;
        $resultArray['isactive'] = $isActive;

        return $resultArray;
    }

    static function getEmptyVoucherPromotion()
    {
        // return an array containing an empty voucher promotion record

        return self::getVoucherPromotion(0, '');
    }

    static function getVoucherPromotionFromCode($pCode)
    {
        // return an array containing the voucher promotion for the specified voucher promotion code

        return self::getVoucherPromotion(0, $pCode);
    }

    static function getVoucherPromotionFromID($pID)
    {
        // return an array containing the voucher promotion for the specified voucher promotion record id

        return self::getVoucherPromotion($pID, '-');
    }

    static function getPaymentMethodsList($pRequiresDelivery = -1)
    {
        // return an array containing the TAOPIX payment methods

        global $gSession;
        global $gConstants;

        $paymentMethodsList = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `id`, `code`, `name`, `availablewhenshipping`, `availablewhennotshipping`, `active` FROM `PAYMENTMETHODS` ORDER BY `id`'))
            {
                if ($stmt->bind_result($paymentMethodID, $paymentMethodCode, $paymentMethodName, $availableWhenShipping,
                                $availableWhenNotShipping, $isActive))
                {
                    if ($stmt->execute())
                    {
                        while ($stmt->fetch())
                        {
                            $canAdd = true;
                            if ($pRequiresDelivery > -1)
                            {
                                // we are processing payment methods for an order
                                if (($pRequiresDelivery == 1) && ($availableWhenShipping == 0))
                                {
                                    $canAdd = false;
                                }

                                if (($pRequiresDelivery == 0) && ($availableWhenNotShipping == 0))
                                {
                                    $canAdd = false;
                                }
                                // if the payment method is card make sure there is a provider set in the config file
                                if ($paymentMethodCode == 'CARD')
                                {
                                    if (($gSession['order']['ccitype'] == '') || ($gSession['order']['ccitype'] == 'NONE'))
                                    {
                                        $canAdd = false;
                                    }
                                }
                            }

                            if (!$gConstants['optioncfs'])
                            {

                                if ($paymentMethodCode == 'PAYINSTORE')
                                {

                                    $canAdd = false;
                                }
                            }

                            if ($canAdd)
                            {
                                $paymentMethodItem['id'] = $paymentMethodID;
                                $paymentMethodItem['code'] = $paymentMethodCode;
                                $paymentMethodItem['name'] = $paymentMethodName;
                                $paymentMethodItem['availablewhenshipping'] = $availableWhenShipping;
                                $paymentMethodItem['availablewhennotshipping'] = $availableWhenNotShipping;
                                $paymentMethodItem['isactive'] = $isActive;

                                $paymentMethodsList[] = $paymentMethodItem;
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $paymentMethodsList;
    }

    static function orderProcessed($pBatchRef, $pUploadRef)
    {
        // return an array containing data on the order processing status
        $result = '';
        $resultParam = '';
        $processedItemsArray = Array();

        if ($pBatchRef == '')
        {
            $pBatchRef = $pUploadRef;
        }

        if ($pBatchRef != 'ALLOCATE')
        {
            $result = 'str_NoOrder';

            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                if ($stmt = $dbObj->prepare('SELECT oi.id, oi.orderid, oi.uploadref, oi.projectref, oi.projectname, oi.productcode, oi.productcodepurchased, oi.producttotalcost, oi.producttotalweight,
                	IF (oic.componentlocalcode IS NULL, "", oic.componentlocalcode) as localcovercode,
                	IF (oic.componentcode IS NULL, "", oic.componentcode) as covercode,
                	IF (oic.componenttotalcost IS NULL, 0.00, oic.componenttotalcost) as covertotalcost,
                	IF (oic.componenttotalweight IS NULL, 0.00, oic.componenttotalweight) as covertotalweight,
                	IF (oip.componentlocalcode IS NULL, "", oip.componentlocalcode) as papercode,
                	IF (oip.componentunitcost IS NULL, 0.00, oip.componentunitcost) as paperunitcost,
                	IF (oip.componentunitweight IS NULL, 0.00, oip.componentunitweight) as paperunitweight,
                    oi.pagecountpurchased, oi.pagecount, oi.qty,
                	IF (oip.componenttotalsell IS NULL, 0.00, oip.componenttotalsell) as papertotalsell,
                    oi.canupload, oi.canuploadproductcodeoverride, oi.canuploadpagecountoverride, oi.canuploadenablesaveoverride, oi.status, oh.groupcode, oh.shoppingcarttype, oh.ordernumber, oh.temporder,
                    oi.active, os.shippingratecost
                    FROM `ORDERITEMS` oi
                    LEFT JOIN `ORDERHEADER` oh ON oh.id = oi.orderid
                    LEFT JOIN `ORDERSHIPPING` os ON os.orderid = oi.orderid
					LEFT JOIN ORDERITEMCOMPONENTS oic ON (oi.id = oic.orderitemid) AND (oic.componentcategorycode="COVER")
					LEFT JOIN ORDERITEMCOMPONENTS oip ON (oi.id = oip.orderitemid) AND (oip.componentcategorycode="PAPER")
					WHERE (`oi`.`uploadbatchref` = ?) AND (`oh`.`orderready` = 1) AND (`oi`.`parentorderitemid` = 0)'))
                {
                    if ($stmt->bind_param('s', $pBatchRef))
                    {
                        if ($stmt->bind_result($recordID, $orderID, $uploadRef, $projectRef, $projectName, $productCode,
                                        $productCodePurchased, $productTotalCost, $productTotalWeight, $localCoverCode, $coverCode,
                                        $coverTotalCost, $coverTotalWeight, $paperCode, $paperUnitCost, $paperUnitWeight,
                                        $pageCountPurchased, $pageCount, $qty, $paperTotalSell, $canUpload, $canUploadProductCodeOverride,
                                        $canUploadPageCountOverride, $canUploadEnableSaveOverride, $status, $groupCode, $shoppingCartType,
                                        $orderNumber, $tempOrder, $orderItemActive, $shippingRateCost))
                        {
                            if ($stmt->execute())
                            {
                                while ($stmt->fetch())
                                {
                                    if ($orderItemActive != TPX_ORDER_STATUS_IN_PROGRESS)
                                    {
                                        $canUpload = 0;
                                    }

                                    $itemArray = Array();
                                    $itemArray['recordid'] = $recordID;
                                    $itemArray['orderid'] = $orderID;
                                    $itemArray['projectref'] = $projectRef;
                                    $itemArray['projectname'] = $projectName;
                                    $itemArray['productcode'] = $productCode;
                                    $itemArray['productcodepurchased'] = $productCodePurchased;
                                    $itemArray['uploadref'] = $uploadRef;
                                    $itemArray['producttotalcost'] = $productTotalCost;
                                    $itemArray['producttotalweight'] = $productTotalWeight;
                                    $itemArray['covercode'] = $localCoverCode;
                                    $itemArray['covercomponentcode'] = $coverCode;
                                    $itemArray['covertotalcost'] = $coverTotalCost;
                                    $itemArray['covertotalweight'] = $coverTotalWeight;
                                    $itemArray['papercode'] = $paperCode;
                                    $itemArray['paperunitcost'] = $paperUnitCost;
                                    $itemArray['paperunitweight'] = $paperUnitWeight;
                                    $itemArray['pagecountpurchased'] = $pageCountPurchased;
                                    $itemArray['pagecount'] = $pageCount;
                                    $itemArray['qty'] = $qty;
                                    $itemArray['papertotalsell'] = $paperTotalSell;
                                    $itemArray['canupload'] = $canUpload;
                                    $itemArray['canuploadproductcodeoverride'] = $canUploadProductCodeOverride;
                                    $itemArray['canuploadpagecountoverride'] = $canUploadPageCountOverride;
                                    $itemArray['canuploadenablesaveoverride'] = $canUploadEnableSaveOverride;
                                    $itemArray['status'] = $status;
                                    $itemArray['groupcode'] = $groupCode;
                                    $itemArray['shoppingcarttype'] = $shoppingCartType;
                                    $itemArray['ordernumber'] = $orderNumber;
                                    $itemArray['temporder'] = $tempOrder;
                                    $itemArray['orderstatus'] = $orderItemActive;
                                    $itemArray['shippingratecost'] = $shippingRateCost;

                                    if ($tempOrder == 0)
                                    {
                                        $itemArray['outputdeliverymethods'] = 'PRODUCT';
                                    }
                                    else
                                    {
                                        $itemArray['outputdeliverymethods'] = 'UPLOADRENDERED';
                                    }

                                    $processedItemsArray[] = $itemArray;

                                    $result = '';
                                }
                            }
                            else
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'orderprocessed execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'orderprocessed bind result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'orderprocessed bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'orderprocessed prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
                // could not open database connection
                $result = 'str_DatabaseError';
                $resultParam = 'orderprocessed connect ' . $dbObj->error;
            }
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['processeditemslist'] = &$processedItemsArray;

        return $resultArray;
    }

    static function updateOrderUploadStatus($pUploadRef, $pUploadDataType, $pUploadMethod, $pUploadAppVersion, $pUploadAppPlatform,
            $pUploadAppCPUType, $pUploadAppOSVersion, $pProjectStartTime, $pProjectDuration, $pProjectDataSize, $pProjectUploadDuration,
            $pCanUploadFiles, $pStatus)
    {
        // update the order upload status based on the supplied parameters

        $result = '';
        $resultParam = '';
        $orderItemsArray = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // obtain the list of items we are going to update
            if ($stmt = $dbObj->prepare('SELECT `oi`.`id`, `oi`.`currentowner`, `oh`.`id`, `oh`.`temporder`, `oi`.`parentorderitemid` FROM `ORDERITEMS` oi JOIN `ORDERHEADER` oh ON `oh`.`id` = `oi`.`orderid`
                        WHERE (`uploadref` = ?) AND ((`canupload` = 1) OR (`status` = 0)) AND (`active` = 0)'))
            {
                if ($stmt->bind_param('s', $pUploadRef))
                {
                    if ($stmt->bind_result($orderItemID, $currentOwner, $orderID, $tempOrder, $parentOrderItemID))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $itemArray = Array();
                                $itemArray['id'] = $orderItemID;
                                $itemArray['orderid'] = $orderID;
                                $itemArray['currentowner'] = $currentOwner;
                                $itemArray['temporder'] = $tempOrder;
                                $itemArray['parentorderitemid'] = $parentOrderItemID;

                                $orderItemsArray[] = $itemArray;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'updateOrderUploadMethod select execute ' . $dbObj->error;
                        }
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'updateOrderUploadMethod select bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'updateOrderUploadMethod select prepare ' . $dbObj->error;
            }


            // update the item status for all active items with this uploadref
            if ($stmt = $dbObj->prepare('UPDATE `ORDERITEMS` SET `canupload` = ?, `canuploadproductcodeoverride` = 0, `canuploadpagecountoverride` = 0,
                       `status` = ?, `statusdescription` = "", `statustimestamp` = now()
                        WHERE (`uploadref` = ?) AND ((`canupload` = 1) OR (`status` = 0)) AND (`active` = 0)'))
            {
                if ($stmt->bind_param('iis', $pCanUploadFiles, $pStatus, $pUploadRef))
                {
                    if (!$stmt->execute())
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'updateOrderUploadMethod update1 execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'updateOrderUploadMethod update1 bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'updateOrderUploadMethod update1 prepare ' . $dbObj->error;
            }

            if ($result == '')
            {
                // update the files received status for all items with this uploadref
                if (($pStatus == TPX_ITEM_STATUS_FILES_ON_REMOTE_FTP_SERVER) || ($pStatus == TPX_ITEM_STATUS_FILES_RECEIVED))
                {
                    if ($stmt = $dbObj->prepare('UPDATE `ORDERITEMS` SET `uploaddatatype` = ?, `uploadmethod` = ? , `uploadappversion` = ?, `uploadappplatform` = ?,
                        `uploadappcputype` = ?, `uploadapposversion` = ?, `projectbuildstartdate` = ?, `projectbuildduration` = ?, `uploaddatasize` = ?, `uploadduration` = ?,
                        `canmodify` = 0, `filesreceivedtimestamp` = now(), `filesreceiveduserid` = 0
                        WHERE `uploadref` = ?'))
                    {
                        if ($stmt->bind_param('iisssssiiis', $pUploadDataType, $pUploadMethod, $pUploadAppVersion, $pUploadAppPlatform,
                                        $pUploadAppCPUType, $pUploadAppOSVersion, $pProjectStartTime, $pProjectDuration, $pProjectDataSize,
                                        $pProjectUploadDuration, $pUploadRef))
                        {
                            if (!$stmt->execute())
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'updateOrderUploadMethod update2 execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bind parameters
                            $result = 'str_DatabaseError';
                            $resultParam = 'updateOrderUploadMethod update2 bind params ' . $dbObj->error;
                        }
                        $stmt->free_result();
                        $stmt->close();
                        $stmt = null;
                    }
                    else
                    {
                        // could not prepare statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'updateOrderUploadMethod update2 prepare ' . $dbObj->error;
                    }
                }
                else
                {
                    $timeStamp = '0000-00-00 00:00:00';

                    if ($stmt = $dbObj->prepare('UPDATE `ORDERITEMS` SET `uploaddatatype` = ?, `uploadmethod` = ? , `uploadappversion` = ?, `uploadappplatform` = ?,
                        `uploadappcputype` = ?, `uploadapposversion` = ?, `projectbuildstartdate` = ?, `projectbuildduration` = ?, `uploaddatasize` = ?, `uploadduration` = ?,
                        `canmodify` = 0, `filesreceivedtimestamp` = ?, `filesreceiveduserid` = 0
                        WHERE `uploadref` = ?'))
                    {
                        if ($stmt->bind_param('iisssssiiiss', $pUploadDataType, $pUploadMethod, $pUploadAppVersion, $pUploadAppPlatform,
                                        $pUploadAppCPUType, $pUploadAppOSVersion, $pProjectStartTime, $pProjectDuration, $pProjectDataSize,
                                        $pProjectUploadDuration, $timeStamp, $pUploadRef))
                        {
                            if (!$stmt->execute())
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'updateOrderUploadMethod update3 execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bind parameters
                            $result = 'str_DatabaseError';
                            $resultParam = 'updateOrderUploadMethod update3 bind params ' . $dbObj->error;
                        }
                        $stmt->free_result();
                        $stmt->close();
                    }
                    else
                    {
                        // could not prepare statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'updateOrderUploadMethod update3 prepare ' . $dbObj->error;
                    }
                }
            }

            $dbObj->close();
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['items'] = &$orderItemsArray;

        return $resultArray;
    }

    /**
     * Updates the database with the product data supplied by TAOPIX™ Builder after a product upload
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 1.0.0
     */
    static function uploadProductsUpdate($dbObj, $pOwnerCompany, $pProductCollectionCode, $pProductCollectionName, $pProductCollectionDescription,
            $pProductCollectionVersion, $pProductCollectionAppVersion,
            $pProductCollectionDataVersion, $pProductCollectionSize, $pProductCollectionChecksum, $pProductCollectionDependencies,
            $pProductCollectionOnlineDependencies, $pProductCollectionSeparateComponents, $pProductCollectionHasPreview,
            $pProductsHaveDimensions, $pProductHasDesktopLayouts, $pProductHasOnlineLayouts, $pProductLayoutList,
            $pProductCollectionMoreInformationURL, $pProductCollectionThumbnailResourceRef, $pProductCollectionThumbnailResourceDataUID, $pProductCollectionPreviewResourceRef,
            $pProductCollectionPreviewResourceDataUID, $pProductCollectionSortLevel, $pProductCollectionTextEngineVersion, $pProductCollectionPublishVersion, $pProductCollectionSummary,
            $pProductCollectionThumbnailResourceDevicePixelRatio, $pProductCollectionPreviewResourceDevicePixelRatio)
    {
        $result = '';
        $resultParam = '';
        $productsHaveDimensions = 0;
        $applicationFileRecordID = 0;
        $productOptions = TPX_PRODUCTOPTION_PRICING_NON;
		$priceTransformationStage = TPX_PRICETRANSFORMATIONSTAGE_POST;

        $filename = $pProductCollectionCode . '.zip';

        if ($pProductsHaveDimensions == 'TRUE')
        {
            $productsHaveDimensions = 1;
        }

        // first loop around the products (layouts) and either update them or add them

        $newProductsArray = Array();
        $newProductKeyArray = Array();

        $itemCount = count($pProductLayoutList);

        for ($i = 0; $i < $itemCount; $i++)
        {
            $layoutItem = $pProductLayoutList[$i];

            if ($layoutItem['spreads'] == 'TRUE')
            {
                $layoutItem['spreads'] = 1;
            }
            else
            {
                $layoutItem['spreads'] = 0;
            }

            if ($layoutItem['paperinsidebleed'] == 'TRUE')
            {
                $layoutItem['paperinsidebleed'] = 1;
            }
            else
            {
                $layoutItem['paperinsidebleed'] = 0;
            }

            if ($layoutItem['cover1active'] == 'TRUE')
            {
                $layoutItem['cover1active'] = 1;
            }
            else
            {
                $layoutItem['cover1active'] = 0;
            }

            if ($layoutItem['cover1flexiblespine'] == 'TRUE')
            {
                $layoutItem['cover1flexiblespine'] = 1;
            }
            else
            {
                $layoutItem['cover1flexiblespine'] = 0;
            }

            if ($layoutItem['cover2active'] == 'TRUE')
            {
                $layoutItem['cover2active'] = 1;
            }
            else
            {
                $layoutItem['cover2active'] = 0;
            }

            if ($layoutItem['type'] == TPX_PRODUCTCOLLECTIONTYPE_SINGLEPRINTS)
            {
                $previewType = 3;
                $productOptions = TPX_PRODUCTOPTION_PRICING_PERCOMPONENTSUBCOMPONENT;
                $priceTransformationStage = TPX_PRICETRANSFORMATIONSTAGE_PRE;
            }
            else
            {
                $previewType = 1;
            }

            $productArray = self::getProductFromCode($layoutItem['code']);
            if ($productArray['result'] == '')
            {
                // we already have a product record so just update it
                if ($stmt = $dbObj->prepare('UPDATE `PRODUCTS` SET `companycode` = ?, `name` = ?, `deleted` = 0 WHERE `code` = ?'))
                {
                    if ($stmt->bind_param('sss', $pOwnerCompany, $layoutItem['name'], $layoutItem['code']))
                    {
                        if (!$stmt->execute())
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'uploadProductsUpdate execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'uploadProductsUpdate bind ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'uploadProductsUpdate prepare ' . $dbObj->error;
                }

                if ($result == '')
                {
                    // if this is being converted from a global product to a company product we need to remove any product configuration linking records
                    if (($pOwnerCompany != '') && ($productArray['companycode'] == ''))
                    {
                        $linkClearResultArray = self::clearProductLinkRecord($dbObj, $layoutItem['code']);

                        $result = $linkClearResultArray['error'];
                        $resultParam = $linkClearResultArray['errorparam'];
                    }
                }
            }
            else
            {
                // we don't have a product so insert the minimum values
                if ($stmt = $dbObj->prepare('INSERT INTO `PRODUCTS` (`id`, `datecreated`, `companycode`, `code`, `name`, `previewtype`, `productoptions`, `pricetransformationstage`)
                            VALUES (0, now(), ?, ?, ?, ?, ?, ?)'))
                {
                    if ($stmt->bind_param('sssiii', $pOwnerCompany, $layoutItem['code'], $layoutItem['name'], $previewType, $productOptions, $priceTransformationStage))
                    {
                        if (!$stmt->execute())
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'uploadProductsUpdate insert execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'uploadProductsUpdate insert bind ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'uploadProductsUpdate insert prepare ' . $dbObj->error;
                }
            }

            // append the product (layout) code to a list so that we can quickly look them up later
            $newProductsArray[] = $layoutItem['code'];

            if ($layoutItem['availabledesktop'] == 'TRUE')
            {
                $layoutItem['availabledesktop'] = 1;
            }
            else
            {
                $layoutItem['availabledesktop'] = 0;
            }

            if ($layoutItem['availableonline'] == 'TRUE')
            {
                $layoutItem['availableonline'] = 1;
            }
            else
            {
                $layoutItem['availableonline'] = 0;
            }

            $newProductKeyArray[$layoutItem['code']] = $layoutItem;
        }

        // if we have no error then insert the product collection data
        if ($result == '')
        {
            $appFileResultArray = self::uploadApplicationFilesUpdate($dbObj, $pOwnerCompany, TPX_APPLICATION_FILE_TYPE_PRODUCTCOLLECTION,
                            $pProductCollectionCode, $pProductCollectionAppVersion, $pProductCollectionDataVersion,
                            "", "", $pProductCollectionName,
                            $pProductCollectionDescription, '', '', $filename, $pProductCollectionVersion, 'FALSE', 0,
                            $pProductCollectionDependencies, $pProductCollectionOnlineDependencies, $pProductCollectionSize,
                            $pProductCollectionChecksum, 'FALSE', $pProductCollectionHasPreview, $pProductCollectionSeparateComponents,
                            'FALSE', $pProductHasDesktopLayouts, $pProductHasOnlineLayouts, '');

            // if we have no error the final stage is to update the product collection link table with the list of products (layouts) for the collection
            if ($appFileResultArray['result'] == '')
            {

                $applicationFileRecordID = $appFileResultArray['recordid'];

                $deletionIDList = Array();
                $updateProductsArray = Array();

                // first get the list of current links
                if ($stmt = $dbObj->prepare('SELECT `id`, `productcode` FROM `PRODUCTCOLLECTIONLINK` WHERE `collectioncode` = ?'))
                {
                    if ($stmt->bind_param('s', $pProductCollectionCode))
                    {
                        if ($stmt->bind_result($id, $productCode))
                        {
                            if ($stmt->execute())
                            {
                                while ($stmt->fetch())
                                {
                                    // determine if we need to keep the record
                                    if (in_array($productCode, $newProductsArray))
                                    {
                                        // this code is already in the new products (layouts) list
                                        // we don't want to insert it again so remove it from the list
                                        // for simplicity we implode the array to a csv string, compare for an equal match (single elements) or a string replace before exploding back to an array
                                        $arrayString = implode(',', $newProductsArray);
                                        if ($arrayString == $productCode)
                                        {
                                            $newProductsArray = Array();
                                        }
                                        else
                                        {
                                            // look for the product code surrounded by commas
                                            $arrayString = str_replace(',' . $productCode . ',', ',', ',' . $arrayString . ',');

                                            // remove the start and end commas
                                            $arrayString = substr($arrayString, 1, -1);

                                            // explode the string back into an array
                                            $newProductsArray = explode(',', $arrayString);
                                        }

                                        $updateProductsArray[$id] = $newProductKeyArray[$productCode];
                                    }
                                    else
                                    {
                                        // this code is not in the new list so mark it for deletion
                                        $deletionIDList[] = $id;
                                    }
                                }
                            }
                            else
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'uploadProductsUpdate select product collection link execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'uploadProductsUpdate select product collection link bind result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'uploadProductsUpdate select product collection link bind params ' . $dbObj->error;
                    }

                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'uploadProductsUpdate select product collection link prepare ' . $dbObj->error;
                }

                // if we have no error we can delete any the records that are not required anymore
                // as we have retrieved the record id's ourselves there is no chance of sql injection so we do not have to bind the parameters
                if ($result == '')
                {
                    if (count($deletionIDList) > 0)
                    {
                        if ($stmt = $dbObj->prepare('DELETE FROM PRODUCTCOLLECTIONLINK WHERE `id` IN (' . join(',', $deletionIDList) . ')'))
                        {
                            if (!$stmt->execute())
                            {
                                // could not execute statement
                                $result = 'str_DatabaseError';
                                $resultParam = 'uploadProductsUpdate delete product collection link execute ' . $dbObj->error;
                            }

                            $stmt->free_result();
                            $stmt->close();
                        }
                        else
                        {
                            // could not prepare statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'uploadProductsUpdate delete product collection link prepare ' . $dbObj->error;
                        }
                    }
                }


                // if we have no error the next stage is to insert new entries
                // hasbeenavailabledesktop is set to the same as availabledesktop for new entries
                // the data has come from outside so we need to bind the values
                if ($result == '')
                {
                    if ($stmt = $dbObj->prepare('INSERT INTO `PRODUCTCOLLECTIONLINK` (`id`, `datecreated`, `companycode`, `collectioncode`, `collectionname`, `collectiontype`, `productcode`, `productname`, `productdescription`, `producthasdimensions`, `productminpagecount`, `productmaxpagecount`, `productdefaultpagecount`,
                    `productpageinsertcount`, `productpagepaperwidth`, `productpagepaperheight`, `productpagebleed`, `productpageisspreads`, `productpageinsidebleed`, `productpagewidth`,
                    `productpageheight`, `productpagefirstpage`, `productcover1active`, `productcover1type`, `productcover1paperwidth`, `productcover1paperheight`, `productcover1bleed`,
                    `productcover1backflap`, `productcover1frontflap`, `productcover1wraparound`, `productcover1spine`, `productcover1flexiblespine`, `productcover1width`, `productcover1height`,
                    `productcover1flexiblespinedata`, `productcover2active`, `productcover2paperwidth`, `productcover2paperheight`, `productcover2bleed`, `productcover2width`, `productcover2height`,
                    `availabledesktop`, `hasbeenavailabledesktop`, `availableonline`,
                    `publishversion`, `collectiondescription`, `collectionmoreinformationurl`, `collectionthumbnailresourceref`, `collectionthumbnailresourcedatauid`, `collectionpreviewresourceref`,
