    /**
     * Removes the product link record for the passed product code
     *
     * @param DbObj $pDBObj Taopix Database object
     * @param String $pProductCode The code to clear
     * @return Array Standard taopix error array
     */
    static function clearProductLinkRecord($pDBObj, $pProductCode)
    {
        $resultArray = UtilsObj::getReturnArray();
        $result = '';
        $resultParam = '';

        $sql = "DELETE FROM `pricelink`
                    WHERE `productcode` = ? AND `linkedproductcode` != ''";

        $stmt = $pDBObj->prepare($sql);

        if ($stmt)
        {
            $bindOK = $stmt->bind_param('s', $pProductCode);

            if ($bindOK)
            {
                if (! $stmt->execute())
                {
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . ' execute: ' . $pDBObj->error;
                }
            }
            else
            {
                $result = 'str_DatabaseError';
                $resultParam = __FUNCTION__ . ' execute: ' . $pDBObj->error;
            }
        }
        else
        {
            $result = 'str_DatabaseError';
            $resultParam = __FUNCTION__ . ' execute: ' . $pDBObj->error;
        }

        $resultArray['error'] = $result;
        $resultArray['errorparam'] = $resultParam;

        return $resultArray;
    }

    /**
     * Updates the database with the application asset file data supplied by TAOPIX™ Builder
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 1.0.0
     */
    static function uploadApplicationFilesUpdate($dbObj, $pCompanyCode, $pItemType, $pItemRef, $pItemAppVersion, $pItemDataVersion,
            $pItemCategoryCode, $pItemCategoryName, $pItemName, $pItemDescription, $pItemProducts, $pItemThemes, $pItemFileName,
            $pItemDateModified, $pItemEncrypted, $pItemPriority, $pItemDependencies, $pItemOnlineDependencies, $pItemSize, $pItemChecksum,
            $pItemHasFPO, $pItemHasPreview, $pSeparateComponents, $pItemHiddenFromUser, $pItemHasDesktopLayouts, $pItemHasOnlineLayouts,
            $pItemWebBrandCode)
    {
        // update the auto-update application files information (performed after an application file has been uploaded to the server)

        $result = '';
        $resultParam = '';
        $recordID = 0;
        $isEncrypted = 0;
        $hasFPO = 0;
        $hasPreview = 0;
        $isSeparateComponents = 0;
        $isHiddenFromUser = 0;
        $hasDesktopLayouts = 0;
        $hasOnlineLayouts = 0;

        if ($pItemEncrypted == 'TRUE')
        {
            $isEncrypted = 1;
        }

        if ($pItemHasFPO == 'TRUE')
        {
            $hasFPO = 1;
        }

        if ($pItemHasPreview == 'TRUE')
        {
            $hasPreview = 1;
        }

        if ($pSeparateComponents == 'TRUE')
        {
            $isSeparateComponents = 1;
        }

        if ($pItemHiddenFromUser == 'TRUE')
        {
            $isHiddenFromUser = 1;
        }

        if ($pItemHasDesktopLayouts == 'TRUE')
        {
            $hasDesktopLayouts = 1;
        }

        if ($pItemHasOnlineLayouts == 'TRUE')
        {
            $hasOnlineLayouts = 1;
        }

        if ($dbObj)
        {
            $stmt = $dbObj->prepare('SELECT id FROM `APPLICATIONFILES` WHERE (`type` = ?) AND (`ref` = ?) AND (`webbrandcode` = ?)');
            if ($stmt)
            {
                if ($stmt->bind_param('iss', $pItemType, $pItemRef, $pItemWebBrandCode))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($recordID))
                                {
                                    if (!$stmt->fetch())
                                    {
                                        $recordID = 0;
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'uploadApplicationFilesUpdate bind result ' . $dbObj->error;
                                }
                            }
                            else
                            {
                                $recordID = 0;
                            }

                            $stmt->free_result();
                            $stmt->close();
                            $stmt = null;

                            if ($result == '')
                            {
                                if ($recordID > 0)
                                {
                                    // we have an item so just update it
                                    if ($stmt = $dbObj->prepare('UPDATE `APPLICATIONFILES` SET `companycode` = ?, `appversion` = ?, `dataversion` = ?, `categorycode` = ?, `categoryname` = ?, `name` = ?, `description` = ?,
								        `products` = ?, `themes` = ?, `filename` = ?, `versiondate` = ?, `encrypted` = ?, `updatepriority` = ?, `dependencies` = ?, `onlinedependencies` = ?, `size` = ?, `checksum` = ?,
								        `hasfpo` = ?, `haspreview` = ?, `separatecomponents` = ?, `hiddenfromuser` = ?, `hasdesktoplayouts` = ?, `hasonlinelayouts` = ?, `webbrandcode` = ?, `deleted` = 0 WHERE `id` = ?'))
                                    {
                                        if ($stmt->bind_param('ssisssss' . 'sssiissdsii' . 'iiiisi', $pCompanyCode, $pItemAppVersion,
                                                        $pItemDataVersion, $pItemCategoryCode, $pItemCategoryName, $pItemName,
                                                        $pItemDescription, $pItemProducts, $pItemThemes, $pItemFileName, $pItemDateModified,
                                                        $isEncrypted, $pItemPriority, $pItemDependencies, $pItemOnlineDependencies,
                                                        $pItemSize, $pItemChecksum, $hasFPO, $hasPreview, $isSeparateComponents,
                                                        $isHiddenFromUser, $hasDesktopLayouts, $hasOnlineLayouts, $pItemWebBrandCode,
                                                        $recordID))
                                        {
                                            if (!$stmt->execute())
                                            {
                                                // could not execute statement
                                                $result = 'str_DatabaseError';
                                                $resultParam = 'uploadApplicationFilesUpdate update execute ' . $dbObj->error;
                                            }
                                        }
                                        else
                                        {
                                            // could not bind parameters
                                            $result = 'str_DatabaseError';
                                            $resultParam = 'uploadApplicationFilesUpdate update bind ' . $dbObj->error;
                                        }
                                        $stmt->free_result();
                                        $stmt->close();
                                        $stmt = null;
                                    }
                                    else
                                    {
                                        // could not prepare statement
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'uploadApplicationFilesUpdate update prepare ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // we don't have an item so insert the minimum values
                                    if ($stmt = $dbObj->prepare('INSERT INTO `APPLICATIONFILES` (`id`, `datecreated`, `companycode`, `type`, `ref`, `appversion`, `dataversion`, `categorycode`, `categoryname`, `name`, `description`,
								            `products`, `themes`, `filename`, `versiondate`, `encrypted`, `updatepriority`, `dependencies`, `onlinedependencies`, `size`, `checksum`, `hasfpo`, `haspreview`, `separatecomponents`,
								            `hiddenfromuser`, `hasdesktoplayouts`, `hasonlinelayouts`, `webbrandcode`)
                                            VALUES (0, now(), ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'))
                                    {
                                        if ($stmt->bind_param('sississss' . 'ssssiissds' . 'iiiiiis', $pCompanyCode, $pItemType, $pItemRef,
                                                        $pItemAppVersion, $pItemDataVersion, $pItemCategoryCode, $pItemCategoryName,
                                                        $pItemName, $pItemDescription, $pItemProducts, $pItemThemes, $pItemFileName,
                                                        $pItemDateModified, $isEncrypted, $pItemPriority, $pItemDependencies,
                                                        $pItemOnlineDependencies, $pItemSize, $pItemChecksum, $hasFPO, $hasPreview,
                                                        $isSeparateComponents, $isHiddenFromUser, $hasDesktopLayouts, $hasOnlineLayouts,
                                                        $pItemWebBrandCode))
                                        {
                                            if (!$stmt->execute())
                                            {
                                                // could not execute statement
                                                $result = 'str_DatabaseError';
                                                $resultParam = 'uploadApplicationFilesUpdate insert execute ' . $dbObj->error;
                                            }
                                            else
                                            {
                                                $recordID = $dbObj->insert_id;
                                            }
                                        }
                                        else
                                        {
                                            // could not bind parameters
                                            $result = 'str_DatabaseError';
                                            $resultParam = 'uploadApplicationFilesUpdate insert bind ' . $dbObj->error;
                                        }
                                        $stmt->free_result();
                                        $stmt->close();
                                        $stmt = null;
                                    }
                                    else
                                    {
                                        // could not prepare statement
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'uploadApplicationFilesUpdate insert prepare ' . $dbObj->error;
                                    }
                                }
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'uploadApplicationFilesUpdate store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'uploadApplicationFilesUpdate execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'uploadApplicationFilesUpdate bind params ' . $dbObj->error;
                }
                if ($stmt)
                {
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'uploadApplicationFilesUpdate init prepare ' . $dbObj->error;
            }
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'uploadApplicationFilesUpdate connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;

        return $resultArray;
    }

    /**
     * Updates the database with the license key update file data supplied by TAOPIX™ Builder
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 1.0.0
     */
    static function uploadLicenseKeysUpdate($pLicenseKeyUpdateArray)
    {
        $result = '';
        $resultParam = '';
        $companyCode = $pLicenseKeyUpdateArray['companycode'];
        $groupCode = $pLicenseKeyUpdateArray['groupcode'];
        $fileName = $pLicenseKeyUpdateArray['filename'];
        $fileSize = $pLicenseKeyUpdateArray['size'];
        $fileChecksum = $pLicenseKeyUpdateArray['checksum'];
        $filePriority = $pLicenseKeyUpdateArray['priority'];
        $maxOrderBatchSize = $pLicenseKeyUpdateArray['maxorderbatchsize'];
        $version = $pLicenseKeyUpdateArray['version'];
        $dataVersion = $pLicenseKeyUpdateArray['dataversion'];
        $customerName = $pLicenseKeyUpdateArray['companyname'];
        $customerAddress1 = $pLicenseKeyUpdateArray['address1'];
        $customerAddress2 = $pLicenseKeyUpdateArray['address2'];
        $customerAddress3 = $pLicenseKeyUpdateArray['address3'];
        $customerAddress4 = $pLicenseKeyUpdateArray['address4'];
        $customerAddressCity = $pLicenseKeyUpdateArray['city'];
        $customerAddressCounty = $pLicenseKeyUpdateArray['county'];
        $customerAddressState = $pLicenseKeyUpdateArray['state'];
        $customerRegionCode = $pLicenseKeyUpdateArray['regioncode'];
        $customerRegion = 'STATE';
        $customerPostCode = $pLicenseKeyUpdateArray['postcode'];
        $customerCountryCode = $pLicenseKeyUpdateArray['countrycode'];
        $customerEmailAddress = $pLicenseKeyUpdateArray['email'];
        $customerTelephoneNumber = $pLicenseKeyUpdateArray['telephonenumber'];
        $customerContactFirstName = $pLicenseKeyUpdateArray['contactfirstname'];
        $customerContactLastName = $pLicenseKeyUpdateArray['contactlastname'];
        $customerCountryName = UtilsAddressObj::getCountryNameFromCode($customerCountryCode);

        // try and match region to get a region code
        // use 'regionCode' field to see if address has new format
        if (($customerCountryCode != '') && ($customerRegionCode == ''))
        {
            // first see if state or county is actually region code,
            // i.e. the customer has entered 'CA' and not 'California'
            $match = UtilsAddressObj::getRegionCodeFromCode($customerCountryCode, $customerAddressState, $customerAddressCounty);

            // if no match found, try to match the region name
            if ($match['regioncode'] == '')
            {
                $match = UtilsAddressObj::getRegionCodeFromName($customerCountryCode, $customerAddressState, $customerAddressCounty);
            }
            // if region is STATE,  $match[regioncode] holds state code
            // if region is COUNTY, $match[regioncode] holds county code
            $customerRegionCode = $match['regioncode'];
            $customerRegion = $match['region'];

            if ($customerRegionCode != '')
            {
                if ($customerRegion == 'STATE')
                {
                    $customerAddressState = $match['regionname'];
                }
                else
                {
                    $customerAddressCounty = $match['regionname'];
                }
            }
        }

        $licenseKeyArray = self::getLicenseKeyFromCode($groupCode);
        if ($licenseKeyArray['result'] == '')
        {
            // we already have a license key record so just update it
            $dbObj = DatabaseObj::getGlobalDBConnection();
            if ($dbObj)
            {
                if ($stmt = $dbObj->prepare('UPDATE `LICENSEKEYS` SET `companycode` = ?, `name` = ?, `address1` = ?, `address2` = ?, `address3` = ?, `address4` = ?, `city` = ?, `county` = ?,
