    static function getProductNamesList($companyCode = '', $pOrderRoutingAdminCall = false)
    {
        // return an array containing the TAOPIX product record id's, codes and names
        global $gSession;

        $productNamesList = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {

            switch ($gSession['userdata']['usertype'])
            {
                case TPX_LOGIN_SYSTEM_ADMIN:
                    // getting companies for the system administrator
                    if ($pOrderRoutingAdminCall)
                    {
                        $stmt = $dbObj->prepare('SELECT `id`, `code`, `name` FROM `PRODUCTS` WHERE `deleted` = 0 ORDER BY `code`');
                        $bindOK = true;
                    }
                    else
                    {
                        $stmt = $dbObj->prepare('SELECT `id`, `code`, `name` FROM `PRODUCTS` WHERE `deleted` = 0 AND (`companycode` = ? OR `companycode` = "") ORDER BY `code`');
                        $bindOK = $stmt->bind_param('s', $companyCode);
                    }

                    break;
                case TPX_LOGIN_COMPANY_ADMIN:
                    // getting companies comboBox based on companycode of company administrator
                    $stmt = $dbObj->prepare('SELECT `id`, `code`, `name` FROM `PRODUCTS` WHERE `deleted` = 0 AND (`companycode` = ? OR `companycode` = "") ORDER BY `code`');
                    $bindOK = $stmt->bind_param('s', $gSession['userdata']['companycode']);
                    break;
            }

            if ($stmt)
            {
                if ($bindOK)
                {
                    if ($stmt->bind_result($productID, $productCode, $productName))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $productItem['id'] = $productID;
                                $productItem['code'] = $productCode;
                                $productItem['name'] = $productName;
                                array_push($productNamesList, $productItem);
                            }
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        return $productNamesList;
    }

