    static function getOrderLanguage($pOrderID)
    {
        // return the language code used when the order process was performed

        $result = '';
        $recordID = 0;
        $languageCode = '';
        $error = '';

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `id`, `languagecode` FROM `ORDERHEADER` WHERE `id` = ?'))
            {
                if ($stmt->bind_param('i', $pOrderID))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($recordID, $languageCode))
                                {
                                    if ($stmt->fetch())
                                    {
                                        $result = $languageCode;
                                    }
                                    else
                                    {
                                        $error = __FUNCTION__ . ' fetch ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    $error = __FUNCTION__ . ' bind result ' . $dbObj->error;
                                }
                            }
                        }
                        else
                        {
                            $error = __FUNCTION__ . ' store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        $error = __FUNCTION__ . ' execute ' . $dbObj->error;
                    }
                }
                else
                {
                    $error = __FUNCTION__ . ' bind param ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        return $result;
    }

    static function convertIDList2SQL($pIDList, $pColumnName)
    {
        $theResult = '';

        $idListArray = explode(',', $pIDList);
        $itemCount = count($idListArray);
        if ($itemCount > 0)
        {
            $theResult = $theResult . '(';
            for ($i = 0; $i < $itemCount; $i++)
            {
                $theResult .= '(' . $pColumnName . ' = ' . $idListArray[$i] . ')';
                if ($i < ($itemCount - 1))
                {
                    $theResult .= ' OR ';
                }
            }
            $theResult .= ')';
        }

        return $theResult;
    }


    static function getOrderListCart($pUserID, $pLocale)
    {
        // return an array containing the orders that meet the specified criteria
        $itemsArray = Array();
		$error = '';
		$errorParam = '';
		$onlineProjectPresent = false;

		$systemConfigDataArray = DatabaseObj::getSystemConfig();
		if ($systemConfigDataArray['result'] == '')
		{
			$dbObj = self::getGlobalDBConnection();
			if ($dbObj)
			{
				$sqlStatement = "SELECT oi.id, oi.orderid, oi.projectref, oi.projectname, oi.productname, oi.uploadref, oi.status, oh.orderdate,
										oh.ordernumber, oh.total, oh.currencysymbol, oh.currencysymbolatfront, oh.currencydecimalplaces,
										oi.active, oi.previewsonline, oi.origorderid, oh.temporder, oh.temporderexpirydate,
										oh.sessionid, oi.source, oi.producttype, oi.canreorder, oi.canmodify, oi.productcollectioncode, oi.productcode, oi.parentorderitemid, oh.paymentreceived,
										oh.groupcode,
                                        IF (oi.productiondata = 0 AND oi.ftpdata = 0 AND oi.dbdata = '0000-00-00 00:00:00', 1, 0) as dataavailable
								FROM `ORDERITEMS` oi
									JOIN `ORDERHEADER` oh ON (oh.id = oi.orderid)
									LEFT JOIN PRODUCTS pr ON (pr.code = oi.productcode)
								WHERE ((oi.active = ?)
										OR (oi.active = ?)
										OR (oi.active = ?))
									AND (oh.userid = ?)
                                    AND (oh.redacted = 0)
								ORDER BY oh.id DESC";

				$stmt = $dbObj->prepare($sqlStatement);
				if ($stmt)
				{
					$statusCancelled = TPX_ORDER_STATUS_CANCELLED;
					$statusCompleted = TPX_ORDER_STATUS_COMPLETED;
					$statusInProgress = TPX_ORDER_STATUS_IN_PROGRESS;
					if ($stmt->bind_param('iiii', $statusCancelled, $statusCompleted, $statusInProgress, $pUserID))
					{
						if ($stmt->execute())
						{
							if ($stmt->store_result())
							{
								if ($stmt->num_rows > 0)
								{
									if ($stmt->bind_result($id, $orderid, $projectRef, $projectname, $productname, $uploadref, $status, $orderdate,
										$ordernumber, $total, $currencysymbol, $currencysymbolatfront, $currencydecimalplaces,
										$orderstatus, $previewsonline, $origorderid, $temporder, $temporderexpirydate,
										$sessionid, $source, $producttype, $canreorder, $canmodify, $productcollectioncode, $productcode, $parentorderitemid, $paymentreceived, $groupCode, $dataavailable))
									{

										$existingIDArray = array();
										while ($stmt->fetch())
										{
											// the sql statement may return multiple copies of the same row
											// the quickest way is to filter the list via a hash table
											if (!isset($existingIDArray[$id]))
											{
												$queueItem['id'] = $id;

												$queueItem['orderid'] = $orderid;
												$queueItem['projectname'] = $projectname;
												$queueItem['projectref'] = $projectRef;
												$queueItem['productname'] = LocalizationObj::getLocaleString($productname, $pLocale, true);
												$queueItem['uploadref'] = $uploadref;
												$queueItem['status'] = $status;
												$queueItem['ordernumber'] = $ordernumber;
												$queueItem['orderstatus'] = $orderstatus;
												$queueItem['canreorder'] = $canreorder;
												$queueItem['canmodify'] = $canmodify;
                                                $queueItem['parentorderitemid'] = $parentorderitemid;
                                                $queueItem['paymentreceived'] = $paymentreceived;
												$queueItem['previewimage'] = UtilsObj::getAssetRequest($productcode, 'products');
												if ($source == TPX_SOURCE_ONLINE)
												{
													// If data is not available then the order data has been deleted and can't have a preview.
													$queueItem['previewsonline'] = $dataavailable;
												}
												else
												{
													$queueItem['previewsonline'] = $previewsonline;
												}

												$queueItem['temporder'] = $temporder;
												$queueItem['temporderexpirydate'] = $temporderexpirydate;
												$queueItem['sessionid'] = $sessionid;
												$queueItem['source'] = $source;
												$queueItem['workflowtype'] = $producttype;
												$queueItem['formatteddateexpires'] = LocalizationObj::formatLocaleDate($temporderexpirydate, $pLocale);
												$queueItem['formattedorderdate'] = LocalizationObj::formatLocaleDate($orderdate, $pLocale);
												$queueItem['formattedordertotal'] = UtilsObj::formatCurrencyNumber($total, $currencydecimalplaces,
													$pLocale, $currencysymbol, $currencysymbolatfront);
												$productIdent = UtilsObj::encryptData($productcollectioncode . chr(9) . $productcode . chr(9) . $groupCode,
														$systemConfigDataArray['systemkey'], true);
												$queueItem['productindent'] = $productIdent;
                                                $queueItem['dataavailable'] = $dataavailable;

												//mark online projects as present if true
												if ($source == TPX_SOURCE_ONLINE)
												{
													$onlineProjectPresent = true;
												}
											}

											$itemsArray[] = $queueItem;

											$existingIDArray[$id] = true;

										}
									}
									else
									{
										$error = 'str_DatabaseError';
										$errorParam = 'getOrderListCart bind_result';
									}
								}
							}
							else
							{
								$error = 'str_DatabaseError';
								$errorParam = 'getOrderListCart store_result';
							}
						}
						else
						{
							$error = 'str_DatabaseError';
							$errorParam = 'getOrderListCart execute';
						}

						// if the query failed for some reason we may still have a statement so get rid of it now
						if ($stmt)
						{
							$stmt->free_result();
							$stmt->close();
							$stmt = null;
						}
					}
					else
					{
						$error = 'str_DatabaseError';
						$errorParam = 'getOrderListCart bind_param';
					}
					$dbObj->close();
				}
				else
				{
					$error = 'str_DatabaseError';
					$errorParam = 'getOrderListCart prepare';
				}
			}
			else
			{
				// could not open database connection
				$error = 'str_DatabaseError';
				$errorParam = 'getOrderListCart connect ' . $dbObj->error;
			}
		}
		else
		{
			// could not open database connection
			$error = $systemConfigDataArray['result'];
			$errorParam = $systemConfigDataArray['resultparam'];
		}
		//create return array from parts
		$returnArray = array ('items' => $itemsArray, 'error' => $error, 'errorparam' => $errorParam, 'onlineprojectpresent' => $onlineProjectPresent);

        return $returnArray;
    }

    static function getOrderListCollectFromStore($dcId, $storeId, $pOwner, $pUserID, $pOrderNumber, $pOrderItemActive,
            $pOrderStatusWaitingForPayment, $pItemStatus, $pItemStatusOnHold, $pSort, $pLocale, $pSortField, $searchFields, $searchValue)
    {
        // return an array containing the orders that meet the specified criteria

        global $gConstants;

        $resultArray = Array();
        $itemsArray = Array();
        $params = Array();
        $sqlBindTypes = '';

        $sqlStatement = 'SELECT oi.id, oi.datelastmodified, oi.currentowner, oi.ownerorderkey, oi.orderid, oi.userid, oi.projectname, oi.productcode, oi.productname, oi.productheight,
	        oi.productwidth,
        	IF (oic.componentlocalcode IS NULL, "", oic.componentlocalcode) as covercode,
        	IF (oic.componentname IS NULL, "", oic.componentname) as covername,
        	IF (oip.componentdefaultcode IS NULL, "", oip.componentdefaultcode) as productdefaultpapercode,
        	IF (oip.componentlocalcode IS NULL, "", oip.componentlocalcode) as papercode,
        	IF (oip.componentname IS NULL, "", oip.componentname) as papername,
	        oi.qty, oi.pagecount, oi.uploaddatatype, oi.uploadmethod, oi.uploadref, oi.jobticketoutputfilename, oi.pagesoutputfilename, oi.cover1outputfilename, oi.cover2outputfilename,
	        oi.jobticketoutputdevicecode, oi.pagesoutputdevicecode, oi.cover1outputdevicecode, oi.cover2outputdevicecode, oi.onhold, oi.onholdreason, oi.status, oi.statusdescription,
	        oh.datelastmodified, oh.shoppingcarttype, oh.orderdate, oh.ordernumber, oh.total, oh.currencysymbol, oh.currencysymbolatfront, oh.currencydecimalplaces, oh.paymentreceived,
	        oi.active, oh.groupcode, oh.webbrandcode, oh.billingcustomername, oh.billingcustomeraddress1, oh.billingcustomeraddress2, oh.billingcustomeraddress3,
	        oh.billingcustomeraddress4, oh.billingcustomercity, oh.billingcustomercounty, oh.billingcustomerstate, oh.billingcustomerregioncode, oh.billingcustomerregion,
	        oh.billingcustomerpostcode, oh.billingcustomercountrycode, oh.billingcustomercountryname, oh.billingcustomertelephonenumber, oh.billingcustomeremailaddress,
	        oh.billingcontactfirstname, oh.billingcontactlastname, oh.paymentreceiveddate, os.storecode,
	        oi.shippeddistributioncentrereceiveddate, oi.shippeddistributioncentreshippeddate, oi.shippedstorereceiveddate, oi.shippedcustomercollecteddate, oi.shippingtrackingreference
	        FROM ORDERITEMS oi
	        JOIN ORDERHEADER oh ON (oh.id = oi.orderid)
	        LEFT JOIN `ORDERSHIPPING` os ON (os.orderid = oi.orderid)
			LEFT JOIN ORDERITEMCOMPONENTS oic ON (oi.id = oic.orderitemid) AND (oic.componentcategorycode="COVER")
			LEFT JOIN ORDERITEMCOMPONENTS oip ON (oi.id = oip.orderitemid) AND (oip.componentcategorycode="PAPER")';

        if ($pOrderNumber != '')
        {
            $sqlStatement = $sqlStatement . 'WHERE (oh.ordernumber = ?)';
            $params[] = $pOrderNumber;
            $sqlBindTypes .= 's';
        }
        else
        {
            if ($pOrderItemActive < 3)
            {
                $sqlStatement = $sqlStatement . 'WHERE (oi.active = ?)';
                $params[] = $pOrderItemActive;
                $sqlBindTypes .= 'i';
            }
            else
            {
                $sqlStatement = $sqlStatement . 'WHERE ((oi.active = 1) OR (oi.active = 2))';
            }
        }

        if ($pUserID > 0)
        {
            $sqlStatement = $sqlStatement . ' AND (oh.userid = ?)';
            $params[] = $pUserID;
            $sqlBindTypes .= 'i';
        }

        if ($pOrderStatusWaitingForPayment == '1')
        {
            $sqlStatement = $sqlStatement . ' AND (oh.paymentreceived = 0)';
        }

        if ($pItemStatusOnHold == '1')
        {
            $sqlStatement = $sqlStatement . ' AND (oi.onhold = 1)';
        }

        if ($pItemStatus != '')
        {
            $listSQL = self::convertIDList2SQL($pItemStatus, 'oi.status');
            if ($listSQL != '')
            {
                $sqlStatement .= ' AND ' . $listSQL;
            }
        }

        if (($pOwner != '**ALL**') && ($gConstants['optionms']))
        {
            $sqlStatement .= ' AND (oi.currentowner = ?)';
            $params[] = $pOwner;
            $sqlBindTypes .= 's';
        }

        if ($dcId != '-1')
        {
            $sqlStatement .= ' AND (os.distributioncentrecode = ?)';
            $params[] = $dcId;
            $sqlBindTypes .= 's';
        }
        else
        {
            $sqlStatement .= ' AND (os.storecode = ?)';
            $params[] = $storeId;
            $sqlBindTypes .= 's';
        }


        if ($searchFields != '')
        {
            $searchQuery = $searchValue;
            $selectedfields = str_replace("[", "", $searchFields);
            $selectedfields = str_replace("]", "", $selectedfields);
            $selectedfields = str_replace('"', "", $selectedfields);
            $selectedfields = explode(',', $selectedfields);

            $i = 1;
            $stmt = '';
            if ($searchQuery != '')
            {
                foreach ($selectedfields as $value)
                {
                    if ($i == 1)
                    {
                        $operator = ' AND (';
                    }
                    else
                    {
                        $operator = 'OR';
                    }
                    $params[] = '%' . $searchQuery . '%';

                    switch ($value)
                    {
                        case 'orderDate':
                            $value = 'oh.orderdate';
                            break;
                        case 'orderNumber':
                            $value = 'oh.ordernumber';
                            break;
                        case 'productName':
                            $value = 'oi.productname';
                            break;
                        case 'qty':
                            $value = 'oi.qty';
                            break;
                        case 'orderTotal':
                            $value = 'oh.total';
                            break;
                        case 'paymentConfirmed':
                            $value = 'oh.paymentreceived';
                            break;
                        case 'status':
                            $value = 'oi.status';
                            break;
                        case 'billingContactFirstName':
                            $value = 'oh.billingcontactfirstname';
                            break;
                        case 'billingContactLastName':
                            $value = 'oh.billingcontactlastname';
                            break;
                        case 'shippingRef':
                            $value = 'oi.shippingtrackingreference';
                            break;
                        case 'storeCode':
                            $value = 'os.storecode';
                            break;
                    }

                    $stmt .= $operator . '(' . $value . ' LIKE ?)';
                    $sqlBindTypes .= 's';
                    $i++;
                }
                $stmt .= ')';
                $bind = 1;
            }
            else
            {
                $bind = 0;
            }
            $sqlStatement = $sqlStatement . $stmt;
        }
        if ($pSort)
        {
            switch ($pSortField)
            {
                case 'orderDate':
                    $pSortField = 'oh.orderdate';
                    break;
                case 'orderNumber':
                    $pSortField = 'oh.ordernumber';
                    break;
                case 'productName':
                    $pSortField = 'oi.productname';
                    break;
                case 'qty':
                    $pSortField = 'oi.qty';
                    break;
                case 'orderTotal':
                    $pSortField = 'oh.total';
                    break;
                case 'paymentConfirmed':
                    $pSortField = 'oh.paymentreceived';
                    break;
                case 'status':
                    $pSortField = 'oi.status';
                    break;
                case 'billingContactFirstName':
                    $pSortField = 'oh.billingcontactfirstname';
                    break;
                case 'billingContactLastName':
                    $pSortField = 'oh.billingcontactlastname';
                    break;
                case 'shippingRef':
                    $pSortField = 'oi.shippingtrackingreference';
                    break;
                case 'storeCode':
                    $pSortField = 'os.storecode';
                    break;
                default:
                    $pSortField = 'oh.ordernumber';
            }

            $sqlStatement = $sqlStatement . ' ORDER BY ' . $pSortField . ' ' . $pSort;
        }
        else
        {
            $sqlStatement = $sqlStatement . ' ORDER BY oh.ordernumber';
        }


        $bind_names[] = $sqlBindTypes;
        for ($i = 0; $i < count($params); $i++)
        {         //go through incoming params and added em to array
            $bind_name = 'bind' . $i;       //give them an arbitrary name
            $$bind_name = $params[$i];     //add the parameter to the variable variable
            $bind_names[] = &$$bind_name;   //now associate the variable as an element in an array
        }

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);
                $bindOk = call_user_func_array(array($stmt, 'bind_param'), $bind_names);
                if ($bindOk)
                {
                    if ($stmt->bind_result($id, $dateLastModified, $currentOwner, $ownerOrderKey, $orderID, $userID, $projectName,
                                    $productCode, $productName, $productHeight, $productWidth, $coverCode, $coverName, $defaultPaperCode,
                                    $paperCode, $paperName, $qty, $pageCount, $uploadDataType, $uploadMethod, $uploadRef,
                                    $jobTicketOutputFilename, $pagesOutputFilename, $cover1OutputFilename, $cover2OutputFilename,
                                    $jobTicketOutputDeviceCode, $pagesOutputDeviceCode, $cover1OutputDeviceCode, $cover2OutputDeviceCode,
                                    $onHold, $onHoldReason, $status, $statusDescription, $orderDateLastModified, $orderShoppingCartType,
                                    $orderDate, $orderNumber, $orderTotal, $orderCurrencySymbol, $orderCurrencySymbolAtFront,
                                    $orderCurrencyDecimalPlaces, $paymentReceived, $orderItemActive, $groupCode, $brandCode, $companyName,
                                    $billingcustomeraddress1, $billingcustomeraddress2, $billingcustomeraddress3, $billingcustomeraddress4,
                                    $billingcustomercity, $billingcustomercounty, $billingcustomerstate, $billingcustomerregioncode,
                                    $billingcustomerregion, $billingcustomerpostcode, $billingcustomercountrycode,
                                    $billingcustomercountryname, $billingcustomertelephonenumber, $billingcustomeremailaddress,
                                    $contactFirstName, $contactLastName, $paymentreceiveddate, $storeCode,
                                    $shippeddistributioncentrereceiveddate, $shippeddistributioncentreshippeddate,
                                    $shippedstorereceiveddate, $shippedcustomercollecteddate, $shippingRef))
                    {
                        if ($stmt->execute())
                        {
                            // process each item
                            while ($stmt->fetch())
                            {

                                $queueItem['id'] = $id;
                                $queueItem['currentowner'] = $currentOwner;
                                $queueItem['ownerorderkey'] = $ownerOrderKey;
                                $queueItem['orderid'] = $orderID;
                                $queueItem['userid'] = $userID;
                                $queueItem['projectname'] = $projectName;
                                $queueItem['productcode'] = $productCode;
                                $queueItem['productname'] = LocalizationObj::getLocaleString($productName, $pLocale, true);
                                $queueItem['productheight'] = $productHeight;
                                $queueItem['productwidth'] = $productWidth;
                                $queueItem['covercode'] = $coverCode;
                                $queueItem['covername'] = LocalizationObj::getLocaleString($coverName, $pLocale, true);
                                $queueItem['defaultpapercode'] = $defaultPaperCode;
                                $queueItem['papercode'] = $paperCode;
                                $queueItem['papername'] = LocalizationObj::getLocaleString($paperName, $pLocale, true);
                                $queueItem['qty'] = $qty;
                                $queueItem['pagecount'] = $pageCount;
                                $queueItem['uploaddatatype'] = $uploadDataType;
                                $queueItem['uploadmethod'] = $uploadMethod;
                                $queueItem['uploadref'] = $uploadRef;
                                $queueItem['jobticketoutputfilename'] = $jobTicketOutputFilename;
                                $queueItem['pagesoutputfilename'] = $pagesOutputFilename;
                                $queueItem['cover1outputfilename'] = $cover1OutputFilename;
                                $queueItem['cover2outputfilename'] = $cover2OutputFilename;
                                $queueItem['jobticketoutputdevicecode'] = $jobTicketOutputDeviceCode;
                                $queueItem['pagesoutputdevicecode'] = $pagesOutputDeviceCode;
                                $queueItem['cover1outputdevicecode'] = $cover1OutputDeviceCode;
                                $queueItem['cover2outputdevicecode'] = $cover2OutputDeviceCode;
                                $queueItem['onhold'] = $onHold;
                                $queueItem['onholdreason'] = $onHoldReason;
                                $queueItem['status'] = $status;
                                $queueItem['statusdescription'] = $statusDescription;
                                $queueItem['shoppingcarttype'] = $orderShoppingCartType;
                                $queueItem['orderdate'] = $orderDate;
                                $queueItem['ordernumber'] = $orderNumber;
                                $queueItem['paymentreceived'] = $paymentReceived;
                                $queueItem['orderstatus'] = $orderItemActive;
                                $queueItem['groupcode'] = $groupCode;
                                $queueItem['brandcode'] = $brandCode;
                                $queueItem['companyname'] = $companyName;
                                $queueItem['billingcustomeraddress1'] = $billingcustomeraddress1;
                                $queueItem['billingcustomeraddress2'] = $billingcustomeraddress2;
                                $queueItem['billingcustomeraddress3'] = $billingcustomeraddress3;
                                $queueItem['billingcustomeraddress4'] = $billingcustomeraddress4;
                                $queueItem['billingcustomercity'] = $billingcustomercity;
                                $queueItem['billingcustomercounty'] = $billingcustomercounty;
                                $queueItem['billingcustomerstate'] = $billingcustomerstate;
                                $queueItem['billingcustomerregioncode'] = $billingcustomerregioncode;
                                $queueItem['billingcustomerregion'] = $billingcustomerregion;
                                $queueItem['billingcustomerpostcode'] = $billingcustomerpostcode;
                                $queueItem['billingcustomercountrycode'] = $billingcustomercountrycode;
                                $queueItem['billingcustomercountryname'] = $billingcustomercountryname;
                                $queueItem['billingcustomertelephonenumber'] = $billingcustomertelephonenumber;
                                $queueItem['billingcustomeremailaddress'] = $billingcustomeremailaddress;
                                $queueItem['contactfirstname'] = $contactFirstName;
                                $queueItem['contactlastname'] = $contactLastName;
                                $queueItem['ordertotal'] = $orderTotal;
                                $queueItem['paymentreceiveddate'] = $paymentreceiveddate;

                                if ($shippeddistributioncentrereceiveddate != '0000-00-00 00:00:00')
                                {
                                    $queueItem['bookedDCConfirmed'] = '1';
                                    $queueItem['bookedDCConfirmedDate'] = LocalizationObj::formatLocaleDate($shippeddistributioncentrereceiveddate);
                                    $queueItem['bookedDCConfirmedTime'] = LocalizationObj::formatLocaleTime($shippeddistributioncentrereceiveddate);
                                }
                                else
                                {
                                    $queueItem['bookedDCConfirmed'] = '0';
                                    $queueItem['bookedDCConfirmedDate'] = '';
                                    $queueItem['bookedDCConfirmedTime'] = '';
                                }

                                if ($shippeddistributioncentreshippeddate != '0000-00-00 00:00:00')
                                {
                                    $queueItem['shippedToStoreConfirmed'] = '1';
                                    $queueItem['shippedToStoreConfirmedDate'] = LocalizationObj::formatLocaleDate($shippeddistributioncentreshippeddate);
                                    $queueItem['shippedToStoreConfirmedTime'] = LocalizationObj::formatLocaleTime($shippeddistributioncentreshippeddate);
                                }
                                else
                                {
                                    $queueItem['shippedToStoreConfirmed'] = '0';
                                    $queueItem['shippedToStoreConfirmedDate'] = '';
                                    $queueItem['shippedToStoreConfirmedTime'] = '';
                                }

                                if ($shippedstorereceiveddate != '0000-00-00 00:00:00')
                                {
                                    $queueItem['bookedconfirmed'] = '1';
                                    $queueItem['bookedconfirmeddate'] = LocalizationObj::formatLocaleDate($shippedstorereceiveddate);
                                    $queueItem['bookedconfirmedtime'] = LocalizationObj::formatLocaleTime($shippedstorereceiveddate);
                                }
                                else
                                {
                                    $queueItem['bookedconfirmed'] = '0';
                                    $queueItem['bookedconfirmeddate'] = '';
                                    $queueItem['bookedconfirmedtime'] = '';
                                }

                                if ($shippedcustomercollecteddate != '0000-00-00 00:00:00')
                                {
                                    $queueItem['collectedConfirmed'] = '1';
                                    $queueItem['collectedConfirmedDate'] = LocalizationObj::formatLocaleDate($shippedcustomercollecteddate);
                                    $queueItem['collectedConfirmedTime'] = LocalizationObj::formatLocaleTime($shippedcustomercollecteddate);
                                }
                                else
                                {
                                    $queueItem['collectedConfirmed'] = '0';
                                    $queueItem['collectedConfirmedDate'] = '';
                                    $queueItem['collectedConfirmedTime'] = '';
                                }

                                $queueItem['storeCode'] = $storeCode;

                                if ($pLocale != '')
                                {
                                    $queueItem['orderdate'] = LocalizationObj::formatLocaleDate($orderDate, $pLocale);
                                    $queueItem['paymentreceiveddate'] = LocalizationObj::formatLocaleDate($paymentreceiveddate, $pLocale);
                                    $queueItem['ordertotal'] = UtilsObj::formatCurrencyNumber($orderTotal, $orderCurrencyDecimalPlaces,
                                                    $pLocale, $orderCurrencySymbol, $orderCurrencySymbolAtFront);
                                }
                                $queueItem['shippingRef'] = $shippingRef;

                                array_push($itemsArray, $queueItem);
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getOrderList execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = 'getOrderList bind result ' . $dbObj->error;
                    }
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getOrderList prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getOrderList connect ' . $dbObj->error;
        }

        $resultArray['items'] = &$itemsArray;

        return $resultArray;
    }

