    static function updateCustomerAccountBalance($pUserID, $pAccountBalanceDifference)
    {
        global $gConstants;
        global $gSession;

        $balanceUpdated = false;

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('UPDATE `USERS` SET `accountbalance` = `accountbalance` + ? WHERE `id` = ?'))
            {
                if ($stmt->bind_param('di', $pAccountBalanceDifference, $pUserID))
                {
                    if ($stmt->execute())
                    {
                        $balanceUpdated = true;
                    }
                }

                $stmt->free_result();
                $stmt->close();
            }

            $dbObj->close();
        }

        if ($balanceUpdated)
        {
            if (($gConstants['optionwscrp']) && (file_exists('../Customise/scripts/EDL_ExternalCustomerAccount.php')))
            {
                require_once('../Customise/scripts/EDL_ExternalCustomerAccount.php');

                if (method_exists('ExternalCustomerAccountObj', 'updateGiftCardBalance'))
                {
                    $userAccountArray = self::getUserAccountFromID($pUserID);
                    $licenseKeyArray = self::getLicenseKeyFromCode($userAccountArray['groupcode']);

                    $paramArray = Array();
                    $paramArray['languagecode'] = UtilsObj::getBrowserLocale();
                    $paramArray['groupcode'] = $userAccountArray['groupcode'];
                    $paramArray['brandcode'] = $licenseKeyArray['webbrandcode'];
                    $paramArray['id'] = $pUserID;
                    $paramArray['login'] = $userAccountArray['login'];
                    $paramArray['accountcode'] = $userAccountArray['accountcode'];
                    $paramArray['accountbalancedifference'] = $pAccountBalanceDifference;

                    $externalResponse = ExternalCustomerAccountObj::updateAccountBalance($paramArray);
                }
            }
        }
    }

