    /**
     * Update the email address and login of a user account.
     *
     * @param array $pUpdateEmailData - new email address data for the account
     * @param boolean $pUpdateLogin - if true, update the login field at the same time.
     * @return string
     */
    static function updateAccountEmailAndLogin($pUpdateEmailData, $pUpdateLogin)
    {
        $resultArray = array('result' => '', 'resultparam' => '');

        // Create the update SQL.
        $sql = 'UPDATE `USERS` SET `emailaddress` = ?';
        $bindParams = array('s', $pUpdateEmailData['new']);

        // If the login and the email address needs to be updated, add this to the query.
        if ($pUpdateLogin)
        {
            $sql .= ', `login` = ?';
            $bindParams[0] .= 's';
            $bindParams[] = $pUpdateEmailData['new'];
        }

        $sql .= ' WHERE `id` = ?';
        $bindParams[0] .= 'i';
        $bindParams[] = $pUpdateEmailData['userid'];

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            // Prepare the SQL.
            $stmt = $dbObj->prepare($sql);
            if ($stmt)
            {
                // Bind the parameters.
                $bindOK = $stmt->bind_param(...$bindParams);
                if ($bindOK)
                {
                    // Execute the SQL.
                    if (! $stmt->execute())
                    {
                        // The SQL failed, return an error.
                        $resultArray['result'] = 'str_DatabaseError';
                        $resultArray['resultparam'] = __FUNCTION__ . ' execute ' . $dbObj->error;
                    }
                }
                else
                {
                    $resultArray['result'] = 'str_DatabaseError';
                    $resultArray['resultparam'] = __FUNCTION__ . ' bind_param ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                $resultArray['result'] = 'str_DatabaseError';
                $resultArray['resultparam'] = __FUNCTION__ . ' prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            $resultArray['result'] = 'str_DatabaseError';
            $resultArray['resultparam'] = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        return $resultArray;
    }

    static function deleteOrderThumbnails($pUploadRef)
    {
        // delete the specified order thumbnails

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('DELETE FROM `ORDERTHUMBNAILS` WHERE `uploadref` = ?'))
            {
                if ($stmt->bind_param('s', $pUploadRef))
                {
                    $result = $stmt->execute();
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }
    }

    static function insertOrderThumbnails($pUploadRef, $pOrderThumbnailData)
    {
        // insert the order thumbnail data into the database
        // we perform all actions within a single transaction so we must be prepared to handle deadlocks

        $result = '';
        $resultParam = '';
        $previewsOnline = 0;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $transactionCommited = false;
            $retryCount = 3;

            while (! $transactionCommited)
            {
                $dbObj->query('START TRANSACTION');

                $result = '';
                $resultParam = '';

                if ($stmt = $dbObj->prepare('DELETE FROM `ORDERTHUMBNAILS` WHERE `uploadref` = ?'))
                {
                    if ($stmt->bind_param('s', $pUploadRef))
                    {
                        if (!$stmt->execute())
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'insertOrderThumbnails execute ' . $dbObj->error;

                            // if the error was not a deadlock reduce the amount of times we can retry
                            if ($dbObj->error != 1213)
                            {
                                $dbObj->query('ROLLBACK');

                                $retryCount--;
                            }
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $dbObj->query('ROLLBACK');

                        $result = 'str_DatabaseError';
                        $resultParam = 'insertOrderThumbnails bind ' . $dbObj->error;

                        $retryCount--;
                    }

                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $dbObj->query('ROLLBACK');

                    $result = 'str_DatabaseError';
                    $resultParam = 'insertOrderThumbnails prepare ' . $dbObj->error;

                    $retryCount--;
                }


                // if no error has occurred the previous order thumbnails have been deleted so now insert the new ones
                if ($result == '')
                {
                    if ($stmt = $dbObj->prepare('INSERT INTO `ORDERTHUMBNAILS` (`id`, `datecreated`, `uploadref`, `pageref`, `pagename`, `width`, `height`, `version`) VALUES (0, now(), ?, ?, ?, ?, ?, ?)'))
                    {
                        $itemCount = count($pOrderThumbnailData);
                        for ($i = 0; $i < $itemCount; $i++)
                        {
                            if ($stmt->bind_param('sssiii', $pUploadRef, $pOrderThumbnailData[$i]['pageref'],
                                            $pOrderThumbnailData[$i]['pagename'], $pOrderThumbnailData[$i]['thumbwidth'],
                                            $pOrderThumbnailData[$i]['thumbheight'], $pOrderThumbnailData[$i]['previewversion']))
                            {
                                if ($stmt->execute())
                                {
                                    $previewsOnline = 1;
                                }
                                else
                                {
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'insertOrderThumbnails execute2 ' . $dbObj->error;

                                    // if the error was not a deadlock reduce the amount of times we can retry
                                    if ($dbObj->error != 1213)
                                    {
                                        $dbObj->query('ROLLBACK');

                                        $retryCount--;

                                        break;
                                    }
                                }
                            }
                            else
                            {
                                // could not bind parameters
                                $dbObj->query('ROLLBACK');

                                $result = 'str_DatabaseError';
                                $resultParam = 'insertOrderThumbnails bind2 ' . $dbObj->error;

                                $retryCount--;

                                break;
                            }
                        }

                        $stmt->free_result();
                        $stmt->close();
                        $stmt = null;
                    }
                    else
                    {
                        // could not prepare statement
                        $dbObj->query('ROLLBACK');

                        $result = 'str_DatabaseError';
                        $resultParam = 'insertOrderThumbnails prepare2 ' . $dbObj->error;

                        $retryCount--;
                    }

                    // if no error has occurred update the status to say if the previews are online
                    if ($result == '')
                    {
                        if ($stmt = $dbObj->prepare('UPDATE `ORDERITEMS` SET `previewsonline` = ? WHERE `uploadref` = ?'))
                        {
                            if ($stmt->bind_param('is', $previewsOnline, $pUploadRef))
                            {
                                if ($stmt->execute())
                                {
                                    if ($dbObj->commit())
                                    {
                                        $transactionCommited = true;
                                    }
                                    else
                                    {
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'insertOrderThumbnails commit ' . $dbObj->error;

                                        // if the error was not a deadlock reduce the amount of times we can retry
                                        if ($dbObj->error != 1213)
                                        {
                                            $dbObj->query('ROLLBACK');

                                            $retryCount--;
                                        }
                                    }
                                }
                                else
                                {
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'insertOrderThumbnails execute3 ' . $dbObj->error;

                                    // if the error was not a deadlock reduce the amount of times we can retry
                                    if ($dbObj->error != 1213)
                                    {
                                        $dbObj->query('ROLLBACK');

                                        $retryCount--;
                                    }
                                }
                            }
                            else
                            {
                                // could not bind parameters
                                $dbObj->query('ROLLBACK');

                                $result = 'str_DatabaseError';
                                $resultParam = 'insertOrderThumbnails bind3 ' . $dbObj->error;

                                $retryCount--;
                            }

                            $stmt->free_result();
                            $stmt->close();
                            $stmt = null;
                        }
                        else
                        {
                            // could not prepare statement
                            $dbObj->query('ROLLBACK');

                            $result = 'str_DatabaseError';
                            $resultParam = 'insertOrderThumbnails prepare3 ' . $dbObj->error;

                            $retryCount--;
                        }
                    }
                }


                // exit if we are not allowed to retry anymore
                if ($retryCount < 1)
                {
                    break;
                }

                // if the transaction has not been committed perform a sleep before we retry
                if (! $transactionCommited)
                {
                    UtilsObj::resetPHPScriptTimeout(5);

                    usleep(100000);
                }
            }

            $dbObj->close();
        }
    }

    static function getOrderThumbnails($pUploadRef, $pLocale)
    {
        // return the order preview thumbnails for the specified uploadref

        $resultArray = Array();

        $recordID = 0;
        $dateCreated = '';
        $pageRef = '';
        $pageName = '';
        $thumbnailWidth = 0;
        $thumbnailHeight = 0;

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `id`, `datecreated`, `pageref`, `pagename`, `width`, `height` FROM `ORDERTHUMBNAILS` WHERE `uploadref` = ?'))
            {
                if ($stmt->bind_param('s', $pUploadRef))
                {
                    if ($stmt->bind_result($recordID, $dateCreated, $pageRef, $pageName, $thumbnailWidth, $thumbnailHeight))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $thumbItem['id'] = $recordID;
                                $thumbItem['datecreated'] = $dateCreated;
                                $thumbItem['pageref'] = $pageRef;
                                $thumbItem['pagename'] = LocalizationObj::getLocaleString($pageName, $pLocale, true);
                                $thumbItem['thumbwidth'] = $thumbnailWidth;
                                $thumbItem['thumbheight'] = $thumbnailHeight;

                                array_push($resultArray, $thumbItem);
                            }
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $resultArray;
    }

    /**
     * Return the date of the order to determine the thumbnails location.
     */
    static function getOrderDateFromUploadRefs($pUploadRefArray)
    {
        $resultArray = array(
            'result' => '',
            'resultparam' => '',
            'count' => 0,
            'data' => array()
        );

        $dateCreated = '';
        $uploadRef = '';

        // Take the array of upload refs and create a string for the query.
        $uploadRefString = "'" . implode("','", $pUploadRefArray) . "'";

        // Build the query.
        $sql = 'SELECT `datecreated`, `uploadref` FROM `ORDERITEMS` WHERE `uploadref` IN (' . $uploadRefString . ') AND `origorderid`=0';

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare($sql))
            {
                if ($stmt->bind_result($dateCreated, $uploadRef))
                {
                    if ($stmt->execute())
                    {
                        while ($stmt->fetch())
                        {
                            $resultArray['data'][$uploadRef] = strtotime($dateCreated);
                            $resultArray['count']++;
                        }
                    }
                    else
                    {
                        $resultArray['result'] = 'str_DatabaseError';
                        $resultArray['resultparam'] = __FUNCTION__ . ' - execute: error (' . $dbObj->error . ')';
                    }
                }
                else
                {
                    $resultArray['result'] = 'str_DatabaseError';
                    $resultArray['resultparam'] = __FUNCTION__ . ' - bind_result: error (' . $dbObj->error . ')';
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                $resultArray['result'] = 'str_DatabaseError';
                $resultArray['resultparam'] = __FUNCTION__ . ' - prepare: error (' . $dbObj->error . ')';
            }

            $dbObj->close();
        }
        else
        {
            $resultArray['result'] = 'str_DatabaseError';
            $resultArray['resultparam'] = __FUNCTION__ . ' - connection: error (' . $dbObj->error . ')';
        }

        return $resultArray;
    }

    static function getRow($pTableName, $pColumnName, $pColumnID)
    {
        $resultArray = Array();
        $row = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT * FROM `' . $pTableName . '` WHERE `' . $pColumnName . '` = ?'))
            {
                if ($stmt->bind_param('i', $pColumnID))
                {
                    $stmt->execute();
                    self::stmt_bind_assoc($stmt, $row);
                    while ($stmt->fetch())
                    {
                        foreach ($row as $key => $value)
                        {
                            $resultArray[$key] = $value;
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
            }

            $dbObj->close();
        }

        return $resultArray;
    }

    static function getTableColumnNames($pTableName)
    {
        $resultArray = Array();
        $row = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SHOW COLUMNS FROM `' . $pTableName . '`'))
            {
                if ($stmt->execute())
                {
                    self::stmt_bind_assoc($stmt, $row);
                    while ($stmt->fetch())
                    {
                       $resultArray[] = $row['Field'];
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }

            $dbObj->close();
        }

        return $resultArray;
    }

	/**
	 * updateRedactionProgress
	 * - update the state of the account from $pCurrentState to $pNewState
	 *
	 */
	static function updateRedactionProgress($pCurrentState, $pNewState, $pUserID, $pGroupCode, $pDate, $pReasonMessage)
	{
		$dbObj = self::getGlobalDBConnection();

		$resultArray = array('result' => '', 'resultparam' => '', 'count' => 0);

		// update the redaction progress of the users listed
		if ($dbObj)
		{
			$sql = 'UPDATE `USERS` SET `redactionprogress` = ?, `redactiondate` = ? ';
			$bindParams = array('is', $pNewState, $pDate);

			if ($pNewState == TPX_REDACTION_ERROR)
			{
				$sql .= ', `redactionreason` = CONCAT(`redactionreason`, ?) ';
				$bindParams[0] .= 's';
				$bindParams[] = ' - Error';
			}
			else if ($pReasonMessage != '')
			{
				$sql .= ', `redactionreason` = ? ';
				$bindParams[0] .= 's';
				$bindParams[] = $pReasonMessage;
			}
			$sql .= 'WHERE (`redactionprogress` = ?) AND (`protectfromredaction` = 0) AND (`id` = ?)';
			$bindParams[0] .= 'ii';
			$bindParams[] = $pCurrentState;
			$bindParams[] = $pUserID;

			if ($stmt = $dbObj->prepare($sql))
			{
				$bindOK = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindParams));

				if ($bindOK)
				{
					if ($stmt->execute())
					{
						$resultArray['count'] = $stmt->affected_rows;
						if ($resultArray['count'] == 0)
						{
							$resultArray['result'] = 'str_ErrorProtectedFromRedaction';
							$resultArray['resultparam'] = $pUserID;
						}
					}
					else
					{
						$resultArray['result'] = 'str_DatabaseError';
						$resultArray['resultparam'] = __FUNCTION__ . ' - execute: error (' . $dbObj->error . ')';
					}

					$stmt->free_result();
					$stmt->close();
					$stmt = null;
				}
				else
				{
					$resultArray['result'] = 'str_DatabaseError';
					$resultArray['resultparam'] = __FUNCTION__ . ' - bind_param: error (' . $dbObj->error . ')';
				}
			}
			else
			{
				$resultArray['result'] = 'str_DatabaseError';
				$resultArray['resultparam'] = __FUNCTION__ . ' - prepare: error (' . $dbObj->error . ')';
			}
		}

        return $resultArray;
	}


	static function getUpdateStates($pUserIDArray, $pNewState)
	{
		$dbObj = self::getGlobalDBConnection();

		$resultArray = array('error' => '', 'errorparam' => '', 'data' => array('updated' => array(), 'failed' => array()));

		$idList = implode(',', $pUserIDArray);

		$userID = 0;
		$updatedProgress = 0;

		// update the redaction progress of the users listed
		if ($dbObj)
		{
			$sql = 'SELECT `id`, `redactionprogress` FROM `USERS`';
			$sql .= ' WHERE (`id` IN (' . $idList . '))';

			if ($stmt = $dbObj->prepare($sql))
			{
				if ($stmt->execute())
				{
					if ($stmt->store_result())
					{
						if ($stmt->num_rows > 0)
						{
							if ($stmt->bind_result($userID, $updatedProgress))
							{
								while ($stmt->fetch())
								{
									if ($updatedProgress == $pNewState)
									{
										$resultArray['data']['updated'][] = $userID;
									}
									else
									{
										$resultArray['data']['failed'][] = $userID;
									}
								}
							}
							else
							{
								$resultArray['error'] = 'str_DatabaseError';
								$resultArray['errorparam'] = __FUNCTION__ . ' - bind_result: error (' . $dbObj->error . ')';
							}
						}
						else
						{
							$resultArray['error'] = 'str_DatabaseError';
							$resultArray['errorparam'] = __FUNCTION__ . ' - num_rows: error (' . $dbObj->error . ')';
						}
					}
					else
					{
						$resultArray['error'] = 'str_DatabaseError';
						$resultArray['errorparam'] = __FUNCTION__ . ' - store_result: error (' . $dbObj->error . ')';
					}
				}
				else
				{
					$resultArray['error'] = 'str_DatabaseError';
					$resultArray['errorparam'] = __FUNCTION__ . ' - execute: error (' . $dbObj->error . ')';
				}

				$stmt->free_result();
				$stmt->close();
				$stmt = null;
			}
			else
			{
				$resultArray['error'] = 'str_DatabaseError';
				$resultArray['errorparam'] = __FUNCTION__ . ' - prepare: error (' . $dbObj->error . ')';
			}
		}
		else
		{
			$resultArray['error'] = 'str_DatabaseError';
			$resultArray['errorparam'] = __FUNCTION__ . ' - connection: error (' . $dbObj->error . ')';
		}

		return $resultArray;
	}


    static function updateActivityLog($pSessionID, $pOrderID, $pUserID, $pUserLogin, $pUserName, $pImportance, $pSectionCode, $pActionCode,
            $pActionNotes, $pSuccess, $pClientIpAddress = null)
    {
        // insert a new entry into the activity log
        // same as updateActivityLog2() but open DB connection first

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            self::updateActivityLog2($dbObj, $pSessionID, $pOrderID, $pUserID, $pUserLogin, $pUserName, $pImportance, $pSectionCode,
                    $pActionCode, $pActionNotes, $pSuccess, $pClientIpAddress);

            $dbObj->close();
