    static function updateActivityLog2($pDbObj, $pSessionID, $pOrderID, $pUserID, $pUserLogin, $pUserName, $pImportance, $pSectionCode,
            $pActionCode, $pActionNotes, $pSuccess, $pClientIpAddress = null)
    {
    	if (null === $pClientIpAddress)
    	{
			$ipAddress = UtilsObj::getClientIPAddress();
		}
		else
		{
			$ipAddress = $pClientIpAddress;
		}

		$remoteIPAddress = inet_pton($ipAddress);

        // insert a new entry into the activity log
        if ($stmt = $pDbObj->prepare('INSERT INTO `ACTIVITYLOG` (`id`, `datecreated`, `sessionid`, `orderid`, `ipaddress`, `remoteipaddress`, `userid`, `userlogin`, `username`, `importance`, `sectioncode`, `actioncode`, `actionnotes`, `success`)
				VALUES (0, now(), ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'))
        {
            if ($stmt->bind_param('iissississsi', $pSessionID, $pOrderID, $ipAddress, $remoteIPAddress, $pUserID, $pUserLogin, $pUserName, $pImportance, $pSectionCode,
                            $pActionCode, $pActionNotes, $pSuccess))
            {
                $stmt->execute();
            }

            $stmt->free_result();
            $stmt->close();
        }
    }

    static function getServerTime($pOffsetMinutes = 0)
    {
        // return the time on the server
        // we do this via the database to eliminate timezone issues between php & mysql

        $result = '';
        $resultParam = '';

        $serverTime = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($pOffsetMinutes == 0)
            {
                if ($stmt = $dbObj->prepare('SELECT now()'))
                {
                    if ($stmt->bind_result($serverTime))
                    {
                        if ($stmt->execute())
                        {
                            $stmt->fetch();
                        }
                        else
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'getservertime execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = 'getservertime bind ' . $dbObj->error;
                    }

                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getservertime prepare ' . $dbObj->error;
                }
            }
            else
            {
                if ($stmt = $dbObj->prepare('SELECT DATE_ADD(now(), INTERVAL ? MINUTE)'))
                {
                    if ($stmt->bind_param('i', $pOffsetMinutes))
                    {
                        if ($stmt->bind_result($serverTime))
                        {
                            if ($stmt->execute())
                            {
                                $stmt->fetch();
                            }
                            else
                            {
                                $result = 'str_DatabaseError';
                                $resultParam = 'getservertime execute2 ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getservertime bindresult2 ' . $dbObj->error;
                        }

                        $stmt->free_result();
                        $stmt->close();
                        $stmt = null;
                    }
                    else
                    {
                        // could not bind params
                        $result = 'str_DatabaseError';
                        $resultParam = 'getservertime bindparams2 ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getservertime prepare2 ' . $dbObj->error;
                }
            }
            $dbObj->close();
        }

        return $serverTime;
    }

