    /*
      Session Handling
     */

    static function getSessionData($pSessionID)
    {
        // return an array containing the session data for the specified session record id
        $resultArray = Array();

        $result = '';
        $resultParam = '';
        $recordID = 0;
        $isSessionActive = 0;
        $sessionEnabled = 0;
        $isOrderSession = 0;
        $sessionRevived = 0;
        $sessionExpireDate = '';
        $sessionData = '';
        $sessionSecondsToExpiration = 0;
        $serializedDataLength = 0;
        $basketRef = '';
		$csrfToken = '';

        if ($pSessionID > 0)
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                $sqlStatement = '
					SELECT
						`id`,
						`sessionactive`,
						`sessionenabled`,
						`sessionrevived`,
						`ordersession`,
						`sessionexpiredate`,
                        UNIX_TIMESTAMP(`sessionexpiredate`) - UNIX_TIMESTAMP(now()),
                        `serializeddatalength`,
                        `sessionarraydata`,
                        `basketref`,
                        `csrftoken`
					FROM `SESSIONDATA`
					WHERE `id` = ?
				';

                if ($stmt = $dbObj->prepare($sqlStatement))
                {
                    if ($stmt->bind_param('i', $pSessionID))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($recordID, $isSessionActive, $sessionEnabled, $sessionRevived, $isOrderSession,
                                                    $sessionExpireDate, $sessionSecondsToExpiration, $serializedDataLength, $sessionData, $basketRef, $csrfToken))
                                    {
                                        if ($stmt->fetch())
                                        {
                                            // we have the session data now unserialize it back into an array
                                            if ($serializedDataLength > 0)
                                            {
                                                $sessionData = gzuncompress($sessionData, $serializedDataLength);
                                            }

                                            $resultArray = unserialize($sessionData);
                                        }
                                        else
                                        {
                                            // no row
                                            $result = 'str_ErrorNoSessionRef';
                                        }
                                    }
                                    else
                                    {
                                        // could not bind result
                                        $result = 'str_DatabaseError';
                                        $resultParam = 'getsessiondata bind result ' . $dbObj->error;
                                    }
                                }
                                else
                                {
                                    // no row returned
                                    $result = 'str_ErrorNoSessionRef';
                                }
                            }
                            else
                            {
                                // could not store result
                                $result = 'str_DatabaseError';
                                $resultParam = 'getsessiondata store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getsessiondata execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'getsessiondata bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'getsessiondata str_DatabaseError';
                    $resultParam = 'prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
            else
            {
                // could not open database connection
                $result = 'str_DatabaseError';
                $resultParam = 'getsessiondata connect ' . $dbObj->error;
            }
        }
        else
        {
            // no session reference supplied
            $result = 'str_ErrorNoSessionRef';
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['ref'] = $recordID;
        $resultArray['issessionactive'] = $isSessionActive;
        $resultArray['sessionenabled'] = $sessionEnabled;
        $resultArray['sessionrevived'] = $sessionRevived;
        $resultArray['isordersession'] = $isOrderSession;
        $resultArray['sessionexpiredate'] = $sessionExpireDate;
        $resultArray['sessionsecondstoexpiration'] = $sessionSecondsToExpiration;
        $resultArray['basketref'] = $basketRef;
		$resultArray['csrftoken'] = $csrfToken;

        return $resultArray;
    }

    static function getListOfSessions()
    {
        // return an array of session id's from the sessions table
        $resultArray = array();

        $result = '';
        $resultParam = '';
        $sessionCount = 0;
        $sessionList = array();


        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $sqlStatement = 'SELECT `id` FROM `SESSIONDATA`';
            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($stmt->execute())
                {
                    if ($stmt->store_result())
                    {
                        if ($stmt->num_rows > 0)
                        {
                            if ($stmt->bind_result($recordID))
                            {
                                while ($stmt->fetch())
                                {
                                    $sessionList[] = $recordID;
                                    $sessionCount++;
                                }
                            }
                            else
                            {
                                // could not bind result
                                $result = 'str_DatabaseError';
                                $resultParam = __FUNCTION__ . ' bind result: ' . $dbObj->error;
                            }
                        }
                    }
                    else
                    {
                        // could not store result
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' store result: ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not execute statement
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . ' execute: ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = __FUNCTION__ . ' prepare: ' . $dbObj->error;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = __FUNCTION__ . ' connect: ' . $dbObj->error;
        }


        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['count'] = $sessionCount;
        $resultArray['sessionsids'] = $sessionList;


        return $resultArray;
    }

