    static function updateSession2($pSessionArray)
    {

        // update the session database with the session array
        if ($pSessionArray['isordersession'] == 1)
        {
            $voucherCode = $pSessionArray['order']['vouchercode'];
        }
        else
        {
            $voucherCode = '';
        }

        // CSRF token
		$csrfToken = isset($pSessionArray['csrftoken']) ? $pSessionArray['csrftoken'] : null;

        // convert the session array into a serialized string
        $sessionData = serialize($pSessionArray);
        $serializedDataLength = strlen($sessionData);

        if ($serializedDataLength > 49152)
        {
            $sessionData = gzcompress($sessionData, 9);
        }
        else
        {
            $serializedDataLength = 0;
        }

        if ($pSessionArray['ref'] > 0)
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                if ($stmt = $dbObj->prepare('UPDATE
                                                `SESSIONDATA`
                                            SET
                                                `sessionrevived` = ?,
                                                `serializeddatalength` = ?,
                                                `sessionarraydata` = ?,
                                                `vouchercode` = ?,
                                                `csrftoken` = ?
                                            WHERE
                                                `id` = ?'))
                {
                    if ($stmt->bind_param('iisssi', $pSessionArray['sessionrevived'], $serializedDataLength,
						$sessionData, $voucherCode, $csrfToken, $pSessionArray['ref']))
                    {
                        $stmt->execute();
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'updateSession2 bind ' . $dbObj->error;
                    }

                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'updateSession2 prepare ' . $dbObj->error;
                }
            }

            $dbObj->close();
        }
    }

    static function startSession($pUserID, $pUserLogin, $pUserName, $pUsertype, $pCompanyCode, $pUserOwner, $pWebBrandCode,
            $pUserGroupCode, $pSSOToken, $pSSOPrivateData)
    {
        // start a session by either creating a new session record or updating a session record created via the API's
        // this also creates a cookie to track the session

        global $ac_config;
        global $gConstants;
        global $gSession;
        global $gAuthSession;

        $gSession['userid'] = $pUserID;
        $gSession['userlogin'] = $pUserLogin;
        $gSession['username'] = $pUserName;

        $gSession['userdata']['ssotoken'] = $pSSOToken;
        $gSession['userdata']['ssoprivatedata'] = $pSSOPrivateData;

        $systemConfig = self::getSystemConfig();
        $gSession['licensekeydata']['systemkey'] = $systemConfig['systemkey'];
        $gSession['licensekeydata']['ownercode'] = $systemConfig['ownercode'];
        $gSession['licensekeydata']['ownercode2'] = $systemConfig['ownercode2'];

        if ($pUserGroupCode != '')
        {
            $gSession['licensekeydata']['groupcode'] = $pUserGroupCode;
        }

        if ($gConstants['optionms'])
        {
            $gSession['userdata']['userowner'] = $pUserOwner;
            $gSession['userdata']['companycode'] = $pCompanyCode;
        }
        else
        {
            if (($pUsertype == TPX_LOGIN_DISTRIBUTION_CENTRE_USER) || ($pUsertype == TPX_LOGIN_STORE_USER) || ($pUsertype == TPX_LOGIN_SITE_ADMIN))
            {
                $gSession['userdata']['userowner'] = $pUserOwner;
            }
            else
            {
                $gSession['userdata']['userowner'] = '';
            }
            $gSession['userdata']['companycode'] = '';
        }

        $gSession['userdata']['usertype'] = $pUsertype;
        $gSession['userdata']['webbrandcode'] = $pWebBrandCode;

        $recordID = $gSession['ref'];

        $sessionDuration = (int) $ac_config['SESSIONDURATION'];

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($recordID > 0)
            {
                // we already have a session so make it active, set the userid and if it has not been revived set the expiration date (revived sessions already have an expiration date in the future)
                if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `sessionactive` = 1,
                    `sessionexpiredate` = IF(`sessionrevived` = 0, DATE_ADD(now(), INTERVAL ? MINUTE), `sessionexpiredate`), `userid` = ?, `ssotoken` = ? WHERE `id` = ?'))
                {
                    if ($stmt->bind_param('iisi', $sessionDuration, $pUserID, $pSSOToken, $recordID))
                    {
                        $stmt->execute();
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'startSession bind ' . $dbObj->error;
                    }

                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'startSession prepare ' . $dbObj->error;
                }
            }
            else
            {
                if ($stmt = $dbObj->prepare('INSERT INTO `SESSIONDATA` (`id`, `datecreated`, `sessionactive`, `sessionenabled`, `sessionexpiredate`, `userid`, `ssotoken`)
                                    VALUES (0, NOW(), 1, 1, DATE_ADD(NOW(), INTERVAL ? MINUTE), ?, ?)'))
                {
                    if ($stmt->bind_param('iis', $sessionDuration, $pUserID, $pSSOToken))
                    {
                        if ($stmt->execute())
                        {
                            $recordID = $dbObj->insert_id;
                            $gSession['ref'] = $recordID;
                            self::updateSession();
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'startSession insert execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'startSession insert bind ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'startSession insert prepare ' . $dbObj->error;
                }
            }
            $dbObj->close();
        }

        setcookie('mawebdata' . $gSession['ref'], md5(base64_encode($gSession['ref'])),
                    UtilsObj::calcClientCookieExpiryTime(((int) $ac_config['SESSIONDURATION'] * 60)), '/', '', UtilsObj::needSecureCookies(), true);
        $gAuthSession = false; // temporarily switch off authenticating this session via cookies for the rest of this request
        // remove any old sessions from the database
        self::removeExpiredSessions();

        return $recordID;
    }

	static function insertOrderSessionDataRecord($pProjectRef, $pHighLevelBasketRef)
	{
		$result = '';
		$resultParam = '';
		$resultArray = array();
		$ref = 0;
		$dbObj = DatabaseObj::getConnection();

        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('INSERT INTO `SESSIONDATA` ( `id`, `datecreated`, `sessionactive`, `sessionenabled`, `sessionrevived`, `ordersession`, `projectref`, `basketref`)
                                        VALUES (0, now(), 0, 1, 0, 1, ?, ?)'))
            {
                // Insert projectref into session so we can check if a project is in shopping cart.
                // this is mainly for Taopix Online to kill the existing session when user delete/open a project.
                if ($stmt->bind_param('ss',  $pProjectRef, $pHighLevelBasketRef))
                {
                    if ($stmt->execute())
                    {
                        $ref = $dbObj->insert_id;
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'order insert session data execute ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'order insert session data bind_param ' . $dbObj->error;
                }
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'order insert session data prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'order insert session data connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['ref'] = $ref;

        return $resultArray;
	}

    static function updateSessionExpire($pSessionRef)
    {
        // update the session expiration date and cookie data
        global $ac_config;

        $sessionDuration = (int) $ac_config['SESSIONDURATION'];

        setcookie('mawebdata' . $pSessionRef, md5(base64_encode($pSessionRef)),
                UtilsObj::calcClientCookieExpiryTime(((int) $ac_config['SESSIONDURATION'] * 60)), '/', '', UtilsObj::needSecureCookies(), true);

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `sessionexpiredate` = DATE_ADD(now(), INTERVAL ? MINUTE) WHERE (`id` = ?) AND (`sessionrevived` = 0)'))
            {
                if ($stmt->bind_param('ii', $sessionDuration, $pSessionRef))
                {
                    $stmt->execute();
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'updatesessionexpire bind ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'updatesessionexpire prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
    }

    static function getSessionExpire($pSessionRef)
    {
        // return the session expiration status
        $resultArray = Array();

        $result = '';
        $resultParam = '';

        $isSessionActive = 0;
        $isSessionEnabled = 0;
        $sessionExpire = 0;
        $serverTime = 0;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `sessionactive`, `sessionenabled`, `sessionexpiredate`, now() FROM `SESSIONDATA` WHERE `id` = ?'))
            {
                if ($stmt->bind_param('i', $pSessionRef))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($isSessionActive, $isSessionEnabled, $sessionExpire, $serverTime))
                                {
                                    if ($stmt->fetch())
                                    {
                                        if ($isSessionEnabled == 1)
                                        {
                                            if ($isSessionActive == 1)
                                            {
                                                if ($sessionExpire != '')
                                                {
                                                    $sessionExpire = strtotime($sessionExpire);
                                                    $serverTime = strtotime($serverTime);
                                                }
                                                else
                                                {
                                                    // the session has not been started
                                                    $sessionExpire = 0;
                                                }
                                            }
                                            else
                                            {
                                                // the session is not active
                                                $sessionExpire = -1;
                                            }
                                        }
                                        else
                                        {
                                            // the session has been disabled for user interaction (ie it has been completed)
                                            $sessionExpire = -2;
                                        }
                                    }
                                    else
                                    {
                                        // the session doesn't exist in the database
                                        $sessionExpire = -2;
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'getsessionexpire bind result' . $dbObj->error;
                                }
                            }
                            else
                            {
                                // no rows found - the session doesn't exist in the database
                                $sessionExpire = -2;
                            }
                        }
                        else
                        {
                            // could not store result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getsessionexpire store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        $result = 'str_DatabaseError';
                        $resultParam = 'getsessionexpire execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'getsessionexpire bind params ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getsessionexpire prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }

        $resultArray['servertime'] = $serverTime;
        $resultArray['sessionexpiretime'] = $sessionExpire;

        return $resultArray;
    }

    static function clearSessionExpire($pSessionRef)
    {
        // clear the session expiration date and cookie
        // this has the effect of logging out the user
        setcookie('mawebdata' . $pSessionRef, '', 1, '/');

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `sessionactive` = 0, `sessionexpiredate` = "" WHERE `id` = ?'))
            {
                if ($stmt->bind_param('i', $pSessionRef))
                {
                    $stmt->execute();
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'clearsessionexpire bind ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'clearsessionexpire prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }

        // remove any old sessions from the database
        self::removeExpiredSessions();
    }

    static function disableSession($pSessionRef, $pSessionExtendMinutes = 0)
    {
        // disable the specified session without deleting it
        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // determine if we need to extend the session expire time for the paylater payment method
            if ($pSessionExtendMinutes == 0)
            {
                if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `sessionenabled` = 0 WHERE `id` = ?'))
                {
                    if ($stmt->bind_param('i', $pSessionRef))
                    {
                        $result = $stmt->execute();
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'disableSession bind ' . $dbObj->error;
                    }

                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'disableSession prepare ' . $dbObj->error;
                }
            }
            else
            {
                if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `sessionenabled` = 0, `sessionexpiredate` = DATE_ADD(now(), INTERVAL ? MINUTE) WHERE `id` = ?'))
                {
                    if ($stmt->bind_param('ii', $pSessionExtendMinutes, $pSessionRef))
                    {
                        $stmt->execute();
                    }
                    else
                    {
                        // could not bind parameters
                        $result = 'str_DatabaseError';
                        $resultParam = 'disableSession bind2 ' . $dbObj->error;
                    }

                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'disableSession prepare2 ' . $dbObj->error;
                }
            }
            $dbObj->close();
        }
    }

    static function reviveSession($pSessionRef, $pAuthenticateSession)
    {
        // revive the session and create the cookie

        global $ac_config;
        global $gAuthSession;

        $sessionRevived = false;
        $result = '';
        $resultParam = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `sessionenabled` = 1 WHERE `id` = ?'))
            {
                if ($stmt->bind_param('i', $pSessionRef))
                {
                    $stmt->execute();
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'reviveSession bind ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'reviveSession prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }

        if ($result == '')
        {
            $sessionArray = self::getSessionData($pSessionRef);

            if ($sessionArray['ref'] > 0)
            {
                $canRevive = true;

                // if we are trying to revive an order session make sure that the order number hasn't been allocated or that it is a temp order
                if ($sessionArray['isordersession'] == 1)
                {
                    if (($sessionArray['order']['id'] == 0) || ($sessionArray['order']['temporder'] == 1))
                    {
                        $sessionArray['order']['processed'] = 0;
                    }
                    else
                    {
                        $canRevive = false;
                    }
                }

                if ($canRevive == true)
                {
                    $sessionArray['sessionrevived'] = 1;

                    $sessionRevived = true;

                    $sessionDuration = (int) $ac_config['SESSIONDURATION'];

                    if (!$pAuthenticateSession)
                    {
						// if we came from your orders page in control centre then skip authenticating via the cookie
						if ($sessionArray['authenticatecookie'] == 0)
						{
							$gAuthSession = false;
							$sessionArray['authenticatecookie'] = 1;
						}
                    }

					if ($pAuthenticateSession || (((! $pAuthenticateSession) && $sessionArray['authenticatecookie'] == 0)))
					{
						setcookie('mawebdata' . $pSessionRef, md5(base64_encode($pSessionRef)),
                            UtilsObj::calcClientCookieExpiryTime(((int) $ac_config['SESSIONDURATION'] * 60)), '/', '', UtilsObj::needSecureCookies(), true);
					}

					self::updateSession2($sessionArray);
                }
            }
        }

        return $sessionRevived;
    }

