    static function getSessionGiftCardTotal($pSessionRef, $pUserID = 0, $pOtherActiveSessions = false)
    {
        // get value of gift cards used by specified session
        $activeGiftCardTotal = 0;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT giftcardtotal FROM `SESSIONDATA` WHERE (`id` = ?)'))
            {
                if ($stmt->bind_param('i', $pSessionRef))
                {
                    if ($stmt->bind_result($singleSessionGiftCardTotal))
                    {
                       if ($stmt->execute())
                        {
                            if ($stmt->fetch())
                            {
                                $activeGiftCardTotal = $singleSessionGiftCardTotal;
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }

            // get the total for gift cards used by all sessions for the user
            // subtract the value for the specified session, resulting in the total gift card used by other sessions.
            if($pOtherActiveSessions)
            {
                if ($stmt = $dbObj->prepare('SELECT SUM(giftcardtotal) FROM `SESSIONDATA` WHERE (`userid` = ?) AND (`sessionenabled` = 1) AND (`sessionactive` = 1) AND (`sessionexpiredate` > NOW())'))
                {
                    if ($stmt->bind_param('i', $pUserID))
                    {
                        if ($stmt->bind_result($allSessionGiftCardTotal))
                        {
                           if ($stmt->execute())
                            {
                                if ($stmt->fetch())
                                {
                                    $activeGiftCardTotal = ($allSessionGiftCardTotal - $activeGiftCardTotal);
                                }
                            }
                        }
                    }
                    $stmt->free_result();
                    $stmt->close();
                }

            }

            $dbObj->close();
        }

        return $activeGiftCardTotal;
    }

    static function deleteSession($pSessionRef)
    {
        // delete the specified session record

        $dbObj = self::getGlobalDBConnection();

        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('DELETE FROM `SESSIONDATA` WHERE `id` = ?'))
            {
                if ($stmt->bind_param('i', $pSessionRef))
                {
                    $result = $stmt->execute();
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }
    }

    static function removeExpiredSessions()
    {
        // delete all session records older than one hour past their expiration time

        global $ac_config;

        // allow sessions to live on 90 minutes over the expiration time
        $cutOffMinutes = ((int) $ac_config['SESSIONDURATION'] + 90) * -1;

        $sessionIDArray = array();
        $sessionCount = 0;
        $sessionID = 0;

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // find all the sessions which have expired
            $sqlStatement = 'SELECT id FROM `SESSIONDATA`
            WHERE (`sessionexpiredate` BETWEEN "0000-00-00 00:00:01" AND DATE_ADD(NOW(), INTERVAL ? MINUTE))
            UNION
            SELECT id FROM `SESSIONDATA`
            WHERE ((`sessionexpiredate` = "0000-00-00 00:00:00") AND (`datecreated` <= DATE_ADD(NOW(), INTERVAL ? MINUTE)))';

            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($stmt->bind_param('ii', $cutOffMinutes, $cutOffMinutes))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($sessionID))
                                {
                                    while ($stmt->fetch())
                                    {
                                        $sessionIDArray[] = $sessionID;
                                        $sessionCount++;
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = __FUNCTION__ . ' bind result: ' . $dbObj->error;
                                }
                            }
                        }
                        else
                        {
                            // could not store result
                            $result = 'str_DatabaseError';
                            $resultParam = __FUNCTION__ . ' store result: ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' execute: ' . $dbObj->error;
                    }
                }
                else
                {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' bind_param: ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = __FUNCTION__ . ' prepare: ' . $dbObj->error;
            }

            // delete all the sessions which have expired
            if ($sessionCount > 0)
            {
                $sessionIDs = implode(',', $sessionIDArray);

                if ($stmt = $dbObj->prepare('DELETE FROM `SESSIONDATA` WHERE `id` in (' . $sessionIDs  . ')'))
                {
                    if (!$stmt->execute())
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' execute: ' . $dbObj->error;
                    }

                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . ' prepare: ' . $dbObj->error;
                }
            }

            $dbObj->close();
        }
    }

    static function cleanUpProjectOrderDataCache($pProjectRefArray)
    {
        // delete project order cache records that have been ordered or cancelled.
        // also delete all project order cache records older than set days

        global $ac_config;

        $dbObj = self::getGlobalDBConnection();

        $cleanUpDays = (array_key_exists('PROJECTORDERCACHEDATACLEANUPDAYS', $ac_config) ? $ac_config['PROJECTORDERCACHEDATACLEANUPDAYS'] : 90);

        // calculate the expiry time of records for cleanup
        $serverTime = DatabaseObj::getServerTime();
        $expiryDate = date('Y-m-d H:i:s', strtotime($serverTime) - $cleanUpDays * (24 * 60 * 60));

        $projectRef = '';
        $connectorID = 0;
        $connectorURL = '';
        $externalProductId = 0;
        $connectorProductArray = [];
        $returnProjectRefArray = [];
        $projectRefArray = $pProjectRefArray;
        $projectRefsList = "'" . implode("','", $projectRefArray) . "'";

        if ($dbObj)
        {
            // find all the project order cache records which have expired and do not exist in the onlinebasket table
            // Added OR clause to projectref for connectors
            $sqlStatement = 'SELECT `podc`.`projectref`, `podc`.`connectorid`, `conn`.`connectorurl`, `podc`.`externalproductid`,
                `podc`.`orderdate`, `podc`.`ordernumber`
                FROM `PROJECTORDERDATACACHE` `podc`
                LEFT JOIN `ONLINEBASKET` `olb`
                    ON `podc`.`projectref` = `olb`.`projectref`
                LEFT JOIN `CONNECTORS` `conn`
                    ON `conn`.`id` = `podc`.`connectorid`
                WHERE ((`olb`.`projectref` IS NULL) AND (`podc`.`datecreated` < ?))
                OR `podc`.`projectref` IN (' . $projectRefsList . ')';

            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($stmt->bind_param('s', $expiryDate))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($projectRef, $connectorID, $connectorURL, $externalProductId, $orderDate, $orderNumber))
                                {
                                    while ($stmt->fetch())
                                    {

                                        if ($connectorID > 0)
                                        {

                                            if (!isset($connectorProductArray['connector'][$connectorID]))
                                            {
                                                $connectorProductArray['connector'][$connectorID]['connectorurl'] = $connectorURL;
                                            }

                                            $connectorProductArray['connector'][$connectorID]['projectsarray'][] =
                                            [
                                                'projectref' => $projectRef,
                                                'externalproductid' => $externalProductId,
                                                'orderdate' => $orderDate,
                                                'ordernumber' => $orderNumber
                                            ];

                                            //remove the project from the array to prevent immediate deletion when using for external connector
                                            //the EDL script can use its own logic to do this.
                                            unset($projectRefArray[$projectRef]);
                                        } else
                                        {
                                            $projectRefArray[] = $projectRef;
                                        }
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = __FUNCTION__ . ' bind result: ' . $dbObj->error;
                                }
                            }
                        }
                        else
                        {
                            // could not store result
                            $result = 'str_DatabaseError';
                            $resultParam = __FUNCTION__ . ' store result: ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' execute: ' . $dbObj->error;
                    }
                }
                else
                {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' bind_param: ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = __FUNCTION__ . ' prepare: ' . $dbObj->error;
            }

            // perform external products cleanup
            if (count($connectorProductArray) > 0)
            {
                //if method_exists
                if (file_exists('../Customise/scripts/EDL_OnlineBasketAPI.php'))
                {
                    require_once('../Customise/scripts/EDL_OnlineBasketAPI.php');
                }

                if (method_exists('OnlineBasketAPI', 'cleanupTempProducts'))
                {
                    $returnProjectRefArray = OnlineBasketAPI::cleanupTempProducts($connectorProductArray);
                }
            }

            $projectRefArray = array_merge($returnProjectRefArray, $projectRefArray);

            // delete all the project records which are no longer required (cancelled, ordered and expired)
            if (count($projectRefArray) > 0)
            {
                $projectRefs = "'" . implode("','", $projectRefArray) . "'";

                if ($stmt = $dbObj->prepare('DELETE FROM `PROJECTORDERDATACACHE` WHERE `projectref` in (' . $projectRefs  . ')'))
                {
                    if (!$stmt->execute())
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = __FUNCTION__ . ' execute: ' . $dbObj->error;
                    }

                    $stmt->close();
                }
                else
                {
                    // could not prepare statement
                    $result = 'str_DatabaseError';
                    $resultParam = __FUNCTION__ . ' prepare: ' . $dbObj->error;
                }
            }

            $dbObj->close();
        }
    }

