    static function checkSSL()
    {
        ob_start();
        phpinfo(INFO_GENERAL);
        $phpinfo = ob_get_contents();
        ob_end_clean();

        $s = strpos($phpinfo, 'Registered PHP Streams');
        $e = strpos($phpinfo, "\n", $s);
        $test = (strstr(substr($phpinfo, $s, $e - $s), 'https')) ? true : false;

        return $test;
    }

    static function getPaymentIntegrationFromBrand($pBrand)
    // return payment integration from brand, if present, or constants otherwise
    {
        global $gConstants;

        $paymentIntegration = '';

        $brandingArray = self::getBrandingFromCode($pBrand);
        switch ($brandingArray['paymentintegration'])
        {
            case 'DEFAULT':
                $defaultBrand = self::getBrandingFromCode('');
                $paymentIntegration = $defaultBrand['paymentintegration'];
                break;
            case 'NONE':
                $paymentIntegration = ''; // blank
                break;
            default:
                $paymentIntegration = $brandingArray['paymentintegration']; // use brand settings
        }

        return $paymentIntegration;
    }

    /**
     * Converts a component or section path into an array.
     *
     * @static
     *
     * @param string $pPath
     *
     * @return array
     * parseComponentOrSectionPath('')
     * => Array(	[0] => Array(	[issection] => true
     * 							[code] => ""))
     *
     * parseComponentOrSectionPath('$COVER\')
     * => Array(	[0] => Array(	[issection] => true
     * 							[code] => "COVER"))
     *
     * parseComponentOrSectionPath('$COVER\CAT_A.LIST_A1\$SECTION_B\')
     * => Array(	[0] => Array(	[issection] => true
     * 							[code] => "COVER")
     * 			[1] => Array(	[issection] => false
     * 							[code] => "CAT_A.LIST_A1")
     * 			[2] => Array(	[issection] => true
     * 							[code] => "SECTION_B"))
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function parseComponentOrSectionPath($pPath)
    {
        $result = array();
        $item = array();
        $pPath = trim($pPath);

        if ($pPath != '')
        {
            $token = strtok($pPath, '\\');

            while ($token !== false)
            {
                $section = false;
                if (substr($token, 0, 1) == '$')
                {
                    $token = substr($token, 1);
                    $section = true;
                }
                $item['issection'] = $section;
                $item['code'] = $token;
                $result[] = $item;
                $token = strtok('\\');
            }
        }
        else
        {
            $result = array(array('issection' => true, 'code' => ''));
        }

        return $result;
    }

    /**
     * Gets component of a specific component section from the order item in the database.
     *
     * If the section does not exist a suitable empty component is returned.
     *
     * @static
     *
     * @param string $pOrderID
     * id of order header
     * @param string $pOrderItemID
     * id of order item in ORDERITEMS table
     * @param string $pSectionCode
     * code of the desired component section
     *
     * @return array
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function getOrderItemComponents($pOrderID, $pOrderItemID, $pSectionCode, $pLocale = '')
    {
        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $componentsArray = Array();

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $sqlStatement = 'SELECT `id`, `datecreated`, `datemodified`, `orderid`, `orderitemid`, `userid`, `parentcomponentid`, `externalassetservicecode`, `externalassetservicename`,
                                `externalassetpricetype`, `componentcode`, `componentlocalcode`, `skucode`, `componentname`, `componentpath`, `componentcategorycode`,
                                `componentcategoryname`, `componentdescription`, `sortorder`, `pricingmodel`, `islist`, `checkboxselected`, `sectionid`, `componentselectioncount`,
                                `quantity`, `componentunitcost`, `componentunitsell`, `externalassetunitcost`, `externalassetunitsell`, `componentunitweight`, `componenttotalcost`, `componenttotalsell`,
                                `componenttotalweight`, `componenttotaltax`, `branchunitcost`, `branchunitsell`, `branchunitweight`, `branchtotalcost`, `branchtotalsell`,
                                `branchtotalweight`, `branchtotaltax`, `externalassetexpirydate`, `externalassetpageref`, `externalassetpagenumber`, `externalassetpagename`, `externalassetboxref`, `metadatacodelist`
                            FROM `ORDERITEMCOMPONENTS` WHERE (`orderid` = ?) AND (`orderitemid` = ?)';

            if ($pSectionCode != '')
            {
                $sqlStatement .= ' AND (`componentcategorycode` = ?)';
            }

            $sqlStatement .= ' ORDER BY `id`';

            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($pSectionCode == '')
                {
                    $bindResult = $stmt->bind_param('ii', $pOrderID, $pOrderItemID);
                }
                else
                {
                    $bindResult = $stmt->bind_param('iis', $pOrderID, $pOrderItemID, $pComponentCategoryCode);
                }

                if ($bindResult)
                {
                    if ($stmt->bind_result($id, $dateCreated, $dateModified, $orderID, $orderItemID, $userID, $parentComponentID,
                                    $assetServiceCode, $assetServiceName, $assetPriceType, $componentCode, $componentLocalCode,
                                    $componentSKUCode, $componentName, $componentPath, $componentCategoryCode, $componentCategoryName,
                                    $componentDescription, $sortOrder, $pricingModel, $isList, $checkBoxSelected, $sectionID,
                                    $componentSelectionCount, $quantity, $componentUnitCost, $componentUnitSell, $assetUnitCost,
                                    $assetUnitSell, $componentUnitWeight, $componentTotalCost, $componentTotalSell, $componentTotalWeight,
                                    $componentTotalTax, $branchUnitCost, $branchUnitSell, $branchUnitWeight, $branchTotalCost,
                                    $branchTotalSell, $branchTotalWeight, $branchTotalTax, $assetExpiryDate, $assetPageRef,
                                    $assetPageNumber, $assetPageName, $assetBoxRef, $metaDataCodeList))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                if ($pLocale != '')
                                {
                                    $assetServiceName = LocalizationObj::getLocaleString($assetServiceName, $pLocale, true);
                                    $componentName = LocalizationObj::getLocaleString($componentName, $pLocale, true);
                                    $componentCategoryName = LocalizationObj::getLocaleString($componentCategoryName, $pLocale, true);
                                    $componentDescription = LocalizationObj::getLocaleString($componentDescription, $pLocale, true);
                                    $assetPageName = LocalizationObj::getLocaleString($assetPageName, $pLocale, true);
                                }

                                $componentItemArray['id'] = $id;
                                $componentItemArray['datecreated'] = $dateCreated;
                                $componentItemArray['datemodified'] = $dateModified;
                                $componentItemArray['orderid'] = $orderID;
                                $componentItemArray['orderitemid'] = $orderItemID;
                                $componentItemArray['userid'] = $userID;
                                $componentItemArray['parentcomponentid'] = $parentComponentID;
                                $componentItemArray['assetservicecode'] = $assetServiceCode;
                                $componentItemArray['assetservicename'] = $assetServiceName;
                                $componentItemArray['assetpricetype'] = $assetPriceType;
                                $componentItemArray['componentcode'] = $componentCode;
                                $componentItemArray['componentlocalcode'] = $componentLocalCode;
                                $componentItemArray['componentskucode'] = $componentSKUCode;
                                $componentItemArray['componentname'] = $componentName;
                                $componentItemArray['componentpath'] = $componentPath;
                                $componentItemArray['componentcategorycode'] = $componentCategoryCode;
                                $componentItemArray['componentcategoryname'] = $componentCategoryName;
                                $componentItemArray['componentdescription'] = $componentDescription;
                                $componentItemArray['sortorder'] = $sortOrder;
                                $componentItemArray['pricingmodel'] = $pricingModel;
                                $componentItemArray['islist'] = $isList;
                                $componentItemArray['checkboxselected'] = $checkBoxSelected;
                                $componentItemArray['sectionid'] = $sectionID;
                                $componentItemArray['componentselectioncount'] = $componentSelectionCount;
                                $componentItemArray['quantity'] = $quantity;
                                $componentItemArray['componentunitcost'] = $componentUnitCost;
                                $componentItemArray['componentunitsell'] = $componentUnitSell;
                                $componentItemArray['assetunitcost'] = $assetUnitCost;
                                $componentItemArray['assetunitsell'] = $assetUnitSell;
                                $componentItemArray['componentunitweight'] = $componentUnitWeight;
                                $componentItemArray['componenttotalcost'] = $componentTotalCost;
                                $componentItemArray['componenttotalsell'] = $componentTotalSell;
                                $componentItemArray['componenttotalweight'] = $componentTotalWeight;
                                $componentItemArray['componenttotaltax'] = $componentTotalTax;
                                $componentItemArray['branchunitcost'] = $branchUnitCost;
                                $componentItemArray['branchunitsell'] = $branchUnitSell;
                                $componentItemArray['branchunitweight'] = $branchUnitWeight;
                                $componentItemArray['branchtotalcost'] = $branchTotalCost;
                                $componentItemArray['branchtotalsell'] = $branchTotalSell;
                                $componentItemArray['branchtotalweight'] = $branchTotalWeight;
                                $componentItemArray['branchtotaltax'] = $branchTotalTax;
                                $componentItemArray['assetexpirydate'] = $assetExpiryDate;
                                $componentItemArray['assetpageref'] = $assetPageRef;
                                $componentItemArray['assetpagenumber'] = $assetPageNumber;
                                $componentItemArray['assetpagename'] = $assetPageName;
                                $componentItemArray['assetboxref'] = $assetBoxRef;
                                $componentItemArray['metadatacodelist'] = $metaDataCodeList;

                                $componentsArray[] = $componentItemArray;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'getOrderItemComponent execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = 'getOrderItemComponent bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'getOrderItemComponent bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'getOrderItemComponent prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getOrderItemComponent connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['components'] = &$componentsArray;

        return $resultArray;
    }

    /**
     * Updates an item component structure of a given category in the order session.
     *
     * If there is no component of the specified component category, it will be created.
     *
     * @static
     *
     * @param string $pOrderItemId
     * index of order item, as in $gSession['items'][$pOrderItemId]
     * @param string $pSectionCode
     * component section code
     * @param array $pComponent
     * component structure
     *
     * @return array
     * result, resultParam
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function updateSessionOrderItemSection($pOrderItemId, $pSectionCode, $pComponent)
    {
        global $gSession;

        $resultArray = Array();
        $result = '';
        $resultParam = '';

        $new = true;

        // check if a component of this category exists already in the session
        $orderLineComponents = & $gSession['items'][$pOrderItemId]['sections'];
        $itemCount = count($orderLineComponents);
        for ($i = 0; $i < $itemCount; $i++)
        {
            if ($orderLineComponents[$i]['categorycode'] == $pComponent['categorycode'])
            {
                // category code found, replace component structure
                $orderLineComponents[$i] = $pComponent;
                $new = false;

                break;
            }
        }

        if ($new)
        {
            // add empty component
            array_push($orderLineComponents, $pComponent);
            // The order item now has a component of the specified category.
        }

        self::updateSession();

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

        return $resultArray;
    }

    /**
     * Adds a new empty item component structure of a given category to the order session.
     *
     * @static
     *
     * @param string $pOrderItemId
     * index of order item, as in $gSession['items'][$pOrderItemId]
     * @param string $pSectionCode
     * code of the desired component section
     *
     * @return array
     * result, resultParam
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function addSessionOrderItemComponent($pOrderItemId, $pSectionCode) // not $pComponentCategoryCode
    {
        global $gSession;

        $resultArray = self::createSessionOrderItemComponent($pOrderItemId, $pSectionCode);

        array_push($gSession['items'][$pOrderItemId]['sections'], $resultArray['component']);
        self::updateSession();

        return $resultArray;
    }

    /**
     * Gets a section specified by the order line id. By reference.
     *
     * @param string $pOrderlineId 		order line id of checkbox
     * @param array $pHaystack 			the array, optional, defaults to $gSession
     * 									so it serches gSession[order] and gSession[items]
     *
     * @return array
     *
     * @since Version 3.0.0
     * @author Steffen Haugk
     */
    static function &getSectionByOrderLineId($pOrderlineId, &$pHaystack = NULL)
    {
        global $gSession;

        $result = NULL;

        if (is_null($pHaystack))
        {
            $pHaystack = &$gSession;
        }

        if (is_array($pHaystack))
        {
            foreach ($pHaystack as &$item)
            {
                if (is_array($item))
                {
                    if (array_key_exists('orderlineid', $item) && ($pOrderlineId == (string) $item['orderlineid']))
                    {
                        $result = &$item;
                    }
                    else
                    {
                        if (is_null($result))
                        {
                            $result = &self::getSectionByOrderLineId($pOrderlineId, $item);
                        }
                    }
                }
            }
        }

        return $result;
    }

    /**
     * Adds a new empty section structure to the order session.
     *
     * @static
     *
     * @param string $pSectionCode
     * code of the desired component section
     *
     * @return array
     * result, resultParam, section array
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function addSessionOrderSection($pSectionCode)
    {
        $resultArray = array();
        $result = '';
        $resultParam = '';
        $categoryCode = '';
        $categoryName = '';
        $prompt = '';
        $pricingModel = '';
        $sectionLabel = '';
        $sectionName = '';

        $section = array('defaultcode' => '',
            'productcode' => '',
            'id' => 0,
            'sectioncode' => $pSectionCode,
            'sectionlabel' => '',
            'sectionname' => '',
            'pricingmodel' => 0,
            'path' => '', // is the same for the section as for the selected component, and will be set in the calling function
            'categorycode' => '',
            'categoryname' => '',
            'skucode' => '',
            'priceinfo' => '',
            'prompt' => '',
            'haspreviews' => 0, // do components have previews?
            'count' => 0,
            // following fields for selected component (always list component)
            'code' => '',
            'localcode' => '',
            'name' => '',
            'info' => '',
            'islist' => 1,
            'orderfootertaxrate' => 0.00,
            'orderfootertaxcode' => '',
            'orderfootertaxname' => '',
            'unitcost' => 0.00,
            'unitsell' => 0.00,
            'totalcost' => 0.00,
            'totalsell' => 0.00,
            'totaltax' => 0.00,
            'totalsellnotax' => 0.00,
            'totalsellwithtax' => 0.00,
            'pricetaxcode' => '',
            'pricetaxrate' => 0.00,
            'discountvalue' => 0.0,
            'discountvalueraw' => 0.0,
            'discountvaluenotax' => 0.0,
            'discountvaluewithtax' => 0.0,
            'discountedtax' => 0.0,
            'unitweight' => 0.0000,
            'totalweight' => 0.0000,
            'haspreview' => 0, // does this component have a preview?
            'assetid' => '',
            'quantity' => 0,
            'itemqty' => 0,
            'itemqtyaccumulative' => 0,
            'subtotal' => 0.00,
            'orderlineid' => '',
            'subsections' => array(),
            'checkboxes' => array());

        // does section even exist?
        $dbSection = self::getSectionFromCode($pSectionCode);

        if ($dbSection['result'] != '')
        {
            $result = $dbSection['result'];
            $resultParam = 'addSessionOrderSection init ' . $pSectionCode;
        }

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // get defaults from component category
            $stmt = $dbObj->prepare('SELECT c.code, c.name, c.prompt, c.pricingmodel, s.label, s.name FROM `COMPONENTCATEGORIES` c,
                                        `SECTIONS` s
                                        WHERE (c.code = s.categorycode)
                                        and s.code = ?');
            if ($stmt)
            {
                if ($stmt->bind_param('s', $pSectionCode))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($categoryCode, $categoryName, $prompt, $pricingModel, $sectionLabel, $sectionName))
                                {
                                    if ($stmt->fetch())
                                    {
                                        $section['sectionlabel'] = $sectionLabel;
                                        $section['sectionname'] = $sectionName;
                                        $section['prompt'] = $prompt;
                                        $section['pricingmodel'] = $pricingModel;
                                        $section['categorycode'] = $categoryCode;
                                        $section['categoryname'] = $categoryName;
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'addSessionOrderSection bind result ' . $dbObj->error;
                                }
                            }
                        }
                        else
                        {
                            // could not bind result
                            $result = 'str_DatabaseError';
                            $resultParam = 'addSessionOrderSection store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'addSessionOrderSection execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'addSessionOrderSection bind params ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'addSessionOrderSection prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'addSessionOrderSection connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['section'] = $section;

        return $resultArray;
    }

    /**
     * Create a new empty item component structure of a given category.
     *
     * @static
     *
     * @param string $pSectionCode
     * code of the desired component section
     * @param string $pOrderItemId
     * index of order item, as in $gSession['items'][$pOrderItemId]
     *
     * @return array
     * result, resultParam, component
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function createSessionOrderItemComponent($pOrderItemId, $pSectionCode) // not $pComponentCategoryCode
    {
        global $gSession;

        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $componentCategoryCode = '';
        $componentCategoryName = '';
        $componentCategoryPrompt = '';
        $isList = '';
        $sectionLabel = '';
        $sectionName = '';

        $component = Array('defaultcode' => '',
            'id' => 0,
            'code' => '',
            'name' => '',
            'info' => '',
            'islist' => 1, // checkbox (0) or list component (1)
            'default' => -1, // checkbox ticked (1) or not (0), list component (-1) by default
            'ticked' => -1, // checkbox ticked (1) or not (0), list component (-1)
            'sectioncode' => $pSectionCode,
            'sectionlabel' => '',
            'sectionname' => '',
            'prompt' => '',
            'categorycode' => '',
            'categoryname' => '',
            'haspreviews' => 0, // do components have previews?
            'unitcost' => 0.00,
            'unitsell' => 0.00,
            'totalcost' => 0.00,
            'totalsell' => 0.00,
            'totaltax' => 0.00,
            'totalsellnotax' => 0.00,
            'totalsellwithtax' => 0.00,
            'subtotal' => 0.00,
            'unitweight' => 0.0000,
            'totalweight' => 0.0000,
            'count' => 0,
            'haspreview' => 0, // does this component have a preview?
            'assetid' => '',
            'quantity' => 0,
            'itemqty' => 0,
            'orderlineid' => $gSession['items'][$pOrderItemId]['orderlineid'] . '_' . Order_model::getNextOrderLineId());

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            // get defaults from component category
            if ($stmt = $dbObj->prepare('SELECT c.code, c.name, c.prompt, c.islist, s.label, s.name FROM `COMPONENTCATEGORIES` c, `SECTIONS` s WHERE (c.code = s.categorycode) and s.code = ?'))
            {
                if ($stmt->bind_param('s', $pSectionCode))
                {
                    if ($stmt->bind_result($componentCategoryCode, $componentCategoryName, $componentCategoryPrompt, $isList, $sectionLabel, $sectionName))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->fetch())
                            {
                                $component['sectionlabel'] = $sectionLabel;
                                $component['sectionname'] = $sectionName;
                                $component['categorycode'] = $componentCategoryCode;
                                $component['categoryname'] = $componentCategoryName;
                                $component['prompt'] = $componentCategoryPrompt;
                                $component['islist'] = $isList;
                                $component['default'] = ($isList) ? -1 : 0;
                                $component['ticked'] = ($isList) ? -1 : 0;
                            }
                        }
                        else
                        {
                            // could not execute statement
                            $result = 'str_DatabaseError';
                            $resultParam = 'createSessionOrderItemComponent execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bind result
                        $result = 'str_DatabaseError';
                        $resultParam = 'createSessionOrderItemComponent bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'createSessionOrderItemComponent bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'createSessionOrderItemComponent prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'createSessionOrderItemComponent connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['component'] = $component;

        return $resultArray;
    }

    /**
     * Get an item section structure of a given section in the order session.
     *
     * The data is returned by reference.
     * If the specified section does not exist, it will be created.
     *
     * @static
     *
     * @param string $pSectionPath
     * path to the desired section, i.e."$ORDERFOOTER\$SECTION_E\CAT_E.LIST_E1\$SECTION_F"
     *
     * @param string $pOrderItemId
     * index of order item, as in $gSession['items'][$pOrderItemId]
     * in the case of the order footer, $pOrderItemId is ignored
     *
     * @return array
     * component
     *
     * @author Steffen Haugk
     * @since Version 3.0.0
	 *
	 * This function is correcting the component counts using the associated order lines for footer components
	 * but only does it *after* the price break logic has applied minimum break quantity rules.
     */
    static function &getSessionOrderSection($pOrderItemId, $pProductCode, $pSectionPath, $pExchangeRate, $pCurrencyDecimalPlaces, $pItemQty,
            $pRebuild = false, $pComponentCode = '', $pOrderFooterAccumlativePageCount = 0)
    {
        global $gSession;

        $sectionArray = Array();
        $component = Array();
        $existingItemQty = 0;
        $hit = false;
        $index = 0;

        // parse path
        $parsedPath = self::parseComponentOrSectionPath($pSectionPath);
        $origSectionCode = $parsedPath[0]['code'];
        $sectionCode = $origSectionCode;
        $pathRoot = $sectionCode;

		switch ($origSectionCode)
        {
            case 'ORDERFOOTER':
                $sectionArray = &$gSession['order']['orderFooterSections'];
                $orderlineId = '-1';
                array_shift($parsedPath);
                $sectionCode = $parsedPath[0]['code'];
                break;
            case 'LINEFOOTER':
                $sectionArray = &$gSession['items'][$pOrderItemId]['lineFooterSections'];
                $orderlineId = $gSession['items'][$pOrderItemId]['orderlineid'];
                array_shift($parsedPath);
                $sectionCode = $parsedPath[0]['code'];
                break;
            default:
                $sectionArray = &$gSession['items'][$pOrderItemId]['sections'];
                $orderlineId = $gSession['items'][$pOrderItemId]['orderlineid'];
        }

        // find
        $itemCount = count($sectionArray);

        // if there is no hit, this will be the last item, after the new section has been added
        $index = $itemCount;

        for ($i = 0; $i < $itemCount; $i++)
        {
            if ($sectionArray[$i]['sectioncode'] == $sectionCode)
            {
                $hit = true;
                $index = $i;
                break;
            }
        }

        // if we don't have this section or we do have it and have been requested to re-build it then continue
        if ((!$hit) || (($hit && $pRebuild)))
        {
            if ($hit)
            {
                // copy the existing section
                $existingSection = $sectionArray[$index];

                if (!$pRebuild)
                {
                    $existingItemQty = $existingSection['itemqty'];
                }

                // remove the existing section so that it gets added again at the end in the correct order
                array_splice($sectionArray, $index, 1);
                $index = count($sectionArray);

                // re-assign the updated sections list using a reference to the array
                switch ($origSectionCode)
                {
                    case 'ORDERFOOTER':
                        $gSession['order']['orderFooterSections'] = &$sectionArray;
                        break;
                    case 'LINEFOOTER':
                        $gSession['items'][$pOrderItemId]['lineFooterSections'] = &$sectionArray;
                        break;
                    default:
                        $gSession['items'][$pOrderItemId]['sections'] = &$sectionArray;
                }
            }
            else
            {
                $pRebuild = false;
            }

            $resultValues = self::addSessionOrderSection($sectionCode);

            if ($resultValues['result'] == '')
            {
                $section = $resultValues['section'];

                // get defaults

                $tempArray = Order_model::getOrderComponentList($pOrderItemId, $pProductCode, $section['categorycode'], $pSectionPath,
                                false, $pComponentCode, $pRebuild, $pItemQty, $pOrderFooterAccumlativePageCount, 0);

                $section['defaultcode'] = $tempArray['defaultcode'];
                $section['defaultlocalcode'] = $tempArray['defaultlocalcode'];

                // if we are re-building the section we must copy the current codes and id from the existing section array
                // otherwise set the values to the default codes
                if ($pRebuild)
                {
                    $section['code'] = $existingSection['code'];
                    $section['localcode'] = $existingSection['localcode'];
                    $section['skucode'] = $existingSection['skucode'];
                    $section['priceinfo'] = $existingSection['priceinfo'];
                    $section['orderlineid'] = $existingSection['orderlineid'];
                    $section['itemproductcode'] = $pProductCode;
                    $section['quantity'] = $existingSection['quantity'];
                    $section['itemqty'] = $existingSection['itemqty'];

                    // if we have been provided with a qty update it now otherwise use the existing one from the section
                    if ($pItemQty == -1)
                    {
                        $section['itemqtyaccumulative'] = $existingSection['itemqtyaccumulative'];
                    }
                    else
                    {
                        $section['itemqtyaccumulative'] = $pItemQty;
                    }

                    $section['itempagecount'] = $existingSection['itempagecount'];
                    $section['quantityisdropdown'] = $existingSection['quantityisdropdown'];
                    $section['pricedata'] = $existingSection['pricedata'];
                    $section['pricetaxcode'] = $existingSection['pricetaxcode'];
                    $section['pricetaxrate'] = $existingSection['pricetaxrate'];

                    $section['orderfooterusesproductquantity'] = $existingSection['orderfooterusesproductquantity'];
                    $section['orderfootertaxlevel'] = $existingSection['orderfootertaxlevel'];
                    $section['componenthasprice'] = $existingSection['componenthasprice'];
                }
                else
                {
                    // if we are intialising a reorder and we are re building the order footer
                    // we must look up the details for the ordered component in the specific section
                    // and set it as default.
                    if ($origSectionCode == 'ORDERFOOTER' && $gSession['order']['isreorder'] == 1)
                    {
                    	foreach($tempArray['component'] as $tempComponent)
                    	{
                    		if ($pComponentCode == $tempComponent['code'])
                    		{
                    			$tempArray['component'] = array($tempComponent);
                    			$tempArray['defaultcode'] = $tempComponent['code'];
                   				$tempArray['defaultlocalcode'] = $tempComponent['localcode'];
                   				$tempArray['defaultskucode'] = $tempComponent['skucode'];
                   				$tempArray['defaultpriceinfo'] = $tempComponent['priceinfo'];
                   				$tempArray['quantity'] = $tempComponent['quantity'];
                   				$tempArray['quantityisdropdown'] = $tempComponent['quantityisdropdown'];
                   				$tempArray['pricedata'] = $tempComponent['pricedata'];
                   				$tempArray['orderfooterusesproductquantity'] = $tempComponent['orderfooterusesproductquantity'];
                   				$tempArray['orderfootertaxlevel'] = $tempComponent['orderfootertaxlevel'];
                   				$tempArray['pricetaxcode'] = $tempComponent['pricetaxcode'];
                   				$tempArray['pricetaxrate'] = $tempComponent['pricetaxrate'];
                    			break;
                    		}
                    	}
                    }

                    $section['code'] = $tempArray['defaultcode'];
                    $section['localcode'] = $tempArray['defaultlocalcode'];
                    $section['skucode'] = $tempArray['defaultskucode'];
                    $section['priceinfo'] = $tempArray['defaultpriceinfo'];
                    $section['orderlineid'] = $orderlineId . '_' . Order_model::getNextOrderLineId();
                    $section['itemproductcode'] = $pProductCode;
                    $section['quantity'] = $tempArray['quantity'];
                    $section['itemqty'] = $tempArray['itemqty'];
                    $section['itemqtyaccumulative'] = $pItemQty;
                    $section['itempagecount'] = $tempArray['itempagecount'];
                    $section['quantityisdropdown'] = $tempArray['quantityisdropdown'];
                    $section['pricedata'] = $tempArray['pricedata'];
                    $section['orderfooterusesproductquantity'] = $tempArray['orderfooterusesproductquantity'];
                    $section['orderfootertaxlevel'] = $tempArray['orderfootertaxlevel'];
                    $section['pricetaxcode'] = $tempArray['pricetaxcode'];
                    $section['pricetaxrate'] = $tempArray['pricetaxrate'];

                    //check to see if the section is empty.
                    // if it is then there are no components but we have to set the componenthasprice flag to 1 for validation
                    if ($tempArray['component'])
                    {
                        $section['componenthasprice'] = $tempArray['defaultcomponenthasprice'];
                    }
                    else
                    {
                        $section['componenthasprice'] = 1;
                    }

                    if ($tempArray['result'] != '')
                    {
                        $section['componenthasprice'] = 0;
                    }
                }

                // check to see if we are dealing with components in the $ORDERFOOTER section
                if (substr($pSectionPath, 0, 13) == '$ORDERFOOTER\\')
                {
                    // check to see if the component should use the product quantites to calcualte the price.
                    if ($section['orderfooterusesproductquantity'] == 1)
                    {
                        $section['itemqty'] = $section['itemqtyaccumulative'];
                    }
                    else
                    {
                        $priceArray = self::priceStringToArray($section['pricingmodel'], $section['pricedata']);
                        $section['itemqty'] = $priceArray[0]['startqty'];
                    }
                }
                else
                {
                    $section['itemqty'] = $pItemQty;
                }

                $section['path'] = $pSectionPath;

                // get metadata for the selected component
                $componentArray = self::getComponentByCode($section['code']);

                if ($componentArray['keywordgroupheaderid'] > 0 && $section['componenthasprice'] == 1)
                {
                    $section['metadata'] = MetaDataObj::getKeywordList('COMPONENT', '', '', $componentArray['keywordgroupheaderid']);
                }
                else
                {
                    $section['metadata'] = Array();
                }

                // if we are rebuilding the section attempt to match the meta-data
                if ($pRebuild)
                {
                    foreach ($section['metadata'] as &$metadataItem)
                    {
                        $componentOldMetadata = $existingSection['metadata'];
                        foreach ($componentOldMetadata as &$oldMetadataItem)
                        {
                            if ($metadataItem['ref'] == $oldMetadataItem['ref'])
                            {
                                $metadataItem['defaultvalue'] = $oldMetadataItem['defaultvalue'];
                                break;
                            }
                        }
                    }
                }

                // check to see if the section belongs to the order footer.
                if ($orderlineId == TPX_ORDERFOOTER_ID)
                {
                    $itemPageCount = $section['itempagecount'];
                }
                else
                {
                    $orderlineId = $gSession['items'][$pOrderItemId]['orderlineid'];
                    $itemPageCount = $gSession['items'][$pOrderItemId]['itempagecount'];
                }
                // get list of component section root checkboxes
                $rootCheckboxList = self::getOrderCheckboxes($pProductCode, $gSession['licensekeydata']['groupcode'],
                                $gSession['userdata']['companycode'], $pSectionPath, $pExchangeRate, $pCurrencyDecimalPlaces, $pItemQty,
                                $itemPageCount, $orderlineId, $pRebuild);

                // get the selected component's checkboxes
                $checkboxList = self::getOrderCheckboxes($pProductCode, $gSession['licensekeydata']['groupcode'],
                                $gSession['userdata']['companycode'], $pSectionPath . $section['localcode'] . '\\', $pExchangeRate,
                                $pCurrencyDecimalPlaces, $pItemQty, $itemPageCount, $orderlineId, $pRebuild);

                $sectionCheckboxList = Array();
                if ($rootCheckboxList['result'] == '')
                {
                    $sectionCheckboxList = $rootCheckboxList['checkboxes'];
                }

                if ($checkboxList['result'] == '')
                {
                    $sectionCheckboxList = array_merge($sectionCheckboxList, $checkboxList['checkboxes']);
                }

                $section['checkboxes'] = $sectionCheckboxList;


                // if we are re-building the section attempt to set the checked status and meta-data for existing checkboxes
                if ($pRebuild)
                {
                    foreach ($section['checkboxes'] as &$sectionCheckboxItem)
                    {
                        foreach ($existingSection['checkboxes'] as &$existingCheckboxItem)
                        {
                            if ($sectionCheckboxItem['code'] == $existingCheckboxItem['code'])
                            {
                                $sectionCheckboxItem['checked'] = $existingCheckboxItem['checked'];
                                $sectionCheckboxItem['quantity'] = $existingCheckboxItem['quantity'];

                                foreach ($sectionCheckboxItem['metadata'] as &$metadataItem)
                                {
                                    foreach ($existingCheckboxItem['metadata'] as &$oldMetadataItem)
                                    {
                                        if ($metadataItem['ref'] == $oldMetadataItem['ref'])
                                        {
                                            $metadataItem['defaultvalue'] = $oldMetadataItem['defaultvalue'];
                                            break;
                                        }
                                    }
                                }

                                break;
                            }
                        }
                    }
                }

                // get list of sub-sections

                // first get list of required sections
                // this is current section plus current component
                $sectionList = self::getOrderSectionList($pProductCode, $gSession['licensekeydata']['groupcode'],
                                $gSession['userdata']['companycode'], $pSectionPath . $section['localcode'] . '\\');

                foreach ($sectionList['sections'] as $subSectionCode)
                {
                    $resultValues = self::addSessionOrderSection($subSectionCode);

                    if ($resultValues['result'] == '')
                    {
                        $subSection = $resultValues['section'];
                        $subSection['orderlineid'] = $orderlineId . '_' . Order_model::getNextOrderLineId();
                        $subSection['path'] = $pSectionPath . $section['localcode'] . '\\' . '$' . $subSectionCode . '\\';
                        $subSection['itemproductcode'] = $pProductCode;

                        // also need default code
                        $tempArray = Order_model::getOrderComponentList($pOrderItemId, $pProductCode, $subSection['categorycode'],
                                        $subSection['path'], false, '', false, $pItemQty, $pOrderFooterAccumlativePageCount, 0);

                        $subSection['defaultcode'] = $tempArray['defaultcode'];
                        $subSection['defaultlocalcode'] = $tempArray['defaultlocalcode'];
                        $subSection['itemproductcode'] = $pProductCode;
                        $subSection['orderfooterusesproductquantity'] = $tempArray['orderfooterusesproductquantity'];
                        $subSection['orderfootertaxlevel'] = $tempArray['orderfootertaxlevel'];
                        $subSection['itemqtyaccumulative'] = $pItemQty;
                        $subSection['itempagecount'] = $pOrderFooterAccumlativePageCount;
                        $subSection['quantity'] = $tempArray['quantity'];
                        $subSection['pricedata'] = $tempArray['pricedata'];
                        $subSection['pricetaxcode'] = $tempArray['pricetaxcode'];
                        $subSection['pricetaxrate'] = $tempArray['pricetaxrate'];



                        //check to see if the section is empty.
                        // if it is then there are no components but we have to set the componenthasprice flag to 1 for validation
                        if ($tempArray['component'])
                        {
                            $subSection['componenthasprice'] = $tempArray['defaultcomponenthasprice'];

                            foreach ($tempArray['component'] as &$subComponent)
                            {
                                if ($subComponent['code'] == $pComponentCode)
                                {
                                    $subSection['orderfooterusesproductquantity'] = $subComponent['orderfooterusesproductquantity'];
                                }
                            }
                        }
                        else
                        {
                            $subSection['componenthasprice'] = 1;
                        }

                        // if we are rebuilding the section attempt to keep the same sub-sections selected
                        $newSelectedComponentCode = $tempArray['defaultcode'];
                        $newSelectedComponentLocalCode = $tempArray['defaultlocalcode'];
                        $newSelectedComponetSkuCode = $tempArray['defaultskucode'];
                        $newSelectedComponetPriceInfo = $tempArray['defaultpriceinfo'];

                        $matchedSubSection = false;
                        $existingSubSection = Array();

                        if ($pRebuild)
                        {
                            $newSubSectionDepth = substr_count($subSection['path'], '\\');

                            foreach ($existingSection['subsections'] as $subSectionComponent)
                            {
                                $existingSectionDepth = substr_count($subSectionComponent['path'], '\\');

                                if (($newSubSectionDepth == $existingSectionDepth) && ($subSection['sectioncode'] == $subSectionComponent['sectioncode']))
                                {
                                    foreach ($tempArray['component'] as $sectionComponent)
                                    {
                                        if ($sectionComponent['code'] == $subSectionComponent['code'])
                                        {
                                            $existingSubSection = &$subSectionComponent;
                                            $matchedSubSection = true;

                                            // if we have been provided with a qty update it now otherwise use the existing one from the section
                                            if ($pItemQty == -1)
                                            {
                                                $subSection['itemqtyaccumulative'] = $existingSection['itemqtyaccumulative'];
                                            }
                                            else
                                            {
                                                $subSection['itemqtyaccumulative'] = $pItemQty;
                                            }
                                            $newSelectedComponentCode = $subSectionComponent['code'];
                                            $newSelectedComponentLocalCode = $subSectionComponent['localcode'];
                                            $newSelectedComponetSkuCode = $subSectionComponent['skucode'];
											$newSelectedComponetPriceInfo = $subSectionComponent['priceinfo'];
                                            $subSection['quantity'] = $subSectionComponent['quantity'];
                                            $subSection['orderfooterusesproductquantity'] = $subSectionComponent['orderfooterusesproductquantity'];
                                            $subSection['orderfootertaxlevel'] = $subSectionComponent['orderfootertaxlevel'];
                                            break;
                                        }
                                    }

                                    break;
                                }
                            }
                        }

                        // check to see if we are dealing with components in the $ORDERFOOTER section
                        if (substr($subSection['path'], 0, 13) == '$ORDERFOOTER\\')
                        {
                            // check to see if the component should use the product quantites to calcualte the price.
                            if ($subSection['orderfooterusesproductquantity'] == 1)
                            {
                                $subSection['itemqty'] = $subSection['itemqtyaccumulative'];
                            }
                            else
                            {
                                $priceArray = self::priceStringToArray($subSection['pricingmodel'], $subSection['pricedata']);
                                $subSection['itemqty'] = $priceArray[0]['startqty'];
                            }
                        }
                        else
                        {
                            $subSection['itemqty'] = $pItemQty;
                        }

                        $subSection['code'] = $newSelectedComponentCode;
                        $subSection['localcode'] = $newSelectedComponentLocalCode;
                        $subSection['skucode'] = $newSelectedComponetSkuCode;
                        $subSection['priceinfo'] = $newSelectedComponetPriceInfo;


                        // get metadata for the selected component
                        $componentArray = self::getComponentByCode($subSection['code']);

                        if ($componentArray['keywordgroupheaderid'] > 0)
                        {
                            $subSection['metadata'] = MetaDataObj::getKeywordList('COMPONENT', '', '',
                                            $componentArray['keywordgroupheaderid']);
                        }
                        else
                        {
                            $subSection['metadata'] = Array();
                        }

                        // if we are rebuilding the section attempt to match the meta-data
                        if ($pRebuild && $matchedSubSection)
                        {
                            foreach ($subSection['metadata'] as &$metadataItem)
                            {
                                $componentOldMetadata = $existingSubSection['metadata'];
                                foreach ($componentOldMetadata as &$oldMetadataItem)
                                {
                                    if ($metadataItem['ref'] == $oldMetadataItem['ref'])
                                    {
                                        $metadataItem['defaultvalue'] = $oldMetadataItem['defaultvalue'];
                                        break;
                                    }
                                }
                            }
                        }

                        // get list of checkboxes
                        $checkboxList = self::getOrderCheckboxes($pProductCode, $gSession['licensekeydata']['groupcode'],
                                        $gSession['userdata']['companycode'], $subSection['path'], $pExchangeRate, $pCurrencyDecimalPlaces,
                                        $pItemQty, $itemPageCount, $orderlineId);

                        if ($checkboxList['result'] == '')
                        {
                            $subSection['checkboxes'] = $checkboxList['checkboxes'];

                            // if we are re-building the section attempt to set the checked status and meta-data for existing checkboxes
                            if ($pRebuild && $matchedSubSection)
                            {
                                foreach ($subSection['checkboxes'] as &$subSectionCheckboxItem)
                                {
                                    foreach ($existingSubSection['checkboxes'] as &$existingSubCheckboxItem)
                                    {
                                        if ($subSectionCheckboxItem['code'] == $existingSubCheckboxItem['code'])
                                        {
                                            $subSectionCheckboxItem['checked'] = $existingSubCheckboxItem['checked'];
                                            $subSectionCheckboxItem['quantity'] = $existingSubCheckboxItem['quantity'];

                                            foreach ($subSectionCheckboxItem['metadata'] as &$metadataItem)
                                            {
                                                foreach ($existingSubCheckboxItem['metadata'] as &$oldMetadataItem)
                                                {
                                                    if ($metadataItem['ref'] == $oldMetadataItem['ref'])
                                                    {
                                                        $metadataItem['defaultvalue'] = $oldMetadataItem['defaultvalue'];
                                                        break;
                                                    }
                                                }
                                            }

                                            break;
                                        }
                                    }
                                }
                            }
                        }

                        array_push($section['subsections'], $subSection);
                    }
                }

                array_push($sectionArray, $section);
            }

            self::updateSession();
        }
        else
        {
            // section found, nothing to do
        }

        return $sectionArray[$index];
    }

    /* Returns price lists for the component category provided.
     *
     * @param string $pCategoryCode
     *  Category code of requested pricelists
     * @return string $componentCategoryPriceListArray
     *  Returns id, code, name and price of the requested pricelist.
     *
     * @since Version 3.0.0
     * @author Stuart Milne
     */

    static function getPriceListFromComponentCategoryCode($pCategoryCode, $pCompanyCode)
    {
        $dbObj = self::getGlobalDBConnection();
        $componentCategoryPriceListArray = Array();
        $decimalPlaces = 0;

        if ($dbObj)
        {
            if ($pCategoryCode == 'PRODUCT')
            {
                if ($pCompanyCode == '')
                {
                    $stmt = $dbObj->prepare('SELECT `id`, `price`, `pricelistcode`, `pricelistlocalcode`, `pricelistname`, `quantityisdropdown`, `taxcode`, `active` FROM `PRICES` WHERE `categorycode` = ? AND `ispricelist` = 1 ORDER BY `pricelistlocalcode`');
                    $bindOk = $stmt->bind_param('s', $pCategoryCode);
                }
                else
                {
                    $stmt = $dbObj->prepare('SELECT `id`, `price`, `pricelistcode`, `pricelistlocalcode`, `pricelistname`, `quantityisdropdown`, `taxcode`, `active` FROM `PRICES` WHERE `categorycode` = ? AND `ispricelist` = 1 AND (`companycode` = ? OR `companycode` = "") ORDER BY `pricelistlocalcode`');
                    $bindOk = $stmt->bind_param('ss', $pCategoryCode, $pCompanyCode);
                }

                $bindResult = $stmt->bind_result($priceListID, $priceListPrice, $priceListCode, $priceListLocalCode, $priceListName,
                        $qtyIsDropdown, $taxCode, $active);
            }
            else
            {

                if ($pCompanyCode == '')
                {
                    $stmt = $dbObj->prepare('SELECT `pr`.`id`, `pr`.`price`, `pr`.`pricelistcode`, `pr`.`pricelistlocalcode`, `pr`.`pricelistname`, `pr`.`quantityisdropdown`, `pr`.`taxcode`, `pr`.`active`,
											`cc`.`componentpricingdecimalplaces` FROM `PRICES` pr JOIN `COMPONENTCATEGORIES` cc ON `pr`.`categorycode` = `cc`.`code` WHERE `pr`.`categorycode` = ? AND `pr`.`ispricelist` = 1 ORDER BY `pr`.`pricelistlocalcode`');
                    $bindOk = $stmt->bind_param('s', $pCategoryCode);
                }
                else
                {
                    $stmt = $dbObj->prepare('SELECT `pr`.`id`, `pr`.`price`,`pr`. `pricelistcode`, `pr`.`pricelistlocalcode`, `pr`.`pricelistname`, `pr`.`quantityisdropdown`, `pr`.`taxcode`, `pr`.`active`,
											`cc`.`componentpricingdecimalplaces` FROM `PRICES` pr JOIN `COMPONENTCATEGORIES` cc ON `pr`.`categorycode` = `cc`.`code` WHERE `pr`.`categorycode` = ? AND `pr`.`ispricelist` = 1
											AND (`pr`.`companycode` = ? OR `pr`.`companycode` = "") ORDER BY `pr`.`pricelistlocalcode`');
                    $bindOk = $stmt->bind_param('ss', $pCategoryCode, $pCompanyCode);
                }

                $bindResult = $stmt->bind_result($priceListID, $priceListPrice, $priceListCode, $priceListLocalCode, $priceListName,
                        $qtyIsDropdown, $taxCode, $active, $decimalPlaces);
            }

            if ($stmt)
            {
                if ($bindOk)
                {
                    if ($bindResult)
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $priceItem['id'] = $priceListID;
                                $priceItem['price'] = $priceListPrice;
                                $priceItem['pricelistcode'] = $priceListCode;
                                $priceItem['pricelistlocalcode'] = $priceListLocalCode;
                                $priceItem['pricelistname'] = $priceListName;
                                $priceItem['qtyisdropdown'] = $qtyIsDropdown;
                                $priceItem['taxcode'] = $taxCode;
                                $priceItem['isactive'] = $active;
                                $priceItem['decimalplaces'] = $decimalPlaces;
                                array_push($componentCategoryPriceListArray, $priceItem);
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $componentCategoryPriceListArray;
    }

    /**
     * Calculate the price depending on pricing model.
     * This functions also accepts -1 as the quantity / pagecount to return the first price (useful for auto-update when just determining if a price exists)
     *
     * @static
     *
     * @param array $pPriceArray
     * @param integer $pQty
     * @param integer $pPageCount
     * @param float $pCurrencyExchangeRate
     * @param integer $pCurrencyDecimalPlaces
     *
     * @return array
     * price row
     *
     * @author Dasha Salo
     * @author Steffen Haugk
     * @since Version 3.0.0
     */
    static function calculatePrice($pPriceArray, $pIsProductPrice, $pCurrencyExchangeRate, $pCurrencyDecimalPlaces, $pQty, $pPageCount,
            $pLineBreakQTY, $pComponentQty, $pCanCorrectComponentQty, $pPriceBreakQtyIsComponentQty, $pApplyBasePriceLineSubtract)
    {
		global $gSession;

        // no need to check 'result' or 'isactive' in $pPriceArray, this has been done in calling function
        $result = '';
        $resultParam = '';
        $recordID = 0;
        $dateCreated = '';
        $itemCode = '';
        $productCode = '';
        $itemCode = '';
        $groupCode = '';
        $shoppingCartType = $pPriceArray['shoppingcarttype'];
        $newProductQty = $pQty;
        $newComponentQty = $pComponentQty;
        $priceBreakQty = $pLineBreakQTY;
        $startPageCount = 0;
        $endPageCount = 0;
        $unitSell = 0.00;
        $totalSell = 0.00;
        $lineSubtract = 0.00;
        $basePrice = 0.00;
        $productInfo = '';
        $isActive = 0;
        $priceFound = false;
        $outOfRange = false;

		// check that the external shopping cart script exists and can be used for this order
        if (key_exists('order', $gSession))
        {
            if (($shoppingCartType == TPX_SHOPPINGCARTTYPE_EXTERNAL) && ($gSession['order']['externalcartscriptexists'] == 0))
            {
                // if the external cart script does not exist, fall back to Taopix cart
                $shoppingCartType = TPX_SHOPPINGCARTTYPE_INTERNAL;
            }
        }

        // if the product is handled by the Taopix shopping cart make sure there is a price available
        if ($shoppingCartType == TPX_SHOPPINGCARTTYPE_INTERNAL)
        {
            $result = 'str_ErrorNoPriceForRange';

            $recordID = $pPriceArray['recordid'];
            $dateCreated = $pPriceArray['datecreated'];
            $isActive = $pPriceArray['isactive'];
            $pricingModel = $pPriceArray['pricingmodel'];

            $priceItemArray = self::priceStringToArray($pricingModel, $pPriceArray['price']);

            $itemCount = count($priceItemArray);

            // determine if we need to modify the qty values that have been supplied
            $firstlineOfProductQtyRange = true;
            for ($i = 0; $i < $itemCount; $i++)
            {
                $thePriceItem = &$priceItemArray[$i];
                $startQty = $thePriceItem['startqty'];
                $endQty = $thePriceItem['endqty'];
                $startCmpCount = $thePriceItem['startcmpqty'];
                $endCmpCount = $thePriceItem['endcmpqty'];

                // if we are looking for a product price then make sure the product qty is in range
                // if we have not been provided with a product qty we calculate it now
                if (($pIsProductPrice) || ($newProductQty == -1))
                {
                    // if the qty supplied is -1 we use the start or end qty of this line depending on if it is a dropdown
                    if ($newProductQty == -1)
                    {
                        if ($pPriceArray['quantityisdropdown'])
                        {
                            $newProductQty = $endQty;
                        }
                        else
                        {
                            $newProductQty = $startQty;
                        }
                    }
                    else
                    {
                        // we have been provided with a product qty so make sure it is in range
                        // if the qty is less than the start qty of the first entry update the qty
                        // if the qty is more than the end qty of the last entry update the qty
                        if (($i == 0) && ($newProductQty < $startQty))
                        {
                            $newProductQty = $startQty;
                        }
                        elseif (($i == ($itemCount - 1)) && ($newProductQty > $endQty))
                        {
                            $outOfRange = true;
                            $newProductQty = $endQty;
                        }
                    }
                }

                if (!$pIsProductPrice)
                {
                    // for component based pricing models we need to check the component qty
                    if (($pricingModel == TPX_PRICINGMODEL_PERPRODCMPQTY) || ($pricingModel == TPX_PRICINGMODEL_PERSIDEPERPRODPERCMPQTY))
                    {
                        // first make sure we have a product qty in range
                        if (($newProductQty >= $startQty) && ($newProductQty <= $endQty))
                        {
                            // if the out of range flag is false then we know that the product qty is out of range when the product qty has been changed.
                            if (!$outOfRange)
                            {
                                $priceFound = true;
                            }

                            // if the qty supplied is -1 we use the start or end qty of this line depending on if it is a dropdown
                            if ($newComponentQty == -1)
                            {

                                if ($pCanCorrectComponentQty)
								{
									if ($pPriceArray['quantityisdropdown'])
									{
										$newComponentQty = $endCmpCount;
									}
									else
									{
										$newComponentQty = $startCmpCount;
									}

									if ($pPriceBreakQtyIsComponentQty)
									{
										$priceBreakQty = $newComponentQty;
									}
								}
                            }
                            else
                            {
                                // we have been provided with a component qty so make sure it is in range
                                // if the qty is less than the start qty of the first matching product qty range entry update the component qty
                                // if the qty is more than the end qty of the last entry update the component qty
                                if (($firstlineOfProductQtyRange) && ($newComponentQty < $startCmpCount))
                                {
                                    if ($pCanCorrectComponentQty)
									{
										$priceFound = true;
										if ($pPriceArray['quantityisdropdown'])
										{
											$newComponentQty = $endCmpCount;
										}
										else
										{
											$newComponentQty = $startCmpCount;
										}

										if ($pPriceBreakQtyIsComponentQty)
										{
											$priceBreakQty = $newComponentQty;
										}
									}
                                }
                                elseif (($i == ($itemCount - 1)) && ($newComponentQty > $endCmpCount))
                                {
                                    if ($pCanCorrectComponentQty)
									{
										$newComponentQty = $endCmpCount;
										$priceFound = true;

										if ($pPriceBreakQtyIsComponentQty)
										{
											$priceBreakQty = $newComponentQty;
										}
									}
                                }
                            }

                            $firstlineOfProductQtyRange = false;
                        }
                        elseif (($i > 0) && ($startQty > $priceItemArray[$i - 1]['startqty']) &&
                                ($newProductQty >= $priceItemArray[$i - 1]['startqty']) && ($newProductQty <= $priceItemArray[$i - 1]['endqty']) &&
                                ($newComponentQty > $priceItemArray[$i - 1]['endcmpqty']))
                        {
                            // if the qty is more than the end qty of the last entry for the product qty range update the component qty to the qty from the previous price line
                            if ($pCanCorrectComponentQty)
							{
								$newComponentQty = $priceItemArray[$i - 1]['endcmpqty'];
								$priceFound = true;

								if ($pPriceBreakQtyIsComponentQty)
								{
									$priceBreakQty = $newComponentQty;
								}
							}
                        }
                    }
                    else
                    {
                        // the pricing model is not based on the component qty so just set the component qty to 1
                        $newComponentQty = 1;
                        if (($newProductQty >= $startQty) && ($newProductQty <= $endQty))
                        {
                            $priceFound = true;
                        }
                    }
                }
                else
                {
                    // if we are just getting a product price then set priceFound to true
                    $priceFound = true;
                }
            }

            if ($priceFound)
            {
                // find the entry that matches
                for ($i = 0; $i < $itemCount; $i++)
                {
                    $thePriceItem = &$priceItemArray[$i];
                    $startQty = $thePriceItem['startqty'];
                    $endQty = $thePriceItem['endqty'];

                    if (($newProductQty >= $startQty) && ($newProductQty <= $endQty))
                    {
                        $startPageCount = $thePriceItem['startpagecount'];
                        $endPageCount = $thePriceItem['endpagecount'];
                        $startCmpCount = $thePriceItem['startcmpqty'];
                        $endCmpCount = $thePriceItem['endcmpqty'];
                        $basePrice = $thePriceItem['baseprice'];
                        $unitSell = $thePriceItem['unitsell'];
                        $lineSubtract = $thePriceItem['linesubtract'];

						// if we are dealing with consolidated single print quantities we
						// only want to apply base price and line subtract once per consolidate size/stock option
						if (! $pApplyBasePriceLineSubtract)
						{
							$basePrice = 0.00;
							$lineSubtract = 0.00;
						}

                        switch ($pricingModel)
                        {
                            case TPX_PRICINGMODEL_PERQTY:
                                // calculate the sell price as we will sort  by the price
                                $totalSell = $basePrice + ($unitSell * $newProductQty) - $lineSubtract;
                                $result = '';

                                break 2;
                            case TPX_PRICINGMODEL_PERSIDEQTY:
                                if ((($pPageCount == -1) || (($pPageCount >= $startPageCount) && ($pPageCount <= $endPageCount))))
                                {
                                    // calculate the sell price as we will sort by the price
                                    // if the page count supplied is -1 we use the start page count of this line
                                    if ($pPageCount == -1)
                                    {
                                        $pPageCount = $startPageCount;
                                    }

                                    $totalSell = $basePrice + ($unitSell * $pPageCount) - $lineSubtract;
                                    $totalSell = $newProductQty * $totalSell;

                                    $result = '';
                                    break 2;
                                }
                                break 1;
                            case TPX_PRICINGMODEL_PERPRODCMPQTY:
                                if (($priceBreakQty >= $startCmpCount) && ($priceBreakQty <= $endCmpCount))
                                {
                                    // calculate the sell price as we will sort by the price
                                    $totalSell = $basePrice + ($unitSell * $newComponentQty) - $lineSubtract;
                                    $totalSell = $newProductQty * $totalSell;

                                    $result = '';
                                    break 2;
                                }
                                break 1;
                            case TPX_PRICINGMODEL_PERSIDEPERPRODPERCMPQTY:
                                if ((($priceBreakQty >= $startCmpCount) && ($priceBreakQty <= $endCmpCount)) &&
                                        (($pPageCount == -1) || (($pPageCount >= $startPageCount) && ($pPageCount <= $endPageCount))))
                                {
                                    // calculate the sell price as we will sort by the price
                                    // if the page count supplied is -1 we use the start page count of this line
                                    if ($pPageCount == -1)
                                    {
                                        $pPageCount = $startPageCount;
                                    }

                                    $totalSell = $basePrice + ($unitSell * $pPageCount) - $lineSubtract;
                                    $totalSell = $newProductQty * $newComponentQty * $totalSell;

                                    $result = '';
                                    break 2;
                                }
                                break 1;
                        }
                    }
                }

                if ($totalSell < 0.00)
                {
                    $totalSell = 0.00;
                }
                else
                {
                    $totalSell = UtilsObj::bround($pCurrencyExchangeRate * $totalSell, $pCurrencyDecimalPlaces);

                    // calculate the unit sell by dividing the total sell by the qty (this is because we are using a matrix to determine the actual price)
                    if ($newProductQty > 0)
                    {
                        $unitSell = UtilsObj::bround($totalSell / $newProductQty, $pCurrencyDecimalPlaces);
                    }
                }
            }
        }

        if ($pIsProductPrice)
        {
            $newQty = $newProductQty;
        }
        else
        {
            $newQty = $newComponentQty;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['recordid'] = $recordID;
        $resultArray['datecreated'] = $dateCreated;
        $resultArray['shoppingcarttype'] = $shoppingCartType;
        $resultArray['newqty'] = $newQty;
        $resultArray['startpagecount'] = $startPageCount;
        $resultArray['endpagecount'] = $endPageCount;
        $resultArray['unitsell'] = $unitSell;
        $resultArray['totalsell'] = $totalSell;
        $resultArray['linesubtract'] = $lineSubtract;
        $resultArray['baseprice'] = $basePrice;
        $resultArray['isactive'] = $isActive;

        return $resultArray;
    }

    /*
     * Function bind parameters dynamically
     * @params: dbconnection Object, datatype String, valueArray Array
     * @return: true/false
     *
     */

    static function bindParams(&$pStmt, $pDataTypes, $pValuesArray)
    {
        if (is_array($pDataTypes))
        {
            $pDataTypes = join('', $pDataTypes);
        }

        if (count($pValuesArray) > 0)
        {
            $params = array_merge(Array($pDataTypes), $pValuesArray);
            $tmp = array();
            foreach ($params as $key => $value)
            {
                $tmp[$key] = &$params[$key];
            }
            $bindOK = call_user_func_array(Array($pStmt, 'bind_param'), array_values($tmp));
        }
        else
        {
            $bindOK = true;
        }

        return $bindOK;
    }

    static function isUserIPAllowed($userIpAddress, $userIpAccessList, $userIpAccessType, $userCompanyCode)
    {
        global $gConstants;

        $result = 'str_ErrorIPNotAllowed';
        $matchCount = 0;

        // get restrictions for company
        $userCompanyDetails = self::getCompanyFromCode($userCompanyCode);
        $companyIpAccessList = $userCompanyDetails['ipaccesslist'];

        // if company is set to use default company's list
        if (($userCompanyCode != '') && ($userCompanyDetails['usedefaultipaccesslist'] == 1))
        {
            $companyIpAccessList = $gConstants['defaultipaccesslist'];
        }

        if ($userIpAccessType == 0)
        {
            // use default
            $userIpAccessList = $companyIpAccessList;
        }
        else
        {
            if ($userIpAccessType == 1)
            {
                // append default
                $userIpAccessList = $companyIpAccessList . ',' . $userIpAccessList;
            }
        }

        // Filter out empty elements after the explode.
        $userIpAccessListArray = array_filter(explode(',', $userIpAccessList));
		$ipInList = count($userIpAccessListArray);

        // if there are any restrictions at all
        if ($ipInList > 0)
        {
            $userIpArray = explode('.', $userIpAddress);
            $accessIpArray = array();
            foreach ($userIpAccessListArray as $accessIp)
            {
                if ($accessIp != '')
                {
					$accessIpArray = explode('.', $accessIp);
					$matchCount = 0;
					for ($i = 0; $i < count($accessIpArray); $i++)
					{
						if ($i <= 3)
						{
							if ($accessIpArray[$i] == '*')
							{
								$matchCount++;
							}
							else
							{

								if ($accessIpArray[$i] == $userIpArray[$i])
								{
									$matchCount++;
								}
							}
						}
					}
					if ($matchCount == 4)
					{
						$result = '';
					}
                }
                else
                {
                	$result = '';
                }
            }
        }
        else
        {
            $result = '';
        }

        return array('result' => $result, 'count' => $ipInList);
    }

    static function createEvent($taskCode, $companyCode, $groupCode, $brandCode, $nextRunTime, $parentid, $param1, $param2, $param3,
            $param4, $param5, $param6, $param7, $param8, $orderHeaderID, $orderItemID, $userID, $pTask1, $pTask2, $pTargetUserID)
    {
        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $maxRunCount = 0;
        $eventActive = 1;
        $recordID = 0;

        $taskDetails = self::getTask($taskCode);
        $result = $taskDetails['result'];
        if ($result != '')
        {
            $resultParam = $taskDetails['resultParam'];
        }
        else
        {
            // If no next runtime has been set the use the tasks next run time
            if ($nextRunTime == '')
            {
                $nextRunTime = $taskDetails['nextRunTime'];
            }

            $maxRunCount = $taskDetails['maxRunCount'];
        }

		$param1DataLength = strlen($param1);
		$param2DataLength = strlen($param2);

		if ($param1DataLength > 15728640)
		{
			$param1 = gzcompress($param1, 9);
		}
		else
		{
			$param1DataLength = 0;
		}

		if ($param2DataLength > 15728640)
		{
			$param2 = gzcompress($param2, 9);
		}
		else
		{
			$param2DataLength = 0;
		}

        if ($result == '')
        {
            $dbObj = self::getGlobalDBConnection();
            if ($dbObj)
            {
                if ($stmt = $dbObj->prepare('INSERT INTO `EVENTS` (`datecreated`, `taskcode`, `maxruncount`, `companycode`, `groupcode`, `webbrandcode`,
												`nextruntime`, `parentid`, `param1`, `param1datalength`, `param2`, `param2datalength`, `param3`,
												`param4`, `param5`, `param6`, `param7`, `param8`, `task1`, `task2`, `orderheaderid`, `orderitemid`,
												`userid`, `active`, `targetuserid`)
												VALUES (now(), ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'))
                {
                    if (($stmt) && ($stmt->bind_param('sissssisisissssssssiiiii', $taskCode, $maxRunCount, $companyCode, $groupCode, $brandCode,
