    static function getActiveEventsByTaskCode($taskCode, $limit)
    {
        $resultArray = array();
        $eventsArray = array();
        $result = '';
        $resultParam = '';

        if ($limit > -1)
        {
            $limit = 'LIMIT 0, ' . (int) $limit;
        }
        else
        {
            $limit = '';
        }

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            // retrieve the event data
            // we use an inner join here as it prevents mysql from retrieving blob data until we have a final list of rows we need to retrieve
            if ($stmt = $dbObj->prepare('SELECT `e2`.`id`, `e2`.`companycode`, `e2`.`groupcode`, `e2`.`webbrandcode`, `e2`.`runcount`, `e2`.`parentid`, `e2`.`priority`,
                                                `e2`.`param1`, `e2`.`param1datalength`, `e2`.`param2`, `e2`.`param2datalength`, `e2`.`param3`,
												`e2`.`param4`, `e2`.`param5`, `e2`.`param6`, `e2`.`param7`, `e2`.`param8`, `e2`.`task1`, `e2`.`task2`,
												`e2`.`orderheaderid`, `e2`.`orderitemid`, `e2`.`userid`
                                        FROM `EVENTS` `e2` INNER JOIN
                                            (SELECT `id`
                                                FROM `EVENTS` WHERE (`taskcode` = ?)
                                                AND ((`nextruntime` <= NOW()))
                                                AND (`active` = 1) AND (`statuscode` != 2) AND (`runcount` < `maxrunCount`)
                                                ORDER BY `priority` DESC, `nextruntime` DESC ' . $limit . '
                                            ) AS `e1`
                                        WHERE `e2`.`id` = `e1`.`id`'))
            {
                if ($stmt->bind_param('s', $taskCode))
                {
					if ($stmt->execute())
					{
						$stmt->store_result();

						if ($stmt->bind_result($id, $companyCode, $groupCode, $webBrandCode, $runCount, $parentID, $priority, $param1, $param1DataLength, $param2,
								$param2DataLength, $param3, $param4, $param5, $param6, $param7, $param8, $task1, $task2, $orderHeaderID, $orderItemID,
								$userID))
						{
							UtilsObj::resetPHPScriptTimeout();

							while ($stmt->fetch())
							{
								$eventItemArray = array();
								$eventItemArray['id'] = $id;
								$eventItemArray['companyCode'] = $companyCode;
								$eventItemArray['groupCode'] = $groupCode;
								$eventItemArray['webBrandCode'] = $webBrandCode;
								$eventItemArray['runCount'] = $runCount;
								$eventItemArray['parentId'] = $parentID;
								$eventItemArray['priority'] = $priority;

								if ($param1DataLength > 0)
								{
									$param1 = gzuncompress($param1, $param1DataLength);
								}

								if ($param2DataLength > 0)
								{
									$param2 = gzuncompress($param2, $param2DataLength);
								}

								$eventItemArray['param1'] = $param1;
								$eventItemArray['param2'] = $param2;
								$eventItemArray['param3'] = $param3;
								$eventItemArray['param4'] = $param4;
								$eventItemArray['param5'] = $param5;
								$eventItemArray['param6'] = $param6;
								$eventItemArray['param7'] = $param7;
								$eventItemArray['param8'] = $param8;
								$eventItemArray['task1'] = $task1;
								$eventItemArray['task2'] = $task2;
								$eventItemArray['orderheaderid'] = $orderHeaderID;
								$eventItemArray['orderitemid'] = $orderItemID;
								$eventItemArray['userid'] = $userID;
								$eventsArray[] = $eventItemArray;

								UtilsObj::resetPHPScriptTimeout();
							}
						}
					}
					else
					{
						$result = 'str_DatabaseError';
						$resultParam = 'getActiveEventsByTaskCode execute ' . $dbObj->error;
					}
                }
                else
                {
                    $result = 'str_DatabaseError';
                    $resultParam = 'getActiveEventsByTaskCode bind ' . $dbObj->error;
                }

                $stmt->free_result();
				$stmt->close();
				$stmt = null;
            }
            else
            {
                $result = 'str_DatabaseError';
                $resultParam = 'getActiveEventsByTaskCode prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            $result = 'str_DatabaseError';
            $resultParam = 'getActiveEventsByTaskCode connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['events'] = $eventsArray;

        return $resultArray;
    }

