    static function updateEvent($eventId, $runDate, $nextRunTime, $statusCode, $statusMessage)
    {
        $resultArray = array();
        $result = '';
        $resultParam = '';
        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('UPDATE `EVENTS` SET `lastruntime` = ?, `nextruntime` = ?, `statuscode` = ?, `statusmessage` = ?, runcount = runcount + 1  WHERE `id` = ?'))
            {
                if ($stmt->bind_param('ssisi', $runDate, $nextRunTime, $statusCode, $statusMessage, $eventId))
                {
                    $stmt->execute();
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'updateEvent bind ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'updateEvent prepare ' . $dbObj->error;
            }
            $dbObj->close();
        }
        $resultArray['result'] = $result;
        $resultArray['resultParam'] = $resultParam;
        return $resultArray;
    }

