    static function removeDeadEvents($pTaskCode, $pDeleteExpiredInterval)
    {
        $resultArray = Array();
        $result = '';
        $resultParam = '';

        $dbObj = DatabaseObj::getGlobalDBConnection();

        $serverTime = DatabaseObj::getServerTime();
        $expiryTime = date('Y-m-d H:i:s', strtotime($serverTime) - ($pDeleteExpiredInterval * (24 * 60 * 60)));

        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('DELETE FROM `EVENTS` WHERE (`taskcode` = ?) AND (`lastruntime` <= ?) AND (`statuscode` = 2)'))
            {
                if ($stmt->bind_param('ss', $pTaskCode, $expiryTime))
                {
                    if (!$stmt->execute())
                    {
                        // could not open database connection
                        $result = 'str_DatabaseError';
                        $resultParam = 'removeDeadEvents ' . $dbObj->error;
                    }
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'removeDeadEvents connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

        return $resultArray;
    }

    /**
     * @param $pTargetUserID
     * @param $pStatusCode
     * @param string $pTaskCode
     * @return int
     */
    static function updateEventsByTargetUser($pTargetUserID, $pStatusCode, $pTaskCode = '')
    {
        $affectedRows = 0;

        $dbObj = DatabaseObj::getGlobalDBConnection();

        $sql = 'UPDATE `EVENTS` SET `statuscode` = ?
                WHERE `targetuserid` = ?
                AND `statuscode` != ?';

        $bindings = Array('iii', $pStatusCode, $pTargetUserID, $pStatusCode);

        if ($pTaskCode != '')
        {
            $sql .= ' AND `taskcode` = ?';
            $bindings[0] .= 's';
            $bindings[] = $pTaskCode;
        }

        if ($stmt = $dbObj->prepare($sql))
        {
            $bindOk = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindings));
            if ($bindOk)
            {
                if ($stmt->execute())
                {
                    $affectedRows = $stmt->affected_rows;
                }
            }

            $stmt->free_result();
            $stmt->close();
        }

        $dbObj->close();

        return $affectedRows;
    }

