    static function updateTaskStatus($pTaskCode, $pParams, &$pDBObj)
	{
		if ($pDBObj)
		{
			$typesArray = array();
			$paramArray = array();
			$stmtArray = array();

			foreach ($pParams as $paramName => $paramData)
			{
				$stmtArray[] = $paramName . ' = ?';
				$paramArray[] = $paramData['value'];
				$typesArray[] = $paramData['type'];
			}

			if (count($stmtArray) > 0)
			{
				$stmtArray = join(', ', $stmtArray);
			}
			else
			{
				$stmtArray = '';
			}

			$stmt = $pDBObj->prepare('UPDATE `TASKS` SET ' . $stmtArray . ' WHERE `taskcode` = ?');
			if ($stmt)
			{
				$paramArray[] = $pTaskCode;
				$typesArray[] = 's';

				$bindOK = DatabaseObj::bindParams($stmt, $typesArray, $paramArray);

				if ($bindOK)
				{
					if (! $stmt->execute())
					{
						UtilsObj::writeLogEntry("str_DatabaseError - 'updateTaskStatus execute '" . $pDBObj->error);
					}
				}
				$stmt->free_result();
				$stmt->close();
			}
		}
		else
		{
			UtilsObj::writeLogEntry("str_DatabaseError - 'updateTaskStatus connect '" . $pDBObj->error);
		}
	}

    /**
     * Retrieves the entire asset record for the supplied record id.
     * This function does not use data binding to avoid memory related issues
     *
     * @static
     *
     * @return array
     *   the result array will contain the response of the database operation
     *
     * @author Kevin Gale
     * @since Version 3.0.0
     */
    static function getAssetFromID($pAssetID)
    {
        $resultArray = Array('id' => 0, 'retrievalid' => '', 'datecreated' => '', 'datemodified' => '', 'name' => '', 'assettype' => 0,
            'data' => '', 'previewtype' => '', 'previewwidth' => 0, 'previewheight' => 0);

        $result = '';
        $resultParam = '';

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            $pAssetID = (int) $pAssetID; // make sure the assetID is an integer to prevent any sql injection

            $resultSet = $dbObj->query('SELECT * FROM `ASSETDATA` WHERE `id` = ' . $pAssetID);
            if ($resultSet)
            {
                $dataRow = $resultSet->fetch_Array(MYSQLI_ASSOC);
                if ($dataRow)
                {
                    $resultArray = $dataRow;
                }
            }
            else
            {
                // could not execute query
                $result = 'str_DatabaseError';
                $resultParam = 'getAssetFromID query ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getAssetFromID connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

        return $resultArray;
    }

    /**
     * Inserts or Updates the asset record with the specified parameters
     *
     * @static
     *
     * @return array
     *   the result array will contain the result of the database operation
     *
     * @author Kevin Gale
     * @since Version 3.0.0
     */
    static function updateAssetRecord($pAssetID, $pName, $pAssetType, &$pData, $pPreviewType, $pWidth, $pHeight)
    {
        $resultArray = Array();
        $result = '';
        $resultParam = '';
        $assetID = 0;

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            if ($pAssetID == 0)
            {
                if ($stmt = $dbObj->prepare('INSERT INTO `ASSETDATA` (`datecreated`, `datemodified`) VALUES (now(), now())'))
                {
                    if ($stmt->execute())
                    {
                        $assetID = $dbObj->insert_id;
                    }

                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }

                $retrievalID = UtilsObj::generateAssetRetrievalID($assetID);
            }

            if ($pAssetID == 0)
            {
                $stmt = $dbObj->prepare('UPDATE `ASSETDATA` SET `retrievalid` = ?, `name` = ? , `assettype` = ? , `data` = ?, `previewtype` = ?, `previewwidth` = ?, `previewheight` = ? WHERE `id` = ?');
                $bindOK = $stmt->bind_param('ssissiii', $retrievalID, $pName, $pAssetType, $pData, $pPreviewType, $pWidth, $pHeight,
                        $assetID);
            }
            else
            {
                $assetID = $pAssetID;

                $stmt = $dbObj->prepare('UPDATE `ASSETDATA` SET `datemodified` = now(), `data` = ?, `previewtype` = ?, `previewwidth` = ?, `previewheight` = ? WHERE `id` = ?');
                $bindOK = $stmt->bind_param('ssiii', $pData, $pPreviewType, $pWidth, $pHeight, $assetID);
            }

            if ($stmt)
            {
                if ($bindOK)
                {
                    if (!$stmt->execute())
                    {
                        $result = 'str_DatabaseError';
                        $resultParam = 'updateAssetRecord execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'updateAssetRecord bind ' . $dbObj->error;
                }
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'updateAssetRecord prepare ' . $dbObj->error;
            }

            $stmt->free_result();
            $stmt->close();
            $stmt = null;

            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'updateAssetRecord connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['assetid'] = $assetID;

        return $resultArray;
    }

    static function deleteAssetRecord($pAssetID)
    {
        $resultArray = Array();
