    static function updatePreviewImage($pAssetID, $pPreviewPath, $pPreviewType, $pName)
    {
        global $gSession;

        $result = '';
        $resultParam = '';
        $width = 0;
        $height = 0;
        $imageData = '';
        $imageSize = 0;
        $assetType = TPX_ASSETTYPE_IMAGE;

        if ($pPreviewPath != '')
        {
            list($width, $height) = getimagesize($pPreviewPath);
            $imageSize = filesize($pPreviewPath);

            // process an image file which has been uploaded via the browser

            $validImageTypes = Array('image/jpeg', 'image/pjpeg', 'image/gif', 'image/png', 'image/x-png');

            if ($imageSize > 0)
            {
                // make sure that the file is a valid type
                if (in_array(strtolower($pPreviewType), $validImageTypes))
                {
                    // read the image data
                    $fp = fopen($pPreviewPath, 'rb');
                    if ($fp)
                    {
                        $imageData = fread($fp, $imageSize);
                        fclose($fp);
                    }
                    else
                    {
                        $imageSize = 0;
                    }
                }
                else
                {
                    $result = 'str_ErrorUploadInvalidFileType';
                }

                // remove the temp upload file
                UtilsObj::deleteFile($pPreviewPath);
            }
        }

        if ($result == '')
        {
            $updateAssetResultArray = self::updateAssetRecord($pAssetID, $pName, $assetType, $imageData, $pPreviewType, $width, $height);
            $result = $updateAssetResultArray['result'];
            $resultParam = $updateAssetResultArray['resultparam'];
            $assetID = $updateAssetResultArray['assetid'];

            if ($result == '')
            {
                DatabaseObj::updateActivityLog($gSession['ref'], 0, $gSession['userid'], $gSession['userlogin'], $gSession['username'], 0,
                        'ADMIN', 'COMPONENTPREVIEWIMAGE-UPDATE', $assetID, 1);
            }
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['assetid'] = $assetID;

        return $resultArray;
    }

    static function getPreviewImage()
    {
        global $gSession;

        $resultArray = Array();
        $previewType = '';
        $previewWidth = '';
        $previewHeight = '';
        $image = '';
        $error = '';

        $assetID = $_GET['id'];
        $showTempFile = $_GET['tmp'];

        if (($showTempFile == '1') && ($gSession['previewpath'] != ''))
        {
            // a temporary image file has been uploaded
            $previewPath = $gSession['previewpath'];
            $previewType = $gSession['previewtype'];
            $previewSize = filesize($previewPath);

            list($previewWidth, $previewHeight) = getimagesize($previewPath);

            // read the image data
            $fp = fopen($previewPath, 'rb');
            if ($fp)
            {
                $image = fread($fp, $previewSize);
                fclose($fp);
            }
        }
        else
        {
            $dbObj = DatabaseObj::getGlobalDBConnection();
            if ($dbObj)
            {
                $sqlStatement = 'SELECT `previewtype`, `data`, `previewwidth`, `previewheight` FROM `ASSETDATA` WHERE (`id` = ?)';
                if ($stmt = $dbObj->prepare($sqlStatement))
                {
                    if ($stmt->bind_param('i', $assetID))
                    {
                        if ($stmt->execute())
                        {
                            if ($stmt->store_result())
                            {
                                if ($stmt->num_rows > 0)
                                {
                                    if ($stmt->bind_result($previewType, $image, $previewWidth, $previewHeight))
                                    {
                                        if (!$stmt->fetch())
                                        {
                                            // fetch error
                                            $error = 'getPreviewImage: fetch ' . $dbObj->error;
                                        }
                                    }
                                    else
                                    {
                                        // bind result error
                                        $error = 'getPreviewImage: bind result ' . $dbObj->error;
                                    }
                                }
                            }
                            else
                            {
                                // store result error
                                $error = 'getPreviewImage: store result ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // execute error
                            $error = 'getPreviewImage: execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // bind params error
                        $error = 'getPreviewImage: bind params ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
                else
                {
                    // prepare error
                    $error = 'getPreviewImage: Prepare ' . $dbObj->error;
                }
                $dbObj->close();
            }
        }

        $resultArray['previewtype'] = $previewType;
        $resultArray['image'] = $image;
        $resultArray['previewwidth'] = $previewWidth;
        $resultArray['previewheight'] = $previewHeight;

        return $resultArray;
    }

    /**
	 * This function returns an array which is either the original array or an array
	 * with scaled values if one of the dimensions is larger than the recommended dimensions
	 *
	 * @param array $pCurrentDimensions Current dimensions of the image
	 * @param array $pRecommendedDimensions Recommended dimensions of the image
	 * @return array An array containing either the current width/height or a rescaled width/height
	 */
	static function getAutoScaleInfo($pCurrentDimensions, $pRecommendedDimensions)
	{
		$sizeInfo = [];
		$ratios = ['width' => 1, 'height' => 1];
		if($pCurrentDimensions['width'] > $pRecommendedDimensions['width'])
		{
			$ratios['width'] = $pRecommendedDimensions['width']/$pCurrentDimensions['width'];
		}
		if($pCurrentDimensions['height'] > $pRecommendedDimensions['height'])
		{
			$ratios['height'] = $pRecommendedDimensions['height']/$pCurrentDimensions['height'];
		}
		if(($ratios['width'] !== 1) || ($ratios['height'] !== 1))
		{
			// set the ratio to be the smallest value a ratio of 0.6 gives a smaller image than 0.8
			$ratio = ($ratios['width'] < $ratios['height']) ? $ratios['width'] : $ratios['height'];
			$sizeInfo = [
				'width' => ($pCurrentDimensions['width'] * $ratio),
				'height' => ($pCurrentDimensions['height'] * $ratio)
			];
		}
		else
		{
			$sizeInfo = $pCurrentDimensions;
		}
		return $sizeInfo;
	}

	/**
	 *
	 * @param string $pImageType image mime type
	 * @param string $pImagePath path to the image
	 * @param array $pCurrentSizeInfo current image dimensions
	 * @param array $pRecommendedDimensions desired image dimensions
	 * @return bool returns if we have scaled the image
	 */
	static function autoScaleImage($pImageType, $pImagePath, $pCurrentSizeInfo, $pRecommendedDimensions)
	{
		// get the desired image size
		$sizeInfo = self::getAutoScaleInfo($pCurrentSizeInfo, $pRecommendedDimensions);
		$image = null;
		$return = false;

		switch(strtolower($pImageType))
		{
			case 'image/jpeg':
			case 'image/pjpeg':
			{
				$image = imagecreatefromjpeg($pImagePath);
				break;
			}
			case 'image/gif':
			{
				$image = imagecreatefromgif($pImagePath);
				break;
			}
			case 'image/png':
			case 'image/x-png':
			{
				$image = imagecreatefrompng($pImagePath);
				break;
			}
			default:
			{
				// noop
				break;
			}
		}

		// we only resize if there is an image and if the current size is not the desired size
		// or resave the image to optimize slightly, this will remove any exif data on the image.
		if($image !== null)
		{
			$saveSize = ($pCurrentSizeInfo !== $sizeInfo) ? $sizeInfo : $pCurrentSizeInfo;
			$return = self::scaleAndSaveImage($pImageType, $pImagePath, $sizeInfo, $image);
		}

		return $return;
	}

	/**
	 *
	 * @param string $pImageType mime type of the image
	 * @param string $pPathToImage file path to the image
	 * @param array $pSizeDetails image size
	 * @param reference $image original image to resize
	 * @return bool
	 */
	static function scaleAndSaveImage($pImageType, $pPathToImage, $pSizeDetails, &$image)
	{
		$scaled = imagescale($image, $pSizeDetails['width'], $pSizeDetails['height']);
		$saved = false;

		// save the image according to what type it is
		switch(strtolower($pImageType))
		{
			case 'image/jpeg':
			case 'image/pjpeg':
			{
				$saved = imagejpeg($scaled, $pPathToImage);
				break;
			}
			case 'image/gif':
			{
				$saved = imagegif($scaled, $pPathToImage);
				break;
			}
			case 'image/png':
			case 'image/x-png':
			{
                // integer representation of the color black (rgb: 0,0,0)
                $background = imagecolorallocate($scaled, 255, 255, 255);

                // removing the black from the placeholder
                imagecolortransparent($scaled, $background);

                // turning off alpha blending (to ensure alpha channel information is preserved, rather than removed (blending with the rest of the image in the form of black))
                imagealphablending($scaled, false);

                // turning on alpha channel information saving (to ensure the full range of transparency is preserved)
                imagesavealpha($scaled, true);
                $saved = imagepng($scaled, $pPathToImage);
				break;
			}
			default:
			{
				// noop
				break;
			}
		}
		if($saved === true)
		{
			// if we saved the image clear any memory used during this operation
			imagedestroy($image);
			imagedestroy($scaled);
		}
		return $saved;
	}

	/**
	 * Defines and provides an array of recommended image sizes for use in preview uploads
	 *
	 * @param string $pSection section to get image information for
	 * @return array recommended width and height for images used in previews
	 */
	static function getRecommendedImageSizes($pSection)
	{
		// for initial update only this needs to move somewhere useful possibly be a config option
		// from control center so if a user were to change these values through css/branding options
		// the values here should update rather than be defined as static magic numbers values are pixels
		// array format is section => [width, height]
		$previewImageSizes = array(
			'default' => array('width' => 75, 'height' => 75),
			'splashscreen' => array('width' => 800, 'height' => 600),
			'components' => array('width' => 320, 'height' => 320),
			'products' => array('width' => 110, 'height' => 75),
			'shippingmethods' => array('width' => 600, 'height' => 150)
		);
		$section = strtolower($pSection);

		// if there is no key for the given section ($pSection) use the default sizes
		return array_key_exists($section, $previewImageSizes) ? $previewImageSizes[$section] : $previewImageSizes['default'];
	}

	/**
	 * Uploads a preview image, this also resizes any oversized images to be the recommended sizes,
	 * the recommended sizes are currently defined in $previewImageSizes in this function
	 *
	 * @global array $gSession Session array passed globally
	 * @param string $pSection String for which section we are uploading the image for
	 * @return array Array containing information on the original image size and recommended sizes as well as upload status
	 */
    static function uploadPreviewImage($pSection)
    {
        global $gSession;

		$recommended = self::getRecommendedImageSizes($pSection);

        $result = '';
        $resultParam = '';
        $width = 0;
        $height = 0;
        $logoPath = $_FILES['preview']['tmp_name'];
        $logoPathNew = '';
        $logoType = $_FILES['preview']['type'];
        $fileUploadResultArray = Array('result' => '', 'filetype' => '', 'filedata' => '');

        list($width, $height) = getimagesize($logoPath);

        $validImageTypes = Array('image/jpeg', 'image/pjpeg', 'image/gif', 'image/png', 'image/x-png');

        // make sure that the file is a valid type
        if (in_array(strtolower($logoType), $validImageTypes))
        {
            // first make sure that we are dealing with a file that has been uploaded
            // create a new temporary file
            $logoPathNew = tempnam(sys_get_temp_dir(), 'LGO');
            if (move_uploaded_file($logoPath, $logoPathNew))
            {
				//image rescale move to another class/function or should this add something to image proc que
				$currentSizeInfo = ['width' => $width, 'height' => $height];
				$scaled = self::autoScaleImage($logoType, $logoPathNew, $currentSizeInfo, $recommended);

				$gSession['previewpath'] = $logoPathNew;
                $gSession['previewtype'] = $logoType;
                DatabaseObj::updateSession();
            }
        }
        else
        {
            $result = 'str_ErrorUploadInvalidFileType';
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['width'] = $width;
        $resultArray['height'] = $height;
		// if we dont have an image size profile here set the recommended to be 75px x 75px
		$resultArray['recommendedwidth'] = isset($recommended['width']) ? $recommended['width'] : 75;
		$resultArray['recommendedheight'] = isset($recommended['height']) ? $recommended['height'] : 75;

        return $resultArray;
    }

