    static function getOrderItemById($pOrderItemId)
    {
        // determine which database table the uploadref exists in

        $result = '';
        $resultParam = '';

        $orderId = 0;
        $userId = 0;
        $uploadRef = '';
        $projectName = '';
        $productName = '';
        $dataAvailable = false;

        $sqlStatement = "SELECT
                                `orderid`,
                                `userid`,
                                `uploadref`,
                                `projectname`,
                                `productname`,
                                IF (`productiondata` = 0 AND `ftpdata` = 0 AND `dbdata` = '0000-00-00 00:00:00', 1, 0) as `dataavailable`
                            FROM
                            `ORDERITEMS` WHERE `id` = ?";

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($stmt->bind_param('i', $pOrderItemId))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($orderId, $userId, $uploadRef, $projectName, $productName, $dataAvailable))
                                {
                                    if (!$stmt->fetch())
                                    {
                                        // no matching order
                                        $result = 'str_NoOrder';
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $result = 'str_DatabaseError';
                                    $resultParam = 'getOrderItemById bind result ' . $dbObj->error;
                                }
                            }
                            else
                            {
                                // no rows
                                $result = 'str_NoOrder';
                            }
                        }
                        else
                        {
                            // could not store result
                            $result = 'str_DatabaseError';
                            $resultParam = 'getOrderItemById store result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $result = 'str_DatabaseError';
                        $resultParam = 'getOrderItemById execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'getOrderItemById bind params ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getOrderItemById connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['orderid'] = $orderId;
        $resultArray['userid'] = $userId;
        $resultArray['uploadref'] = $uploadRef;
        $resultArray['projectname'] = $projectName;
        $resultArray['productname'] = $productName;
        $resultArray['dataavailable'] = ($dataAvailable == 1);

        return $resultArray;
    }

    static function getOrderItemsByIds($pOrderItemIdArray)
    {
        // determine which database table the uploadref exists in

        $result = '';
        $resultParam = '';

        $orderArray = array();

        $id = 0;
        $orderId = 0;
        $userId = 0;
        $uploadRef = '';
        $projectName = '';
        $productName = '';
        $dataAvailable = false;

        $sqlStatement = "SELECT
                                `id`,
                                `orderid`,
                                `userid`,
                                `uploadref`,
                                `projectname`,
                                `productname`,
                                IF (`productiondata` = 0 AND `ftpdata` = 0 AND `dbdata` = '0000-00-00 00:00:00', 1, 0) as `dataavailable`
                            FROM
                                `ORDERITEMS` WHERE `id` IN (" . implode(',', $pOrderItemIdArray) . ")";

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($stmt->execute())
                {
                    if ($stmt->store_result())
                    {
                        if ($stmt->num_rows > 0)
                        {
                            if ($stmt->bind_result($id, $orderId, $userId, $uploadRef, $projectName, $productName, $dataAvailable))
                            {
                                while($stmt->fetch())
                                {
                                    $orderArray[] = array(
                                                            'orderitemid' => $id,
                                                            'orderid' => $orderId,
                                                            'userid' => $userId,
                                                            'uploadref' => $uploadRef,
                                                            'projectname' => $projectName,
                                                            'productname' => $productName,
                                                            'dataavailable' => ($dataAvailable == 1));
                                }
                            }
                            else
                            {
                                // could not bind result
                                $result = 'str_DatabaseError';
                                $resultParam = 'getOrderItemsByIds bind result ' . $dbObj->error;
                            }
                        }
                    }
                    else
                    {
                        // could not store result
                        $result = 'str_DatabaseError';
                        $resultParam = 'getOrderItemsByIds store result ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not execute statement
                    $result = 'str_DatabaseError';
                    $resultParam = 'getOrderItemsByIds execute ' . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }
        else
        {
            // could not open database connection
            $result = 'str_DatabaseError';
            $resultParam = 'getOrderItemsByIds connect ' . $dbObj->error;
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;
        $resultArray['orders'] = $orderArray;

        return $resultArray;
    }

    static function getProductList($companyCode = '**ALL**')
    {
        global $gSession;

        $productsArray = array();
        $productItem = array();

        $dbObj = DatabaseObj::getGlobalDBConnection();
        if ($dbObj)
        {
            if (($companyCode == '**ALL**') || ($companyCode == ''))
            {
                $stmt = $dbObj->prepare('SELECT `id`, `code`, `name`, `active` FROM `PRODUCTS` WHERE `deleted` = 0 ORDER BY `code`');
                $bindOk = true;
            }
            else
            {
                $stmt = $dbObj->prepare('SELECT `id`, `code`, `name`, `active` FROM `PRODUCTS` WHERE `deleted` = 0 AND (`companycode` = ? OR `companycode` = "") ORDER BY `code`');
                $bindOk = $stmt->bind_param('s', $companyCode);
            }
            if (($stmt) && ($bindOk))
            {
                if ($stmt->bind_result($productId, $productCode, $productName, $productActive))
                {
                    if ($stmt->execute())
                    {
                        while ($stmt->fetch())
                        {
                            $productItem['id'] = $productId;
                            $productItem['code'] = $productCode;
                            $productItem['name'] = UtilsObj::encodeString(LocalizationObj::getLocaleString($productName,
                                                    $gSession['browserlanguagecode'], true), false);
                            $productItem['active'] = $productActive;
                            array_push($productsArray, $productItem);
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        return $productsArray;
    }

