	/**
	 * Returns an array of the order item components for a project. This list can be returned in the new lookup format or the old format.
	 * The old format may be used if the old structure is required, e.g. reorder for the eCommerce API.
	 *
	 * @param int $pOrderItemId Order items to return for that id.
	 * @param boolean $pOriginalFormat If true return the pictures in the original session format, if false use the new lookup format.
	 * @return array
	 */
    static function getOrderItemComponentSinglePrints($pOrderItemId, $pOriginalFormat = false)
    {
        $result = '';
        $resultParam = '';
        $pictures = array();
        $componentPath = '$SINGLEPRINT\\\%';
        $dbObj = DatabaseObj::getGlobalDBConnection();
		$printData = array();
		$pictureNames = array();
		$assetData = array();
		$prefix = ($pOriginalFormat) ? 'component' : '';

        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('SELECT `id`, `parentcomponentid`, `componentcategorycode`, `componentlocalcode`, `quantity`, `externalassetpageref`, `externalassetpagenumber`, `externalassetpagename`, `externalassetboxref`, `externalassetservicecode`,
            									`externalassetservicename`, `externalassetpricetype`, `skucode`, `componentname`, `externalassetunitcost`, `externalassetunitsell`, `componentunitsell`, `componentunitcost`, `subtotal`,
            									`componentunitweight`, `componenttotalsell`, `componenttaxrate`, `discountvalue`, `componentdiscountedtax`, `componentpath`, `setid`, `setname`, `componenttotaltax`
            								FROM `ORDERITEMCOMPONENTS` WHERE `orderitemid` = ? AND `componentpath` LIKE ? ORDER BY `sortorder`'))
            {
                if ($stmt->bind_param('is', $pOrderItemId, $componentPath))
                {
                    if ($stmt->bind_result($recordID, $parentID, $componentCategoryCode, $componentLocalCode, $quantity, $externalAssetPageRef,
                                    $externalAssetPageNumber, $exernalAssetPageName, $externalAssetBoxRef, $externalAssetServiceCode,
                                    $externalAssetServiceName, $externalAssetPriceType, $skuCode, $componentName, $externalAssetUnitCost,
                                    $externalAssetUnitSell, $componentUnitSell, $componentUnitCost, $subtotal, $componentUnitWeight,
                                    $componentTotalSell, $componenttaxrate, $discountvalue, $componentdiscountedtax, $componentPath, $setID, $setName, $componentTotalTax))
                    {
                        if ($stmt->execute())
                        {
                            $parentComponentCode = '';

                            while ($stmt->fetch())
                            {
								$parentComponentCode = $componentLocalCode;
								$picture['parentid'] = $parentID;
								$picture[$prefix . 'category'] = $componentCategoryCode;
								$picture[$prefix . 'code'] = $componentLocalCode;
								$picture['skucode'] = $skuCode;
								$picture[$prefix . 'name'] = $componentName;
								$picture[$prefix . 'qty'] = $quantity;
								$picture['pageref'] = $externalAssetPageRef;
								$picture['pagenumber'] = $externalAssetPageNumber;
								$picture['pagename'] = $exernalAssetPageName;
								$picture['boxref'] = $externalAssetBoxRef;
								$picture['picturename'] = $exernalAssetPageName;
								$picture['assetservicecode'] = $externalAssetServiceCode;
								$picture['assetservicename'] = $externalAssetServiceName;
								$picture['assetid'] = $skuCode;
								$picture['assetpricetype'] = $externalAssetPriceType;
								$picture['assetcost'] = $externalAssetUnitCost;
								$picture['assetsell'] = $externalAssetUnitSell;
								$picture['unitsell'] = $componentUnitSell;
								$picture['subtotal'] = $subtotal;
								$picture['unitcost'] = $componentUnitCost;
								$picture['unitweight'] = $componentUnitWeight;
								$picture['orderfootertaxrate'] = $componenttaxrate;
								$picture['discountvalue'] = $discountvalue;
								$picture['discountedtax'] = $componentdiscountedtax;
								$picture['totalcost'] = 0.00;
								$picture['totalsell'] = $componentTotalSell; //Email Content. Added this to the array to display totalsell for external asset.
								$picture['totaltax'] = $componentTotalTax;
								$picture['totalsellnotax'] = $componentTotalSell;
								$picture['totalsellwithtax'] = $componentTotalSell;
								$picture['totalweight'] = 0.0000;
								$picture['pricetaxcode'] = '';
								$picture['pricetaxrate'] = 0.00;

								// sub component structure
								$picture['setid'] = $setID;
								$picture['setname'] = $setName;
								$picture['sub' . $prefix . 'category'] = '';
								$picture['sub' . $prefix . 'code'] = '';
								$picture['sub' . $prefix . 'name'] = '';
								$picture['sub' . $prefix . 'skucode'] = '';
								$picture['sub' . $prefix . 'unitsell'] = 0.00;
								$picture['sub' . $prefix . 'unitcost'] = 0.00;
								$picture['sub' . $prefix . 'weight'] = 0.00;
								$picture['sub' . $prefix . 'totalcost'] = 0.00;
								$picture['sub' . $prefix . 'totalsell'] = 0.00;
								$picture['sub' . $prefix . 'totaltax'] = 0.00;
								$picture['sub' . $prefix . 'totalsellnotax'] = 0.00;
								$picture['sub' . $prefix . 'totalsellwithtax'] = 0.00;
								$picture['sub' . $prefix . 'totalweight'] = 0.00;
								$picture['sub' . $prefix . 'pricetaxcode'] = '';
								$picture['sub' . $prefix . 'pricetaxrate'] = '';
								$picture['componenthasprice'] = 1;

								// here we add the parent single print record to the array with the place holder subcomponet structure.
								// we then add the subcomponent information to the array based of its parentid.
								if ($picture['parentid'] == 0)
								{
									$pictures[$recordID] = $picture;
								}
								else
								{
									$parentID = $picture['parentid'];
									$pictures[$parentID]['setid'] = $picture['setid'];
									$pictures[$parentID]['setname'] = $picture['setname'];
									$pictures[$parentID]['sub' . $prefix . 'category'] = $picture[$prefix . 'category'];
									$pictures[$parentID]['sub' . $prefix . 'code'] = $picture[$prefix . 'code'];
									$pictures[$parentID]['sub' . $prefix . 'name'] = $picture[$prefix . 'name'];
									$pictures[$parentID]['sub' . $prefix . 'skucode'] = $picture['skucode'];
									$pictures[$parentID]['sub' . $prefix . 'unitsell'] = $picture['unitsell'];
									$pictures[$parentID]['sub' . $prefix . 'unitcost'] = $picture['unitcost'];
									$pictures[$parentID]['sub' . $prefix . 'unitweight'] = $picture['unitweight'];
									$pictures[$parentID]['sub' . $prefix . 'totalsell'] = $picture['totalsell'];
									$pictures[$parentID]['sub' . $prefix . 'totaltax'] = $picture['totaltax'];
									$pictures[$parentID]['sub' . $prefix . 'totalsellnotax'] = $picture['totalsellnotax'];
									$pictures[$parentID]['sub' . $prefix . 'totalsellwithtax'] = $picture['totalsellwithtax'];
								}
                            }
                        }
                        else
                        {
                            $result = 'str_DatabaseError';
                            $resultParam = 'getOrderItemComponentSinglePrints execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        $result = 'str_DatabaseError';
                        $resultParam = 'getOrderItemComponentSinglePrints bind result ' . $dbObj->error;
                    }
                }
                else
                {
                    $result = 'str_DatabaseError';
                    $resultParam = 'getOrderItemComponentSinglePrints bind ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                $result = 'str_DatabaseError';
                $resultParam = 'getOrderItemComponentSinglePrints prepare ' . $dbObj->error;
            }
        }
        else
        {
            $result = 'str_DatabaseError';
            $resultParam = 'getOrderItemComponentSinglePrints connect ' . $dbObj->error;
        }

		if (! $pOriginalFormat)
		{
			// Build a lookup table containing the picture data.
			$picturesLookup = array('data' => array(), 'key' => array(), 'printdata' => array(), 'asset' => array());
			$picturesIndex = 0;
			$pictureNamesIndex = 0;
			$pictureNamesLookup = array();

			foreach ($pictures as $picture)
			{
				$lookupUpKey = TPX_PICTURES_LOOKUP_CATEGORY_KEY . TPX_PICTURES_LOOKUP_SEPERATOR . $picture['code'] . TPX_PICTURES_LOOKUP_SEPERATOR .  $picture['qty']
					. TPX_PICTURES_LOOKUP_SEPERATOR . $picture['subcode'];

				$uniqueLookup = $lookupUpKey . TPX_PICTURES_LOOKUP_SEPERATOR . $picturesIndex;

				// We need to know the key so we can store it in the print data so we can look it up later.
				$pictureNameKey = -1;

				if (! in_array($picture['picturename'], $pictureNames))
				{
					$pictureNames[$pictureNamesIndex] = $picture['picturename'];
					$pictureNameKey = $pictureNamesIndex;
					$pictureNamesIndex++;
				}
				else
				{
					$pictureNameFlipped = array_flip($pictureNames);
					$pictureNameKey = $pictureNameFlipped[$picture['picturename']];
				}

				// We need to know the key so we can store it in the print data so we can look it up later.
				if (! array_key_exists($picture['picturename'], $pictureNamesLookup))
				{
					$pictureNamesLookup[$picture['picturename']] = $pictureNamesIndex;
					$pictureNames[$pictureNamesIndex] = $picture['picturename'];
					$pictureNameKey = $pictureNamesIndex;
					$pictureNamesIndex++;
				}
				else
				{
					$pictureNameKey = $pictureNamesLookup[$picture['picturename']];
				}

				$printData[$uniqueLookup] = array(
					'fn' => $pictureNameKey,
					'us' => $picture['unitsell'],
					'tc' => $picture['totalcost'],
					'ts' => $picture['totalsell'],
					'tt' => $picture['totaltax'],
					'tsnt' => $picture['totalsellnotax'],
					'tswt' => $picture['totalsellwithtax'],
					'tw' => $picture['totalweight'],
					'subus' => $picture['subunitsell'],
					'subtc' => $picture['subtotalcost'],
					'subts' => $picture['subtotalsell'],
					'subtt' => $picture['subtotaltax'],
					'subtsnt' => $picture['subtotalsellnotax'],
					'subtswt' => $picture['subtotalsellwithtax'],
					'subtw' => $picture['subtotalweight'],
					'subtotal' => $picture['subtotal'],
					'pageref' => $picture['pageref'],
					'pagenumber' => $picture['pagenumber'],
					'boxref' => $picture['boxref']
				);

				// Check it has an asset service code.
				if ($picture['assetservicecode'] != '')
				{
					$assetDataArray = array();
					$assetDataArray['asc'] = $picture['assetservicecode'];
					$assetDataArray['asn'] = $picture['assetservicename'];
					$assetDataArray['aid'] = $picture['assetid'];
					$assetDataArray['apt'] = $picture['assetpricetype'];
					$assetDataArray['ac'] = $picture['assetcost'];
					$assetDataArray['as'] = $picture['assetsell'];

					$assetData[$uniqueLookup] = $assetDataArray;
				}

				unset($picture['boxref']);
				unset($picture['pageref']);
				unset($picture['pagename']);
				unset($picture['pagenumber']);

				if (! array_key_exists($lookupUpKey, $picturesLookup['data']))
				{
					$picturesLookup['data'][$lookupUpKey] = $picture;
				}

				$picturesLookup['key'][] = $lookupUpKey;
				$picturesLookup['printdata'] = $printData;
				$picturesLookup['pname'] = $pictureNames;
				$picturesLookup['asset'] = $assetData;

				$picturesIndex++;
			}

			// Free memory.
			unset($pictures);

			$resultArray['pictures'] = $picturesLookup;
		}
		else
		{
			$resultArray['pictures'] = $pictures;
		}

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

        return $resultArray;
    }

    static function getOrderItemComponentCalendarComponents($pOrderItemId)
    {
        $result = '';
        $resultParam = '';
        $calendarCustomisations = array();
        $componentPath = '$CALENDARCUSTOMISATION\\\%';
        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
