                                        $archivedOrderData['webbranddisplayurl'] = $webBrandData['displayurl'];
                                        $archivedOrderData['webbrandemailsettings'] = array('usedefaultemailsettings' => $webBrandData['usedefaultemailsettings'],
                                        													'smtporderconfirmationactive' => $webBrandData['smtporderconfirmationactive'],
                                        													'smtporderconfirmationname' => $webBrandData['smtporderconfirmationname'],
                                        													'smtporderconfirmationaddress' => $webBrandData['smtporderconfirmationaddress'],
                                        													'isactive' => $webBrandData['isactive']);
                                        $archivedOrderData['items'] = self::getOrderItemFromOrderHeaderID($orderID, $languagecode);

                                        foreach ($archivedOrderData['items'] as $item)
                                        {
                                            foreach ($item as $key => $value)
                                            {
