											(
											'0' => Array
												(
												'ratecode' => $shippingratecode,
												'zonecode' => '',
												'methodcode' => $shippingmethodcode,
												'methodname' => $shippingmethodname,
												'info' => $shippingrateinfo,
												'usedefaultbillingaddress' => '0',
												'usedefaultshippingaddress' => '0',
												'canmodifycontactdetails' => '0',
												'requiresdelivery' => '0',
												'isdefault' => '0',
												'cost' => $shippingratecost,
												'sell' => $shippingratesell
											)
										);

										$archivedOrderData['paymentmethods'] = Array
											(
											'0' => Array
												(
												'id' => '1',
												'code' => $paymentmethodcode,
												'name' => $paymentmethodname,
												'availablewhenshipping' => '1',
												'availablewhennotshipping' => '1',
												'isactive' => '1'
											)
										);

										$archivedOrderData['formattedshippingaddress'] = '';
										$archivedOrderData['formattedbillingaddress'] = '';
										$archivedOrderData['custominit'] = '';
										$metaData = MetaDataObj::getMetaData($orderID, 0, 0, 'ORDER', $metadatacodelist, $languagecode);
										$archivedOrderData['metadata']['layouthtml'] = MetaDataObj::buildDisplayOrderKeywordHTML($metaData, 'ORDER');
										$archivedOrderData['metadata']['submitform'] = '';
										$archivedOrderData['metadata']['submitjavascript'] = '';
										$archivedOrderData['previousstage'] = 'shipping';
										$archivedOrderData['nextstage'] = 'payment';
										$archivedOrderData['orderid'] = $orderID;
										$archivedOrderData['emailtemplate'] = $pEmailTemplate;
                                    }
                                }
                            }
                        }
                    }
                }

                if ($stmt)
                {
                    $stmt->free_result();
                    $stmt->close();
                    $stmt = null;
                }
            }

            $dbObj->close();
        }

        return $archivedOrderData;
    }

    /*
     * This function is to get Section and SubSections
     * If $pComponentCateogoryCode = '' it will get main sections
     * otherwise it will get the subsections from the given section
     */

    static function getOrderSections($pOrderID, $pOderItemID, $pParentComponentId, $pBrowserLanguageCode, $pComponentPath = '')
    {
        $resultArray = Array();
        $componentArray = Array();
        $i = 0;
        $ignoreSinglePrintBindParam = '$SINGLEPRINT\\\%';
        $ignoreCalendarCustomBindParam = '$CALENDARCUSTOMISATION\\\%';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $statement = 'SELECT
			oic.id, oic.componentdefaultcode, oic.sectionid , oic.componentcategorycode, oic.componentinfo, oic.skucode, oic.componentcategoryname, oic.componentpath, oic.componentcode, oic.componentname, oic.metadatacodelist, oic.islist, oic.quantity,
			oic.componentunitcost, oic.componentunitsell, oic.componenttotalcost, oic.subtotal, oic.componenttotalsell, oic.componenttotaltax, oic.componentunitweight, oic.componenttotalweight, oic.pricingmodel,
			oic.componentlocalcode, oic.componentdefaultcode, oic.componenttaxname, oic.componenttaxrate, oic.discountvalue, oic.componentdiscountedtax,
			oic.orderitemid, ot.productcode, oic.componentinfo, oic.componentpriceinfo
			FROM `ORDERITEMCOMPONENTS` oic, `ORDERITEMS` ot
			WHERE';

            if ($pComponentPath != '')
            {
                // select sections in orderfooter
                if ($pOderItemID == '-1')
                {
                    /*
                     * - Check orderid, orderitemid = -1
                     * - Check if length of subsection componentpath > length of given section componentpath
                     * - Check if subsection componentpath appears at the begining of section componentpath
                     * -
                     */
                    $statement .= ' oic.`orderid` = ? AND oic.`orderitemid` = ? AND oic.orderid = ot.orderid
					AND oic.`parentcomponentid` = ?
					AND LENGTH(oic.`componentpath`) >= LENGTH(?)
					AND INSTR(oic.`componentpath`, ?) = 1
					AND ((oic.componentpath NOT LIKE ?) AND (oic.componentpath NOT LIKE ?))
					GROUP BY (oic.componentpath)';
                }
                // select normal sections.
                else
                {
                    /* select subsection that belongs to the given section:
                     * - Check orderid, orderitemid
                     * - Check if length of subsection componentpath > length of given section componentpath
                     * - Check if subsection componentpath appears at the begining of section componentpath
                     */
                    $statement .= ' oic.`orderid` = ? AND oic.`orderitemid` = ? AND oic.orderid = ot.orderid AND ot.`id` = oic.`orderitemid`
					AND oic.`parentcomponentid` = ?
					AND LENGTH(oic.`componentpath`) > LENGTH(?)
					AND INSTR(oic.`componentpath`, ?) = 1
					AND ((oic.componentpath NOT LIKE ?) AND (oic.componentpath NOT LIKE ?))
					AND oic.islist = 1';
                }
            }
            else
            {
                /* select main section of the given item
                 * - Check orderid, orderitemid
                 * - AND ? = ? doesn't do anything, its there to make number of ? same as the query above so we can use the same bind_param for both statements.
                 * - Count number of $ to make sure it is = 1 (means it is main section: $COVER\, $PAPER\ etc...)
                 */
                $statement .= ' oic.`orderid` = ? AND oic.`orderitemid` = ? AND oic.orderitemid = ot.id
				AND oic.`parentcomponentid` = ?
				AND ? = ?
				AND ((oic.componentpath NOT LIKE ?) AND (oic.componentpath NOT LIKE ?))
				AND (LENGTH(oic.`componentpath`) - LENGTH(REPLACE(oic.`componentpath`, "$", "")) ) = 1 AND oic.islist = 1';
            }

            if ($stmt = $dbObj->prepare($statement))
            {
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);

                if ($stmt->bind_param('iiissss', $pOrderID, $pOderItemID, $pParentComponentId, $pComponentPath, $pComponentPath, $ignoreSinglePrintBindParam, $ignoreCalendarCustomBindParam))
                {
                    if ($stmt->bind_result($orderitemcomponentid, $componentdefaultcode, $sectionid, $componentcategorycode, $componentinfo,
                                    $skucode, $componentcategoryname, $componentpath, $componentcode, $componentname, $metadatacodelist,
                                    $islist, $quantity, $componentunitcost, $componentunitsell, $componenttotalcost, $subtotal,
                                    $componenttotalsell, $componenttotaltax, $componentunitweight, $componenttotalweight, $pricingmodel,
                                    $componentlocalcode, $componentdefaultcode, $componenttaxname, $componenttaxrate, $discountvalue,
                                    $componentdiscountedtax, $itemid, $productcode, $orderComponentInfo, $priceInfo))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $i++;
                                $componentArray['defaultcode'] = $componentdefaultcode;
                                $componentArray['productcode'] = $productcode;
                                $componentArray['id'] = $itemid;
                                $componentArray['sectioncode'] = $componentcategorycode;
                                $componentArray['sectionlabel'] = $componentcategoryname;
                                $componentArray['sectionname'] = $componentcategoryname;
                                $componentArray['path'] = $componentpath;
                                $componentArray['categorycode'] = $componentcategorycode;
                                $componentArray['categoryname'] = $componentcategoryname;
                                $componentArray['info'] = $componentinfo;
                                $componentArray['prompt'] = $componentcategoryname;
                                $componentArray['count'] = 1;
                                $componentArray['code'] = $componentcode;
                                $componentArray['name'] = $componentname;
                                $componentArray['info'] = $orderComponentInfo;
                                $componentArray['moreinfolinkurl'] = '';
                                $componentArray['moreinfolinktext'] = '';
                                $componentArray['priceinfo'] = $priceInfo;
                                $componentArray['islist'] = $islist;
                                $componentArray['unitcost'] = $componentunitcost;
                                $componentArray['unitsell'] = $componentunitsell;
                                $componentArray['totalcost'] = $componenttotalcost;
                                $componentArray['totalsell'] = $componenttotalsell;
                                $componentArray['subtotal'] = $subtotal;
                                $componentArray['totaltax'] = $componenttotaltax;
                                $componentArray['displaytaxraw'] = $componenttotaltax;
                                $componentArray['totalsellnotax'] = $componenttotalsell;
                                $componentArray['totalsellwithtax'] = $componenttotalsell;
                                $componentArray['orderfootertaxname'] = $componenttaxname;
                                $componentArray['orderfootertaxrate'] = $componenttaxrate;
                                $componentArray['discountvalue'] = $discountvalue;
                                $componentArray['discountedtax'] = $componentdiscountedtax;
                                $componentArray['unitweight'] = $componentunitweight;
                                $componentArray['totalweight'] = $componenttotalweight;
                                $componentArray['pricingmodel'] = $pricingmodel;
                                $componentArray['quantity'] = $quantity;
                                $componentArray['orderlineid'] = $pOderItemID . "_" . $i;
                                $componentArray['checkboxes'] = self::getOrderCheckboxesFromDatabase($pOrderID, $itemid,
                                                $pBrowserLanguageCode, $orderitemcomponentid, $componentpath . $componentlocalcode . '\\');

                                $componentArray['defaultlocalcode'] = $componentlocalcode;
                                $componentArray['localcode'] = $componentlocalcode;
								$componentArray['componenthasprice'] = 1;
								$componentArray['hasprice'] = 1;

                                $metaData = MetaDataObj::getMetaData($pOrderID, $itemid, $orderitemcomponentid, 'COMPONENT',
                                                $metadatacodelist, $pBrowserLanguageCode);
                                $componentArray['metadatahtml'] = MetaDataObj::buildDisplayOrderKeywordHTML($metaData, 'COMPONENT');

                                $componentArray['subsections'] = self::getOrderSections($pOrderID, $itemid, $orderitemcomponentid,
                                                $pBrowserLanguageCode, $componentpath);

                                $resultArray[] = $componentArray;
                            }
                        }
                    }
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }


        return $resultArray;
    }

    static function getOrderItemFromOrderHeaderID($pOrderHeaderID, $pBrowserLanguageCode)
    {
        $resultArray = Array();
        $itemAsset = Array();
        $pictureAsset = Array();

        $i = 1;
        $dbObj = DatabaseObj::getGlobalDBConnection();

        $sqlStatement = 'SELECT ot.id, ot.itemnumber, ot.taxrate, ot.productcode, ot.productname, ot.productinfo, ot.projectname, ot.assetid, ot.qty, ot.producttotalsell, ot.producttotaltax,
						 ot.pagecount, ot.productdefaultpagecount, ot.totalsell, ot.totaltax, ot.subtotal, ot.voucherapplied , ot.discountname, ot.discountvalue, ot.taxrate, ot.taxname, ot.taxcode, ot.source, ot.productoptions, ot.producttype,
						 ot.projectref, ot.parentorderitemid
						 FROM ORDERITEMS ot
						 WHERE ot.orderid = ? ';
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);
                if ($stmt->bind_param('i', $pOrderHeaderID))
                {
                    if ($stmt->bind_result($orderLineID, $itemnumber, $taxRate, $productCode, $productname, $productinfo, $projectname,
                                    $assetid, $qty, $producttotalsell, $producttotaltax, $pagecount, $productdefaultpagecount, $totalsell,
                                    $totaltax, $subtotal, $voucherapplied, $discountname, $discountvalue, $taxrate, $taxname, $taxcode,
                                    $source, $productOptions, $productType, $projectRef, $parentOrderItemID))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $itemExternalAssetsResult = self::getOrderItemComponentAssets($orderLineID);
                                $itemPicturesResult = self::getOrderItemComponentSinglePrints($orderLineID, false);
								$itemCalendarComponentsResult = self::getOrderItemComponentCalendarComponents($orderLineID);
								$itemAIComponentResult = self::getOrderItemComponentAIComponents($orderLineID);

                                if ($itemExternalAssetsResult['result'] == '')
                                {
                                    $itemAsset = $itemExternalAssetsResult['externalassets'];
                                }

                                if ($itemPicturesResult['result'] == '')
                                {
                                    $pictureAsset = $itemPicturesResult['pictures'];
                                }

                                if ($itemCalendarComponentsResult['result'] == '')
                                {
                                    $calendarCustomisations = $itemCalendarComponentsResult['calendarcustomisations'];
								}

								if (($itemAIComponentResult['result'] == '') && (!empty($itemAIComponentResult['aicomponents'])))
								{
									$AIComponent = $itemAIComponentResult['aicomponents'][0];

									$AIComponentDisplayDetails = self::getComponentByCode($AIComponent['componentcategory'] . '.' . $AIComponent['componentcode']);
									$AIComponent['info'] = $AIComponentDisplayDetails['info'];
									$AIComponent['assetid'] = $AIComponentDisplayDetails['assetid'];
									$AIComponent['name'] = $AIComponentDisplayDetails['name'];
								}

                                $orderLine['orderlineid'] = $orderLineID;
                                $orderLine['itemnumber'] = $itemnumber;
                                $orderLine['itemtaxrate'] = $taxRate;
                                $orderLine['itemproductcode'] = $productCode;
                                $orderLine['itemproductname'] = $productname;
                                $orderLine['itemproductinfo'] = $productinfo;
                                $orderLine['itemprojectname'] = $projectname;
                                $orderLine['assetid'] = $assetid;
                                $orderLine['itemqty'] = $qty;
                                $orderLine['itemproducttotalsell'] = $producttotalsell;
                                $orderLine['itemproducttotaltax'] = $producttotaltax;
                                $orderLine['itemproducttotalsellnotax'] = 0;
                                $orderLine['itemproducttotalsellwithtax'] = 0;
                                $orderLine['itemtotalsell'] = $totalsell;
                                $orderLine['itemtaxtotal'] = $totaltax;
                                $orderLine['itemhasproductprice'] = 1;
                                $orderLine['itemsubtotal'] = $subtotal;
                                $orderLine['itempagecount'] = $pagecount;
                                $orderLine['itemproductdefaultpagecount'] = $productdefaultpagecount;
                                $orderLine['itemexternalassets'] = $itemAsset;
                                $orderLine['pictures'] = $pictureAsset;
								$orderLine['calendarcustomisations'] = $calendarCustomisations;
                                $orderLine['itemvoucherapplied'] = $voucherapplied;
                                $orderLine['itemvouchername'] = $discountname;
                                $orderLine['itemdiscountvalue'] = $discountvalue;
                                $orderLine['itemqtydropdown'] = Array();
                                $orderLine['checkboxes'] = self::getOrderCheckboxesFromDatabase($pOrderHeaderID, $orderLineID,
                                                $pBrowserLanguageCode, 0, '');
                                $orderLine['lineFooterCheckboxes'] = self::getOrderCheckboxesFromDatabase($pOrderHeaderID, $orderLineID,
                                                $pBrowserLanguageCode, 0, '$LINEFOOTER\\');
                                $orderLine['lineFooterSections'] = self::getOrderSections($pOrderHeaderID, $orderLineID, 0,
                                                $pBrowserLanguageCode, '$LINEFOOTER\\');
                                $orderLine['itemtaxname'] = $taxname;
                                $orderLine['itemtaxrate'] = $taxrate;
                                $orderLine['itemtaxcode'] = $taxcode;
                                $orderLine['sections'] = self::getOrderSections($pOrderHeaderID, $orderLineID, 0, $pBrowserLanguageCode, '');
                                $orderLine['source'] = $source;
                                $orderLine['productoptions'] = $productOptions;
								$orderLine['itemproducttype'] = $productType;
								$orderLine['itemprojectref'] = $projectRef;
								$orderLine['parentorderitemid'] = $parentOrderItemID;

                                if ($assetid != 0)
                                {
                                    $orderLine['haspreview'] = 1;
                                }
                                else
                                {
                                    $orderLine['haspreview'] = 0;
								}

								if(!empty($AIComponent))
								{
									$orderLine['aicomponent'] = $AIComponent;
								}

                                $resultArray[] = $orderLine;
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
            }
            $dbObj->close();
        }

        return $resultArray;
    }

    static function getOrderCheckboxesFromDatabase($pOrderHeaderID, $pOrderItemID, $pBrowserLanguageCode, $pParentComponentID, $pSectionPath)
    {
        $result = '';
        $resultParam = '';
        $existingCodesList = array();
        $checkBoxArray = array();
        $resultArray = array();
        $bindParamAttr = [];
        $parentSectionPath = '';

        $sectionArray = explode("\\", $pSectionPath);

        $bindParamAttr[] = 'iiis';
		$bindParamAttr[] = $pOrderHeaderID;
        $bindParamAttr[] = $pOrderItemID;
        $bindParamAttr[] = $pParentComponentID;
        $bindParamAttr[] = $pSectionPath;

        if (count($sectionArray) > 1)
        {
            if ($sectionArray[0] != '')
            {
                $parentSectionPath = $sectionArray[0] . '\\';

                //If linefooter or orderfooter the sectioncode needs to be added to the path too
                if ($sectionArray[0] == '$LINEFOOTER' || $sectionArray[0] == '$ORDERFOOTER')
                {
                    $parentSectionPath .=  $sectionArray[1] . '\\';
                }

                $bindParamAttr[0] .= 's';
                $bindParamAttr[] = $parentSectionPath;
            }
        }

        $dbObj = self::getGlobalDBConnection();

        if ($dbObj)
        {

            $sql = 'SELECT oic.id, oic.componentcode, oic.componentname, oic.pricingmodel, oic.quantity, oic.componentcategoryname,oic.componentcategorycode, oic.componentinfo, oic.componentpriceinfo, oic.componentunitcost, oic.componentunitsell,
                    oic.componentunitweight, oic.componenttotalsell, oic.componenttotaltax, oic.metadatacodelist, oic.componenttaxname, oic.componenttaxrate, oic.discountvalue, oic.componentdiscountedtax, oic.subtotal,oic.componenttotaltax
                    FROM `ORDERITEMCOMPONENTS` oic
                    WHERE oic.orderid = ? AND oic.orderitemid = ? AND oic.parentcomponentid = ?
                    AND oic.islist = 0 AND checkboxselected = 1
                    AND (   oic.componentpath = ? ';

                    if ($parentSectionPath != '')
                    {
                        $sql .= 'OR oic.componentpath = ?';
                    }

                    $sql .= '   )';

            // get defaults from component category
            if ($stmt = $dbObj->prepare($sql))
            {
                $stmt->attr_set(MYSQLI_STMT_ATTR_CURSOR_TYPE, MYSQLI_CURSOR_TYPE_READ_ONLY);

                $bindOk = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindParamAttr));

                if ($bindOk)
                {
                    if ($stmt->bind_result($orderitemcomponentid, $componentCode, $componentName, $pricingmodel, $quantity,
                                    $componentCategoryName, $categoryCode, $componentinfo, $componentpriceinfo, $unitCost,
                                    $componentunitsell, $weight, $componenttotalsell, $componenttotaltax, $metadatacodelist,
                                    $componenttaxname, $componenttaxrate, $discountvalue, $componentdiscountedtax, $subtotal,
                                    $componenttotaltax))
                    {
                        if ($stmt->execute())
                        {
                            while ($stmt->fetch())
                            {
                                $component['code'] = $componentCode;
                                $component['name'] = $componentName;
                                $component['info'] = '';
                                $component['categorycode'] = $categoryCode;
                                $component['info'] = $componentinfo;
								$component['moreinfolinkurl'] = '';
                                $component['moreinfolinktext'] = '';
                                $component['categoryname'] = $componentCategoryName;
                                $component['prompt'] = $componentCategoryName;
                                $component['default'] = 1;
                                $component['checked'] = 1;
                                $component['priceinfo'] = $componentpriceinfo;
                                $component['id'] = 0;  // id is set to 0 because it won't be used
                                $component['path'] = $pSectionPath;
                                $component['unitsell'] = $componentunitsell;
                                $component['unitcost'] = $unitCost;
                                $component['unitweight'] = $weight;
                                $component['previewtype'] = '';
                                $component['orderlineid'] = '';
                                $component['totalsell'] = $componenttotalsell;
                                $component['totaltax'] = $componenttotaltax;
                                $component['totalsellnotax'] = $componenttotalsell;
                                $component['totalsellwithtax'] = $componenttotalsell;
                                $component['orderfootertaxname'] = $componenttaxname;
                                $component['orderfootertaxrate'] = $componenttaxrate;
                                $component['discountvalue'] = $discountvalue;
                                $component['discountedtax'] = $componentdiscountedtax;
                                $component['displaytaxraw'] = $componenttotaltax;
                                $component['subtotal'] = $subtotal;
                                $component['pricingmodel'] = $pricingmodel;
                                $component['quantity'] = $quantity;

                                if ($componentunitsell > 0)
                                {
                                    $component['componenthasprice'] = 1;
                                    $component['hasprice'] = 1;
                                }

                                $metaData = MetaDataObj::getMetaData($pOrderHeaderID, $pOrderItemID, $orderitemcomponentid, 'COMPONENT',
                                                $metadatacodelist, $pBrowserLanguageCode);
                                $component['metadatahtml'] = MetaDataObj::buildDisplayOrderKeywordHTML($metaData, 'COMPONENT');

                                $checkBoxArray[] = $component;
                            }
                        }
                    }
                }
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            $dbObj->close();
        }

        $resultArray = $checkBoxArray;

        return $resultArray;
    }

    static function getCacheData($pCacheKey, $pPreviousCacheVersion = '')
    {
        $resultArray = Array('error' => '', 'cachedata' => array(), 'cacheversion' => '', 'cacheversionmatch' => false);
        $error = '';
        $cacheVersionMatch = false;
        $cacheData = '';
        $cacheVersion = '';
        $serializedDataLength = 0;

		// retrieve the cache data for the cache key unless the cache record version matches the supplied version
        $sqlStatement = 'SELECT IF(`cacheversion` = ?, 1, 0), IF(`cacheversion` = ?, "", `cachedata`), IF(`cacheversion` = ?, 0, `serializeddatalength`), `cacheversion`
        				FROM `CACHEDATA` WHERE `datacachekey` = ?';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($stmt->bind_param('ssss', $pPreviousCacheVersion, $pPreviousCacheVersion, $pPreviousCacheVersion, $pCacheKey))
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($isCacheVersionSame, $cacheData, $serializedDataLength, $cacheVersion))
                                {
                                    if ($stmt->fetch())
                                    {
                                    	if ($isCacheVersionSame == 1)
                                    	{
                                    		$cacheVersionMatch = true;
                                    	}
                                    }
                                }
                                else
                                {
                                    $error = 'Error: bind_result: ' . __FUNCTION__ . $dbObj->error;
                                }
                            }
                        }
                        else
                        {
                            $error = 'Error: store_result: ' . __FUNCTION__ . $dbObj->error;
                        }
                    }
                    else
                    {
                        $error = 'Error: excecute: ' . __FUNCTION__ . $dbObj->error;
                    }
                }
                else
                {
                    $error = 'Error: bind_param: ' . __FUNCTION__ . $dbObj->error;
                }

                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                $error = 'Error: prepare: ' . __FUNCTION__ . $dbObj->error;
            }

            $dbObj->close();
        }

        if ($cacheData != '')
        {
            if ($serializedDataLength > 49152)
            {
                $cacheData = gzuncompress($cacheData, $serializedDataLength);
            }

            $resultArray['cachedata'] = unserialize($cacheData);
        }

		$resultArray['error'] = $error;
		$resultArray['cacheversion'] = $cacheVersion;
		$resultArray['cacheversionmatch'] = $cacheVersionMatch;

        return $resultArray;
    }

    static function insertCacheData($pCacheKey, $pGroupCode, $pCompanyCode, $pCacheArray, $pCacheVersion)
    {
        // convert the cache array into a serialized string
        $pCacheData = serialize($pCacheArray);

        $serializedDataLength = strlen($pCacheData);

        if ($serializedDataLength > 49152)
        {
            $pCacheData = gzcompress($pCacheData, 9);
        }

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
            $sqlStatement = 'INSERT INTO `CACHEDATA` (`datacachekey`, `datecreated`, `groupcode`, `companycode`, `cachedata`, `serializeddatalength`, `cacheversion`)
               VALUES (?, NOW(), ?, ?, ?, ?, ?)  ON DUPLICATE KEY UPDATE `cachedata` = ? ,`cacheversion` = ?, `serializeddatalength` = ?';
            if ($stmt = $dbObj->prepare($sqlStatement))
            {
                if ($stmt->bind_param('ssssisssi', $pCacheKey, $pGroupCode, $pCompanyCode, $pCacheData, $serializedDataLength,
                                $pCacheVersion, $pCacheData, $pCacheVersion, $serializedDataLength))
                {
                    if (! $stmt->execute())
                    {
                        $error = 'Error: excecute: ' . __FUNCTION__ . $dbObj->error;
                    }
                }
                else
                {
                    $error = 'Error: bind_param: ' . __FUNCTION__ . $dbObj->error;
                }

                // if the query failed for some reason we may still have a statement so get rid of it now
                $stmt->free_result();
                $stmt->close();
                $stmt = null;
            }
            else
            {
                $error = 'Error: prepare: ' . __FUNCTION__ . $dbObj->error;
            }

            $dbObj->close();
        }
    }

