	/**
	*  Acquire a mutex using MySQL
	*
	* @param string $pName // name of the mutex
	* @param integer $pWaitTime // GET_LOCK timeout
	* @return array
	*/
   static function acquireDBMutex($pName, $pWaitTime = 5)
    {
    	$resultArray = Array();
    	$locked = false;
        $error = '';

		$dbObj = self::getGlobalDBConnection();
		if ($dbObj)
		{
			$lockName = self::getLockName($pName);

			$sql = 'SELECT GET_LOCK(\'' . $lockName . '\', ' . $pWaitTime . ')';

			// if we have specified a wait time for the lock then we retry up to 10 times
			// if we have not specified a wait time then we only test once
			if ($pWaitTime > 0)
			{
				$retryCount = 10;
			}
			else
			{
				$retryCount = 1;
			}

			while ($retryCount > 0)
			{
				// increase the standard php timeout for the duration we are going to wait on the lock + 1 for overhead
				UtilsObj::resetPHPScriptTimeout(5 + 1);

				$error = '';

				$stmt = $dbObj->prepare($sql);
				if ($stmt)
				{
					if ($stmt->bind_result($lockResult))
					{
						if ($stmt->execute())
						{
							if ($stmt->fetch())
							{
								if ($lockResult == 1)
								{
									// we have successfully managed to grab the lock
									$locked = true;
									$retryCount = 0;
								}
								else
								{
									// could not get status of the lock
									$error = 'ALREADYRUNNING';
								}
							}
							else
							{
								// Show the readable name in the error message.
								$error = 'acquireDBMutex: no lock result ' . $pName;
							}
						}
						else
						{
							$error = 'acquireDBMutex: execute ' . $dbObj->error;
						}
					}
					else
					{
						$error = 'acquireDBMutex: bind result ' . $dbObj->error;
					}

					$stmt->free_result();
					$stmt->close();
					$stmt = null;
				}
				else
				{
					$error = 'acquireDBMutex: Prepare ' . $dbObj->error;
				}

				$retryCount--;
			}

			$dbObj->close();
		}
		else
        {
            $error = 'acquireDBMutex: unable to connect';
        }

		$resultArray['result'] = $locked;
		$resultArray['error'] = $error;

		return $resultArray;
    }


	/**
	* Check to see if the named MySQL based mutex is free
	*
	* @param string $pName // name of the mutex to check
	* @return array
	*/
    static function dbMutexFree($pName)
    {
		$resultArray = Array();
    	$free = false;
        $error = '';

		$dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
			$lockName = self::getLockName($pName);

            $sql = 'SELECT IS_FREE_LOCK(\'' . $lockName . '\')';

			$stmt = $dbObj->prepare($sql);
			if ($stmt)
			{
				if ($stmt->bind_result($freeResult))
				{
					if ($stmt->execute())
					{
						if ($stmt->fetch())
						{
							// we have successfully managed to check the status of the mutex
							$free = $freeResult;
						}
						else
						{
							// Show the readable name in the error message.
							$error = 'dbMutexFree: no status result ' . $pName;
						}
					}
					else
					{
						$error = 'dbMutexFree: execute ' . $dbObj->error;
					}
				}
				else
				{
					$error = 'dbMutexFree: bind result ' . $dbObj->error;
				}

				$stmt->free_result();
				$stmt->close();
				$stmt = null;
			}
			else
			{
				$error = 'dbMutexFree: Prepare ' . $dbObj->error;
			}

            $dbObj->close();
        }
        else
        {
            $error = 'dbMutexFree: unable to connect';
        }

        $resultArray['result'] = $free;
        $resultArray['error'] = $error;

        return $resultArray;

	}


	/**
	* Wait until the named MySQL based mutex has become free
	*
	* @param string $pName // name of the mutex to wait on
	* @param string $pTimeout // number of seconds to wait
	* @return array
	*/
    static function waitForNoDBMutex($pName, $pTimeout)
    {
    	$resultArray = Array();
    	$free = false;
        $error = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
			$lockName = self::getLockName($pName);

            $sql = 'SELECT IS_FREE_LOCK(\'' . $lockName . '\')';

            $retryCount = $pTimeout;
			while ($retryCount > 0)
			{
				// increase the standard php timeout for the time we might sleep + 1 for overhead
				UtilsObj::resetPHPScriptTimeout(2);

				$error = '';

				$stmt = $dbObj->prepare($sql);
				if ($stmt)
				{
					if ($stmt->bind_result($freeResult))
					{
						if ($stmt->execute())
						{
							if ($stmt->fetch())
							{
								if ($freeResult == 1)
								{
									// we have successfully managed to check the status of the mutex
									$free = true;
									$retryCount = 0;
								}
								else
								{
									// Show the readable name in the error message.
									$error = 'waitForDBMutex: could not check status ' . $pName;
								}
							}
							else
							{
								// Show the readable name in the error message.
								$error = 'waitForDBMutex: no status result ' . $pName;
							}
						}
						else
						{
							$error = 'waitForDBMutex: execute ' . $dbObj->error;
						}
					}
					else
					{
						$error = 'waitForDBMutex: bind result ' . $dbObj->error;
					}

					$stmt->free_result();
					$stmt->close();
					$stmt = null;
				}
				else
				{
					$error = 'waitForDBMutex: Prepare ' . $dbObj->error;
				}

				if ($retryCount > 0)
				{
					UtilsObj::wait(1);
				}
			}

            $dbObj->close();
        }
        else
        {
            $error = 'waitForDBMutex: unable to connect';
        }

        $resultArray['result'] = $free;
        $resultArray['error'] = $error;

        return $resultArray;
    }


	/**
	* Release the named MySQL based mutex
	*
	* @param string $pName // name of the mutex to release
	* @return array
	*/
    static function releaseDBMutex($pName)
    {
    	$resultArray = Array();
    	$unlocked = false;
        $error = '';

        $dbObj = self::getGlobalDBConnection();
        if ($dbObj)
        {
			$lockName = self::getLockName($pName);

            $sql = 'SELECT RELEASE_LOCK(\'' . $lockName . '\')';

            $retryCount = 10;
			while ($retryCount > 0)
			{
				$error = '';

				$stmt = $dbObj->prepare($sql);
				if ($stmt)
				{
					if ($stmt->bind_result($unlockResult))
					{
						if ($stmt->execute())
						{
							if ($stmt->fetch())
							{
								if ($unlockResult == 1)
								{
									// we have successfully managed to release the mutex
									$unlocked = true;
									$retryCount = 0;
								}
								else
								{
									// Show the readable name in the error message.
									$error = 'releaseMutex: could not unlock ' . $pName;
								}
							}
							else
							{
								// Show the readable name in the error message.
								$error = 'releaseMutex: no unlock result ' . $pName;
							}
						}
						else
						{
							$error = 'releaseMutex: execute ' . $dbObj->error;
						}
					}
					else
					{
						$error = 'releaseMutex: bind result ' . $dbObj->error;
					}

					$stmt->free_result();
					$stmt->close();
					$stmt = null;
				}
				else
				{
					$error = 'releaseMutex: Prepare ' . $dbObj->error;
				}
			}

            $dbObj->close();
        }
        else
        {
            $error = 'releaseMutex: unable to connect';
        }

        $resultArray['result'] = $unlocked;
        $resultArray['error'] = $error;

        return $resultArray;
    }

