    static function linkOnlineBasketToSession($pSessionRef, $pBasketRef, $pUserID)
    {
        $resultArray = array();
        $result = '';
        $resultParam = '';

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `basketref` = ? WHERE `id` = ?'))
            {
                if ($stmt->bind_param('si', $pBasketRef, $pSessionRef))
                {
                    if (! $stmt->execute())
                    {
                        $result = 'str_DatabaseError';
                        $resultParam = 'linkOnlineBasketToSession execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind parameters
                    $result = 'str_DatabaseError';
                    $resultParam = 'linkOnlineBasketToSession bind ' . $dbObj->error;
                }

				$stmt->free_result();
				$stmt->close();
				$stmt = null;
            }
            else
            {
                // could not prepare statement
                $result = 'str_DatabaseError';
                $resultParam = 'linkOnlineBasketToSession prepare ' . $dbObj->error;
            }

			if ($result == '')
			{
				if ($stmt = $dbObj->prepare('UPDATE `ONLINEBASKET` SET `sessionid` = ? WHERE `basketref` = ?'))
				{
					if ($stmt->bind_param('is', $pSessionRef, $pBasketRef))
					{
						if (! $stmt->execute())
						{
							$result = 'str_DatabaseError';
							$resultParam = 'linkOnlineBasketToSession execute ' . $dbObj->error;
						}
					}
					else
					{
						// could not bind parameters
						$result = 'str_DatabaseError';
						$resultParam = 'linkOnlineBasketToSession bind ' . $dbObj->error;
					}

					$stmt->free_result();
					$stmt->close();
					$stmt = null;
				}
				else
				{
					// could not prepare statement
					$result = 'str_DatabaseError';
					$resultParam = 'linkOnlineBasketToSession prepare ' . $dbObj->error;
				}
			}


			if ($pUserID > 0 && $result == '')
			{
				if ($stmt = $dbObj->prepare('UPDATE `SESSIONDATA` SET `basketref` = ? WHERE `userid` = ? AND `ordersession` = 1 AND `basketref` != ""'))
				{
					if ($stmt->bind_param('si', $pBasketRef, $pUserID))
					{
						if (! $stmt->execute())
						{
							$result = 'str_DatabaseError';
							$resultParam = 'linkOnlineBasketToSession execute ' . $dbObj->error;
						}
					}
					else
					{
						// could not bind parameters
						$result = 'str_DatabaseError';
						$resultParam = 'linkOnlineBasketToSession bind ' . $dbObj->error;
					}

					$stmt->free_result();
					$stmt->close();
					$stmt = null;
				}
				else
				{
					// could not prepare statement
					$result = 'str_DatabaseError';
					$resultParam = 'linkOnlineBasketToSession prepare ' . $dbObj->error;
				}
			}

            $dbObj->close();
        }

        $resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

        return $resultArray;
    }

	static function getProductCollectionLinkByCollectionCode($pCollectionCode)
	{
		$resultArray = array();
		$result = '';
		$resultParam = '';
		$productLinkCache = array();
