		{
			// get existing product collection link details with that productcode
			if ($stmt = $dbObj->prepare('SELECT `id`, `productcode`, `collectiontype`, `availableonline`
				FROM
					`PRODUCTCOLLECTIONLINK`
				WHERE
					`collectioncode` = ?'))

			{
				if ($stmt->bind_param('s', $pCollectionCode))
				{
					if ($stmt->bind_result($productLinkCacheID, $productLinkCacheProductCode, $productLinkCacheCollectionType, $productLinkCacheAvailableOnline))
					{
						if ($stmt->execute())
						{
							while ($stmt->fetch())
							{
								$productLink = array();
								$productLink['id'] = $productLinkCacheID;
								$productLink['productcode'] = $productLinkCacheProductCode;
								$productLink['collectiontype'] = $productLinkCacheCollectionType;
								$productLink['availableonline'] = $productLinkCacheAvailableOnline;

								$productLinkCache[] = $productLink;
							}
						}
						else
						{
							// could not execute statement
							$result = 'str_DatabaseError';
							$resultParam = __FUNCTION__ . ' select product collection link execute ' . $dbObj->error;
						}
					}
					else
					{
						// could not bind result
						$result = 'str_DatabaseError';
						$resultParam = __FUNCTION__ . ' select product collection link bind result ' . $dbObj->error;
					}
				}
				else
				{
					// could not bind parameters
					$result = 'str_DatabaseError';
					$resultParam = 'uploadProductsUpdate select product collection link bind params ' . $dbObj->error;
				}

				$stmt->free_result();
				$stmt->close();
			}
			else
			{
				// could not prepare statement
				$result = 'str_DatabaseError';
				$resultParam = __FUNCTION__ . ' select product collection link prepare ' . $dbObj->error;
			}

			$dbObj->close();
		}

		$resultArray['data'] = $productLinkCache;
		$resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

		return $resultArray;
	}

	/**
	 * Checks the ASSETDATA via the BRANDASSETLINK tables for a record.
	 * If one is found then use that, else defaults to checking for an asset in the branding folder and then the default folder.
	 *
	 * @param int $pBrandID The ID of the brand to lookup the asset for.
	 * @param int $pObjectType The type of asset to retrieve.
	 * @param boolean $pReturnDefault True to retrieve the default assets if a custom asset was not found.
	 * @return array Array containing the the asset details.
	 */
	static function getBrandAssetData($pBrandID, $pObjectType, $pReturnDefault)
	{
		$resultArray = array();
		$result = '';
		$resultParam = '';
		$assetDataID = 0;
		$assetDataName = '';
		$previewMime = '';
		$previewHeight = 0;
		$previewWidth = 0;

		$assetData = array();
		$assetData['id'] = 0;
		$assetData['name'] = '';
		$assetData['mime'] = '';
		$assetData['height'] = 0;
		$assetData['width'] = 0;
		$assetData['path'] = '';

		$assetDataResult = $assetData;

		$dbObj = DatabaseObj::getGlobalDBConnection();
		if ($dbObj)
		{
			$sql = 'SELECT `a`.`id`, `a`.`name`, `a`.`previewtype`, `a`.`previewheight`, `a`.`previewwidth`
					FROM `ASSETDATA` `a`
					INNER JOIN `BRANDASSETLINK` as `b` on `a`.`id` = `b`.`assetdataid`
					WHERE `b`.`brandid` = ? AND `b`.`objecttype` = ?';

			$stmt = $dbObj->prepare($sql);
			if ($stmt)
			{
				if ($stmt->bind_param('ii', $pBrandID, $pObjectType))
				{
					if ($stmt->execute())
					{
						if ($stmt->store_result())
						{
							$numRows = $stmt->num_rows;
							if ($numRows == 1)
							{
								if ($stmt->bind_result($assetDataID, $assetDataName, $previewMime, $previewHeight, $previewWidth))
								{
									if ($stmt->fetch())
									{
										$assetData['id'] = $assetDataID;
										$assetData['name'] = $assetDataName;
										$assetData['mime'] = $previewMime;
										$assetData['height'] = $previewHeight;
										$assetData['width'] = $previewWidth;
										$assetData['path'] = $assetDataName;
									}
									else
									{
										// Could not fetch result.
										$result = 'str_DatabaseError';
										$resultParam = __FUNCTION__ . '  fetch ' . $dbObj->error;
									}
								}
								else
								{
									// Could not bind result.
									$result = 'str_DatabaseError';
									$resultParam = __FUNCTION__ . '  bind result ' . $dbObj->error;
								}
							}
							else
							{
								if ($pReturnDefault)
								{
									// Get the default brand asset.
									$assetDataResult = UtilsObj::getBrandImage($pBrandID, $pObjectType);

									if ($assetDataResult['result'] == '')
									{
										$assetData = $assetDataResult['data'];
									}
									else
									{
										$result = $assetDataResult['result'] ;
										$resultParam = 'Object type: ' . $pObjectType;
									}
								}
							}
						}
						else
						{
							// Could not execute statement.
							$result = 'str_DatabaseError';
							$resultParam = __FUNCTION__ . ' store result ' . $dbObj->error;
						}
					}
					else
					{
						// Could not execute statement.
						$result = 'str_DatabaseError';
						$resultParam = __FUNCTION__ . '  execute ' . $dbObj->error;
					}
				}
				else
				{
					// Could not bind parameters.
					$result = 'str_DatabaseError';
					$resultParam = __FUNCTION__ . ' bind params ' . $dbObj->error;
				}

				$stmt->free_result();
				$stmt->close();
				$stmt = null;
			}
			else
			{
				// Could not prepare statement.
				$result = 'str_DatabaseError';
				$resultParam = __FUNCTION__ . ' prepare ' . $dbObj->error;
			}

			$dbObj->close();
		}

		$resultArray['data'] = $assetData;
		$resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

		return $resultArray;
	}


