	/**
	 * Checks the ASSETDATA via the BRANDASSETLINK tables for a record.
	 * If one is found then use that, else defaults to checking for an asset in the branding folder and then the default folder.
	 *
	 * @param int $pBrandID The ID of the brand to lookup the asset for.
	 * @param int $pObjectType The type of asset to retrieve.
	 * @return array Array containing the the asset details.
	 */
	static function getBrandCustomText($pBrandID, $pObjectType)
	{
		$resultArray = array();
		$result = '';
		$resultParam = '';
		$assetDataName = '';
		$previewMime = '';
		$previewHeight = 0;
		$previewWidth = 0;
		$assetDataID = 0;
		$assetBrandID = 0;
		$brandAssetLinkID = 0;
		$assetDataEnabled = 0;
		$textAssetType = TPX_ASSETTYPE_EMAIL_TEXT;
		$brandAssetLinkToUse = 0;

		$assetDataResult = array(
							'id' => 0,
							'found' => false,
							'default' => 0,
							'object' => $pObjectType,
							'enabled' => 0,
							'name' => '',
							'data' => '',
							'defaultdata' => '');

		// New brands ($pBrandID = -1) will have no entry.
		if ($pBrandID != -1)
		{
			$dbObj = DatabaseObj::getGlobalDBConnection();
			if ($dbObj)
			{
				$sql = 'SELECT `id`, `brandid`, `assetdataid`, `enabled`
						FROM `BRANDASSETLINK`
						WHERE (`brandid` = ? OR `brandid` = 1) AND `objecttype` = ?
						ORDER BY `brandid` DESC';

				$bindParams = array('ii', $pBrandID, $pObjectType);

				$stmt = $dbObj->prepare($sql);
				if ($stmt)
				{
					$bindOK = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindParams));
					if ($bindOK)
					{
						if ($stmt->bind_result($brandAssetLinkID, $assetBrandID, $assetDataID, $assetDataEnabled))
						{
							if ($stmt->execute())
							{
								while ($stmt->fetch())
								{
 									// Has the matching brand record been found.
									if ($assetBrandID == $pBrandID)
									{
										$assetDataResult['enabled'] = $assetDataEnabled;

										if ($assetDataID == 0)
										{
											// The record has been set to use the default brand record,
											// continue reading the data to get the desired record.
											$assetDataResult['default'] = 1;
										}
										else
										{
											// Brand has text configured, get the data and skip any other records.
											$brandAssetLinkToUse = $assetDataID;
											break;
										}
									}
									else if ($assetBrandID == 1)
									{
										// Check if the record is set to use the default brand record.
										if ($assetDataResult['default'] == 1)
										{
											// Get the asset data ID of the default brand.
											$brandAssetLinkToUse = $assetDataID;
										}
									}
								}
							}
							else
							{
								// could not execute statement
								$result = 'str_DatabaseError';
								$resultParam = __FUNCTION__ . ' select product collection link execute ' . $dbObj->error;
							}
						}
						else
						{
							// could not bind result
							$result = 'str_DatabaseError';
							$resultParam = __FUNCTION__ . ' select product collection link bind result ' . $dbObj->error;
						}
					}
					else
					{
						// Could not bind result.
						$result = 'str_DatabaseError';
						$resultParam = __FUNCTION__ . '  bind param ' . $dbObj->error;
					}

					$stmt->free_result();
					$stmt->close();
					$stmt = null;
				}
				else
				{
					// Could not bind parameters.
					$result = 'str_DatabaseError';
					$resultParam = __FUNCTION__ . ' prepare ' . $dbObj->error;
				}

				// Look up the record found in the Brand asset link table, as a record was found
				if ($brandAssetLinkToUse > 0)
				{
					$sql = 'SELECT `a`.`id`, `a`.`name`, `a`.`data`
							FROM `ASSETDATA` `a`
							WHERE `a`.`id` = ? and `a`.`assettype` = ?';

					$bindParams = array('ii', $assetDataID, $textAssetType);

					$stmt = $dbObj->prepare($sql);
					if ($stmt)
					{
						$bindOK = call_user_func_array(array(&$stmt, 'bind_param'), UtilsObj::makeValuesReferenced($bindParams));
						if ($bindOK)
						{
							if ($stmt->execute())
							{
								if ($stmt->store_result())
								{
									$numRows = $stmt->num_rows;
									if ($numRows == 1)
									{
										if ($stmt->bind_result($assetDataID, $assetDataName, $assetDataData))
										{
											if ($stmt->fetch())
											{
												$assetDataResult['found'] = true;
												$assetDataResult['id'] = $assetDataID;
												$assetDataResult['name'] = $assetDataName;
												$assetDataResult['data'] = $assetDataData;
											}
											else
											{
												// Could not execute statement.
												$result = 'str_DatabaseError';
												$resultParam = __FUNCTION__ . '  fetch ' . $dbObj->error;
											}
										}
										else
										{
											// Could not execute statement.
											$result = 'str_DatabaseError';
											$resultParam = __FUNCTION__ . '  bind_result ' . $dbObj->error;
										}
									}
								}
								else
								{
									// Could not bind result.
									$result = 'str_DatabaseError';
									$resultParam = __FUNCTION__ . '  store_result ' . $dbObj->error;
								}
							}
							else
							{
								// Could not bind parameters.
								$result = 'str_DatabaseError';
								$resultParam = __FUNCTION__ . ' execute ' . $dbObj->error;
							}
						}
						else
						{
							// Could not bind parameters.
							$result = 'str_DatabaseError';
							$resultParam = __FUNCTION__ . ' bind params ' . $dbObj->error;
						}

						$stmt->free_result();
						$stmt->close();
						$stmt = null;
					}
					else
					{
						// Could not prepare statement.
						$result = 'str_DatabaseError';
						$resultParam = __FUNCTION__ . ' prepare ' . $dbObj->error;
					}
				}

				$dbObj->close();
			}
		}

		$resultArray['data'] = $assetDataResult;
		$resultArray['result'] = $result;
        $resultArray['resultparam'] = $resultParam;

		return $resultArray;
    }

    static function addProjectOrderDataCache($pExternalCartInitArray, $pExternalShoppingCartData)
    {
        $resultArray = array('result'=>'', 'resultparam'=>'', 'id'=>-1);

        $dbObj = DatabaseObj::getGlobalDBConnection();

        // copy the items array and remove them from the original array.
        $cartItemsArray = $pExternalCartInitArray['items'];
        unset($pExternalCartInitArray['items']);

		if ($dbObj)
		{
            $dbObj->query('START TRANSACTION');

            if ($stmt = $dbObj->prepare('INSERT INTO `projectorderdatacache` (`datecreated`, `projectref`, `projectdata`, `projectdatalength`, `source`, `externalproductid`, `connectorid`)
            VALUES (NOW(), ?, ?, ?, ?, ?, ?) ON DUPLICATE KEY UPDATE `datecreated` = NOW(), `projectdata` = ? , `projectdatalength` = ?, `externalproductid` = ?'))
            {
                foreach ($cartItemsArray as $item)
                {
                    $projectRef = $item['projectref'];
                    $source = $item['source'];
                    $externalProductID = '';
                    $connectorID = 0;

                    if (array_key_exists('externalproductdata', $pExternalShoppingCartData))
                    {
                        $externalProductData = $pExternalShoppingCartData['externalproductdata'];

                        if ((array_key_exists('externalproductids', $externalProductData)) && (array_key_exists($projectRef, $externalProductData['externalproductids'])))
                        {
                            $externalProductID = $externalProductData['externalproductids'][$projectRef];
                        }

                        if (array_key_exists('connectorid', $externalProductData))
                        {
                            $connectorID = $externalProductData['connectorid'];
                        }
                    }

                    // add each item back into the array so that each item has all of the required information including the header information
                    // this is so that desktop checkout items are stored the same as an idividual add to basket from online.
                    $pExternalCartInitArray['items'][0] = $item;

                    // convert the cart array into a serialized string
                    $serializedProjectData = \serialize($pExternalCartInitArray);
                    $serializedProjectDataLength = strlen($serializedProjectData);

                    // Check the size of the serialized string to make sure the length of the string is not greater than what a mediumblob column can hold.
                    // If it is greater, then we must compress the string and record the size of the orignal string before compression.
                    // If it is not greater, then we can store the datalegth as 0.
                    // When reading the data back the 0 indicates that the data has not been compressed which in turn means we wont attempt to uncompress it.
                    if ($serializedProjectDataLength > 15728640)
                    {
                        $serializedProjectData = gzcompress($serializedProjectData, 9);
                    }
                    else
                    {
                        $serializedProjectDataLength = 0;
                    }

                    if ($stmt->bind_param('ssiisssis', $projectRef, $serializedProjectData, $serializedProjectDataLength, $source, $externalProductID, $connectorID, $serializedProjectData, $serializedProjectDataLength, $externalProductID))
                    {
                        if (! $stmt->execute())
                        {
                            // could not execute statement
                            $resultArray['result'] = 'str_DatabaseError';
                            $resultArray['resultparam'] = 'add projectorderdatacache execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        $resultArray['result'] = 'str_DatabaseError';
                        $resultArray['resultparam'] = 'add projectorderdatacache bind ' . $dbObj->error;
                    }
                    $stmt->free_result();

                }

                $stmt->close();
                $stmt = null;
            }
            else
            {
                // could not prepare statement
                $resultArray['result'] = 'str_DatabaseError';
                $resultArray['resultparam'] = 'add projectorderdatacache prepare ' . $dbObj->error;
            }

            if ($resultArray['result'] == '')
            {
                // commit
                if (! $dbObj->query('COMMIT'))
                {
                    // if the commit fails, rollback
                    $dbObj->query('ROLLBACK');

                    $resultArray['result'] = 'str_DatabaseError';
                    $resultArray['resultparam'] = __FUNCTION__ . ' commit ' . $dbObj->error;
                }
            }
            else
            {
                // rollback
                $dbObj->query('ROLLBACK');
            }

            $dbObj->close();
        }
        else
        {
            // unabble to connect to the database
            $resultArray['result'] = 'str_DatabaseError';
            $resultArray['resultparam'] = 'add projectorderdatacache unable to connect to the database';
        }

        return $resultArray;

    }

	/**
	 * Get the lock name for *_LOCK functions.
	 *
	 * @param string $pLockName Lock name to format.
	 * @return string Lock name.
	 */
	static function getLockName($pLockName)
	{
		// As of MySQL 5.7, lock names can only be 64 characters.
		// md5 the name to keep the name to 32 characters.
		return hash('md5', $pLockName);
	}

    /**
     * Get a list of project thumbnails that have valid records of the same age as the requested upload
     * @param array $pRefsToCheckArray the project references to check
     * @param array $pDateModifiedsArray a parallel array containing the projectdatemodifieds for each of the project refs
     * @return array error array containing the project refs that do not need uploading as well as any database errors
     */
    static function getUnneededThumbnailsForUpload($pRefsToCheckArray, $pDateModifiedsArray)
    {
        $error = '';
        $errorParam = '';
        $resultArray = UtilsObj::getReturnArray('projects');
        $projectResultArray = Array();

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            $refCount = count($pRefsToCheckArray);
            $bindDataTypes = Array();
            $searchParams = '';
            $searchFields = Array();

            for ($i = 0; $i < $refCount; $i++)
            {
                array_push($bindDataTypes, 's', 's');

                if ($i !== 0)
                {
                    $searchParams .= ' OR';
                }

                //simple = comparison as both a newer and older thumbnail will potentially be different to what is being ordered
                $searchParams .= ' (`projectref` = ? AND `projectdatemodified` = ? AND `available` = 1)';
                array_push($searchFields, $pRefsToCheckArray[$i], $pDateModifiedsArray[$i]);
            }

            $sql = 'SELECT `projectref`
                    FROM `DESKTOPPROJECTTHUMBNAILS`
                    WHERE' . $searchParams;

            $stmt = $dbObj->prepare($sql);

            if ($stmt)
            {
                $bindOK = DatabaseObj::bindParams($stmt, $bindDataTypes, $searchFields);

                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($projectRef))
                                {
                                    while ($stmt->fetch())
                                    {
                                        $projectResultArray[] = $projectRef;
                                    }
                                }
                                else
                                {
                                    // could not bind result
                                    $error = 'str_DatabaseError';
                                    $errorParam = __FUNCTION__ . ' bind result: ' . $dbObj->error;
                                }
                            }
                        }
                        else
                        {
                            // Could not store result.
                            $error = 'str_DatabaseError';
                            $errorParam = __FUNCTION__ . '  store_result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // Could not execute query.
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . ' execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // Could not bind parameters.
                    $error = 'str_DatabaseError';
                    $errorParam = __FUNCTION__ . ' bindparams ' . $dbObj->error;
                }
            }
            else
            {
                // Could not prepare statement.
                $error = 'str_DatabaseError';
                $errorParam = __FUNCTION__ . ' prepare ' . $dbObj->error;
            }
        }
        else
        {
            // could not open database connection
            $error = 'str_DatabaseError';
            $errorParam = __FUNCTION__ . 'connect ' . $dbObj->error;
        }

        $resultArray['error'] = $error;
        $resultArray['errorparam'] = $errorParam;
        $resultArray['projects'] = $projectResultArray;

        return $resultArray;
    }
    /**
     * Set the available status to passed thumbnail records to 0
     * @param array containing project refs of thumbnails to mark as unavailable
     * @return array error array
     */
    static function markDesktopProjectThumbnailsUnavailable($pThumbNailsToMark)
    {
        $resultArray = UtilsObj::getReturnArray();
        $error = '';
        $errorParam = '';

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            $projectRefBind = "";
            $bindDataTypes = Array();
            $thumbnailCount = count($pThumbNailsToMark);
            for ($i = 0; $i < $thumbnailCount; $i++)
            {
                if ($i !== 0)
                {
                    $projectRefBind .= ' ,';
                }

                $projectRefBind .= '?';
                $bindDataTypes[] = 's';
            }

            $sql = 'UPDATE `DESKTOPPROJECTTHUMBNAILS`
                    SET `available` = 0
                    WHERE `projectref` IN (' . $projectRefBind . ')';

            $stmt = $dbObj->prepare($sql);

            if ($stmt)
            {
                $bindOK = DatabaseObj::bindParams($stmt, $bindDataTypes, $pThumbNailsToMark);

                if ($bindOK)
                {
                    if (! $stmt->execute())
                    {
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . ' execute ' . $dbObj->error;
                    }
                }
                else
