     * @param array $pResourcesToInsertArray resources to insert
     * @param string $pCollectionVersionDate Collection version date in datetime format
     * @param string $pCollectionCode Collection code
     * @return array error array
     */
    static function insertProductCollectionResourceRecords($pDBObj, $pResourcesToInsertArray, $pCollectionVersionDate, $pCollectionCode)
    {
        $resultArray = UtilsObj::getReturnArray();
        $error = '';
        $errorParam = '';

        $recordCount = count($pResourcesToInsertArray);
        $bindDataTypes = Array();
        $bindValues = Array();
        $insertFields = '';

        for ($i = 0; $i < $recordCount; $i++)
        {
            $theRecord = $pResourcesToInsertArray[$i];

            //add a comma before subsequent records
            if ($i !== 0)
            {
                $insertFields .= " ,";
            }

            $insertFields .= '(NOW(), ?, ?, ?, ?, ?, 1)';
            array_push($bindDataTypes,'s', 's', 's', 'i', 's');
            array_push($bindValues, $pCollectionVersionDate, $pCollectionCode, $theRecord['ref'], $theRecord['kind'], $theRecord['datauid']);
        }

        $sql = 'INSERT INTO `PRODUCTCOLLECTIONRESOURCES` (`datecreated`, `collectionversiondate`, `collectioncode`, `resourceref`, `resourcekind`, `resourcedatauid`, `islatest`)
                VALUES' . $insertFields .
                ' ON DUPLICATE KEY UPDATE `datecreated` = NOW(), `islatest` = 1, `nextpurgetime` = "0000-00-00 00:00:00"';

        $stmt = $pDBObj->prepare($sql);

        if ($stmt)
        {
            $bindOK = DatabaseObj::bindParams($stmt, $bindDataTypes, $bindValues);

