                }
            }
            else
            {
                $error = 'str_DatabaseError';
                $errorParam = __FUNCTION__ . ' bindparams ' . $pDBObj->error;
            }

            $stmt->close();
        }
        else
        {
            $error = 'str_DatabaseError';
            $errorParam = __FUNCTION__ . ' prepare ' . $pDBObj->error;
        }

        $resultArray['error'] = $error;
        $resultArray['errorparam'] = $errorParam;

        return $resultArray;
    }

