    /**
     * Gets the collection data required to build a json metadata file in the same structure as the collection tag of the JSON
     * @param taopixDB $pDBObj Database Object to execute with
     * @param string $pCollectionCode The collection code to build the metadata fo
     * @return array Return array with required data in 'data' key
     */
    static function getCollectionDataForJSONMetadataFile($pDBObj, $pCollectionCode)
    {
        $resultArray = UtilsObj::getReturnArray();
        $error = '';
        $errorParam = '';
        $firstLoop = true;

        $collectionArray = Array();
        $numRows = 0;
        $layoutNumber = 0;
        $collectionDescripton = '';
        $collectionType = 0;
        $dataVersion = 0;
        $versionDate = '0000-00-00 00:00:00';
        $collectionMoreInformationURL = '';
        $collectionThumbnailResourceRef = '';
        $collectionThumbnailResourceDataUID = '';
        $collectionPreviewResourceRef = '';
        $collectionPreviewResourceDataUID = '';
        $collectionThumbnailResourceDevicePixelRatio = 1;
        $collectionPreviewResourceDevicePixelRatio = 1;
        $productCode = '';
        $productName = '';
        $productDescription = '';
        $productMoreInformationUrl = '';
        $productThumbnailResourceRef = '';
        $productThumbnailResourceDataUID = '';
        $productPreviewResourceRef = '';
        $productPreviewResourceDataUID = '';
        $productTarget = 0;
        $productSortOrder = 0;
        $productMinPageCount = 0;
        $productMaxPageCount = 0;
        $productDefaultPageCount = 0;
        $productPageInsertCount = 0;
        $productCalendarStartYearCanChange = 0;
        $productCalendarStartYear = 0;
        $productCalendarStartMonthCanChange = 0;
        $productCalendarStartMonth = 0;
        $productCalendarStartDayCanChange = 0;
        $productCalendarStartDay = 0;
        $productCalendarLocaleCanChange = 0;
        $productCalendarLocale = '';
        $productConfigurationFlags = 0;
        $productPageContentAssignMode = 0;
        $productOrientation = 0;
        $productSizeCode = '';
        $productSizeName = '';
        $productSizeArea = '0';
        $productThumbnailResourceDevicePixelRatio = 1;
        $productPreviewResourceDevicePixelRatio = 1;

        $sql = 'SELECT `pcl`.`collectiondescription`, `pcl`.`collectiontype`, `af`.`dataversion`, `af`.`versiondate`, `pcl`.`collectionmoreinformationurl`,
                `pcl`.`collectionthumbnailresourceref`, `pcl`.`collectionthumbnailresourcedatauid`, `pcl`.`collectionpreviewresourceref`, `pcl`.`collectionpreviewresourcedatauid`,
                `pcl`.`productcode`, `pcl`.`productname`, `pcl`.`productdescription`, `pcl`.`productmoreinformationurl`, `pcl`.`productthumbnailresourceref`,
                `pcl`.`productthumbnailresourcedatauid`, `pcl`.`productpreviewresourceref`, `pcl`.`productpreviewresourcedatauid`, `pcl`.`producttarget`,
                `pcl`.`productsortorder` ,`pcl`.`productminpagecount`, `pcl`.`productmaxpagecount`, `pcl`.`productdefaultpagecount`, `pcl`.`productpageinsertcount`,
                `pcl`.`productcalendarstartyearcanchange`, `pcl`.`productcalendarstartyear`, `pcl`.`productcalendarstartmonthcanchange`, `pcl`.`productcalendarstartmonth`,
                `pcl`.`productcalendarstartdaycanchange`, `pcl`.`productcalendarstartday`, `pcl`.`productcalendarlocalecanchange`, `pcl`.`productcalendarlocale`,
                `pcl`.`productconfigurationflags`, `pcl`.`productpagecontentassignmode`, `pcl`.`productorientation`, `pcl`.`productsizecode`, `pcl`.`productsizename`,
                `pcl`.`productsizearea`, `pcl`.`collectionthumbnailresourcedevicepixelratio`, `pcl`.`collectionpreviewresourcedevicepixelratio`,
                `pcl`.`productthumbnailresourcedevicepixelratio`, `pcl`.`productpreviewresourcedevicepixelratio`
                FROM `PRODUCTCOLLECTIONLINK` AS `pcl`
                LEFT JOIN `APPLICATIONFILES` AS `af` ON  `pcl`.`collectioncode` = `af`.`ref`
                WHERE `pcl`.`collectioncode` = ?
                ORDER BY `pcl`.`productsortorder` ASC';

        $stmt = $pDBObj->prepare($sql);

        if ($stmt)
        {
            $bindOK = $stmt->bind_param('s', $pCollectionCode);

            if ($bindOK)
            {
                if ($stmt->execute())
                {
                    if ($stmt->store_result())
                    {
                        $numRows = $stmt->num_rows();

                        if ($numRows > 0)
                        {
                            if ($stmt->bind_result($collectionDescripton, $collectionType, $dataVersion, $versionDate, $collectionMoreInformationURL,
                                $collectionThumbnailResourceRef, $collectionThumbnailResourceDataUID, $collectionPreviewResourceRef, $collectionPreviewResourceDataUID,
                                $productCode, $productName, $productDescription, $productMoreInformationUrl, $productThumbnailResourceRef,
                                $productThumbnailResourceDataUID, $productPreviewResourceRef, $productPreviewResourceDataUID, $productTarget, $productSortOrder,
                                $productMinPageCount, $productMaxPageCount, $productDefaultPageCount, $productPageInsertCount,
                                $productCalendarStartYearCanChange, $productCalendarStartYear, $productCalendarStartMonthCanChange, $productCalendarStartMonth,
                                $productCalendarStartDayCanChange, $productCalendarStartDay, $productCalendarLocaleCanChange, $productCalendarLocale,
                                $productConfigurationFlags, $productPageContentAssignMode, $productOrientation, $productSizeCode, $productSizeName,
                                $productSizeArea, $collectionThumbnailResourceDevicePixelRatio, $collectionPreviewResourceDevicePixelRatio,
                                $productThumbnailResourceDevicePixelRatio, $productPreviewResourceDevicePixelRatio))
                            {
                                while ($stmt->fetch())
                                {
                                    // The product collection information will be the same for all loops so only store it once
                                    if ($firstLoop === true)
                                    {
                                        $firstLoop = false;

                                        $collectionArray['code'] = $pCollectionCode;
                                        $collectionArray['description'] = $collectionDescripton;
                                        $collectionArray['type'] = $collectionType;
                                        $collectionArray['dataversion'] = $dataVersion;
                                        $collectionArray['datelastmodified'] = $versionDate;
                                        $collectionArray['moreinformationurl'] = $collectionMoreInformationURL;
                                        $collectionArray['thumbnailresourceref'] = $collectionThumbnailResourceRef;
                                        $collectionArray['thumbnailresourcedatauid'] = $collectionThumbnailResourceDataUID;
                                        $collectionArray['previewresourceref'] = $collectionPreviewResourceRef;
                                        $collectionArray['previewresourcedatauid'] = $collectionPreviewResourceDataUID;
                                        $collectionArray['layoutcount'] = $numRows;
                                        $collectionArray['thumbnailresourcedevicepixelratio'] = $collectionThumbnailResourceDevicePixelRatio;
                                        $collectionArray['previewresourcedevicepixelratio'] = $collectionPreviewResourceDevicePixelRatio;
                                    }

                                    $layoutItem = Array();

                                    $layoutItem['code'] = $productCode;
                                    $layoutItem['name'] = $productName;
                                    $layoutItem['description'] = $productDescription;
                                    $layoutItem['moreinformationurl'] = $productMoreInformationUrl;
                                    $layoutItem['thumbnailresourceref'] = $productThumbnailResourceRef;
                                    $layoutItem['thumbnailresourcedatauid'] = $productThumbnailResourceDataUID;
                                    $layoutItem['previewresourceref'] = $productPreviewResourceRef;
                                    $layoutItem['previewresourcedatauid'] = $productPreviewResourceDataUID;
                                    $layoutItem['target'] = $productTarget;
                                    $layoutItem['sortorder'] = $productSortOrder;
                                    $layoutItem['minpages'] = $productMinPageCount;
                                    $layoutItem['maxpages'] = $productMaxPageCount;
                                    $layoutItem['defaultpages'] = $productDefaultPageCount;
                                    $layoutItem['pageinsertcount'] = $productPageInsertCount;
                                    $layoutItem['configurationflags'] = $productConfigurationFlags;
                                    $layoutItem['pagecontentassignmode'] = $productPageContentAssignMode;
                                    $layoutItem['orientation'] = $productOrientation;
                                    $layoutItem['sizecode'] = $productSizeCode;
                                    $layoutItem['sizename'] = $productSizeName;
                                    $layoutItem['sizearea'] = $productSizeArea;
                                    $layoutItem['thumbnailresourcedevicepixelratio'] = $productThumbnailResourceDevicePixelRatio;
                                    $layoutItem['previewresourcedevicepixelratio'] = $productPreviewResourceDevicePixelRatio;

                                    // Only store the calendar data if we have a calendar collection
                                    if ($collectionType == TPX_PRODUCTCOLLECTIONTYPE_CALENDAR)
                                    {
                                        $calendarItem = Array();

                                        $calendarItem['startyearcanchange'] = $productCalendarStartYearCanChange;
                                        $calendarItem['startyear'] = $productCalendarStartYear;
                                        $calendarItem['startmonthcanchange'] = $productCalendarStartMonthCanChange;
                                        $calendarItem['startmonth'] = $productCalendarStartMonth;
                                        $calendarItem['startdaycanchange'] = $productCalendarStartDayCanChange;
                                        $calendarItem['startday'] = $productCalendarStartDay;
                                        $calendarItem['localecanchange'] = $productCalendarLocaleCanChange;
                                        $calendarItem['locale'] = $productCalendarLocale;

                                        $layoutItem['calendar'] = $calendarItem;
                                    }

                                    $layoutNumber++;

                                    $collectionArray['layout' . $layoutNumber] = $layoutItem;
                                }

                                $resultArray['data'] = $collectionArray;
                            }
                            else
                            {
                                // could not bind result
                                $error = 'str_DatabaseError';
                                $errorParam = __FUNCTION__ . ' bind result: ' . $pDbObj->error;
                            }
                        }
                        else
                        {
                            // Found no results
                            $error = 'str_DatabaseError';
                            $errorParam = __FUNCTION__ . ' no results found: ' . $pDBObj->error;
                        }
                    }
                    else
                    {
                        // Could not store result.
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . '  store_result ' . $pDBObj->error;
                    }
                }
                else
                {
                    // could not execute statement
                    $error = 'str_DatabaseError';
                    $errorParam = __FUNCTION__ . ' execute ' . $pDBObj->error;
                }
            }
            else
            {
                // could not bind params
                $error = 'str_DatabaseError';
                $errorParam = __FUNCTION__ . ' bindparam ' . $pDBObj->error;
            }

            $stmt->free_result();
            $stmt->close();
        }
        else
        {
            // Could not prepare statement
            $error = 'str_DatabaseError';
            $errorParam = __FUNCTION__ . ' prepare ' . $pDBObj->error;
        }

        $resultArray['error'] = $error;
        $resultArray['errorparam'] = $errorParam;

        return $resultArray;
    }

    /**
     * checks if there are any product groups assigned to a voucher and does a first level check to see if they apply
     * while returning information for full checking
     * @param string $pVoucherCode the code of the voucher to check
     * @param array $pProductsArray a multidimensional array containing a list of collections and product codes to check against
     *          in the form of an indexed array with subarrays consisting of collectioncode and layoutcode keys
     * @return array Standard taopix return array containing an array on the data key of the form "groupconfigurations" =>$collectioncode => $layoutcode =>
     *          $groupactive and data subkeys groupfound and group applicable reporting whether any group is linked to the voucher and if first pass failed respectively
     */
    static function retrieveVoucherProductGroupValidity($pVoucherCode, $pProductsArray)
    {
        global $gSession;

        $resultArray = UtilsObj::getReturnArray();
        $error = "";
        $errorParam = "";
        $productGroupFound = false;
        $productGroupApplicable = false;
        $groupArray = array();
        $companyCode = '';

        if ($gSession['userdata']['companycode'] != '')
		{
			$companyCode = $gSession['userdata']['companycode'];
		}

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            $productsCount = count($pProductsArray);
            $bindDataTypes = '';
            $collectionOnField = '';
            $layoutOnField = '';
            $hasProductGroup = 0;
            $productsAssigned = 0;
            $groupActive = 0;
            $groupCollectionCode = '';
            $groupProductCode = '';
            $companyCodeSql = '';

            if (($companyCode !== '') && ($companyCode !== '**ALL**'))
            {
                $companyCodeSql = 'AND (`pgh`.`companycode` = ? OR `pgh`.`companycode` = "")';
                $bindDataTypes .= 's';
            }

            for ($i = 0; $i < $productsCount; $i++)
            {
                if ($i !== 0)
                {
                    $collectionOnField .= ", ";
                    $layoutOnField .= ", ";
                }

                $collectionOnField .= '?';
                $collectionOnValues[] = $pProductsArray[$i]['collectioncode'];
                $layoutOnField .= '?';
                $layoutOnValues[] = $pProductsArray[$i]['layoutcode'];
                $bindDataTypes .= 'ss';
            }

            $bindDataTypes .= 's';
            $bindValues = array_merge($collectionOnValues, $layoutOnValues);
            $bindValues[] = $pVoucherCode;

            if (($companyCode !== '') && ($companyCode !== '**ALL**'))
            {
                array_unshift($bindValues, $companyCode);
            }

            $sql = 'SELECT `v`.`hasproductgroup`, !ISNULL(`pgp`.`productgroupid`) AS `productspresent`,
                    `pgh`.`active`, `pgp`.`collectioncode`, `pgp`.`productcode`
                    FROM `vouchers` AS `v`
                    LEFT JOIN `productgrouplink` AS `pgl`
                    ON `pgl`.`assigneecode` = `v`.`code`
                    LEFT JOIN `productgroupheader` AS `pgh`
                    ON (`pgl`.`productgroupid` = `pgh`.`id` AND `pgh`.`active` = 1 ' . $companyCodeSql . ')
                    LEFT JOIN `productgroupproducts` AS `pgp`
                    ON `pgh`.`id` = `pgp`.`productgroupid` AND ((`pgp`.`collectioncode` IN (' . $collectionOnField . '))
                    OR (`pgp`.`productcode` IN (' . $layoutOnField . ')))
                    WHERE `v`.`code` = ?';

            if ($stmt = $dbObj->prepare($sql))
            {
                $bindOK = DatabaseObj::bindParams($stmt, $bindDataTypes, $bindValues);

                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->num_rows > 0)
                            {
                                if ($stmt->bind_result($hasProductGroup, $productsAssigned, $groupActive, $groupCollectionCode,
                                    $groupProductCode))
                                {
                                    while ($stmt->fetch())
                                    {
                                        if ($hasProductGroup == 0)
                                        {
                                            // no product group is linked to the voucher
                                            $productGroupFound = false;
                                        }
                                        elseif($productsAssigned == 0)
                                        {
                                            // a product group is linked to the voucher but no applicable products are in the order
                                            // if we have already found an applicable product group then don't override it
                                            $productGroupFound = true;
                                            $productGroupApplicable = $productGroupApplicable ? true : false;
                                        }
                                        else
                                        {
                                            // a product group has been found and contains products from the order
                                            // return the data on the product group so that it can be filtered further
                                            $productGroupFound = true;
                                            $productGroupApplicable = true;
                                            $groupArray[$groupCollectionCode][$groupProductCode] = $groupActive;
                                        }
                                    }
                                    $stmt->free_result();
                                }
                                else
                                {
                                    // could not bind result
                                    $error = 'str_DatabaseError';
                                    $errorParam = __FUNCTION__ . ' bind result: ' . $dbObj->error;
                                }
                            }
                        }
                        else
                        {
                            // Could not store result.
                            $error = 'str_DatabaseError';
                            $errorParam = __FUNCTION__ . '  store_result ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not execute statement
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . ' execute ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not bind params
                    $error = 'str_DatabaseError';
                    $errorParam = __FUNCTION__ . ' bindparam ' . $dbObj->error;
                }

                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $error = 'str_DatabaseError';
                $errorParam = __FUNCTION__ . ' prepare ' . $dbObj->error;
            }

            $dbObj->close();
        }
        else
        {
            // could not connect to database
            $error = 'str_DatabaseError';
            $errorParam = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        $resultArray['error'] = $error;
        $resultArray['errorparam'] = $errorParam;
        $resultArray['data']['groupfound'] = $productGroupFound;
        $resultArray['data']['groupapplicable'] = $productGroupApplicable;
        $resultArray['data']['groupconfigurations'] = $groupArray;

        return $resultArray;
    }

