    static function insertProductGroupAndConfiguration($pGroupArray)
    {
        $resultArray = UtilsObj::getReturnArray();
        $error = '';
        $errorParam = '';
        $insertID = 0;

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            // start a transaction so we won't end up with corrupt product groups if something goes wrong
            $dbObj->begin_transaction();

            // insert the header record
            $sql = "INSERT INTO `productgroupheader` (`datecreated`, `companycode`, `name`, `active`)
                VALUES (NOW(), ?, ?, ?)";

            if ($stmt = $dbObj->prepare($sql))
            {
                $bindOK = $stmt->bind_param('ssi', $pGroupArray['companycode'], $pGroupArray['name'], $pGroupArray['active']);

                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                        // get the inserted ID for use in the products table
                        $insertID = $dbObj->insert_id;
                    }
                    else
                    {
                        if($stmt->errno == 1062)
                        {
                            // duplicate name
                            $error = 'str_DuplicateEntryError';
                            $errorParam = __FUNCTION__ . ' header duplicate ' . $dbObj->error;
                        }
                        else
                        {
                            // could not execute
                            $error = 'str_DatabaseError';
                            $errorParam = __FUNCTION__ . ' header execute ' . $dbObj->error;
                        }
                    }
                }
                else
                {
                    // could not bind params
                    $error = 'str_DatabaseError';
                    $errorParam = __FUNCTION__ . ' header bindparam ' . $dbObj->error;
                }
                $stmt->free_result();
                $stmt->close();
            }
            else
            {
                // could not prepare statement
                $error = 'str_DatabaseError';
                $errorParam = __FUNCTION__ . ' header prepare ' . $dbObj->error;
            }

            // insert the records for the productgroupproducts table
            $groupConfiguration = $pGroupArray['configurations'];
            $configurationCount = count($groupConfiguration);

            // only attempt to insert configurations if the group has some set up
            if ($configurationCount > 0)
            {
                $insertFields = '';
                $bindString = '';
                $bindValues = array();

                for ($i = 0; $i < $configurationCount; $i++)
                {
                    $theConfiguration = $groupConfiguration[$i];

                    //add a comma before subsequent records
                    if ($i !== 0)
                    {
                        $insertFields .= " ,";
                    }

                    $insertFields .= "(NOW(), ?, ?, ?)";
                    $bindString .= "iss";
                    array_push($bindValues, $insertID, $theConfiguration['collectioncode'], $theConfiguration['productcode']);
                }

                $sql = "INSERT INTO `productgroupproducts` (`datecreated`, `productgroupid`, `collectioncode`, `productcode`) VALUES " . $insertFields;

                if ($stmt = $dbObj->prepare($sql))
                {
                    $bindOK = DatabaseObj::bindParams($stmt, $bindString, $bindValues);

                    if ($bindOK)
                    {
                        if (! $stmt->execute())
                        {
                            // could not execute
                            $error = 'str_DatabaseError';
                            $errorParam = __FUNCTION__ . ' products execute ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not bindparams
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . ' products bindparams ' . $dbObj->error;
                    }
                    $stmt->free_result();
                    $stmt->close();
                }
                else
                {
                    // could not prepare
                    $error = 'str_DatabaseError';
                    $errorParam = __FUNCTION__ . ' products prepare ' . $dbObj->error;
                }
            }

            if ($error === '')
            {
                // commit the transaction since we have no issues
                $dbObj->commit();
            }
            else
            {
                // something has gone wrong, rollback
                $dbObj->rollback();
            }

            $dbObj->close();
        }
        else
        {
            // could not connect
            $error = 'str_DatabaseError';
            $errorParam = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        $resultArray['error'] = $error;
        $resultArray['errorparam'] = $errorParam;

        return $resultArray;
    }

