    static function getCollectionGridData($pGroupID)
    {
        global $gSession;

        $returnArray = UtilsObj::getReturnArray();
        $error = '';
        $errorParam = '';
        $companyCode = $gSession['userdata']['companycode'];
        $collectionsArray = array();
        $collectionCode = '';
        $collectionName = '';
        $productCode = '';
        $productName = '';
        $selected = 0;
        $collectionRule = 0;

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            $sql = "SELECT `pcl`.`collectioncode`, `pcl`.`collectionname`, `pcl`.`productcode`, `pcl`.`productname`, ! ISNULL(`pgh`.`id`) AS `selected`, IF(`pgp`.`productcode` = '*', 1, 0) AS `iscollectionrule`
                FROM `productcollectionlink` AS `pcl`
                LEFT JOIN (`productgroupproducts` AS `pgp`
                    INNER JOIN `productgroupheader` AS `pgh` ON (`pgh`.`id` = `pgp`.`productgroupid` AND `pgh`.`id` = ?))
                ON (((`pgp`.`productcode` = `pcl`.`productcode`) AND (`pgp`.`collectioncode` = `pcl`.`collectioncode`))
                    OR ((`pgp`.`productcode` = '*') AND (`pgp`.`collectioncode` = `pcl`.`collectioncode`)))
                INNER JOIN `products` AS `p` ON (`p`.`code` = `pcl`.`productcode` AND `p`.`deleted` = 0)";

            if (($companyCode !== '**ALL**') && ($companyCode !== ''))
            {
                $sql .= " WHERE `pcl`.`companycode` = ? OR `pcl`.`companycode` = ''";
            }

            $sql .= " GROUP BY `pcl`.`collectioncode`, `pcl`.`collectionname`, `pcl`.`productcode`, `pcl`.`productname`
                ORDER BY `pcl`.`collectioncode`, `pcl`.`productcode` ASC";

            if ($stmt = $dbObj->prepare($sql))
            {
                $bindOK = false;

                if (($companyCode !== '**ALL**') && ($companyCode !== ''))
                {
                    $bindOK = $stmt->bind_param('is', $pGroupID, $companyCode);
                }
                else
                {
                    $bindOK = $stmt->bind_param('i', $pGroupID);
                }

                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->bind_result($collectionCode, $collectionName, $productCode, $productName, $selected, $collectionRule))
                            {
                                while ($stmt->fetch())
                                {
                                    $collectionsArray[$collectionCode]['name'] = $collectionName;
                                    $collectionsArray[$collectionCode]['selected'] = ($selected == 1 && $collectionRule == 1) ? 1 : 0;
                                    $layoutArray = array('code' => $productCode, 'name' => $productName);
                                    // if there a record had a group products entry without being marked as a collection rule it has been selected
                                    $layoutArray['selected'] = ($selected == 1 && $collectionRule == 0) ? 1 : 0;
                                    $collectionsArray[$collectionCode]['products'][] = $layoutArray;

                                }
                            }
                            else
                            {
                                // could not bind result
                                $error = 'str_DatabaseError';
                                $errorParam = __FUNCTION__ . ' bindresult ' . $dbObj->error;
                            }
                        }
                        else
