    static function updateProductGroup($pGroupArray, $pGroupID, $pLayoutrulesToDeleteArray, $pCollectionRulesToDeleteArray)
    {
        global $gSession;

        $returnArray = UtilsObj::getReturnArray();
        $sql = '';
        $error = '';
        $errorParam = '';
        $whereClause = '';
        $bindValues = array();
        $bindDataTypes = array();
        $layoutRulesToDeleteCount = count($pLayoutrulesToDeleteArray);
        $collectionRulesToDeleteCount = count($pCollectionRulesToDeleteArray);
        $groupConfiguration = $pGroupArray['configurations'];
        $configurationCount = count($groupConfiguration);
        $firstLoop = true;

        $dbObj = DatabaseObj::getGlobalDBConnection();

        if ($dbObj)
        {
            // start a transaction so we can roll it all back if one of the two inserts fails
            if ($dbObj->begin_transaction())
            {
                $sql = 'UPDATE `productgroupheader`
                    SET `name` = ?
                    WHERE `id` = ?';

                $bindValues = array($pGroupArray['name'], $pGroupID);
                $bindDataTypes = array('s', 'i');

                if ($stmt = $dbObj->prepare($sql))
                {
                    $bindOK = DatabaseObj::bindParams($stmt, $bindDataTypes, $bindValues);

                    if ($bindOK)
                    {
                        if (!$stmt->execute())
                        {
                            if($stmt->errno == 1062)
                            {
                                // duplicate name
                                $error = 'str_DuplicateEntryError';
                                $errorParam = __FUNCTION__ . ' header duplicate ' . $dbObj->error;
                            }
                            else
                            {
                                // could not execute
                                $error = 'str_DatabaseError';
                                $errorParam = __FUNCTION__ . ' nameupdate execute ' . $dbObj->error;
                            }
                        }
                    }
                    else
                    {
                        // could not bindparams
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . ' nameupdate bindparams ' . $dbObj->error;
                    }
                }
                else
                {
                    // could not prepare
                    $error = 'str_DatabaseError';
                    $errorParam = __FUNCTION__ . ' nameupdate prepare ' . $dbObj->error;
                }

                // only run the delete query if we actually have something to delete
                if (($error === '') && (($layoutRulesToDeleteCount > 0) || $collectionRulesToDeleteCount > 0))
                {
                    $bindDataTypes = array();
                    $bindValues = array();

                    foreach ($pLayoutrulesToDeleteArray as $theLayoutRuleToDelete)
                    {
                        if (! $firstLoop)
                        {
                            $whereClause .= ' OR ';
                        }

                        $whereClause .= " (`collectioncode` = '*' AND `productcode` = ?)";
                        $bindValues[] = $theLayoutRuleToDelete;
                        $bindDataTypes[] = 's';

                        $firstLoop = false;
                    }

                    // note that we do not reset the firstloop bool as we want a comma if it has looped previously
                    foreach ($pCollectionRulesToDeleteArray as $theCollectionRuleToDelete)
                    {
                        if (! $firstLoop)
                        {
                            $whereClause .= ' OR ';
                        }

                        $whereClause .= " (`collectioncode` = ? AND `productcode` = ?)";
                        $bindValues[] = $theCollectionRuleToDelete['collectioncode'];
                        $bindValues[] = $theCollectionRuleToDelete['productcode'];
                        $bindDataTypes[] = 's';
                        $bindDataTypes[] = 's';

                        $firstLoop = false;
                    }

                    $sql = 'DELETE FROM `productgroupproducts`
                    WHERE (' . $whereClause . ') AND `productgroupid` = ?';

                    $bindValues[] = $pGroupID;
                    $bindDataTypes[] = 'i';


                    if ($stmt = $dbObj->prepare($sql))
                    {
                        $bindOK = DatabaseObj::bindParams($stmt, $bindDataTypes, $bindValues);

                        if ($bindOK)
                        {
                            if (!$stmt->execute())
                            {
                                // could not execute
                                $error = 'str_DatabaseError';
                                $errorParam = __FUNCTION__ . ' delete execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not execute
                            $error = 'str_DatabaseError';
                            $errorParam = __FUNCTION__ . ' delete bindok ' . $dbObj->error;
                        }
                    }
                    else
                    {
                        // could not prepare
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . ' delete prepare ' . $dbObj->error;
                    }
                }

                if (($error === '') && ($configurationCount > 0))
                {
                    $insertFields = '';
                    $bindString = '';
                    $bindDataTypes = array();
                    $bindValues = array();


                    for ($i = 0; $i < $configurationCount; $i++)
                    {
                        $theConfiguration = $groupConfiguration[$i];

                        //add a comma before subsequent records
                        if ($i !== 0)
                        {
                            $insertFields .= " ,";
                        }

                        $insertFields .= "(NOW(), ?, ?, ?)";
                        $bindString .= "iss";
                        array_push($bindValues, $pGroupID, $theConfiguration['collectioncode'], $theConfiguration['productcode']);
                    }

                    $sql = "INSERT INTO `productgroupproducts` (`datecreated`, `productgroupid`, `collectioncode`, `productcode`) VALUES " . $insertFields;

                    if ($stmt = $dbObj->prepare($sql))
                    {
                        $bindOK = DatabaseObj::bindParams($stmt, $bindString, $bindValues);

                        if ($bindOK)
                        {
                            if (! $stmt->execute())
                            {
                                // could not execute
                                $error = 'str_DatabaseError';
                                $errorParam = __FUNCTION__ . ' products execute ' . $dbObj->error;
                            }
                        }
                        else
                        {
                            // could not bindparams
                            $error = 'str_DatabaseError';
                            $errorParam = __FUNCTION__ . ' products bindparams ' . $dbObj->error;
                        }
                        $stmt->free_result();
                        $stmt->close();
                    }
                    else
                    {
                        // could not bindparams
                        $error = 'str_DatabaseError';
                        $errorParam = __FUNCTION__ . ' products prepare ' . $dbObj->error;
                    }
                }
                if ($error === '')
                {
                    // commit the transaction since we have no issues
                    $dbObj->commit();
                }
                else
                {
                    // something has gone wrong, rollback
                    $dbObj->rollback();
                }

                $dbObj->close();
            }
            else
            {
                // could not begintransaction
                $error = 'str_DatabaseError';
                $errorParam = __FUNCTION__ . ' begintransaction ' . $dbObj->error;
            }
        }
        else
        {
            // could not connect
            $error = 'str_DatabaseError';
            $errorParam = __FUNCTION__ . ' connect ' . $dbObj->error;
        }

        $returnArray['error'] = $error;
        $returnArray['errorparam'] = $errorParam;

        return $returnArray;
    }

