                FROM `productgrouplink`
                WHERE `productgroupid` = ?
                GROUP BY `productgroupid`";

            if ($stmt = $dbObj->prepare($sql))
            {
                $bindOK = $stmt->bind_param('i', $pGroupID);

                if ($bindOK)
                {
                    if ($stmt->execute())
                    {
                        if ($stmt->store_result())
                        {
                            if ($stmt->bind_result($rowCount))
                            {
                                if ($stmt->fetch())
                                {
                                    // we can only delete if we have no link records found
                                    if ($rowCount > 0)
                                    {
                                        $result = 'str_WarningDeleteGroupAssignedToVoucher';
