	static function getDataFromTable($pColumns, $pTable, $pDbObj, $pEmptyText = '', $pAssoc = false, $pWhere = [])
	{
		$resultArray = UtilsObj::getReturnArray();
		$params = [];
		$rawCols = array_fill_keys($pColumns, null);
		$cols = [];
		foreach ($rawCols as $key => $value) {
			$cols[] = &$rawCols[$key];
		}

		$query = 'SELECT `' . join('`, `', $pColumns) . '` FROM `' . $pTable . '`';

		if (!empty($pWhere)) {
			$params[0] = '';
			$includeAnd = false;
			foreach ($pWhere as $key => $value) {
				$params[0] .= 's';
				$params[] = $value;
				$query .= ($includeAnd ? ' AND ' : ' WHERE ') . '`' . $key . '` = ?';
				$includeAnd = true;
			}
		}

		try {
			if (!$stmt = $pDbObj->prepare($query)) {
				throw new Exception(__METHOD__ . ' prepare: ' . $pDbObj->error);
			}

			if (!empty($params)) {
				if (!$stmt->bind_param(...$params)) {
					throw new Exception(__METHOD__ . ' bind params: ' . $pDbObj->error);
				}
			}

			if (!$stmt->execute()) {
				throw new Exception(__METHOD__ . ' execute: ' . $pDbObj->error);
			}

			if (!$stmt->store_result()) {
				throw new Exception(__METHOD__ . ' store: ' . $pDbObj->error);
			}

			if ($stmt->num_rows > 0) {
				if (!empty($cols)) {
                    if ($stmt->bind_result(...$cols))
                    {
						throw new Exception(__METHOD__ . ' bind result: ' . $pDbObj->error);
					}

					while ($stmt->fetch()) {
						$item = [];
						foreach ($cols as $key => $value) {
							if ($pAssoc) {
								$item[$key] = '' !== $value ? $value : $pEmptyText;
							} else {
								$item[] = '' !== $value ? $value : $pEmptyText;
							}
						}
						$resultArray['data'][] = $item;
					}
				}
			}
		} catch (Exception $ex) {
			$resultArray['error'] = 'str_DatabaseError';
			$resultArray['errorparam'] = $ex->getMessage();
		}

		return $resultArray;
	}
